// Responsive device detection
const DEVICE = (()=>{
  const w = window.innerWidth;
  const ua = navigator.userAgent||'';
  const isIpad = /ipad/i.test(ua)||(w>=768&&/mac/i.test(ua)&&navigator.maxTouchPoints>1);
  return { isIpad, cardMax: isIpad ? 660 : 420 };
})();
const TEAM_LOGO = "data:image/png;base64,";

const TEAM_LOGOS = {
  bardonBandits: "data:image/png;base64,",
  bardonStars: "data:image/png;base64,",
  bardonBananas: "data:image/png;base64,",
  brisbaneKnights: "data:image/png;base64,",
  glitterDragons: "data:image/png;base64,",
  koalas: "data:image/png;base64,",
  rubies: "data:image/png;base64,",
  springfield: "data:image/png;base64,",
  theGap: "data:image/png;base64,",
  toowongRose: "data:image/png;base64,",
  toowongWhite: "data:image/png;base64,",
  uqfcDiamonds: "data:image/png;base64,",
  uqfcEmeralds: "data:image/png;base64,",
  uqfcSapphires: "data:image/png;base64,",
};

function getTeamLogo(name) {
  if (!name) return null;
  const n = name.toLowerCase();
  if (n.includes('rubies'))                              return TEAM_LOGOS.rubies;
  if (n.includes('bandit'))                              return TEAM_LOGOS.bardonBandits;
  if (n.includes('star') && n.includes('bardon'))        return TEAM_LOGOS.bardonStars;
  if (n.includes('banana'))                              return TEAM_LOGOS.bardonBananas;
  if (n.includes('knight'))                              return TEAM_LOGOS.brisbaneKnights;
  if (n.includes('glitter') || n.includes('dragon'))     return TEAM_LOGOS.glitterDragons;
  if (n.includes('koala'))                               return TEAM_LOGOS.koalas;
  if (n.includes('springfield'))                         return TEAM_LOGOS.springfield;
  if (n.includes('gap'))                                 return TEAM_LOGOS.theGap;
  if (n.includes('rose'))                                return TEAM_LOGOS.toowongRose;
  if (n.includes('white') && n.includes('toowong'))      return TEAM_LOGOS.toowongWhite;
  if (n.includes('emerald'))                             return TEAM_LOGOS.uqfcEmeralds;
  if (n.includes('sapphire'))                            return TEAM_LOGOS.uqfcSapphires;
  if (n.includes('diamond'))                             return TEAM_LOGOS.uqfcDiamonds;
  return null;
}


