//  SCREEN: SETTINGS
// ════════════════════════════════════════════════════════════════════════════════
function SettingsScreen({ settings, onSave, onBack, onViewImportExport }) {
  const [form, setForm] = useState({ ...settings });

  const allTeams = [...new Set(FIXTURES.flatMap(f => [f.home, f.away]))].sort();

  function upd(key, val) { setForm(f=>({...f,[key]:val})); }

  function save() {
    // Keep soccerCoach_fixtureTeam in sync with teamName
    if (form.teamName) localStorage.setItem('soccerCoach_fixtureTeam', form.teamName);
    onSave(form);
    onBack();
  }





  return (
    <div style={{ minHeight:'100vh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)', display:'flex', flexDirection:'column' }}>
      {/* Header */}
      <div style={{ position:'relative', display:'flex', alignItems:'center', padding:'14px 16px 10px', background:'#111111', borderBottom:'1px solid #1A1A1A', flexShrink:0 }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#A1A1A1', fontSize:22, padding:0, lineHeight:1, position:'absolute', left:16 }}>←</button>
        <div style={{ flex:1, textAlign:'center', fontSize:14, fontWeight:700, color:'#FFFFFF', letterSpacing:2, textTransform:'uppercase' }}>Settings</div>
      </div>
      {/* Fields */}
      <div style={{ flex:1, overflowY:'auto', padding:'20px 16px', display:'flex', flexDirection:'column', gap:16 }}>
        <div>
          <div style={S.fieldLbl}>Our team</div>
          <select style={{...S.inp, width:'100%'}} value={form.teamName||''} onChange={e=>upd('teamName',e.target.value)}>
            <option value=''>— Select your team —</option>
            {allTeams.map(t=><option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        {[["coachName","Coach name"],["managerName","Manager name"]].map(([key,lbl])=>(
          <div key={key}>
            <div style={S.fieldLbl}>{lbl}</div>
            <input style={{...S.inp,width:'100%'}} value={form[key]||''} onChange={e=>upd(key,e.target.value)} />
          </div>
        ))}
        <button style={{...S.btnGreen, width:'100%'}} onClick={save}>Save Settings</button>
        <button style={{...S.btnDark, width:'100%', fontSize:13, display:'flex', alignItems:'center', justifyContent:'center', gap:8}} onClick={onViewImportExport}>
          📦 Import / Export Data
        </button>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: PLAYER STATS
// ════════════════════════════════════════════════════════════════════════════════
function StatsScreen({ games, onBack }) {
  const rows = computePlayerStats(games).sort((a,b)=>b.apps-a.apps||b.goals-a.goals);
  const COL = {width:38,textAlign:"center",fontSize:13,fontWeight:700,flexShrink:0};
  return (
    <div style={{ minHeight:'100vh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)', display:'flex', flexDirection:'column' }}>
      <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0, position:'relative' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', color:'#F5C04A', fontSize:22, cursor:'pointer', padding:0, lineHeight:1, flexShrink:0, zIndex:1 }}>←</button>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:40, objectFit:'contain', marginLeft:8, zIndex:1 }} />
        <div style={{ position:'absolute', left:0, right:0, textAlign:'center', pointerEvents:'none' }}>
          <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>Player Stats</span>
        </div>
      </div>
      <div style={{ fontSize:12, color:'#666', padding:'8px 16px 8px 16px', background:'#0D0D0D' }}>{games.length} game{games.length!==1?"s":""} recorded</div>
      <div style={{ flex:1, overflowY:'auto' }}>
        {rows.length===0
          ? <p style={{ padding:"20px 16px", color:"#A1A1A1", fontSize:13 }}>Save some games to see player stats.</p>
          : <>
              <div style={{display:"flex",alignItems:"center",padding:"8px 16px",background:"#0D0D0D",borderBottom:"1px solid #1A1A1A"}}>
                <span style={{flex:1,fontSize:11,fontWeight:700,color:"#A1A1A1",textTransform:"uppercase",letterSpacing:1}}>Player</span>
                <span style={{...COL,fontSize:11,color:"#A1A1A1"}}>Apps</span>
                <span style={{...COL,fontSize:14}}>⚽</span>
                <span style={{...COL,fontSize:14}}>🧤</span>
                <span style={{...COL,fontSize:14}}>⭐</span>
              </div>
              {rows.map((r,i)=>(
                <div key={r.name} style={{display:"flex",alignItems:"center",padding:"10px 16px",borderBottom:"1px solid #1A1A1A",background:i%2===0?"#111111":"#0D0D0D"}}>
                  <span style={{flex:1,fontSize:13,color:"#FFFFFF",fontWeight:600,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.name}</span>
                  <span style={{...COL,color:"#A1A1A1"}}>{r.apps||"–"}</span>
                  <span style={{...COL,color:r.goals>0?"#F5C04A":"#2A2A2A",fontWeight:r.goals>0?800:400}}>{r.goals||"–"}</span>
                  <span style={{...COL,color:r.gkPeriods>0?"#38bdf8":"#2A2A2A",fontWeight:r.gkPeriods>0?700:400}}>{r.gkPeriods||"–"}</span>
                  <span style={{...COL,color:r.potm>0?"#fcd34d":"#2A2A2A",fontWeight:r.potm>0?700:400}}>{r.potm||"–"}</span>
                </div>
              ))}
            </>
        }
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: SEASON LOG
// ════════════════════════════════════════════════════════════════════════════════
function SeasonScreen({ games, onBack, onOpenGame, onDeleteGame }) {
  const fxScores = loadFxScores();
  return (
    <div style={S.page}>
      <div style={{...S.card,maxWidth:440}}>
        <h1 style={S.h1}>Season Log</h1>
        {games.length===0&&<p style={S.sub}>No games saved yet.</p>}
        {games.slice().reverse().map(g=>{
          const sc=getScore(g, fxScores);
          const res=sc.us>sc.them?"W":sc.us<sc.them?"L":"D";
          const resColor=res==="W"?"#F5C04A":res==="L"?"#ef4444":"#A1A1A1";
          return (
            <div key={g.id} style={S.gameRow} onClick={()=>onOpenGame(g.id)}>
              <div style={{...S.resultBadge,background:resColor+"22",color:resColor,border:`1px solid ${resColor}55`}}>{res}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={S.gameOpp}>vs {g.opponent||"Opposition"}</div>
                <div style={S.gameDate}>{new Date(g.date).toLocaleDateString()}</div>
                {(()=>{
                  const scorers=[...new Set((g.goals||[]).filter(x=>x.team==="us").map(x=>x.scorer))];
                  const potmArr=Array.isArray(g.potm)?g.potm:(g.potm?[g.potm]:[]);
                  return (<div style={{display:"flex",gap:6,marginTop:3,flexWrap:"wrap"}}>
                    {scorers.length>0&&<span style={{fontSize:9,color:"#FDE68A",fontWeight:600}}>⚽ {scorers.join(", ")}</span>}
                    {potmArr.length>0&&<span style={{fontSize:9,color:"#fcd34d",fontWeight:600}}>⭐ {potmArr.join(", ")}</span>}
                  </div>);
                })()}
              </div>
              <div style={S.gameScore}>{sc.us}–{sc.them}</div>
              <button style={S.btnTinyX} onClick={e=>{e.stopPropagation();onDeleteGame(g.id);}}>✕</button>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: GAME LOG (standalone component so hooks work correctly)
// ════════════════════════════════════════════════════════════════════════════════
function GameLogScreen({ onBack, onOpenGame, onDeleteGame }) {
  const allRes = getAllResults();
  const [sortOrder, setSortOrder] = React.useState('recent');
  const { wins, draws, losses, gf, ga, gd } = computeSeasonStats();

  const sorted = sortOrder === 'recent' ? [...allRes].reverse() : [...allRes];

  const DAYS   = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  function fmtDate(dateStr) {
    if (!dateStr) return '';
    const d = parseFixtureDate ? parseFixtureDate(dateStr) : null;
    if (!d) return dateStr;
    return `${d.getDate()} ${MONTHS[d.getMonth()]}`;
  }

  return (
    <div style={{ minHeight:'100dvh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)', display:'flex', flexDirection:'column' }}>

      {/* Header */}
      <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0, position:'relative' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', color:'#F5C04A', fontSize:22, cursor:'pointer', padding:0, lineHeight:1, flexShrink:0, zIndex:1 }}>←</button>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:40, objectFit:'contain', marginLeft:8, zIndex:1 }} />
        <div style={{ position:'absolute', left:0, right:0, textAlign:'center', pointerEvents:'none' }}>
          <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>Game Log</span>
        </div>
        <div style={{ flex:1 }} />
        <div style={{ fontSize:12, color:'#A1A1A1' }}>{allRes.length} result{allRes.length!==1?'s':''}</div>
      </div>

      {/* Stats bar */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-around', background:'#111111', borderBottom:'1px solid #1E1E1E', padding:'10px 16px', flexShrink:0 }}>
        {[['W', wins, '#22c55e'], ['D', draws, '#F5C04A'], ['L', losses, '#ef4444'], ['GF', gf, '#FFFFFF'], ['GA', ga, '#A1A1A1'], ['GD', (gd>=0?'+':'')+gd, gd>0?'#22c55e':gd<0?'#ef4444':'#A1A1A1']].map(([label,val,color])=>(
          <div key={label} style={{ textAlign:'center' }}>
            <div style={{ fontSize:17, fontWeight:800, color, lineHeight:1 }}>{val}</div>
            <div style={{ fontSize:9, color:'#555', fontWeight:600, letterSpacing:0.5, marginTop:3, textTransform:'uppercase' }}>{label}</div>
          </div>
        ))}
      </div>

      {/* Filter bar */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', padding:'8px 16px', background:'#111111', borderBottom:'1px solid #1E1E1E', flexShrink:0 }}>
        <span style={{ fontSize:11, fontWeight:700, color:'#A1A1A1', letterSpacing:1 }}>ALL MATCHES</span>
        <select value={sortOrder} onChange={e=>setSortOrder(e.target.value)}
          style={{ background:'#0D0D0D', border:'1px solid #2A2A2A', borderRadius:6, color:'#A1A1A1', fontSize:11, cursor:'pointer', outline:'none', padding:'4px 8px' }}>
          <option value="recent">Most Recent</option>
          <option value="oldest">Oldest First</option>
        </select>
      </div>

      {/* Results list */}
      <div style={{ flex:1, overflowY:'auto', padding:'0 12px 20px' }}>
        {sorted.length === 0 && (
          <div style={{ textAlign:'center', color:'#A1A1A1', fontSize:13, padding:'40px 0' }}>No results yet.</div>
        )}
        {sorted.map((r, i) => {
          const res = r.us > r.them ? 'W' : r.us < r.them ? 'L' : 'D';
          const resColor = res==='W' ? '#F5C04A' : res==='L' ? '#ef4444' : '#A1A1A1';
          const resBg    = res==='W' ? '#F5C04A18' : res==='L' ? '#ef444418' : '#1A1A1A';
          const g = r.game;
          const hasDetail = !!g;
          const scorers = g ? [...new Set((g.goals||[]).filter(x=>x.team==='us').map(x=>x.scorer))] : [];
          const potmArr = g ? (Array.isArray(g.potm)?g.potm:(g.potm?[g.potm]:[])) : [];
          const isFixture = r.type === 'fixture';
          const notLast = i < sorted.length - 1;

          return (
            <div key={r.id||i} style={{ display:'flex', alignItems:'center', gap:10, padding:'12px 4px', borderBottom: notLast ? '1px solid #1A1A1A' : 'none' }}>
              {/* W/D/L badge */}
              <div style={{ width:36, height:36, borderRadius:8, background:resBg, border:`1px solid ${resColor}44`, display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                <span style={{ fontSize:14, fontWeight:700, color:resColor }}>{res}</span>
              </div>
              {/* Team logo */}
              <TeamBadge name={r.opponent} size={44} radius={8} />
              {/* Details */}
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontSize:14, fontWeight:600, color:'#FFFFFF', marginBottom:2 }}>vs {r.opponent}</div>
                <div style={{ fontSize:11, color:'#A1A1A1', marginBottom:1 }}>
                  {r.round && <span>{r.round} · </span>}
                  <span>{r.dateStr || (g ? new Date(g.date).toLocaleDateString('en-AU',{day:'numeric',month:'short'}) : '')}</span>
                  {r.isHome !== null && r.isHome !== undefined && (
                    <span> · <span style={{ color: r.isHome ? '#F5C04A' : '#A1A1A1' }}>{r.isHome ? 'Home' : 'Away'}</span></span>
                  )}
                </div>
                <div style={{ fontSize:10, color:'#A1A1A1' }}>
                  {scorers.length > 0 && <span>⚽ {scorers.join(', ')} </span>}
                  {potmArr.length > 0 && <span>⭐ {potmArr.join(', ')} </span>}
                  {!hasDetail && isFixture && <span style={{ color:'#555' }}>fixture only</span>}
                </div>
              </div>
              {/* Score */}
              <div style={{ fontSize:18, fontWeight:700, color:'#FFFFFF', flexShrink:0, minWidth:40, textAlign:'right' }}>{r.us}–{r.them}</div>
              {/* Action */}
              {hasDetail ? (
                <button onClick={()=>onOpenGame(g.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#F5C04A', fontSize:22, padding:'0 2px', flexShrink:0, lineHeight:1 }}>›</button>
              ) : isFixture ? (
                <span style={{ fontSize:22, color:'#2A2A2A', padding:'0 2px', flexShrink:0, lineHeight:1 }}>›</span>
              ) : (
                <button onClick={e=>{e.stopPropagation(); if(g) onDeleteGame(g.id);}} style={{ background:'none', border:'none', cursor:'pointer', color:'#555', fontSize:18, padding:'0 2px', flexShrink:0, lineHeight:1 }}>×</button>
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
}


// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: SEASON HUB (tabbed)
// ════════════════════════════════════════════════════════════════════════════════
function SeasonHubScreen({ games, onBack, onOpenGame, onDeleteGame, onScout }) {
  const [subScreen, setSubScreen] = useState(() => { const s = _pendingSeasonSub; _pendingSeasonSub = null; return s; });
  const [teamNotes, setTeamNotes] = useState(() => loadTeamNotes());
  const [selectedTeam, setSelected] = useState('');
  const [noteText, setNoteText]   = useState('');
  const [fixtureDetailGame, setFixtureDetailGame] = useState(null);

  const allTeams = [...new Set(FIXTURES.flatMap(f => [f.home, f.away]))].sort();
  function selectTeam(name) { setSelected(name); setNoteText(teamNotes[name] || ''); }
  function saveNote() {
    if (!selectedTeam) return;
    const updated = { ...teamNotes, [selectedTeam]: noteText };
    setTeamNotes(updated); saveTeamNotes(updated);
  }

  const { played, wins, draws, losses, gf, ga, gd } = computeSeasonStats();

  // Shared sub-screen page wrapper
  const subPage = (title, children) => (
    <div style={{ minHeight:'100dvh', background:'#0D0D0D', paddingBottom:90, display:'flex', flexDirection:'column' }}>
      <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0, position:'relative' }}>
        <button onClick={()=>setSubScreen(null)} style={{ background:'none', border:'none', color:'#F5C04A', fontSize:22, cursor:'pointer', padding:0, lineHeight:1, flexShrink:0, zIndex:1 }}>←</button>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:40, objectFit:'contain', marginLeft:8, zIndex:1 }} />
        <div style={{ position:'absolute', left:0, right:0, textAlign:'center', pointerEvents:'none' }}>
          <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>{title}</span>
        </div>
      </div>
      {children}
    </div>
  );

  // Fixture match report overlay
  if (fixtureDetailGame) {
    return <GameDetailScreen game={fixtureDetailGame} onBack={()=>setFixtureDetailGame(null)} onUpdateGame={null} />;
  }

  // ── Game Log ────────────────────────────────────────────────────────────────
  if (subScreen === 'log') {
    return <GameLogScreen onBack={()=>setSubScreen(null)} onOpenGame={onOpenGame} onDeleteGame={onDeleteGame} />;
  }

  // ── Fixtures ────────────────────────────────────────────────────────────────
  if (subScreen === 'fixtures') return subPage('Fixtures', (
    <div style={{ overflowY:'auto', flex:1 }}>
      <FixturesScreen embedded games={games} onViewGame={g=>setFixtureDetailGame(g)} />
    </div>
  ));

  // ── Ladder ──────────────────────────────────────────────────────────────────
  if (subScreen === 'ladder') return subPage('Ladder', (
    <div style={{ overflowY:'auto', flex:1, padding:'0 16px 20px' }}>
      <LadderScreen embedded />
    </div>
  ));

  // ── Scout ───────────────────────────────────────────────────────────────────
  if (subScreen === 'scout') return (
    <div style={{ minHeight:'100dvh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)', display:'flex', flexDirection:'column' }}>
      <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0, position:'relative' }}>
        <button onClick={()=>setSubScreen(null)} style={{ background:'none', border:'none', color:'#F5C04A', fontSize:22, cursor:'pointer', padding:0, lineHeight:1, flexShrink:0, zIndex:1 }}>←</button>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:40, objectFit:'contain', marginLeft:8, zIndex:1 }} />
        <div style={{ position:'absolute', left:0, right:0, textAlign:'center', pointerEvents:'none' }}>
          <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>Scout</span>
        </div>
      </div>
      <div style={{ flex:1, overflowY:'auto', padding:'16px' }}>
        <div style={{ fontSize:11, fontWeight:700, color:'#A1A1A1', textTransform:'uppercase', letterSpacing:1, marginBottom:10 }}>Select a team to scout</div>
        <div style={{ display:'flex', flexDirection:'column', gap:2 }}>
          {allTeams.map((t, i) => (
            <button key={t} onClick={() => onScout ? onScout(t) : setSelected(t)} style={{
              width:'100%', padding:'12px 14px', cursor:'pointer', textAlign:'left',
              background:'#111111',
              border:'1px solid #1E1E1E',
              borderRadius: i===0 ? '14px 14px 4px 4px' : i===allTeams.length-1 ? '4px 4px 14px 14px' : '4px',
              marginBottom:2,
              display:'flex', alignItems:'center', gap:12,
            }}>
              <TeamBadge name={t} size={32} radius={6} />
              <div style={{ flex:1, fontSize:14, fontWeight:600, color:'#FFFFFF' }}>{t}</div>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#555" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18l6-6-6-6"/></svg>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  // ── Insights ────────────────────────────────────────────────────────────────
  if (subScreen === 'insights') return subPage('Insights', (
    <InsightsScreen games={games} />
  ));

  // ── Hub (list nav) ──────────────────────────────────────────────────────────
  const allResults = getAllResults();
  const winRate = played > 0 ? Math.round((wins/played)*100) : null;
  const nextFix  = FIXTURES.find(f => isUpcoming(f));

  const NAV = [
    { id:'log',      icon:'📋', label:'Game Log',    sub: played > 0 ? `${played} result${played!==1?'s':''}` : 'No results yet',        color:'#F5C04A' },
    { id:'fixtures', icon:'📅', label:'Fixtures',    sub: nextFix ? `Next: ${nextFix.opponent||nextFix.away||'TBC'} · ${nextFix.date}` : 'View schedule', color:'#38bdf8' },
    { id:'ladder',   icon:'🏅', label:'Ladder',      sub: 'Season standings',                                                              color:'#a78bfa' },
    { id:'scout',    icon:'🔍', label:'Scout',       sub: `${allTeams.length} teams in the competition`,                                  color:'#22c55e' },
    { id:'insights', icon:'📊', label:'Insights',    sub: played > 0 ? `${winRate}% win rate · GD ${gd>=0?'+':''}${gd}` : 'Season analytics', color:'#F5C04A' },
  ];

  return (
    <div style={{ minHeight:'100dvh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)' }}>

      {/* Header */}
      <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0 }}>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:40, objectFit:'contain' }} />
        <div style={{ flex:1, textAlign:'center' }}>
          <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>Season</span>
        </div>
        <div style={{ width:48 }} />
      </div>

      {/* Season stat strip */}
      {played > 0 && (
        <div style={{ margin:'4px 16px 16px', background:'#111111', border:'1px solid #1E1E1E', borderRadius:14, padding:'12px 16px' }}>
          <div style={{ display:'flex', justifyContent:'space-around' }}>
            {[
              [played, 'Played', '#FFFFFF'],
              [wins,   'Won',    '#22c55e'],
              [draws,  'Drawn',  '#F5C04A'],
              [losses, 'Lost',   '#ef4444'],
              [(gd>=0?'+':'')+gd, 'GD',  gd>0?'#22c55e':gd<0?'#ef4444':'#A1A1A1'],
            ].map(([val, label, color]) => (
              <div key={label} style={{ textAlign:'center' }}>
                <div style={{ fontSize:20, fontWeight:600, color, lineHeight:1 }}>{val}</div>
                <div style={{ fontSize:10, color:'#777', fontWeight:600, textTransform:'uppercase', letterSpacing:0.8, marginTop:3 }}>{label}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Nav list */}
      <div style={{ padding:'0 16px' }}>
        {NAV.map((item, i) => (
          <button key={item.id} onClick={()=>setSubScreen(item.id)} style={{
            width:'100%', background:'#111111',
            border:'1px solid #1E1E1E',
            borderRadius: i===0 ? '14px 14px 4px 4px' : i===NAV.length-1 ? '4px 4px 14px 14px' : '4px',
            padding:'14px 16px', marginBottom:2,
            display:'flex', alignItems:'center', gap:14,
            cursor:'pointer', textAlign:'left',
          }}>
            <div style={{
              width:42, height:42, borderRadius:12, flexShrink:0,
              background: item.color + '18', border: `1px solid ${item.color}33`,
              display:'flex', alignItems:'center', justifyContent:'center', fontSize:20,
            }}>{item.icon}</div>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:15, fontWeight:700, color:'#FFFFFF', marginBottom:2 }}>{item.label}</div>
              <div style={{ fontSize:12, color:'#A1A1A1', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>{item.sub}</div>
            </div>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#555" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
              <path d="M9 18l6-6-6-6"/>
            </svg>
          </button>
        ))}
      </div>
    </div>
  );
}

// ── InsightsScreen ───────────────────────────────────────────────────────────
function InsightsScreen({ games }) {
  const allResults = getAllResults();
  const { played, wins, draws, losses, gf, ga, gd } = computeSeasonStats();

  if (played === 0) {
    return (
      <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:'40px 20px', color:'#A1A1A1', textAlign:'center' }}>
        <div style={{ fontSize:40, marginBottom:12 }}>📊</div>
        <div style={{ fontSize:16, fontWeight:700, color:'#FFFFFF', marginBottom:6 }}>No data yet</div>
        <div style={{ fontSize:13 }}>Record your first match result to see season insights.</div>
      </div>
    );
  }

  const winRate  = Math.round((wins/played)*100);
  const avgGF    = (gf/played).toFixed(1);
  const avgGA    = (ga/played).toFixed(1);

  // Home / Away split
  const homeRes  = allResults.filter(r => r.isHome === true);
  const awayRes  = allResults.filter(r => r.isHome === false);
  const homeWins = homeRes.filter(r => r.us > r.them).length;
  const awayWins = awayRes.filter(r => r.us > r.them).length;

  // Last 5 form
  const last5 = [...allResults].slice(-5).reverse();

  // Top scorers (from game log)
  const scorerTally = {};
  games.forEach(g => {
    (g.goals||[]).filter(x=>x.team==='us' && x.scorer).forEach(gl => {
      scorerTally[gl.scorer] = (scorerTally[gl.scorer]||0) + 1;
    });
  });
  const topScorers = Object.entries(scorerTally).sort((a,b)=>b[1]-a[1]).slice(0,5);

  // Biggest wins/losses
  const byMargin = [...allResults].sort((a,b) => Math.abs(b.us-b.them) - Math.abs(a.us-a.them));
  const biggestWin  = byMargin.find(r => r.us > r.them);
  const biggestLoss = byMargin.find(r => r.us < r.them);

  const card = { background:'#111111', border:'1px solid #1E1E1E', borderRadius:14, padding:'14px 16px', marginBottom:10 };
  const sectionLabel = { fontSize:11, fontWeight:700, color:'#A1A1A1', letterSpacing:1.2, textTransform:'uppercase', marginBottom:10 };

  const FormDot = ({r}) => {
    const res = r.us > r.them ? 'W' : r.us < r.them ? 'L' : 'D';
    const col = res==='W' ? '#22c55e' : res==='L' ? '#ef4444' : '#F5C04A';
    return (
      <div style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:3 }}>
        <div style={{ width:32, height:32, borderRadius:8, background:col+'22', border:`1px solid ${col}55`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:12, fontWeight:700, color:col }}>{res}</div>
        <div style={{ fontSize:9, color:'#A1A1A1', maxWidth:34, textAlign:'center', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{r.opponent.split(' ')[0]}</div>
      </div>
    );
  };

  return (
    <div style={{ flex:1, overflowY:'auto', padding:'14px 16px 40px' }}>

      {/* Key numbers */}
      <div style={card}>
        <div style={sectionLabel}>Season Summary</div>
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:10 }}>
          {[
            ['Win Rate',  winRate+'%',  winRate>=50?'#22c55e':'#ef4444'],
            ['Avg scored', avgGF,       '#F5C04A'],
            ['Avg conceded', avgGA,     '#A1A1A1'],
            ['Clean sheets', allResults.filter(r=>r.them===0).length, '#a78bfa'],
            ['Games won',    wins,      '#22c55e'],
            ['Goal diff',    (gd>=0?'+':'')+gd, gd>=0?'#F5C04A':'#ef4444'],
          ].map(([label, val, color]) => (
            <div key={label} style={{ background:'#0D0D0D', borderRadius:10, padding:'10px 8px', textAlign:'center' }}>
              <div style={{ fontSize:20, fontWeight:800, color, lineHeight:1 }}>{val}</div>
              <div style={{ fontSize:10, color:'#A1A1A1', marginTop:4, lineHeight:1.3 }}>{label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Recent form */}
      <div style={card}>
        <div style={sectionLabel}>Recent Form</div>
        <div style={{ display:'flex', gap:8 }}>
          {last5.map((r,i) => <FormDot key={i} r={r} />)}
          {last5.length === 0 && <div style={{ fontSize:12, color:'#555' }}>No results yet</div>}
        </div>
      </div>

      {/* Home / Away */}
      {(homeRes.length > 0 || awayRes.length > 0) && (
        <div style={card}>
          <div style={sectionLabel}>Home vs Away</div>
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
            {[
              ['🏠 Home', homeRes.length, homeWins, homeRes.filter(r=>r.us===r.them).length, homeRes.filter(r=>r.us<r.them).length],
              ['✈️ Away', awayRes.length, awayWins, awayRes.filter(r=>r.us===r.them).length, awayRes.filter(r=>r.us<r.them).length],
            ].map(([label, p, w, d, l]) => p > 0 && (
              <div key={label} style={{ background:'#0D0D0D', borderRadius:10, padding:'12px 10px' }}>
                <div style={{ fontSize:13, fontWeight:700, color:'#FFFFFF', marginBottom:8 }}>{label}</div>
                <div style={{ display:'flex', gap:8, justifyContent:'center' }}>
                  {[['W',w,'#22c55e'],['D',d,'#F5C04A'],['L',l,'#ef4444']].map(([lbl,val,col])=>(
                    <div key={lbl} style={{ textAlign:'center' }}>
                      <div style={{ fontSize:16, fontWeight:700, color:col }}>{val}</div>
                      <div style={{ fontSize:10, color:'#A1A1A1' }}>{lbl}</div>
                    </div>
                  ))}
                </div>
                <div style={{ fontSize:11, color:'#A1A1A1', textAlign:'center', marginTop:6 }}>{p} game{p!==1?'s':''}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Top scorers */}
      {topScorers.length > 0 && (
        <div style={card}>
          <div style={sectionLabel}>Top Scorers</div>
          {topScorers.map(([name, count], i) => (
            <div key={name} style={{ display:'flex', alignItems:'center', gap:10, paddingBottom:i<topScorers.length-1?8:0, marginBottom:i<topScorers.length-1?8:0, borderBottom:i<topScorers.length-1?'1px solid #1E1E1E':'none' }}>
              <div style={{ width:24, height:24, borderRadius:6, background:'#1A1A1A', display:'flex', alignItems:'center', justifyContent:'center', fontSize:11, fontWeight:700, color:'#A1A1A1', flexShrink:0 }}>{i+1}</div>
              <div style={{ flex:1, fontSize:14, fontWeight:600, color:'#FFFFFF' }}>{name}</div>
              <div style={{ display:'flex', alignItems:'center', gap:4 }}>
                <span style={{ fontSize:16, fontWeight:800, color:'#F5C04A' }}>{count}</span>
                <span style={{ fontSize:11, color:'#A1A1A1' }}>goal{count!==1?'s':''}</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Notable results */}
      {(biggestWin || biggestLoss) && (
        <div style={card}>
          <div style={sectionLabel}>Notable Results</div>
          {biggestWin && (
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:biggestLoss?10:0 }}>
              <div>
                <div style={{ fontSize:11, color:'#22c55e', fontWeight:700, marginBottom:2 }}>BIGGEST WIN</div>
                <div style={{ fontSize:13, color:'#FFFFFF' }}>vs {biggestWin.opponent}</div>
              </div>
              <div style={{ fontSize:18, fontWeight:800, color:'#22c55e' }}>{biggestWin.us}–{biggestWin.them}</div>
            </div>
          )}
          {biggestLoss && (
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <div>
                <div style={{ fontSize:11, color:'#ef4444', fontWeight:700, marginBottom:2 }}>BIGGEST LOSS</div>
                <div style={{ fontSize:13, color:'#FFFFFF' }}>vs {biggestLoss.opponent}</div>
              </div>
              <div style={{ fontSize:18, fontWeight:800, color:'#ef4444' }}>{biggestLoss.us}–{biggestLoss.them}</div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: TEAM HUB
// ════════════════════════════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: TEAM SQUAD (lineup view — full screen, from Team > Squad tab)
// ════════════════════════════════════════════════════════════════════════════════
function TeamSquadScreen({ onBack, onManageSquad, onViewPlayer, onAddPlayer }) {
  const [squad, setSquad]   = React.useState(()=>loadSquad());
  const [search, setSearch] = React.useState('');
  const [sortBy, setSortBy] = React.useState('number');
  const myTeam    = localStorage.getItem('soccerCoach_fixtureTeam') || '';
  const settings  = loadSettings();
  const teamName  = settings.teamName || myTeam || 'My Team';
  const league    = settings.league   || 'U11 Girls';
  const season    = settings.season   || '2026 Season';

  const filtered = React.useMemo(() => {
    let list = search.trim()
      ? squad.filter(p => (p.name||'').toLowerCase().includes(search.toLowerCase()) || (p.nickname||'').toLowerCase().includes(search.toLowerCase()))
      : [...squad];
    if (sortBy === 'number') list.sort((a,b) => (parseInt(a.number)||999)-(parseInt(b.number)||999));
    else list.sort((a,b) => (a.name||'').localeCompare(b.name||''));
    return list;
  }, [squad, search, sortBy]);

  const FunnelIcon = () => (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#F5C04A" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <polygon points="22 3 2 3 10 12.46 10 19 14 21 14 12.46 22 3"/>
    </svg>
  );

  return (
    <div style={{ minHeight:'100dvh', background:'#0D0D0D', paddingTop:'max(env(safe-area-inset-top),0px)', paddingBottom:'calc(72px + env(safe-area-inset-bottom))' }}>

      {/* Team banner card */}
      <div style={{ margin:'12px 16px 0', background:'#111111', borderRadius:16, border:'1px solid #1E1E1E', padding:'14px 16px', display:'flex', alignItems:'center', gap:14, cursor:'pointer' }}
        onClick={onBack}>
        <TeamBadge name={myTeam||teamName} size={62} radius={10} />
        <div style={{ flex:1, minWidth:0 }}>
          <div style={{ fontSize:18, fontWeight:800, color:'#FFF', lineHeight:1.2 }}>{teamName}</div>
          {league && <div style={{ fontSize:12, color:'#A1A1A1', marginTop:3 }}>{league}</div>}
          {season && <div style={{ fontSize:12, color:'#A1A1A1', marginTop:1 }}>{season}</div>}
        </div>
        <div style={{ color:'#F5C04A', fontSize:22, lineHeight:1, flexShrink:0 }}>›</div>
      </div>

      {/* Search + filter */}
      <div style={{ margin:'12px 16px 0', display:'flex', gap:10, alignItems:'center' }}>
        <div style={{ flex:1, position:'relative' }}>
          <div style={{ position:'absolute', left:14, top:'50%', transform:'translateY(-50%)', color:'#555', fontSize:15, pointerEvents:'none' }}>🔍</div>
          <input
            value={search} onChange={e=>setSearch(e.target.value)}
            placeholder="Search players..."
            style={{ width:'100%', background:'#1A1A1A', border:'1px solid #2A2A2A', borderRadius:12, padding:'12px 14px 12px 40px', color:'#FFF', fontSize:14, outline:'none', boxSizing:'border-box' }}
          />
        </div>
        <button
          onClick={()=>setSortBy(s=>s==='number'?'name':'number')}
          style={{ width:48, height:48, background:'#1A1A1A', border:'1px solid rgba(245,192,74,0.35)', borderRadius:12, display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', flexShrink:0 }}>
          <FunnelIcon />
        </button>
      </div>

      {/* Count + sort */}
      <div style={{ margin:'10px 16px 6px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
        <div style={{ fontSize:14, fontWeight:700, color:'#FFF' }}>{filtered.length} Players</div>
        <button onClick={()=>setSortBy(s=>s==='name'?'number':'name')}
          style={{ background:'none', border:'none', color:'#A1A1A1', fontSize:12, cursor:'pointer', display:'flex', alignItems:'center', gap:4, padding:0 }}>
          Sort: {sortBy==='name'?'Name':'Number'}
          <svg width="10" height="10" viewBox="0 0 10 10" fill="#A1A1A1"><path d="M2 3.5L5 7 8 3.5"/></svg>
        </button>
      </div>

      {/* Player list — grouped card */}
      <div style={{ margin:'0 16px' }}>
        {filtered.length === 0 && !search && (
          <div style={{ textAlign:'center', padding:'48px 0' }}>
            <div style={{ fontSize:40, marginBottom:12 }}>👥</div>
            <div style={{ fontSize:16, fontWeight:800, color:'#FFF', marginBottom:6 }}>No players yet</div>
            <div style={{ fontSize:13, color:'#666' }}>Tap Add New Player to get started</div>
          </div>
        )}
        {filtered.length === 0 && search && (
          <div style={{ textAlign:'center', padding:'32px 0', color:'#555', fontSize:13 }}>No players match "{search}"</div>
        )}
        {filtered.length > 0 && (
          <div style={{ background:'#111111', borderRadius:16, border:'1px solid #1E1E1E', overflow:'hidden' }}>
            {filtered.map((p, idx) => {
              const positions = [p.pos, p.pos2, p.pos3].filter(Boolean);
              return (
                <div key={p.name}
                  onClick={() => onViewPlayer && onViewPlayer(p.name)}
                  style={{ display:'flex', alignItems:'center', gap:12, padding:'13px 16px', borderBottom: idx < filtered.length-1 ? '1px solid #1A1A1A' : 'none', cursor:'pointer', WebkitTapHighlightColor:'transparent' }}>

                  {/* Jersey number circle */}
                  <div style={{ width:40, height:40, borderRadius:'50%', border:'2px solid rgba(245,192,74,0.6)', background:'rgba(245,192,74,0.06)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                    <span style={{ fontSize:14, fontWeight:800, color:'#F5C04A' }}>{p.number || '?'}</span>
                  </div>

                  {/* Photo (if set) */}
                  {p.photo && (
                    <div style={{ width:36, height:36, borderRadius:'50%', overflow:'hidden', flexShrink:0 }}>
                      <img src={p.photo} alt={p.name} style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                    </div>
                  )}

                  {/* Name + nickname inline */}
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:15, fontWeight:500, color:'#FFF', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
                      {p.name}
                      {p.nickname && <span style={{ color:'#F5C04A', marginLeft:6 }}>"{p.nickname}"</span>}
                    </div>
                  </div>

                  {/* Position badges */}
                  {positions.length > 0 && (
                    <div style={{ display:'flex', gap:5, flexShrink:0 }}>
                      {positions.map((pid, i) => {
                        const pg = ALL_POSITIONS.find(x=>x.id===pid);
                        return (
                          <div key={i} style={{ background:'#1A1A1A', border:'1px solid #333', borderRadius:6, padding:'4px 8px', fontSize:11, fontWeight:700, color:'#CCC', whiteSpace:'nowrap' }}>
                            {pg ? pg.short : pid.toUpperCase()}
                          </div>
                        );
                      })}
                    </div>
                  )}

                  {/* Chevron */}
                  <div style={{ color:'#F5C04A', fontSize:20, flexShrink:0, lineHeight:1 }}>›</div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* Add New Player */}
      <button
        onClick={() => onAddPlayer && onAddPlayer()}
        style={{ display:'flex', alignItems:'center', justifyContent:'center', gap:10, width:'calc(100% - 32px)', margin:'12px 16px 0', padding:'16px', background:'transparent', color:'#F5C04A', border:'2px dashed rgba(245,192,74,0.4)', borderRadius:16, fontSize:15, fontWeight:700, cursor:'pointer', boxSizing:'border-box' }}>
        <span style={{ fontSize:22, lineHeight:1 }}>+</span>
        <span>Add New Player</span>
      </button>
    </div>
  );
}


function TeamScreen({ onBack, onViewStats, onManageSquad, onGoMatch, onGoFixtures, games, settings, onEditTeam, onViewSquad }) {
  const [tab, setTab] = React.useState('overview');
  const [fixtureDetailGame, setFixtureDetailGame] = React.useState(null);
  // Inline squad management state (Squad tab)
  const [squadData, setSquadData] = React.useState(()=>loadSquad());
  const [sqInput, setSqInput] = React.useState('');
  const [sqShowAdd, setSqShowAdd] = React.useState(false);
  function sqAddPlayer() {
    const name = sqInput.trim();
    if (!name || squadData.some(p=>p.name===name)) return;
    const next = [...squadData, {name, pos:'', pos2:'', pos3:''}];
    setSquadData(next); saveSquad(next); setSqInput(''); setSqShowAdd(false);
  }
  function sqRemove(name) {
    const next = squadData.filter(p=>p.name!==name);
    setSquadData(next); saveSquad(next);
  }
  function sqSetPos(name, field, val) {
    const next = squadData.map(p=>p.name===name?{...p,[field]:val}:p);
    setSquadData(next); saveSquad(next);
  }

  const teamName    = settings?.teamName || localStorage.getItem('soccerCoach_fixtureTeam') || 'My Team';
  const coachName   = settings?.coachName || '';
  const playerCount = (() => { try { return JSON.parse(localStorage.getItem('soccerCoach_squad')||'[]').length; } catch { return 0; } })();
  const myTeam      = localStorage.getItem('soccerCoach_fixtureTeam') || '';
  const venue       = settings?.venue || '';

  const { played, wins, draws, losses, gf, ga, gd } = computeSeasonStats();
  const winRate     = played > 0 ? Math.round(wins / played * 100) : 0;
  const cleanSheets = getAllResults().filter(r => r.them === 0 && r.us > r.them).length;
  const allRes      = getAllResults();
  const last5       = [...allRes].slice(-5).reverse();
  const nextFix     = FIXTURES.find(f => isUpcoming(f) && (f.home===myTeam||f.away===myTeam));
  const fxScores    = loadFxScores();

  const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const DAYS   = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  function fmtDate(ds) {
    const d = parseFixtureDate(ds); if (!d) return ds;
    return `${DAYS[d.getDay()]} ${d.getDate()} ${MONTHS[d.getMonth()]}`;
  }

  // Player stats from games
  const playerStats = React.useMemo(() => {
    const map = {};
    (games||[]).forEach(g => {
      (g.goals||[]).filter(x=>x.team==='us').forEach(x => {
        if (!x.scorer) return;
        if (!map[x.scorer]) map[x.scorer] = { name:x.scorer, goals:0, assists:0, games:0 };
        map[x.scorer].goals++;
      });
      const pts = Array.isArray(g.potm) ? g.potm : (g.potm ? [g.potm] : []);
      pts.forEach(n => { if (!map[n]) map[n]={name:n,goals:0,assists:0,games:0}; map[n].games++; });
    });
    return Object.values(map).sort((a,b)=>b.goals-a.goals||b.games-a.games).slice(0,3);
  }, [games]);

  const squad = (() => { try { return JSON.parse(localStorage.getItem('soccerCoach_squad')||'[]'); } catch { return []; } })();

  const TABS = ['Overview','Squad','Stats','Fixtures'];

  if (fixtureDetailGame) {
    return <GameDetailScreen game={fixtureDetailGame} onBack={()=>setFixtureDetailGame(null)} onUpdateGame={null} />;
  }

  return (
    <div style={{ minHeight:'100vh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)', display:'flex', flexDirection:'column' }}>

      {/* ── Header ── */}
      <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0, position:'relative' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', color:'#F5C04A', fontSize:22, cursor:'pointer', padding:0, lineHeight:1, flexShrink:0, zIndex:1 }}>←</button>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:40, objectFit:'contain', marginLeft:8, zIndex:1 }} />
        <div style={{ position:'absolute', left:0, right:0, textAlign:'center', pointerEvents:'none' }}>
          <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>Your Team</span>
        </div>
        <div style={{ flex:1 }} />
        <button onClick={onEditTeam||onManageSquad} style={{ background:'none', border:'none', cursor:'pointer', padding:0, zIndex:1 }}>
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#777" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/>
          </svg>
        </button>
      </div>

      {/* ── Hero card ── */}
      <div style={{ position:'relative', background:'#111111', borderBottom:'1px solid #1A1A1A', padding:'16px', overflow:'hidden', flexShrink:0 }}>
        <div style={{ position:'absolute', right:-20, top:-20, opacity:0.06 }}>
          <img src={TEAM_LOGO} style={{ width:160, height:160, objectFit:'contain' }}/>
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:14 }}>
          <TeamBadge name={teamName} size={64} radius={12} />
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ fontSize:20, fontWeight:700, color:'#FFFFFF', lineHeight:1.1 }}>{teamName}</div>
            {coachName && <div style={{ fontSize:12, color:'#F5C04A', marginTop:2 }}>Coach: {coachName}</div>}
            <div style={{ display:'flex', alignItems:'center', gap:10, marginTop:6, flexWrap:'wrap' }}>
              {playerCount > 0 && <div style={{ display:'flex', alignItems:'center', gap:4 }}>
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="2"><circle cx="9" cy="7" r="4"/><path d="M3 21v-2a4 4 0 0 1 4-4h4"/><circle cx="18" cy="9" r="3"/><path d="M22 21v-1a3 3 0 0 0-2-2.83"/></svg>
                <span style={{ fontSize:11, color:'#A1A1A1' }}>{playerCount} Players</span>
              </div>}
              {venue && <div style={{ display:'flex', alignItems:'center', gap:4 }}>
                <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>
                <span style={{ fontSize:11, color:'#A1A1A1' }}>{venue}</span>
              </div>}
            </div>
          </div>
          <button onClick={onEditTeam||onManageSquad} style={{ background:'#1A1A1A', border:'1px solid #2A2A2A', borderRadius:8, padding:'6px 10px', color:'#A1A1A1', fontSize:11, fontWeight:600, cursor:'pointer', flexShrink:0 }}>
            ✏️ Edit Team
          </button>
        </div>
      </div>

      {/* ── Tabs ── */}
      <div style={{ display:'flex', background:'#111111', borderBottom:'1px solid #1A1A1A', overflowX:'auto', flexShrink:0 }}>
        {TABS.map(t => (
          <button key={t} onClick={()=>{ if(t==='Stats'){onViewStats();return;} setTab(t.toLowerCase()); }} style={{ flex:'0 0 auto', padding:'11px 18px', background:'none', border:'none', borderBottom: tab===t.toLowerCase() ? '2px solid #F5C04A' : '2px solid transparent', cursor:'pointer', fontSize:13, fontWeight:600, color: tab===t.toLowerCase() ? '#F5C04A' : '#A1A1A1', whiteSpace:'nowrap' }}>{t}</button>
        ))}
      </div>

      {/* ── Tab content ── */}
      <div style={{ flex:1, overflowY:'auto' }}>

        {/* OVERVIEW */}
        {tab === 'overview' && (
          <div style={{ padding:'12px 14px', display:'flex', flexDirection:'column', gap:12 }}>

            {/* Team Form */}
            <div style={{ background:'#1A1A1A', borderRadius:14, padding:'14px', border:'1px solid #2A2A2A' }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
                <span style={{ fontSize:13, fontWeight:600, color:'#FFFFFF' }}>Team Form</span>
                <span style={{ fontSize:11, color:'#A1A1A1' }}>Last {Math.min(last5.length,5)} Matches</span>
              </div>
              {last5.length === 0 ? (
                <div style={{ textAlign:'center', color:'#A1A1A1', fontSize:12, padding:'8px 0' }}>No results yet</div>
              ) : (
                <>
                  <div style={{ display:'flex', gap:6, marginBottom:10 }}>
                    {last5.map((r,i) => {
                      const res = r.us>r.them?'W':r.us<r.them?'L':'D';
                      const col = res==='W'?'#22c55e':res==='L'?'#ef4444':'#f59e0b';
                      return (
                        <div key={i} style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:4 }}>
                          <div style={{ width:36, height:36, borderRadius:'50%', background:col+'22', border:`2px solid ${col}`, display:'flex', alignItems:'center', justifyContent:'center' }}>
                            <span style={{ fontSize:13, fontWeight:700, color:col }}>{res}</span>
                          </div>
                          <span style={{ fontSize:10, color:'#A1A1A1' }}>{r.us}–{r.them}</span>
                        </div>
                      );
                    })}
                  </div>
                  <div style={{ display:'flex', gap:0, borderTop:'1px solid #2A2A2A', paddingTop:10 }}>
                    {[['WON',wins,'#F5C04A'],['DRAWN',draws,'#A1A1A1'],['LOST',losses,'#ef4444'],['GF',gf,'#22c55e'],['GA',ga,'#A1A1A1']].map(([l,v,c])=>(
                      <div key={l} style={{ flex:1, textAlign:'center' }}>
                        <div style={{ fontSize:17, fontWeight:700, color:c }}>{v}</div>
                        <div style={{ fontSize:9, color:'#A1A1A1', marginTop:1 }}>{l}</div>
                      </div>
                    ))}
                  </div>
                </>
              )}
            </div>

            {/* Team Stats */}
            <div style={{ background:'#1A1A1A', borderRadius:14, padding:'14px', border:'1px solid #2A2A2A' }}>
              <div style={{ fontSize:13, fontWeight:600, color:'#FFFFFF', marginBottom:12 }}>Team Stats</div>
              {played === 0 ? (
                <div style={{ textAlign:'center', color:'#A1A1A1', fontSize:12, padding:'8px 0' }}>No stats yet</div>
              ) : [
                ['Win Rate', winRate+'%', winRate],
                ['Goals For', gf, Math.min(gf*5,100)],
                ['Goals Against', ga, Math.min(ga*5,100)],
                ['Clean Sheets', cleanSheets, Math.min(cleanSheets*20,100)],
              ].map(([label, val, pct]) => (
                <div key={label} style={{ display:'flex', alignItems:'center', gap:10, marginBottom:10 }}>
                  <div style={{ fontSize:12, color:'#A1A1A1', minWidth:100 }}>{label}</div>
                  <div style={{ flex:1, height:4, background:'#2A2A2A', borderRadius:2, overflow:'hidden' }}>
                    <div style={{ width:pct+'%', height:'100%', background:'#F5C04A', borderRadius:2 }}/>
                  </div>
                  <div style={{ fontSize:13, fontWeight:700, color:'#FFFFFF', minWidth:30, textAlign:'right' }}>{val}</div>
                </div>
              ))}
            </div>

            {/* Next Match */}
            {nextFix && (
              <div style={{ background:'#1A1A1A', borderRadius:14, padding:'14px', border:'1px solid #2A2A2A' }}>
                <div style={{ fontSize:13, fontWeight:600, color:'#FFFFFF', marginBottom:12 }}>Next Match</div>
                <div style={{ display:'flex', alignItems:'center', gap:8, marginBottom:12 }}>
                  <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:6 }}>
                    <TeamBadge name={nextFix.home} size={44} radius={10} />
                    <div style={{ fontSize:11, fontWeight:600, color:'#FFFFFF', textAlign:'center', lineHeight:1.2 }}>{nextFix.home}</div>
                  </div>
                  <div style={{ padding:'4px 10px', background:'#0D0D0D', borderRadius:6, border:'1px solid #2A2A2A', fontSize:11, color:'#A1A1A1', fontWeight:600 }}>VS</div>
                  <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'center', gap:6 }}>
                    <TeamBadge name={nextFix.away} size={44} radius={10} />
                    <div style={{ fontSize:11, fontWeight:600, color:'#FFFFFF', textAlign:'center', lineHeight:1.2 }}>{nextFix.away}</div>
                  </div>
                </div>
                <div style={{ display:'flex', gap:12, marginBottom:12, flexWrap:'wrap' }}>
                  <div style={{ display:'flex', alignItems:'center', gap:4 }}>
                    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="2" strokeLinecap="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
                    <span style={{ fontSize:11, color:'#A1A1A1' }}>{fmtDate(nextFix.date)}</span>
                  </div>
                  {nextFix.time && <div style={{ display:'flex', alignItems:'center', gap:4 }}>
                    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
                    <span style={{ fontSize:11, color:'#A1A1A1' }}>{nextFix.time}</span>
                  </div>}
                  {nextFix.venue && <div style={{ display:'flex', alignItems:'center', gap:4 }}>
                    <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>
                    <span style={{ fontSize:11, color:'#A1A1A1' }}>{nextFix.venue}</span>
                  </div>}
                </div>
                <button onClick={onGoMatch} style={{ width:'100%', background:'#F5C04A', color:'#0D0D0D', border:'none', borderRadius:10, padding:'11px 0', fontWeight:700, fontSize:13, cursor:'pointer' }}>View Match Centre ›</button>
              </div>
            )}

            {/* Quick Actions */}
            <div style={{ background:'#1A1A1A', borderRadius:14, padding:'14px', border:'1px solid #2A2A2A' }}>
              <div style={{ fontSize:13, fontWeight:600, color:'#FFFFFF', marginBottom:12 }}>Quick Actions</div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8 }}>
                {[
                  { label:'Manage Squad', icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"><circle cx="9" cy="7" r="4"/><path d="M3 21v-2a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/><line x1="19" y1="8" x2="19" y2="14"/><line x1="22" y1="11" x2="16" y2="11"/></svg>, action: onManageSquad },
                  { label:'Player Stats', icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"><line x1="18" y1="20" x2="18" y2="10"/><line x1="12" y1="20" x2="12" y2="4"/><line x1="6" y1="20" x2="6" y2="14"/></svg>, action: onViewStats },
                  { label:'Fixtures', icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>, action: onGoFixtures },
                  { label:'New Match', icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round"><rect x="2" y="3" width="20" height="18" rx="2"/><line x1="12" y1="3" x2="12" y2="21"/><line x1="2" y1="12" x2="22" y2="12"/></svg>, action: onGoMatch },
                ].map((item,i) => (
                  <button key={i} onClick={item.action} style={{ background:'#0D0D0D', border:'1px solid #2A2A2A', borderRadius:10, padding:'14px 10px', display:'flex', flexDirection:'column', alignItems:'center', gap:8, cursor:'pointer', color:'#F5C04A' }}>
                    {item.icon}
                    <span style={{ fontSize:11, fontWeight:600, color:'#FFFFFF' }}>{item.label}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Top Performers */}
            {playerStats.length > 0 && (
              <div style={{ background:'#1A1A1A', borderRadius:14, padding:'14px', border:'1px solid #2A2A2A', marginBottom:4 }}>
                <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>
                  <span style={{ fontSize:13, fontWeight:600, color:'#FFFFFF' }}>Top Performers</span>
                  <button onClick={onViewStats} style={{ background:'none', border:'none', cursor:'pointer', fontSize:12, fontWeight:600, color:'#F5C04A', padding:0 }}>See All</button>
                </div>
                <div style={{ display:'flex', gap:8 }}>
                  {playerStats.map((p,i) => (
                    <div key={i} style={{ flex:1, background:'#0D0D0D', borderRadius:10, padding:'10px 8px', textAlign:'center' }}>
                      <div style={{ width:36, height:36, borderRadius:'50%', background:'#F5C04A22', border:'2px solid #F5C04A44', display:'flex', alignItems:'center', justifyContent:'center', margin:'0 auto 6px', fontSize:14, fontWeight:700, color:'#F5C04A' }}>
                        {(p.name||'?')[0]}
                      </div>
                      <div style={{ fontSize:11, fontWeight:600, color:'#FFFFFF', marginBottom:4 }}>{p.name.split(' ')[0]}</div>
                      <div style={{ fontSize:16, fontWeight:700, color:'#F5C04A' }}>{p.goals}</div>
                      <div style={{ fontSize:9, color:'#A1A1A1' }}>Goals</div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {/* SQUAD tab */}
        {tab === 'squad' && (
          <div style={{ padding:'12px 14px' }}>
            {squadData.length === 0 ? (
              <div style={{ textAlign:'center', padding:'40px 0' }}>
                <div style={{ fontSize:36, marginBottom:10 }}>👥</div>
                <div style={{ fontSize:15, fontWeight:800, color:'#FFF', marginBottom:6 }}>No players yet</div>
                <div style={{ fontSize:13, color:'#666', marginBottom:20 }}>Tap below to add your first player</div>
              </div>
            ) : (
              <div style={{ display:'flex', flexDirection:'column', gap:8, marginBottom:8 }}>
                {squadData.map(p => {
                  const pInitials = (p.name||'?').split(' ').map(w=>w[0]||'').join('').slice(0,2).toUpperCase();
                  const positions = [p.pos, p.pos2, p.pos3].filter(Boolean);
                  return (
                    <div key={p.name}
                      onClick={()=>onViewSquad&&onViewSquad(p.name)}
                      style={{ background:'#111111', borderRadius:14, padding:'12px 14px', border:'1px solid #1E1E1E', display:'flex', alignItems:'center', gap:10, cursor:'pointer', WebkitTapHighlightColor:'transparent' }}>
                      {p.number ? (
                        <div style={{ width:36, height:36, borderRadius:'50%', background:'rgba(245,192,74,0.12)', border:'2px solid rgba(245,192,74,0.35)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                          <span style={{ fontSize:12, fontWeight:900, color:'#F5C04A' }}>{p.number}</span>
                        </div>
                      ) : (
                        <div style={{ width:36, height:36, borderRadius:'50%', background:'#1A1A1A', border:'1px solid #2A2A2A', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                          <span style={{ fontSize:12, fontWeight:800, color:'#555' }}>{pInitials}</span>
                        </div>
                      )}
                      {p.photo && (
                        <div style={{ width:36, height:36, borderRadius:'50%', overflow:'hidden', flexShrink:0 }}>
                          <img src={p.photo} alt={p.name} style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                        </div>
                      )}
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:14, fontWeight:500, color:'#FFF', lineHeight:1.2 }}>{p.name}</div>
                        {p.nickname && <div style={{ fontSize:11, color:'#F5C04A', marginTop:1 }}>"{p.nickname}"</div>}
                      </div>
                      {positions.length > 0 && (
                        <div style={{ display:'flex', gap:4, flexWrap:'wrap', justifyContent:'flex-end', maxWidth:90 }}>
                          {positions.map((pid, i) => {
                            const pg = ALL_POSITIONS.find(x=>x.id===pid);
                            return <div key={i} style={{ background: i===0?'rgba(245,192,74,0.15)':'rgba(255,255,255,0.05)', border:`1px solid ${i===0?'rgba(245,192,74,0.4)':'#2A2A2A'}`, borderRadius:5, padding:'2px 7px', fontSize:10, fontWeight:800, color: i===0?'#F5C04A':'#555' }}>{pg?pg.short:pid.toUpperCase()}</div>;
                          })}
                        </div>
                      )}
                      <div style={{ color:'#444', fontSize:18, flexShrink:0 }}>›</div>
                    </div>
                  );
                })}
              </div>
            )}
            <button
              onClick={()=>{ if(onViewSquad) onViewSquad('__add__'); }}
              style={{ width:'100%', padding:'14px', background:'transparent', color:'#F5C04A', border:'2px dashed rgba(245,192,74,0.35)', borderRadius:14, fontSize:13, fontWeight:800, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:8, boxSizing:'border-box' }}>
              <span style={{ fontSize:18 }}>＋</span>
              <span>Add New Player</span>
            </button>
          </div>
        )}

        {/* STATS tab */}
        {tab === 'stats' && (
          <div style={{ padding:'12px 14px' }}>
            <div style={{ background:'#1A1A1A', borderRadius:14, padding:'16px', border:'1px solid #2A2A2A', textAlign:'center' }}>
              <div style={{ fontSize:13, fontWeight:600, color:'#FFFFFF', marginBottom:8 }}>Player Statistics</div>
              <div style={{ fontSize:12, color:'#A1A1A1', marginBottom:16 }}>Detailed goals, assists and performance data</div>
              <button onClick={onViewStats} style={{ background:'#F5C04A', color:'#0D0D0D', border:'none', borderRadius:10, padding:'12px 24px', fontWeight:700, fontSize:13, cursor:'pointer' }}>View Full Stats ›</button>
            </div>
          </div>
        )}

        {/* FIXTURES tab */}
        {tab === 'fixtures' && (
          <div style={{ padding:'0' }}>
            <FixturesScreen embedded games={games||[]} onViewGame={g=>setFixtureDetailGame(g)} />
          </div>
        )}

      </div>
    </div>
  );
}

// ── Mini pitch ─────────────────────────────────────────────────────────────────
// ════════════════════════════════════════════════════════════════════════════════
//  SHARED: PITCH LINEUP VIEW
// ════════════════════════════════════════════════════════════════════════════════
function PitchLineupView({ positions, slots, selectedSlot, onSlotTap, myTeam, interactive }) {
  // Pitch markings as a purely decorative overlay
  const line = (style) => <div style={{ position:'absolute', background:'rgba(255,255,255,0.22)', pointerEvents:'none', ...style }} />;
  const circle = (style) => <div style={{ position:'absolute', border:'1px solid rgba(255,255,255,0.22)', borderRadius:'50%', pointerEvents:'none', ...style }} />;

  return (
    <div style={{ position:'relative', width:'100%', aspectRatio:'0.62',
      background:'linear-gradient(180deg,#1d5c1d 0%,#165216 25%,#1d5c1d 50%,#165216 75%,#1d5c1d 100%)',
      borderRadius:8, overflow:'hidden' }}>
      {/* Markings */}
      {line({ top:0, left:'10%', right:'10%', height:1 })}
      {line({ bottom:0, left:'10%', right:'10%', height:1 })}
      {line({ top:0, bottom:0, left:'10%', width:1 })}
      {line({ top:0, bottom:0, right:'10%', width:1 })}
      {line({ top:'50%', left:'10%', right:'10%', height:1 })}
      {/* Center circle */}
      {circle({ top:'50%', left:'50%', width:'20%', paddingBottom:'20%', transform:'translate(-50%,-50%)' })}
      {/* Top penalty box */}
      {line({ top:'10%', left:'30%', right:'30%', height:1 })}
      {line({ top:'10%', left:'30%', width:1, height:'10%' })}
      {line({ top:'10%', right:'30%', width:1, height:'10%' })}
      {/* Bottom penalty box */}
      {line({ bottom:'10%', left:'30%', right:'30%', height:1 })}
      {line({ bottom:'10%', left:'30%', width:1, height:'10%' })}
      {line({ bottom:'10%', right:'30%', width:1, height:'10%' })}

      {/* Player tokens */}
      {positions.map(pos => {
        const name    = slots[pos.id] || '';
        const isSel   = selectedSlot === pos.id;
        const isEmpty = !name;
        return (
          <div key={pos.id}
            onClick={() => interactive && onSlotTap && onSlotTap(pos.id)}
            style={{ position:'absolute', left:pos.left, top:pos.top, transform:`translateX(${pos.tx})`,
              display:'flex', flexDirection:'column', alignItems:'center', gap:2, zIndex:2,
              cursor: interactive ? 'pointer' : 'default' }}>
            {/* Circle avatar */}
            <div style={{
              width:42, height:42, borderRadius:'50%', overflow:'hidden',
              border: isSel ? '2.5px solid #F5C04A' : isEmpty ? '2px dashed rgba(255,255,255,0.35)' : '2px solid rgba(255,255,255,0.55)',
              background: isEmpty ? 'rgba(0,0,0,0.25)' : 'rgba(0,0,0,0.45)',
              boxShadow: isSel ? '0 0 0 3px rgba(245,192,74,0.35), 0 2px 8px rgba(0,0,0,0.5)' : '0 2px 6px rgba(0,0,0,0.4)',
              display:'flex', alignItems:'center', justifyContent:'center',
              transition:'border 0.15s, box-shadow 0.15s',
            }}>
              {name
                ? <TeamBadge name={myTeam||'Team'} size={42} />
                : <span style={{ fontSize:16, opacity:0.45, color:'#fff' }}>+</span>}
            </div>
            {/* Player surname */}
            <div style={{
              fontSize:8, fontWeight:800, color: name ? '#FFFFFF' : 'rgba(255,255,255,0.4)',
              textAlign:'center', maxWidth:50, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap',
              textShadow:'0 1px 3px rgba(0,0,0,0.9)', lineHeight:1.2,
            }}>
              {name ? name.split(' ').slice(-1)[0].toUpperCase() : pos.label.toUpperCase()}
            </div>
            {name && <div style={{ fontSize:7, color:'rgba(255,255,255,0.5)', textTransform:'uppercase', letterSpacing:0.4, textShadow:'0 1px 2px rgba(0,0,0,0.8)' }}>{pos.label}</div>}
          </div>
        );
      })}
    </div>
  );
}

function MiniPitch({ slots, positions }) {
  if(!slots) return null;
  return (
    <div style={{position:"relative",width:"100%",aspectRatio:"0.68",borderRadius:12,overflow:"hidden",border:"2px solid #F5C04A44",background:"linear-gradient(180deg,#4A2B00 0%,#3D2000 50%,#4A2B00 100%)"}}>
      <div style={{position:"absolute",top:"50%",left:0,right:0,height:1.5,background:"#ffffff18",pointerEvents:"none"}}/>
      <div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",width:"30%",paddingBottom:"30%",border:"1.5px solid #ffffff18",borderRadius:"50%",pointerEvents:"none"}}/>
      <div style={{position:"absolute",top:0,left:"25%",right:"25%",height:"13%",border:"1.5px solid #ffffff18",borderTop:"none",pointerEvents:"none"}}/>
      <div style={{position:"absolute",bottom:0,left:"25%",right:"25%",height:"13%",border:"1.5px solid #ffffff18",borderBottom:"none",pointerEvents:"none"}}/>
      {positions.map(pos=>{
        const name=slots[pos.id];
        return (
          <div key={pos.id} style={{position:"absolute",left:pos.left,top:pos.top,transform:`translateX(${pos.tx})`,display:"flex",flexDirection:"column",alignItems:"center",gap:2,zIndex:1}}>
            {name
              ? <div style={{background:"#1E1E1E",borderRadius:6,padding:"3px 6px",fontSize:9,fontWeight:700,color:"#fff",textAlign:"center",maxWidth:58,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",border:"1px solid #3b82f644"}}>{name}</div>
              : <div style={{width:40,height:18,border:"1.5px dashed #ffffff25",borderRadius:6}}/>
            }
 
            <span style={{fontSize:6,color:"#ffffff55",fontWeight:600,letterSpacing:0.3,textTransform:"uppercase",textAlign:"center"}}>{pos.label}</span>
          </div>
        );
      })}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: SAVED GAME DETAIL
// ════════════════════════════════════════════════════════════════════════════════
function GameDetailScreen({ game, onBack, onUpdateGame }) {
  const fxScores = loadFxScores();
  const sc = getScore(game, fxScores);
  const isFixtureOnly = !!game._fixtureOnly; // true = only score data, no lineup/goals
  const safeGame = { goals:[], halves:[], matchEvents:[], voiceNotes:'', ...game };
  const [report, setReport] = useState(
    isFixtureOnly ? null : (game.report || buildLocalReport(safeGame))
  );
  const [loading, setLoading] = useState(false);
  const [potm, setPotm] = useState(game.potm||"");
  const [view, setView] = useState("summary");
  const [lineupHalf, setLineupHalf] = useState(0);
  const [lineupPeriod, setLineupPeriod] = useState(0);
  const [editReport, setEditReport] = useState(false);
  const [editedReport, setEditedReport] = useState('');

  const formation = safeGame.config?.formation || DEFAULT_FORMATION;
  const positions = getPositions(formation);
  const halves = safeGame.halves;
  const startingSlots = halves?.[0]?.[0]?.slots;
  const gk = startingSlots?.gk || "—";

  const usGoals  = safeGame.goals.filter(g=>g.team==="us");
  const themGoals= safeGame.goals.filter(g=>g.team==="them");

  const allPlayers = startingSlots
    ? [...new Set([...positions.map(p=>startingSlots[p.id]).filter(Boolean),...(startingSlots.bench||[])])]
    : [];

  function handlePotm(name) {
    setPotm(name);
    if (onUpdateGame) onUpdateGame({...safeGame,potm:name});
  }

  async function regenerateAI() {
    if (isFixtureOnly) return;
    setLoading(true);
    try { const text=await generateAIReport({...safeGame,potm}); setReport(text); if(onUpdateGame) onUpdateGame({...safeGame,potm,report:text}); }
    catch { setReport(buildLocalReport(safeGame)); }
    setLoading(false);
  }

  const curSlots = halves?.[lineupHalf]?.[lineupPeriod]?.slots;
  const numHalves = halves.length;
  const numPeriods = halves[lineupHalf]?.length || 0;

  const res = sc.us > sc.them ? 'W' : sc.us < sc.them ? 'L' : 'D';
  const resColor = res==='W'?'#22c55e':res==='L'?'#ef4444':'#F5C04A';

  return (
    <div style={{ minHeight:'100vh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)', display:'flex', flexDirection:'column' }}>

      {/* Header */}
      <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0, position:'relative' }}>
        <button onClick={onBack} style={{ background:'none', border:'none', color:'#F5C04A', fontSize:22, cursor:'pointer', padding:0, lineHeight:1, flexShrink:0, zIndex:1 }}>←</button>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:40, objectFit:'contain', marginLeft:8, zIndex:1 }} />
        <div style={{ position:'absolute', left:0, right:0, textAlign:'center', pointerEvents:'none' }}>
          <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>Match Report</span>
        </div>
        <div style={{ flex:1 }} />
      </div>

      {/* Score hero */}
      <div style={{ background:'#111111', borderBottom:'1px solid #1E1E1E', padding:'16px 20px', display:'flex', alignItems:'center', gap:14, flexShrink:0 }}>
        <TeamBadge name={game.opponent} size={52} radius={10} />
        <div style={{ flex:1 }}>
          <div style={{ fontSize:36, fontWeight:700, color:'#FFFFFF', lineHeight:1 }}>{sc.us} – {sc.them}</div>
          <div style={{ fontSize:12, color:'#A1A1A1', marginTop:4 }}>
            {game.date ? new Date(game.date).toLocaleDateString(undefined,{weekday:'short',day:'numeric',month:'short'}) : '—'}
          </div>
        </div>
        <div style={{ width:44, height:44, borderRadius:10, background:resColor+'22', border:`1px solid ${resColor}44`, display:'flex', alignItems:'center', justifyContent:'center' }}>
          <span style={{ fontSize:18, fontWeight:700, color:resColor }}>{res}</span>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display:'flex', gap:0, background:'#111111', borderBottom:'1px solid #1E1E1E', flexShrink:0 }}>
        {[["summary","Summary"],["lineup","Lineup"],["events","Events"]].map(([k,l])=>(
          <button key={k} style={{ flex:1, padding:'11px 0', background:'none', border:'none', borderBottom: view===k ? '2px solid #F5C04A' : '2px solid transparent', cursor:'pointer', fontSize:13, fontWeight:700, color: view===k ? '#F5C04A' : '#A1A1A1' }} onClick={()=>setView(k)}>{l}</button>
        ))}
      </div>

      {/* Content */}
      <div style={{ flex:1, overflowY:'auto', padding:'16px 16px 20px' }}>

        {view==="summary" && <>
          {/* Key facts */}
          <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, marginBottom:14 }}>
            {[['Goalkeeper', gk],['Formation', formation], ...(potm?[['Player of Match', potm]]:[])].map(([lbl,val])=>(
              <div key={lbl} style={{ background:'#1A1A1A', borderRadius:10, padding:'10px 12px', gridColumn: lbl==='Player of Match'?'1/-1':'auto' }}>
                <div style={{ fontSize:10, color:'#A1A1A1', fontWeight:600, letterSpacing:0.5, marginBottom:4 }}>{lbl.toUpperCase()}</div>
                <div style={{ fontSize:14, fontWeight:600, color:'#FFFFFF' }}>{val}</div>
              </div>
            ))}
          </div>

          {/* Goals */}
          {usGoals.length > 0 && (
            <div style={{ background:'#1A1A1A', borderRadius:10, padding:'12px 14px', marginBottom:10, borderLeft:'3px solid #F5C04A' }}>
              <div style={{ fontSize:11, fontWeight:700, color:'#F5C04A', letterSpacing:1, marginBottom:8 }}>OUR GOALS</div>
              {usGoals.map((g,i)=>(
                <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'4px 0', borderBottom: i<usGoals.length-1?'1px solid #2A2A2A':'none' }}>
                  <span style={{ fontSize:13, fontWeight:600, color:'#FFFFFF' }}>⚽ {g.scorer}</span>
                  <span style={{ fontSize:11, color:'#A1A1A1' }}>{g.position?`(${g.position}) `:''}H{g.half} {g.timeStr}</span>
                </div>
              ))}
            </div>
          )}
          {themGoals.length > 0 && (
            <div style={{ background:'#1A1A1A', borderRadius:10, padding:'12px 14px', marginBottom:10, borderLeft:'3px solid #ef4444' }}>
              <div style={{ fontSize:11, fontWeight:700, color:'#ef4444', letterSpacing:1, marginBottom:8 }}>OPPOSITION GOALS</div>
              {themGoals.map((g,i)=>(
                <div key={i} style={{ display:'flex', justifyContent:'space-between', padding:'4px 0', borderBottom: i<themGoals.length-1?'1px solid #2A2A2A':'none' }}>
                  <span style={{ fontSize:13, fontWeight:600, color:'#fca5a5' }}>⚽ Opponent</span>
                  <span style={{ fontSize:11, color:'#A1A1A1' }}>H{g.half} {g.timeStr}</span>
                </div>
              ))}
            </div>
          )}

          {/* POTM selector */}
          {allPlayers.length > 0 && (
            <div style={{ marginBottom:12 }}>
              <div style={{ fontSize:11, fontWeight:700, color:'#A1A1A1', letterSpacing:0.5, marginBottom:6 }}>⭐ PLAYER OF THE MATCH</div>
              <select style={{ width:'100%', padding:'10px 12px', borderRadius:10, background:'#1A1A1A', color:'#FFFFFF', border:'1px solid #2A2A2A', fontSize:13 }} value={potm} onChange={e=>handlePotm(e.target.value)}>
                <option value="">— select —</option>
                {allPlayers.map(n=><option key={n} value={n}>{n}</option>)}
              </select>
            </div>
          )}

          {/* Voice notes */}
          {safeGame.voiceNotes && (
            <div style={{ background:'#111111', border:'1px solid #a78bfa33', borderRadius:12, padding:'12px 14px', marginBottom:10 }}>
              <div style={{ fontSize:11, fontWeight:800, color:'#a78bfa', letterSpacing:1, textTransform:'uppercase', marginBottom:6 }}>🎙️ Voice Note Transcription</div>
              <div style={{ fontSize:13, color:'#d1d5db', whiteSpace:'pre-wrap', lineHeight:1.6 }}>{safeGame.voiceNotes}</div>
            </div>
          )}

          {/* Match events summary */}
          {safeGame.matchEvents && safeGame.matchEvents.length > 0 && (
            <div style={{ background:'#111111', border:'1px solid #38bdf833', borderRadius:12, padding:'12px 14px', marginBottom:10 }}>
              <div style={{ fontSize:11, fontWeight:800, color:'#38bdf8', letterSpacing:1, textTransform:'uppercase', marginBottom:8 }}>📋 Match Events ({safeGame.matchEvents.length})</div>
              {safeGame.matchEvents.slice(0,5).map((ev,i) => {
                const rule = (typeof MATCH_EVENT_RULES !== 'undefined' ? MATCH_EVENT_RULES : []).find(r=>r.type===ev.type) || {icon:'📝',label:ev.type,color:'#A1A1A1'};
                return (
                  <div key={i} style={{display:'flex',alignItems:'center',gap:8,padding:'4px 0',borderBottom:i<Math.min(safeGame.matchEvents.length,5)-1?'1px solid #1E1E1E':'none'}}>
                    <span style={{fontSize:11,color:'#555',minWidth:22,fontWeight:700}}>{ev.minute}'</span>
                    <span>{rule.icon}</span>
                    <span style={{fontSize:12,color:rule.color||'#A1A1A1',fontWeight:600,flex:1}}>{rule.label}</span>
                    <span style={{fontSize:11,color:'#555'}}>{ev.team==='us'?(safeGame.config?.teamName||'Us'):(game.opponent||'Them')}</span>
                  </div>
                );
              })}
              {safeGame.matchEvents.length > 5 && <div style={{fontSize:11,color:'#555',paddingTop:6}}>+{safeGame.matchEvents.length-5} more — see Events tab</div>}
            </div>
          )}

          {/* Match report */}
          {isFixtureOnly ? (
            <div style={{ background:'#111111', border:'1px solid #1E1E1E', borderRadius:12, padding:'16px 14px', marginBottom:12 }}>
              <div style={{ fontSize:11, fontWeight:800, color:'#A1A1A1', letterSpacing:1, textTransform:'uppercase', marginBottom:6 }}>📋 Match Report</div>
              <div style={{ fontSize:13, color:'#555', lineHeight:1.7, fontStyle:'italic' }}>
                This result was recorded from fixtures only. Run a full match session to unlock AI reports, goal scorers, lineup tracking, and events.
              </div>
            </div>
          ) : (
            <>
              <div style={{ background:'#111111', border:'1px solid #1E1E1E', borderRadius:12, padding:'14px', marginBottom:10 }}>
                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:8 }}>
                  <div style={{ fontSize:11, fontWeight:800, color:'#A1A1A1', letterSpacing:1, textTransform:'uppercase' }}>📋 Match Report</div>
                  {!loading && !editReport && (
                    <button onClick={()=>{ setEditedReport(report); setEditReport(true); }}
                      style={{ background:'#1A1A1A', border:'1px solid #2A2A2A', borderRadius:6, padding:'4px 10px', color:'#A1A1A1', fontSize:11, fontWeight:700, cursor:'pointer' }}>
                      Edit
                    </button>
                  )}
                  {editReport && (
                    <div style={{ display:'flex', gap:6 }}>
                      <button onClick={()=>setEditReport(false)}
                        style={{ background:'none', border:'none', color:'#555', fontSize:11, cursor:'pointer', padding:'4px 6px' }}>Cancel</button>
                      <button onClick={()=>{ setReport(editedReport); setEditReport(false); if(onUpdateGame) onUpdateGame({...safeGame,potm,report:editedReport}); }}
                        style={{ background:'#F5C04A', border:'none', borderRadius:6, padding:'4px 10px', color:'#000', fontSize:11, fontWeight:800, cursor:'pointer' }}>Save</button>
                    </div>
                  )}
                </div>
                {loading ? (
                  <div style={{ fontSize:13, color:'#555', lineHeight:1.7 }}>✨ Generating…</div>
                ) : editReport ? (
                  <textarea value={editedReport} onChange={e=>setEditedReport(e.target.value)}
                    rows={12} style={{ width:'100%', background:'#0D0D0D', border:'1px solid #2A2A2A', borderRadius:8, padding:'10px 12px', color:'#FFF', fontSize:13, lineHeight:1.7, resize:'vertical', fontFamily:'inherit', outline:'none', boxSizing:'border-box' }}/>
                ) : (
                  <div style={{ fontSize:13, color:'#A1A1A1', lineHeight:1.7, whiteSpace:'pre-wrap' }}>{report}</div>
                )}
              </div>
              {!loading && !editReport && (
                <div style={{ display:'flex', gap:8, marginBottom:4 }}>
                  <button style={{ flex:1, padding:'11px 0', background:'#111111', border:'1px solid #1E1E1E', borderRadius:10, color:'#FFFFFF', fontSize:13, fontWeight:600, cursor:'pointer' }} onClick={()=>navigator.clipboard?.writeText(report)}>Copy</button>
                  <button style={{ flex:1, padding:'11px 0', background:'#a78bfa18', border:'1px solid #a78bfa44', borderRadius:10, color:'#a78bfa', fontSize:13, fontWeight:700, cursor:'pointer' }} onClick={regenerateAI}>✨ AI Rewrite</button>
                </div>
              )}
            </>
          )}
        </>}

        {view==="events" && (() => {
          const evts = game.matchEvents||[];
          const goalEvts = (game.goals||[]).map(g=>({id:'g_'+g.secs+'_'+g.team,type:'GOAL',team:g.team,minute:Math.floor(g.secs/60),timestamp:g.secs*1000}));
          const evGoalKeys=new Set(evts.filter(e=>e.type==='GOAL').map(e=>e.team+'_'+e.minute));
          const filteredGoals=goalEvts.filter(ge=>!evGoalKeys.has(ge.team+'_'+ge.minute));
          const all=[...evts,...filteredGoals].sort((a,b)=>a.minute-b.minute||a.timestamp-b.timestamp);
          const usCt={},themCt={};
          MATCH_EVENT_RULES.forEach(r=>{usCt[r.type]=0;themCt[r.type]=0;});
          all.forEach(ev=>{if(ev.team==='us')usCt[ev.type]=(usCt[ev.type]||0)+1;else if(ev.team==='them')themCt[ev.type]=(themCt[ev.type]||0)+1;});
          const maxSt=Math.max(...MATCH_EVENT_RULES.map(r=>Math.max(usCt[r.type]||0,themCt[r.type]||0)),1);
          return (
            <div>
              {all.length===0 && <p style={{textAlign:'center',color:'#A1A1A1',padding:'30px 0',fontSize:13}}>No events recorded for this match.</p>}
              {all.length>0 && (
                <div style={{background:'#1A1A1A',borderRadius:10,padding:'12px 14px',marginBottom:14}}>
                  <div style={{display:'flex',justifyContent:'space-between',marginBottom:10}}>
                    <span style={{fontSize:12,fontWeight:700,color:'#F5C04A'}}>Us</span>
                    <span style={{fontSize:11,color:'#A1A1A1'}}>Stats</span>
                    <span style={{fontSize:12,fontWeight:700,color:'#fca5a5'}}>{game.opponent||'Them'}</span>
                  </div>
                  {MATCH_EVENT_RULES.filter(r=>r.type!=='NOTE').map(rule=>{
                    const us=usCt[rule.type]||0,them=themCt[rule.type]||0;
                    if(us===0&&them===0)return null;
                    return (<div key={rule.type} style={{marginBottom:10}}>
                      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:3}}>
                        <span style={{fontSize:13,fontWeight:700,color:'#F5C04A',minWidth:20}}>{us}</span>
                        <span style={{fontSize:11,color:'#A1A1A1'}}>{rule.icon} {rule.label}</span>
                        <span style={{fontSize:13,fontWeight:700,color:'#fca5a5',minWidth:20,textAlign:'right'}}>{them}</span>
                      </div>
                      <div style={{position:'relative',height:4,background:'#2A2A2A',borderRadius:2}}>
                        <div style={{position:'absolute',right:'50%',top:0,height:'100%',width:(us/maxSt*50)+'%',background:'#F5C04A',borderRadius:'2px 0 0 2px'}}/>
                        <div style={{position:'absolute',left:'50%',top:0,height:'100%',width:(them/maxSt*50)+'%',background:'#ef4444',borderRadius:'0 2px 2px 0'}}/>
                        <div style={{position:'absolute',left:'50%',top:-2,width:1,height:8,background:'#555'}}/>
                      </div>
                    </div>);
                  })}
                </div>
              )}
              {all.length>0 && <div style={{fontSize:11,fontWeight:700,color:'#A1A1A1',textTransform:'uppercase',letterSpacing:1,marginBottom:8}}>Timeline</div>}
              {all.map(ev=>{
                const rule=MATCH_EVENT_RULES.find(r=>r.type===ev.type)||MATCH_EVENT_RULES[MATCH_EVENT_RULES.length-1];
                return (<div key={ev.id} style={{background:'#1A1A1A',borderLeft:'3px solid '+rule.color,borderRadius:'0 8px 8px 0',padding:'8px 12px',marginBottom:6,display:'flex',alignItems:'flex-start',gap:8}}>
                  <div style={{fontSize:10,color:'#A1A1A1',fontWeight:700,minWidth:28,paddingTop:2}}>{ev.minute}'</div>
                  <div style={{fontSize:15}}>{rule.icon}</div>
                  <div style={{flex:1}}>
                    <div style={{display:'flex',alignItems:'center',gap:5,flexWrap:'wrap'}}>
                      <span style={{fontSize:12,fontWeight:700,color:rule.color}}>{rule.label}</span>
                      {ev.team&&<span style={{fontSize:10,color:ev.team==='us'?'#F5C04A':'#fca5a5',background:ev.team==='us'?'#F5C04A18':'#ef444418',padding:'1px 6px',borderRadius:4}}>{ev.team==='us'?'Us':game.opponent||'Them'}</span>}
                    </div>
                    {ev.player&&<div style={{fontSize:11,color:'#A1A1A1'}}>👤 {ev.player}</div>}
                    {ev.notes&&<div style={{fontSize:11,color:'#A1A1A1'}}>{ev.notes}</div>}
                  </div>
                </div>);
              })}
            </div>
          );
        })()}

        {view==="lineup" && (
          <div>
            {numHalves > 1 && (
              <div style={{display:'flex',gap:6,marginBottom:8}}>
                {halves.map((_,i)=>(
                  <button key={i} style={{flex:1,padding:'9px 0',borderRadius:8,border:'none',fontSize:13,fontWeight:600,cursor:'pointer',background:i===lineupHalf?'#F5C04A22':'#1A1A1A',color:i===lineupHalf?'#F5C04A':'#A1A1A1',borderBottom:i===lineupHalf?'2px solid #F5C04A':'2px solid transparent'}}
                    onClick={()=>{setLineupHalf(i);setLineupPeriod(0);}}>
                    {i===0?'1st Half':'2nd Half'}
                  </button>
                ))}
              </div>
            )}
            {numPeriods > 1 && (
              <div style={{display:'flex',gap:4,marginBottom:8,flexWrap:'wrap'}}>
                {Array.from({length:numPeriods},(_,i)=>(
                  <button key={i} style={{padding:'6px 12px',borderRadius:6,border:'none',fontSize:12,fontWeight:600,cursor:'pointer',background:i===lineupPeriod?'#1A1A1A':'#111111',color:i===lineupPeriod?'#F5C04A':'#A1A1A1'}} onClick={()=>setLineupPeriod(i)}>P{i+1}</button>
                ))}
              </div>
            )}
            {curSlots
              ? <>
                  <p style={{fontSize:11,color:'#A1A1A1',margin:'0 0 10px'}}>H{lineupHalf+1} P{lineupPeriod+1} · {formation}</p>
                  <MiniPitch slots={curSlots} positions={positions} />
                  {(curSlots.bench||[]).length>0 && (
                    <div style={{background:'#1A1A1A',borderRadius:8,padding:'8px 12px',marginTop:8,fontSize:12,color:'#A1A1A1'}}><span style={{fontWeight:700,color:'#FFFFFF'}}>Bench: </span>{curSlots.bench.join(', ')}</div>
                  )}
                </>
              : <p style={{color:'#A1A1A1',fontSize:13}}>No lineup data for this period.</p>
            }
          </div>
        )}

      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: SQUAD + new game setup
// ════════════════════════════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: PLAYER PROFILE
// ════════════════════════════════════════════════════════════════════════════════
function PlayerProfileScreen({ playerName, isNew, onBack, onSave, games }) {
  const photoRef = React.useRef(null);
  const myTeam      = localStorage.getItem('soccerCoach_fixtureTeam') || '';
  const settingsObj = loadSettings();
  const teamName    = settingsObj.teamName || myTeam || 'My Team';
  const league      = settingsObj.league || 'U11 Girls';

  const loadPlayer = () => {
    const sq = loadSquad();
    if (playerName) {
      const p = sq.find(p => p.name === playerName) || { name: playerName };
      if (!p.firstName && !p.lastName) {
        const parts = (p.name||'').trim().split(' ');
        p.firstName = parts[0]||''; p.lastName = parts.slice(1).join(' ')||'';
      }
      return p;
    }
    return { firstName:'', lastName:'', name:'', nickname:'', number:'', pos:'', pos2:'', pos3:'', dob:'', foot:'right', canPlayGK:false, joined:'', coachNotes:'', devFocus:'', photo:'' };
  };

  const [draft,   setDraft]   = React.useState(loadPlayer);
  const [editing, setEditing] = React.useState(!!isNew);

  function upd(k,v) { setDraft(d=>({...d,[k]:v})); }
  function pickPhoto() { photoRef.current && photoRef.current.click(); }
  function onPhotoChange(e) {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => upd('photo', ev.target.result);
    reader.readAsDataURL(file);
  }
  function togglePosition(posId) {
    const cur = [draft.pos,draft.pos2,draft.pos3].filter(Boolean);
    if (cur.includes(posId)) {
      const nxt = cur.filter(p=>p!==posId);
      setDraft(d=>({...d, pos:nxt[0]||'', pos2:nxt[1]||'', pos3:nxt[2]||''}));
    } else if (cur.length < 3) {
      const nxt = [...cur, posId];
      setDraft(d=>({...d, pos:nxt[0]||'', pos2:nxt[1]||'', pos3:nxt[2]||''}));
    }
  }
  function save() {
    const firstName=(draft.firstName||'').trim(), lastName=(draft.lastName||'').trim();
    const fullName=[firstName,lastName].filter(Boolean).join(' ');
    if (!fullName) { alert('Please enter a name.'); return; }
    const sq=loadSquad();
    const trimmed={...draft, firstName, lastName, name:fullName};
    if (sq.some(p=>p.name===fullName&&p.name!==playerName)) { alert('A player with that name already exists.'); return; }
    const next=isNew?[trimmed,...sq]:sq.map(p=>p.name===playerName?trimmed:p);
    saveSquad(next); setDraft(trimmed); setEditing(false);
    if (onSave) onSave(trimmed);
  }
  function fmtJoined(j) {
    if (!j) return ''; try { return new Date(j+'-01').toLocaleDateString('en-AU',{month:'short',year:'numeric'}); } catch{return j;}
  }
  function fmtDate(ts) {
    if (!ts) return ''; try { return new Date(ts).toLocaleDateString('en-AU',{day:'numeric',month:'short',year:'numeric'}); } catch{return '';}
  }

  const displayName = [draft.firstName,draft.lastName].filter(Boolean).join(' ')||draft.name||'New Player';
  const initials    = displayName.split(' ').map(w=>w[0]||'').join('').slice(0,2).toUpperCase()||'?';

  const { playerGoals, appearances, potmList, recentMatches } = React.useMemo(() => {
    if (!games || !displayName) return { playerGoals:0, appearances:0, potmList:[], recentMatches:[] };
    const nm = displayName;
    const appeared = games.filter(g =>
      (g.goals||[]).some(x=>x.scorer===nm||x.assist===nm) ||
      (g.matchEvents||[]).some(e=>e.player===nm||e.secondaryPlayer===nm) ||
      (Array.isArray(g.potm)?g.potm:[g.potm||'']).includes(nm)
    );
    const goals = appeared.reduce((s,g)=>s+(g.goals||[]).filter(x=>x.scorer===nm).length,0);
    const potm  = games.filter(g=>(Array.isArray(g.potm)?g.potm:[g.potm||'']).includes(nm));
    return { playerGoals:goals, appearances:appeared.length, potmList:potm, recentMatches:[...appeared].reverse().slice(0,3) };
  }, [games, displayName]);

  const totalGames   = (games||[]).length;
  const availability = totalGames>0 ? Math.round(appearances/totalGames*100) : 0;

  const inputStyle = { background:'#1A1A1A', border:'1px solid #2A2A2A', borderRadius:10, padding:'11px 14px', color:'#FFF', fontSize:14, outline:'none', width:'100%', boxSizing:'border-box', fontFamily:'inherit' };
  const labelStyle = { fontSize:10, color:'#555', fontWeight:700, letterSpacing:1, textTransform:'uppercase', marginBottom:5 };

  const KhulaHeader = ({ rightEl }) => (
    <div style={{ background:'#0D0D0D', borderBottom:'1px solid #1A1A1A', paddingTop:'max(env(safe-area-inset-top),14px)', paddingBottom:14, paddingLeft:16, paddingRight:16, display:'flex', alignItems:'center', flexShrink:0, position:'relative' }}>
      <button onClick={onBack} style={{ background:'none', border:'none', color:'#F5C04A', fontSize:22, cursor:'pointer', padding:0, lineHeight:1, flexShrink:0, zIndex:1 }}>←</button>
      <img src={KHULA_LOGO} alt="Khula" style={{ height:56, objectFit:'contain', marginLeft:8, zIndex:1 }} />
      <div style={{ position:'absolute', left:0, right:0, textAlign:'center', pointerEvents:'none' }}>
        <span style={{ fontSize:17, fontWeight:500, color:'#CCC' }}>Player Profile</span>
      </div>
      <div style={{ flex:1 }} />
      {rightEl && <div style={{ zIndex:1 }}>{rightEl}</div>}
    </div>
  );

  /* ── VIEW MODE ─────────────────────────────────────────────────────────── */
  if (!isNew && !editing) {
    const preferredPos = [draft.pos, draft.pos2].filter(Boolean);
    const secondaryPos = [draft.pos3].filter(Boolean);
    const coachLines   = (draft.coachNotes||'').split('\n').filter(s=>s.trim());
    const devLines     = (draft.devFocus||'').split('\n').filter(s=>s.trim());

    return (
      <div style={{ background:'#0D0D0D', minHeight:'100dvh', display:'flex', flexDirection:'column' }}>
        <KhulaHeader rightEl={
          <button onClick={()=>{ setDraft(loadPlayer()); setEditing(true); }}
            style={{ background:'none', border:'none', color:'#F5C04A', fontSize:15, fontWeight:600, cursor:'pointer', padding:0 }}>
            Edit
          </button>
        } />

        <div style={{ flex:1, overflowY:'auto', paddingBottom:'calc(80px + env(safe-area-inset-bottom))' }}>

          {/* ── Hero ── */}
          <div style={{ background:'#111111', padding:'16px 16px 14px', borderBottom:'1px solid #1E1E1E' }}>
            <div style={{ display:'flex', gap:14, alignItems:'flex-start' }}>

              {/* Photo + number */}
              <div style={{ position:'relative', flexShrink:0 }}>
                <div style={{ width:80, height:80, borderRadius:'50%', overflow:'hidden', border:'3px solid rgba(245,192,74,0.4)', background:'rgba(245,192,74,0.08)', display:'flex', alignItems:'center', justifyContent:'center' }}>
                  {draft.photo ? <img src={draft.photo} alt={displayName} style={{ width:'100%', height:'100%', objectFit:'cover' }} /> : <span style={{ fontSize:26, fontWeight:700, color:'#F5C04A' }}>{initials}</span>}
                </div>
                {draft.number && (
                  <div style={{ position:'absolute', bottom:-2, right:-2, width:26, height:26, borderRadius:'50%', background:'#F5C04A', border:'2px solid #111111', display:'flex', alignItems:'center', justifyContent:'center' }}>
                    <span style={{ fontSize:11, fontWeight:700, color:'#000' }}>{draft.number}</span>
                  </div>
                )}
              </div>

              {/* Name + nickname + positions + GK */}
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontSize:19, fontWeight:700, color:'#FFF', lineHeight:1.2 }}>{displayName}</div>
                {draft.nickname && <div style={{ fontSize:13, color:'#F5C04A', marginTop:2, fontWeight:400 }}>"{draft.nickname}"</div>}
                <div style={{ display:'flex', gap:6, marginTop:8, flexWrap:'wrap' }}>
                  {[draft.pos,draft.pos2,draft.pos3].filter(Boolean).map((pid,i)=>{
                    const pg=ALL_POSITIONS.find(p=>p.id===pid);
                    return <div key={i} style={{ background:i===0?'#F5C04A':'rgba(255,255,255,0.07)', border:i===0?'none':'1px solid #3A3A3A', borderRadius:6, padding:'4px 10px', fontSize:12, fontWeight:600, color:i===0?'#000':'#BBB' }}>{pg?pg.short:pid.toUpperCase()}</div>;
                  })}
                </div>
                <div style={{ fontSize:11, color:'#777', marginTop:8 }}>Can Play GK: <span style={{ color:'#CCC', fontWeight:500 }}>{draft.canPlayGK?'Yes':'No'}</span></div>
              </div>

              {/* Team badge — bigger */}
              <div style={{ display:'flex', flexDirection:'column', alignItems:'center', flexShrink:0, minWidth:68 }}>
                <TeamBadge name={myTeam||teamName} size={62} radius={10} />
                <div style={{ fontSize:10, fontWeight:600, color:'#DDD', marginTop:6, textAlign:'center', lineHeight:1.3 }}>{teamName}</div>
                <div style={{ fontSize:9, color:'#777', marginTop:2, textAlign:'center' }}>{league}</div>
              </div>
            </div>

            {/* Joined */}
            {draft.joined && (
              <div style={{ display:'flex', alignItems:'center', gap:5, marginTop:10 }}>
                <span style={{ fontSize:12 }}>📅</span>
                <span style={{ fontSize:12, color:'#777' }}>Joined {fmtJoined(draft.joined)}</span>
              </div>
            )}
          </div>

          {/* ── Season Summary ── */}
          <div style={{ margin:'10px 16px 0', background:'#111111', borderRadius:14, border:'1px solid #1E1E1E', padding:'14px 8px' }}>
            <div style={{ fontSize:9, fontWeight:700, color:'#777', letterSpacing:1.5, textTransform:'uppercase', marginBottom:12, paddingLeft:8 }}>Season Summary</div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)' }}>
              {[
                ['⚽', playerGoals,    'Goals'],
                ['👕', appearances,    'Matches'],
                ['⭐', potmList.length,'Awards'],
                [availability+'%', null, 'Availability'],
              ].map(([icon, val, label], i) => (
                <div key={label} style={{ textAlign:'center', padding:'4px', borderRight:i<3?'1px solid #1E1E1E':'none' }}>
                  <div style={{ fontSize:val===null?0:20, lineHeight:1 }}>{val===null?'':icon}</div>
                  <div style={{ fontSize:20, fontWeight:600, color:'#FFF', lineHeight:1.1, marginTop:val===null?0:6 }}>{val===null?icon:val}</div>
                  <div style={{ fontSize:10, color:'#666', marginTop:4, fontWeight:500 }}>{label}</div>
                </div>
              ))}
            </div>
          </div>

          {/* ── Positions | Recognition ── */}
          <div style={{ margin:'10px 16px 0', display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>

            {/* Preferred + Secondary */}
            <div style={{ background:'#111111', borderRadius:14, border:'1px solid #1E1E1E', padding:'14px' }}>
              <div style={{ fontSize:9, fontWeight:700, color:'#777', letterSpacing:1.3, textTransform:'uppercase', marginBottom:10 }}>Positions</div>
              {preferredPos.length > 0 && <>
                <div style={{ fontSize:9, color:'#555', fontWeight:600, letterSpacing:1, textTransform:'uppercase', marginBottom:8 }}>Preferred</div>
                {preferredPos.map((pid,i) => {
                  const pg=ALL_POSITIONS.find(p=>p.id===pid);
                  return (
                    <div key={i} style={{ display:'flex', alignItems:'center', gap:8, marginBottom:i<preferredPos.length-1?8:0, paddingBottom:i<preferredPos.length-1?8:0, borderBottom:i<preferredPos.length-1?'1px solid #1A1A1A':'none' }}>
                      <span style={{ color:'#F5C04A', fontSize:13 }}>★</span>
                      <div>
                        <div style={{ fontSize:13, fontWeight:600, color:'#FFF', lineHeight:1 }}>{pg?pg.short:pid.toUpperCase()}</div>
                        <div style={{ fontSize:10, color:'#555', marginTop:2 }}>{pg?pg.label:''}</div>
                      </div>
                    </div>
                  );
                })}
              </>}
              {secondaryPos.length > 0 && <>
                <div style={{ fontSize:9, color:'#555', fontWeight:600, letterSpacing:1, textTransform:'uppercase', margin:'12px 0 8px' }}>Secondary</div>
                {secondaryPos.map((pid,i) => {
                  const pg=ALL_POSITIONS.find(p=>p.id===pid);
                  return (
                    <div key={i} style={{ display:'flex', alignItems:'center', gap:8 }}>
                      <div style={{ fontSize:13, fontWeight:600, color:'#BBB', minWidth:32, lineHeight:1 }}>{pg?pg.short:pid.toUpperCase()}</div>
                      <div style={{ fontSize:10, color:'#555' }}>{pg?pg.label:''}</div>
                    </div>
                  );
                })}
              </>}
              {!preferredPos.length && !secondaryPos.length && (
                <div style={{ fontSize:11, color:'#444', textAlign:'center', padding:'8px 0' }}>No positions set</div>
              )}
            </div>

            {/* Recent Recognition */}
            <div style={{ background:'#111111', borderRadius:14, border:'1px solid #1E1E1E', padding:'14px' }}>
              <div style={{ fontSize:9, fontWeight:700, color:'#777', letterSpacing:1.3, textTransform:'uppercase', marginBottom:10 }}>Recognition</div>
              {potmList.length === 0 ? (
                <div style={{ fontSize:11, color:'#444', textAlign:'center', padding:'16px 0' }}>No awards yet</div>
              ) : potmList.slice(0,3).map((g,i) => (
                <div key={i} style={{ display:'flex', alignItems:'flex-start', gap:8, marginBottom:i<Math.min(potmList.length,3)-1?10:0 }}>
                  <span style={{ fontSize:15, flexShrink:0 }}>{['🥇','🥈','🥉'][i]||'🏅'}</span>
                  <div style={{ flex:1, minWidth:0 }}>
                    <div style={{ fontSize:11, fontWeight:600, color:'#EEE', lineHeight:1.2 }}>Player of the Match</div>
                    <div style={{ fontSize:10, color:'#666' }}>vs {g.opponent||'—'}</div>
                    <div style={{ fontSize:9, color:'#444', marginTop:1 }}>{fmtDate(g.date)}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* ── Coach Notes | Development Focus — always shown ── */}
          <div style={{ margin:'10px 16px 0', display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
            <div style={{ background:'#111111', borderRadius:14, border:'1px solid #1E1E1E', padding:'14px' }}>
              <div style={{ fontSize:9, fontWeight:700, color:'#777', letterSpacing:1.3, textTransform:'uppercase', marginBottom:10 }}>Coach Notes</div>
              {coachLines.length === 0 ? (
                <div style={{ fontSize:11, color:'#444', fontStyle:'italic', padding:'8px 0' }}>No notes yet</div>
              ) : coachLines.map((note,i)=>(
                <div key={i} style={{ display:'flex', gap:6, marginBottom:6 }}>
                  <span style={{ color:'#F5C04A', flexShrink:0, fontSize:10, marginTop:2 }}>•</span>
                  <span style={{ fontSize:11, color:'#CCC', lineHeight:1.4 }}>{note.trim()}</span>
                </div>
              ))}
            </div>
            <div style={{ background:'#111111', borderRadius:14, border:'1px solid #1E1E1E', padding:'14px' }}>
              <div style={{ fontSize:9, fontWeight:700, color:'#777', letterSpacing:1.3, textTransform:'uppercase', marginBottom:10 }}>Dev Focus</div>
              {devLines.length === 0 ? (
                <div style={{ fontSize:11, color:'#444', fontStyle:'italic', padding:'8px 0' }}>None set</div>
              ) : devLines.map((item,i)=>(
                <div key={i} style={{ display:'flex', gap:8, marginBottom:8, alignItems:'center' }}>
                  <div style={{ width:17, height:17, borderRadius:'50%', border:'1.5px solid rgba(245,192,74,0.5)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                    <span style={{ fontSize:9, color:'#F5C04A', lineHeight:1 }}>✓</span>
                  </div>
                  <span style={{ fontSize:11, color:'#CCC', lineHeight:1.3 }}>{item.trim()}</span>
                </div>
              ))}
            </div>
          </div>

          {/* ── Recent Matches — always shown ── */}
          <div style={{ margin:'10px 16px 0' }}>
            <div style={{ fontSize:9, fontWeight:700, color:'#777', letterSpacing:1.5, textTransform:'uppercase', marginBottom:10 }}>Recent Matches</div>
            <div style={{ background:'#111111', borderRadius:14, border:'1px solid #1E1E1E', overflow:'hidden' }}>
              {recentMatches.length === 0 ? (
                <div style={{ padding:'20px', textAlign:'center', fontSize:12, color:'#444', fontStyle:'italic' }}>No match data recorded yet</div>
              ) : recentMatches.map((g,idx) => {
                const us   = g.scoreUs ?? (g.goals||[]).filter(x=>x.team==='us').length;
                const them = g.scoreThem ?? (g.goals||[]).filter(x=>x.team==='them').length;
                const nm   = displayName;
                const pg   = (g.goals||[]).filter(x=>x.scorer===nm).length;
                const win  = us>them; const draw = us===them;
                const col  = win?'#22c55e':draw?'#F5C04A':'#ef4444';
                return (
                  <div key={idx} style={{ display:'flex', alignItems:'center', gap:10, padding:'11px 14px', borderBottom:idx<recentMatches.length-1?'1px solid #1A1A1A':'none' }}>
                    <TeamBadge name={g.opponent||'?'} size={30} radius={6} />
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:13, fontWeight:500, color:'#EEE', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{g.opponent||'Unknown'}</div>
                      <div style={{ fontSize:10, color:'#555' }}>{fmtDate(g.date)}</div>
                    </div>
                    <div style={{ textAlign:'center', minWidth:56 }}>
                      <span style={{ fontSize:13, fontWeight:600, color:col }}>{us} – {them}</span>
                      <span style={{ fontSize:10, fontWeight:500, color:col, marginLeft:4 }}>({win?'W':draw?'D':'L'})</span>
                    </div>
                    <div style={{ display:'flex', alignItems:'center', gap:3, minWidth:36 }}>
                      <span style={{ fontSize:12 }}>⚽</span>
                      <span style={{ fontSize:12, fontWeight:500, color:'#CCC' }}>{pg}</span>
                    </div>
                    <div style={{ color:'#444', fontSize:18, lineHeight:1 }}>›</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>
    );
  }

  /* ── ADD / EDIT FORM ────────────────────────────────────────────────────── */
  return (
    <div style={{ background:'#0D0D0D', minHeight:'100dvh', display:'flex', flexDirection:'column' }}>
      <KhulaHeader rightEl={!isNew ? (
        <button onClick={()=>{ setDraft(loadPlayer()); setEditing(false); }}
          style={{ background:'none', border:'none', color:'#666', fontSize:13, cursor:'pointer', padding:0 }}>Cancel</button>
      ) : null} />

      <div style={{ flex:1, overflowY:'auto', paddingBottom:'calc(84px + env(safe-area-inset-bottom))' }}>

        {/* Hero avatar */}
        <div style={{ display:'flex', flexDirection:'column', alignItems:'center', padding:'24px 16px 20px', background:'#111111', borderBottom:'1px solid #1E1E1E' }}>
          <div style={{ position:'relative', marginBottom:14 }}>
            <div style={{ width:90, height:90, borderRadius:'50%', overflow:'hidden', background:'rgba(245,192,74,0.1)', border:'2px solid rgba(245,192,74,0.35)', display:'flex', alignItems:'center', justifyContent:'center' }}>
              {draft.photo ? <img src={draft.photo} alt={displayName} style={{ width:'100%', height:'100%', objectFit:'cover' }} /> : <span style={{ fontSize:30, fontWeight:700, color:'#F5C04A' }}>{initials}</span>}
            </div>
            <button onClick={pickPhoto} style={{ position:'absolute', bottom:0, right:0, width:28, height:28, borderRadius:'50%', background:'#F5C04A', border:'2px solid #0D0D0D', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', fontSize:13, padding:0, lineHeight:1 }}>📷</button>
            <input ref={photoRef} type="file" accept="image/*" capture="environment" style={{ display:'none' }} onChange={onPhotoChange} />
          </div>
          <div style={{ fontSize:19, fontWeight:600, color:'#FFF', textAlign:'center' }}>{displayName}</div>
          {draft.nickname && <div style={{ fontSize:13, color:'#F5C04A', marginTop:3 }}>"{draft.nickname}"</div>}
          <div style={{ display:'flex', gap:6, marginTop:10, flexWrap:'wrap', justifyContent:'center' }}>
            {[draft.pos,draft.pos2,draft.pos3].filter(Boolean).map((pid,i)=>{
              const pg=ALL_POSITIONS.find(p=>p.id===pid);
              return <div key={i} style={{ background:i===0?'rgba(245,192,74,0.2)':'rgba(255,255,255,0.07)', border:`1px solid ${i===0?'rgba(245,192,74,0.5)':'#333'}`, borderRadius:8, padding:'5px 12px', fontSize:12, fontWeight:600, color:i===0?'#F5C04A':'#A1A1A1' }}>{pg?pg.short:pid.toUpperCase()}</div>;
            })}
          </div>
        </div>

        <div style={{ padding:'16px 16px 0' }}>

          {/* Player Information */}
          <div style={{ background:'#111111', borderRadius:14, padding:'16px', border:'1px solid #1E1E1E', marginBottom:12 }}>
            <div style={{ fontSize:10, fontWeight:700, color:'#777', letterSpacing:1.5, textTransform:'uppercase', marginBottom:14 }}>Player Information</div>
            <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
                <div><div style={labelStyle}>First Name</div><input value={draft.firstName||''} onChange={e=>upd('firstName',e.target.value)} placeholder="First name" style={inputStyle} autoFocus={!!isNew} /></div>
                <div><div style={labelStyle}>Last Name</div><input value={draft.lastName||''} onChange={e=>upd('lastName',e.target.value)} placeholder="Last name" style={inputStyle} /></div>
              </div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
                <div><div style={labelStyle}>Nickname</div><input value={draft.nickname||''} onChange={e=>upd('nickname',e.target.value)} placeholder='e.g. "Syd"' style={inputStyle} /></div>
                <div><div style={labelStyle}>Jersey #</div><input value={draft.number||''} onChange={e=>upd('number',e.target.value)} placeholder="#" style={inputStyle} /></div>
              </div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
                <div><div style={labelStyle}>Date of Birth</div><input type="date" value={draft.dob||''} onChange={e=>upd('dob',e.target.value)} style={inputStyle} /></div>
                <div><div style={labelStyle}>Preferred Foot</div>
                  <select value={draft.foot||'right'} onChange={e=>upd('foot',e.target.value)} style={{ ...inputStyle, padding:'10px 14px' }}>
                    <option value="right">Right</option><option value="left">Left</option><option value="both">Both</option>
                  </select>
                </div>
              </div>
              <div>
                <div style={labelStyle}>Date Joined (Month)</div>
                <input type="month" value={draft.joined||''} onChange={e=>upd('joined',e.target.value)} style={inputStyle} />
              </div>
            </div>
          </div>

          {/* Preferred Positions */}
          <div style={{ background:'#111111', borderRadius:14, padding:'16px', border:'1px solid #1E1E1E', marginBottom:12 }}>
            <div style={{ fontSize:10, fontWeight:700, color:'#777', letterSpacing:1.5, textTransform:'uppercase', marginBottom:4 }}>Preferred Positions</div>
            <div style={{ fontSize:11, color:'#555', marginBottom:12 }}>Select primary + up to 2 others (tap to toggle)</div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(3,1fr)', gap:8 }}>
              {ALL_POSITIONS.map(pos=>{
                const sel=[draft.pos,draft.pos2,draft.pos3].filter(Boolean).includes(pos.id);
                const isPrimary=draft.pos===pos.id;
                return (
                  <button key={pos.id} onClick={()=>togglePosition(pos.id)}
                    style={{ background:sel?(isPrimary?'rgba(245,192,74,0.18)':'rgba(255,255,255,0.07)'):'#1A1A1A', border:`2px solid ${sel?(isPrimary?'#F5C04A':'rgba(245,192,74,0.3)'):'#2A2A2A'}`, borderRadius:10, padding:'10px 4px 8px', cursor:'pointer', textAlign:'center', position:'relative', transition:'all 0.15s' }}>
                    {sel && <div style={{ position:'absolute', top:4, right:4, width:14, height:14, borderRadius:'50%', background:isPrimary?'#F5C04A':'rgba(245,192,74,0.5)', display:'flex', alignItems:'center', justifyContent:'center' }}><span style={{ fontSize:9, color:'#000', fontWeight:700 }}>✓</span></div>}
                    <div style={{ fontSize:15, fontWeight:600, color:sel?(isPrimary?'#F5C04A':'#DDD'):'#555', lineHeight:1 }}>{pos.short}</div>
                    <div style={{ fontSize:9, color:sel?(isPrimary?'rgba(245,192,74,0.7)':'#777'):'#3A3A3A', marginTop:4, lineHeight:1.2, fontWeight:500 }}>{pos.label}</div>
                  </button>
                );
              })}
            </div>
          </div>

          {/* Can play GK */}
          <div style={{ background:'#111111', borderRadius:14, padding:'16px', border:'1px solid #1E1E1E', marginBottom:12 }}>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
              <div>
                <div style={{ fontSize:14, fontWeight:600, color:'#EEE' }}>Can play Goalkeeper</div>
                <div style={{ fontSize:11, color:'#666', marginTop:2 }}>{draft.canPlayGK?'Can cover in goal if needed':'Not a goalkeeper option'}</div>
              </div>
              <button onClick={()=>upd('canPlayGK',!draft.canPlayGK)}
                style={{ width:50, height:28, borderRadius:14, background:draft.canPlayGK?'#22c55e':'#333', border:'none', cursor:'pointer', position:'relative', transition:'background 0.2s', flexShrink:0, padding:0 }}>
                <div style={{ width:22, height:22, borderRadius:'50%', background:'#FFF', position:'absolute', top:3, left:draft.canPlayGK?24:3, transition:'left 0.2s' }} />
              </button>
            </div>
          </div>

          {/* Coach Notes */}
          <div style={{ background:'#111111', borderRadius:14, padding:'16px', border:'1px solid #1E1E1E', marginBottom:12 }}>
            <div style={{ fontSize:10, fontWeight:700, color:'#777', letterSpacing:1.5, textTransform:'uppercase', marginBottom:8 }}>Coach Notes</div>
            <div style={{ fontSize:11, color:'#555', marginBottom:8 }}>One note per line (shown as bullet points)</div>
            <textarea value={draft.coachNotes||''} onChange={e=>upd('coachNotes',e.target.value)}
              placeholder={"Strong attacking runs\nGood first touch\nNeeds to track back more"}
              rows={4} style={{ ...inputStyle, resize:'vertical', lineHeight:1.5 }} />
          </div>

          {/* Development Focus */}
          <div style={{ background:'#111111', borderRadius:14, padding:'16px', border:'1px solid #1E1E1E', marginBottom:12 }}>
            <div style={{ fontSize:10, fontWeight:700, color:'#777', letterSpacing:1.5, textTransform:'uppercase', marginBottom:8 }}>Development Focus</div>
            <div style={{ fontSize:11, color:'#555', marginBottom:8 }}>One focus area per line</div>
            <textarea value={draft.devFocus||''} onChange={e=>upd('devFocus',e.target.value)}
              placeholder={"Finishing\nFirst Touch\nDecision Making"}
              rows={3} style={{ ...inputStyle, resize:'vertical', lineHeight:1.5 }} />
          </div>

          {/* Save */}
          <button onClick={save}
            style={{ width:'100%', padding:'16px', background:'#F5C04A', color:'#000', border:'none', borderRadius:12, fontSize:15, fontWeight:700, cursor:'pointer', marginBottom:8 }}>
            {isNew ? 'Add Player' : 'Save Changes'}
          </button>
        </div>
      </div>
    </div>
  );
}



function SquadScreen({ mode, onNext, onBack, onViewOpponent, onViewPlayer, onAddPlayer }) {
  const [squad, setSquad]   = useState(()=>loadSquad());
  const [config, setConfig] = useState(()=>{ const cx=loadContextData(contextKey); return cx.config || loadConfig(); });
  const [search, setSearch] = useState('');
  const [showAdd, setShowAdd] = useState(false);
  const [newName, setNewName] = useState('');

  const myTeam = localStorage.getItem('soccerCoach_fixtureTeam') || '';
  const nextFix = FIXTURES.find(f=>(f.home===myTeam||f.away===myTeam)&&isUpcoming(f));
  const suggestedOpponent = nextFix ? (nextFix.home===myTeam?nextFix.away:nextFix.home) : '';
  const [opponent, setOpponent] = useState(suggestedOpponent);

  function persist(next){ setSquad(next); saveSquad(next); }
  function addPlayer(){
    const name=newName.trim();
    if(!name||squad.some(p=>p.name===name)) return;
    persist([{name,pos:'',pos2:'',pos3:''},...squad]);
    setNewName(''); setShowAdd(false); setSearch('');
  }
  function remove(name){ persist(squad.filter(p=>p.name!==name)); }
  function setPos(name,field,val){ persist(squad.map(p=>p.name===name?{...p,[field]:val}:p)); }
  function updCfg(key,val){ const next={...config,[key]:val}; setConfig(next); saveConfig(next); }

  const isNewGame = mode==='newGame';
  const pm = getPeriodMins(config);
  const pmDisplay = Number.isInteger(pm) ? `${pm}` : pm.toFixed(1);

  const posOpts = <><option value="">—</option>{ALL_POSITIONS.map(p=><option key={p.id} value={p.id}>{p.label}</option>)}</>;

  const filtered = search.trim()
    ? squad.filter(p=>p.name.toLowerCase().includes(search.toLowerCase()))
    : squad;

  const selStyle = {
    width:'100%', background:'#111111', border:'1px solid #2A2A2A',
    borderRadius:8, padding:'8px 10px', color:'#FFFFFF', fontSize:12,
    fontWeight:600, outline:'none', cursor:'pointer',
    WebkitAppearance:'none', appearance:'none',
  };

  return (
    <div style={{ height:'100dvh', background:'#0D0D0D', display:'flex', flexDirection:'column', overflow:'hidden' }}>

      {/* ── Header ── */}
      <div style={{ background:'#111111', borderBottom:'1px solid #1E1E1E', padding:'0 16px', height:56, display:'flex', alignItems:'center', gap:10, flexShrink:0 }}>
        <button onClick={onBack} style={{ background:'none', border:'none', color:'#A1A1A1', fontSize:18, cursor:'pointer', padding:'4px 10px 4px 0', lineHeight:1 }}>←</button>
        <span style={{ fontSize:20, lineHeight:1 }}>👥</span>
        <span style={{ flex:1, fontSize:15, fontWeight:800, color:'#FFFFFF', letterSpacing:0.5 }}>
          PLAYERS ({squad.length})
        </span>
      </div>

      {/* ── Scrollable body ── */}
      <div style={{ flex:1, overflowY:'auto', padding:'16px 14px 12px' }}>

        {/* Search */}
        <div style={{ marginBottom:14 }}>
          <input
            style={{ width:'100%', background:'#1A1A1A', border:'1px solid #2A2A2A', borderRadius:10, padding:'12px 14px', color:'#FFFFFF', fontSize:14, outline:'none', boxSizing:'border-box' }}
            placeholder="🔍  Search players..."
            value={search}
            onChange={e=>setSearch(e.target.value)}
          />
        </div>

        {/* Inline add form */}
        {showAdd && (
          <div style={{ background:'#1A1A1A', border:'1px solid #F5C04A44', borderRadius:12, padding:'12px 14px', marginBottom:14 }}>
            <div style={{ fontSize:10, fontWeight:800, color:'#F5C04A', letterSpacing:1.5, textTransform:'uppercase', marginBottom:8 }}>New Player</div>
            <div style={{ display:'flex', gap:8 }}>
              <input
                autoFocus
                style={{ flex:1, background:'#111111', border:'1px solid #333', borderRadius:8, padding:'11px 12px', color:'#FFF', fontSize:14, outline:'none' }}
                placeholder="Player name..."
                value={newName}
                onChange={e=>setNewName(e.target.value)}
                onKeyDown={e=>{ if(e.key==='Enter')addPlayer(); if(e.key==='Escape')setShowAdd(false); }}
              />
              <button
                onClick={addPlayer}
                style={{ background:'#F5C04A', color:'#000', border:'none', borderRadius:8, padding:'11px 18px', fontWeight:800, fontSize:14, cursor:'pointer' }}>
                Add
              </button>
              <button
                onClick={()=>setShowAdd(false)}
                style={{ background:'transparent', color:'#A1A1A1', border:'1px solid #2A2A2A', borderRadius:8, padding:'11px 14px', fontSize:14, cursor:'pointer' }}>
                ✕
              </button>
            </div>
          </div>
        )}

        {/* Player list */}
        <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
          {filtered.length===0 && !showAdd && (
            <div style={{ textAlign:'center', color:'#555', fontSize:13, padding:'32px 0' }}>
              {search ? 'No players match your search.' : 'No players yet. Tap + Add Player to get started.'}
            </div>
          )}
          {filtered.map((p) => {
            const pInitials = (p.name||'?').split(' ').map(w=>w[0]||'').join('').slice(0,2).toUpperCase();
            const positions = [p.pos, p.pos2, p.pos3].filter(Boolean);
            return (
              <div key={p.name}
                onClick={() => onViewPlayer && onViewPlayer(p.name)}
                style={{ background:'#111111', borderRadius:14, padding:'14px 16px', border:'1px solid #1E1E1E', display:'flex', alignItems:'center', gap:12, cursor: onViewPlayer ? 'pointer' : 'default', transition:'background 0.1s', WebkitTapHighlightColor:'transparent' }}>

                {/* Jersey number (only if set) */}
                {p.number ? (
                  <div style={{ width:36, height:36, borderRadius:'50%', background:'rgba(245,192,74,0.12)', border:'2px solid rgba(245,192,74,0.35)', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                    <span style={{ fontSize:13, fontWeight:900, color:'#F5C04A' }}>{p.number}</span>
                  </div>
                ) : (
                  <div style={{ width:36, height:36, borderRadius:'50%', background:'#1A1A1A', border:'1px solid #2A2A2A', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                    <span style={{ fontSize:12, fontWeight:800, color:'#555' }}>{pInitials}</span>
                  </div>
                )}

                {/* Photo avatar (only if set) */}
                {p.photo && (
                  <div style={{ width:36, height:36, borderRadius:'50%', overflow:'hidden', flexShrink:0 }}>
                    <img src={p.photo} alt={p.name} style={{ width:'100%', height:'100%', objectFit:'cover' }} />
                  </div>
                )}

                {/* Name + nickname */}
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:15, fontWeight:500, color:'#FFF', lineHeight:1.2 }}>{p.name}</div>
                  {p.nickname && (
                    <div style={{ fontSize:12, color:'#F5C04A', marginTop:1 }}>"{p.nickname}"</div>
                  )}
                </div>

                {/* Position chips (right side) */}
                {positions.length > 0 && (
                  <div style={{ display:'flex', gap:4, flexWrap:'wrap', justifyContent:'flex-end', maxWidth:100 }}>
                    {positions.map((pid, i) => {
                      const pg = ALL_POSITIONS.find(x => x.id === pid);
                      return (
                        <div key={i} style={{ background: i===0 ? 'rgba(245,192,74,0.15)' : 'rgba(255,255,255,0.05)', border:`1px solid ${i===0?'rgba(245,192,74,0.4)':'#2A2A2A'}`, borderRadius:6, padding:'3px 8px', fontSize:11, fontWeight:800, color: i===0 ? '#F5C04A' : '#555' }}>
                          {pg ? pg.short : pid.toUpperCase()}
                        </div>
                      );
                    })}
                  </div>
                )}

                {/* Chevron */}
                <div style={{ color:'#444', fontSize:18, flexShrink:0, lineHeight:1 }}>›</div>
              </div>
            );
          })}

          {/* Add New Player button */}
          <button
            onClick={() => { if(onAddPlayer){onAddPlayer();}else{setNewName('');setShowAdd(s=>!s);} }}
            style={{ width:'100%', marginTop:4, padding:'16px', background:'transparent', color:'#F5C04A', border:'2px dashed rgba(245,192,74,0.35)', borderRadius:14, fontSize:14, fontWeight:800, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:8, boxSizing:'border-box' }}>
            <span style={{ fontSize:20, lineHeight:1 }}>＋</span>
            <span>Add New Player</span>
          </button>
        </div>



        {/* ── New Game extras ── */}
        {isNewGame && (<>
          <div style={{ marginTop:20 }}>
            <div style={{ fontSize:11, fontWeight:800, color:'#A1A1A1', letterSpacing:1.5, textTransform:'uppercase', marginBottom:10 }}>Opponent</div>
            {(()=>{
              const allTeams=[...new Set(FIXTURES.flatMap(f=>[f.home,f.away]).filter(Boolean))].filter(t=>t!==myTeam).sort();
              return (<>
                <select
                  style={{ ...selStyle, marginBottom:6, fontSize:14, padding:'11px 12px', color:opponent?'#FFF':'#A1A1A1', borderRadius:10 }}
                  value={allTeams.includes(opponent)?opponent:'__custom__'}
                  onChange={e=>{ if(e.target.value!=='__custom__')setOpponent(e.target.value); else setOpponent(''); }}>
                  <option value="" disabled style={{ color:'#A1A1A1' }}>— Select opponent —</option>
                  {suggestedOpponent&&<option value={suggestedOpponent}>📅 {suggestedOpponent} (next fixture)</option>}
                  <option value="__custom__">✏️ Type custom opponent…</option>
                  {allTeams.filter(t=>t!==suggestedOpponent).map(t=><option key={t} value={t}>{t}</option>)}
                </select>
                {(!allTeams.includes(opponent)||opponent==='')&&(
                  <input style={{ ...selStyle, marginBottom:4, fontSize:14, padding:'11px 12px', borderRadius:10, outline:'none' }} placeholder="Type opponent name…" value={opponent} onChange={e=>setOpponent(e.target.value)} />
                )}
                {opponent.trim()&&onViewOpponent&&(
                  <button style={{ width:'100%', marginTop:6, background:'#1E1E1E', border:'1px solid #F5C04A33', borderRadius:10, padding:'10px', color:'#F5C04A', fontSize:12, fontWeight:700, cursor:'pointer' }} onClick={()=>onViewOpponent(opponent.trim())}>🔍 Scout {opponent}</button>
                )}
              </>);
            })()}
          </div>

          <div style={{ background:'#1A1A1A', border:'1px solid #222', borderRadius:14, padding:'14px', marginTop:16 }}>
            <div style={{ fontSize:11, fontWeight:800, color:'#A1A1A1', letterSpacing:1.5, textTransform:'uppercase', marginBottom:12 }}>⚙️ Match Settings</div>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:10 }}>
              <span style={{ fontSize:13, color:'#FFFFFF' }}>Formation</span>
              <select style={{ ...selStyle, width:'auto', minWidth:110, padding:'8px 10px' }} value={config.formation||DEFAULT_FORMATION} onChange={e=>updCfg('formation',e.target.value)}>
                {Object.keys(FORMATIONS).map(f=><option key={f} value={f}>{f}</option>)}
              </select>
            </div>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:10 }}>
              <span style={{ fontSize:13, color:'#FFFFFF' }}>Half length</span>
              <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                <button style={{ background:'#111', border:'1px solid #333', color:'#FFF', width:34, height:34, borderRadius:8, cursor:'pointer', fontSize:18, lineHeight:1 }} onClick={()=>updCfg('halfMins',Math.max(5,config.halfMins-5))}>−</button>
                <span style={{ fontSize:14, fontWeight:700, color:'#FFF', minWidth:52, textAlign:'center' }}>{config.halfMins} min</span>
                <button style={{ background:'#111', border:'1px solid #333', color:'#FFF', width:34, height:34, borderRadius:8, cursor:'pointer', fontSize:18, lineHeight:1 }} onClick={()=>updCfg('halfMins',Math.min(60,config.halfMins+5))}>+</button>
              </div>
            </div>
            <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:10 }}>
              <span style={{ fontSize:13, color:'#FFFFFF' }}>Periods / half</span>
              <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                <button style={{ background:'#111', border:'1px solid #333', color:'#FFF', width:34, height:34, borderRadius:8, cursor:'pointer', fontSize:18, lineHeight:1 }} onClick={()=>updCfg('numPeriods',Math.max(1,config.numPeriods-1))}>−</button>
                <span style={{ fontSize:14, fontWeight:700, color:'#FFF', minWidth:20, textAlign:'center' }}>{config.numPeriods}</span>
                <button style={{ background:'#111', border:'1px solid #333', color:'#FFF', width:34, height:34, borderRadius:8, cursor:'pointer', fontSize:18, lineHeight:1 }} onClick={()=>updCfg('numPeriods',Math.min(6,config.numPeriods+1))}>+</button>
              </div>
            </div>
            <div style={{ fontSize:11, color:'#F5C04A', textAlign:'center', fontWeight:700 }}>= {pmDisplay} min per period</div>
          </div>

          <button
            style={{ width:'100%', marginTop:16, padding:'16px', background: squad.length>=9?'#F5C04A':'#1A1A1A', color:squad.length>=9?'#000':'#555', border:'none', borderRadius:12, fontSize:15, fontWeight:800, cursor:squad.length>=9?'pointer':'default', letterSpacing:0.3 }}
            disabled={squad.length<9}
            onClick={()=>{
              const opp=opponent.trim();
              const mt=localStorage.getItem('soccerCoach_fixtureTeam')||'';
              const mf=FIXTURES.find(f=>isUpcoming(f)&&((f.home===mt&&f.away===opp)||(f.away===mt&&f.home===opp)));
              onNext(squad,config,opp,mf?fixtureKey(mf):null,mf?mf.home===mt:null);
            }}>
            Pick Starting XI →
          </button>
          {squad.length<9&&<p style={{ textAlign:'center', color:'#ef4444', fontSize:12, marginTop:6 }}>Need at least 9 players to continue.</p>}
        </>)}

      </div>

      {/* Fixed Done footer — always visible above keyboard */}
      {!isNewGame && (
        <div style={{ flexShrink:0, padding:'10px 14px', paddingBottom:'max(14px,env(safe-area-inset-bottom))', background:'#0D0D0D', borderTop:'1px solid #1A1A1A' }}>
          <button
            style={{ width:'100%', padding:'15px', background:'#F5C04A', color:'#000', border:'none', borderRadius:12, fontSize:15, fontWeight:800, cursor:'pointer' }}
            onClick={onBack}>
            Done
          </button>
        </div>
      )}
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: LINEUP PICKER  (self-contained — Match tab)
// ════════════════════════════════════════════════════════════════════════════════
function PickerScreen({ onNext, onBack, onSave, onManageSquad, onViewOpponent, onViewStats, onViewPlayerStats, initialTab, contextKey }) {
  const myTeam = localStorage.getItem('soccerCoach_fixtureTeam') || '';

  const [squad,  setSquad]  = useState(()=>{
    const base=loadSquad();
    if(contextKey){
      const cx=loadContextData(contextKey);
      const mp=cx.matchPlayers;
      if(mp){
        const sts=mp.statuses||{};
        const guests=(mp.guests||[]).map(g=>typeof g==='string'?{name:g,pos:'',age:''}:{name:g.name||'',pos:g.pos||'',age:''});
        return [...base.filter(p=>(sts[p.name]||'available')!=='unavailable'),...guests];
      }
      // No matchPlayers yet — still exclude anyone explicitly marked unavailable
      try {
        const allKeys=Object.keys(localStorage).filter(k=>k.startsWith('soccerCoach_ctx_'));
        for(const k of allKeys){
          const d=JSON.parse(localStorage.getItem(k)||'{}')||{};
          if(d.matchPlayers?.statuses){
            const sts=d.matchPlayers.statuses;
            return base.filter(p=>(sts[p.name]||'available')!=='unavailable');
          }
        }
      } catch {}
    }
    return base;
  });
  const [config, setConfig] = useState(()=>loadConfig());

  const initOpp = () => {
    const cx=loadContextData(contextKey);
    if(cx.lineup?.opponent) return cx.lineup.opponent;
    const nf = FIXTURES.find(f=>(f.home===myTeam||f.away===myTeam)&&isUpcoming(f));
    return nf ? (nf.home===myTeam ? nf.away : nf.home) : '';
  };
  const [opponent,  setOpponent]  = useState(initOpp);
  const [customOpp, setCustomOpp] = useState(false);

  const formation = config.formation || DEFAULT_FORMATION;
  const positions = getPositions(formation);
  const posIds    = getPosIds(positions);
  const posLbl    = getPosLabel(positions);
  const names     = squad.map(p=>p.name);
  const pm        = getPeriodMins(config);
  const pmDisplay = Number.isInteger(pm) ? `${pm}` : pm.toFixed(1);

  const makePeriods = (sq, pos, n) => {
    const base = autoFillSlots(sq, pos);
    return Array.from({length: n}, () => cloneSlots(base));
  };

  // ── Persist picker draft so lineup survives navigation ──────────────────────
  const DRAFT_KEY = 'soccerCoach_pickerDraft_'+(contextKey||'default');
  const loadDraft = () => { try { return JSON.parse(localStorage.getItem(DRAFT_KEY)||'{}'); } catch { return {}; } };
  const saveDraft = (patch) => {
    try {
      const prev = loadDraft();
      localStorage.setItem(DRAFT_KEY, JSON.stringify({...prev, ...patch}));
    } catch {}
  };
  const clearDraft = () => { try { localStorage.removeItem(DRAFT_KEY); } catch {} };

  // Sanitize: strip any slot values that are no longer in the current squad
  function sanitizePeriods(periods, validNames) {
    return periods.map(p => {
      const next = {};
      posIds.forEach(id => { next[id] = validNames.includes(p[id]) ? p[id] : ''; });
      return next;
    });
  }
  const validNames = squad.map(p=>p.name);

  const [h1Periods, setH1Periods] = useState(()=>{
    const cx=loadContextData(contextKey).lineup;
    if(cx?.h1Periods?.length) return sanitizePeriods(cx.h1Periods, squad.map(p=>p.name));
    const d = loadDraft();
    const raw = (d.h1Periods && d.h1Periods.length) ? d.h1Periods : makePeriods(squad, positions, config.numPeriods||3);
    return sanitizePeriods(raw, squad.map(p=>p.name));
  });
  const [h2Periods, setH2Periods] = useState(()=>{
    const cx=loadContextData(contextKey).lineup;
    if(cx?.h2Periods?.length) return sanitizePeriods(cx.h2Periods, squad.map(p=>p.name));
    const d = loadDraft();
    const raw = (d.h2Periods && d.h2Periods.length) ? d.h2Periods : makePeriods(squad, positions, config.numPeriods||3);
    return sanitizePeriods(raw, squad.map(p=>p.name));
  });
  const [activeHalf,   setActiveHalf]   = useState(()=>{ const d=loadDraft(); return d.activeHalf||0; });
  const [activePeriod, setActivePeriod] = useState(()=>{ const d=loadDraft(); return d.activePeriod||0; });
  const [selectedSlot, setSelectedSlot] = useState(null);
  const [selectedBench, setSelectedBench] = useState(null);
  const [pickerTab,    setPickerTab]    = useState(initialTab||'squad');

  const activePeriods = activeHalf === 0 ? h1Periods : h2Periods;
  function updateActivePeriods(updater) {
    if (activeHalf === 0) setH1Periods(updater);
    else setH2Periods(updater);
  }

  // ── Auto-save draft on every lineup change ──────────────────────────────────
  useEffect(() => { saveDraft({ h1Periods, h2Periods, activeHalf, activePeriod, opponent }); },
    [h1Periods, h2Periods, activeHalf, activePeriod, opponent]);

  const prevFormation = useRef(formation);
  useEffect(() => {
    if (prevFormation.current === formation) return;
    prevFormation.current = formation;
    const resetPs = makePeriods(squad, getPositions(formation), config.numPeriods||3);
    setH1Periods(resetPs);
    setH2Periods(resetPs.map(s=>cloneSlots(s)));
    setSelectedSlot(null);
  }, [formation]);

  useEffect(() => {
    const n = config.numPeriods || 3;
    const resizeFn = (prev) => {
      if (prev.length === n) return prev;
      const base = prev[0] || autoFillSlots(squad, positions);
      if (prev.length < n) return [...prev, ...Array.from({length:n-prev.length},()=>cloneSlots(base))];
      if (activePeriod >= n) setActivePeriod(n-1);
      return prev.slice(0, n);
    };
    setH1Periods(resizeFn);
    setH2Periods(resizeFn);
  }, [config.numPeriods]);

  // ── Height alignment: left col ref → right col height ──────────────────────
  const leftColRef = useRef(null);
  const [colH, setColH] = useState(null);
  useEffect(() => {
    const el = leftColRef.current;
    if (!el) return;
    const upd = () => setColH(el.getBoundingClientRect().height);
    upd();
    const ro = new ResizeObserver(upd);
    ro.observe(el);
    return () => ro.disconnect();
  }, [positions, h1Periods, h2Periods, activeHalf]);

  const curSlots = activePeriods[activePeriod] || {};
  const assigned = Object.values(curSlots).filter(Boolean);
  const bench    = names.filter(n=>!assigned.includes(n));

  function updCfg(key, val) { const next={...config,[key]:val}; setConfig(next); saveContextData(contextKey,{config:next}); }

  function assignToSlot(posId, playerName) {
    updateActivePeriods(prev=>{
      const prevOccupant = prev[activePeriod]?.[posId];
      return prev.map((p,i)=>{
        if(i < activePeriod) return p;
        // Only cascade to future periods where this slot still has the same occupant
        if(i > activePeriod && p[posId] !== prevOccupant) return p;
        const next=cloneSlots(p);
        // Find where playerName currently sits in this period
        const playerOldSlot = posIds.find(k=>k!==posId && next[k]===playerName);
        const occupantHere  = next[posId];
        // Swap: if playerName was somewhere on field, put displaced occupant there
        if(playerOldSlot && occupantHere && occupantHere !== playerName) {
          next[playerOldSlot] = occupantHere;
        } else if(playerOldSlot) {
          next[playerOldSlot] = '';
        }
        if(Array.isArray(next.bench)) next.bench=next.bench.filter(n=>n!==playerName);
        next[posId]=playerName;
        return next;
      });
    });
    setSelectedSlot(null);
  }

  function handleSlotTap(posId) { setSelectedSlot(s=>s===posId?null:posId); }

  function handlePlayerTap(name) {
    if (selectedSlot) { assignToSlot(selectedSlot, name); return; }
    const cur = Object.keys(curSlots).find(k=>curSlots[k]===name);
    if (cur) setSelectedSlot(cur);
    else { const empty=posIds.find(id=>!curSlots[id]); if(empty) assignToSlot(empty,name); }
  }

  function isPeriodModified(i) {
    if(i===0||!activePeriods[i]||!activePeriods[0]) return false;
    return posIds.some(id=>activePeriods[0][id]!==activePeriods[i][id]);
  }

  // Swap analysis: what changed vs P1 of current half
  function getSwaps(pIdx) {
    if(pIdx===0||!activePeriods[0]||!activePeriods[pIdx]) return [];
    const p1=activePeriods[0], p=activePeriods[pIdx];
    const swaps=[];
    posIds.forEach(id=>{
      if(p1[id]!==p[id]) swaps.push({ pos:posLbl[id], on:p[id]||null, off:p1[id]||null });
    });
    return swaps;
  }

  function swapPitchSlots(posA, posB) {
    updateActivePeriods(prev=>{
      const curA = prev[activePeriod]?.[posA]||'';
      const curB = prev[activePeriod]?.[posB]||'';
      return prev.map((p,i)=>{
        if(i < activePeriod) return p;
        const next=cloneSlots(p);
        if(i === activePeriod){
          next[posA]=curB; next[posB]=curA;
        } else {
          // cascade: only update future periods that still have the pre-swap values
          if(next[posA]===curA) next[posA]=curB;
          if(next[posB]===curB) next[posB]=curA;
        }
        return next;
      });
    });
    setSelectedSlot(null);
  }

  function playerPeriods(name) {
    return activePeriods.map((p,i)=>({ i, on:Object.values(p).includes(name), color:PAIR_COLORS[i%PAIR_COLORS.length] }));
  }

  function canStart() { return h1Periods.every(p=>positions.every(pos=>p[pos.id])); }

  function buildHalves() {
    const toHalf = (ps) => ps.map((slots,i)=>({
      slots:{...cloneSlots(slots), bench:names.filter(n=>!Object.values(slots).includes(n))},
      seeded:i===0,
    }));
    return { half1: toHalf(h1Periods), half2: toHalf(h2Periods) };
  }

  const linkedFix = FIXTURES.find(f=>isUpcoming(f)&&((f.home===myTeam&&f.away===opponent)||(f.away===myTeam&&f.home===opponent)));
  const allTeams  = [...new Set(FIXTURES.flatMap(f=>[f.home,f.away]).filter(Boolean))].filter(t=>t!==myTeam).sort();
  const oppInList = allTeams.includes(opponent);

  const selStyle = { width:'100%', background:'#111111', border:'1px solid #2A2A2A', borderRadius:8, padding:'8px 10px', color:'#FFFFFF', fontSize:12, fontWeight:600, outline:'none', cursor:'pointer' };
  const stepBtn  = { background:'#111', border:'1px solid #2A2A2A', color:'#FFF', width:32, height:32, borderRadius:8, cursor:'pointer', fontSize:18, lineHeight:'1', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 };

  if (squad.length === 0) {
    return (
      <div style={{ minHeight:'100vh', background:'#0D0D0D', display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', padding:32 }}>
        <div style={{ fontSize:48, marginBottom:16 }}>👥</div>
        <div style={{ fontSize:18, fontWeight:800, color:'#FFF', marginBottom:8 }}>No squad yet</div>
        <div style={{ fontSize:13, color:'#A1A1A1', marginBottom:24, textAlign:'center' }}>Add at least 9 players to your squad before planning a match.</div>
        <button onClick={onManageSquad} style={{ background:'#F5C04A', color:'#000', border:'none', borderRadius:12, padding:'14px 28px', fontWeight:800, fontSize:14, cursor:'pointer' }}>Set Up Squad →</button>
        <button onClick={onBack} style={{ marginTop:12, background:'none', border:'none', color:'#A1A1A1', fontSize:13, cursor:'pointer' }}>← Back</button>
      </div>
    );
  }

  const swaps = getSwaps(activePeriod);

  // Pair colors: each change-pair gets a unique color, never repeats
  // Using 8 distinct colors — more than enough for any substitution scenario
  const SUB_PAIR_COLORS = ['#f59e0b','#a855f7','#06b6d4','#22c55e','#f43f5e','#3b82f6','#fb923c','#84cc16'];
  const subPairColors = {};
  if(activePeriod > 0 && activePeriods[activePeriod-1] && activePeriods[activePeriod]) {
    const _prev = activePeriods[activePeriod-1];
    const _curr = activePeriods[activePeriod];
    const _changedIds = posIds.filter(id=>(_prev[id]||'')!==(_curr[id]||''));
    let _ci = 0;
    const _done = new Set();
    _changedIds.forEach(id=>{
      if(_done.has(id)) return;
      const was=_prev[id]||'', now=_curr[id]||'';
      // Detect mutual position swap: another slot where prev=now AND curr=was
      const pairId=_changedIds.find(id2=>id2!==id&&!_done.has(id2)&&(_prev[id2]||'')=== now&&(_curr[id2]||'')=== was);
      const col=SUB_PAIR_COLORS[_ci % SUB_PAIR_COLORS.length]; _ci++;
      if(now) subPairColors[now]=col;
      if(was) subPairColors[was]=col;
      _done.add(id);
      if(pairId) _done.add(pairId); // mutual swap: pair shares this color, skip it next pass
    });
  }

  return (
    <div style={{ height:'100dvh', background:'#0D0D0D', display:'flex', flexDirection:'column', overflow:'hidden' }}>

      {/* ── HERO HEADER ── */}
      <div style={{ flexShrink:0, background:'#111111', borderBottom:'1px solid #1A1A1A' }}>
        <div style={{ display:'flex', alignItems:'center', gap:12, padding:'10px 14px 10px 14px' }}>
          {/* Back */}
          <button onClick={onBack} style={{ background:'none', border:'none', color:'#A1A1A1', fontSize:18, cursor:'pointer', padding:'4px 8px 4px 0', lineHeight:1, flexShrink:0 }}>←</button>
          {/* Badge */}
          <TeamBadge name={myTeam} size={52} radius={10} />
          {/* Name + stats */}
          <div style={{ flex:1, minWidth:0 }}>
            <div style={{ fontSize:9, color:'#A1A1A1', fontWeight:700, letterSpacing:2, textTransform:'uppercase', lineHeight:1, marginBottom:3 }}>YOUR TEAM</div>
            <div style={{ fontSize:18, fontWeight:900, color:'#FFF', lineHeight:1.1, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{myTeam||'My Team'}</div>
            <div style={{ display:'flex', gap:10, marginTop:4 }}>
              <span style={{ fontSize:10, color:'#A1A1A1', fontWeight:600 }}>👥 {squad.length} Players</span>
              <span style={{ fontSize:10, color:'#A1A1A1', fontWeight:600 }}>⚽ {formation}</span>
            </div>
          </div>
          {/* Edit Team */}
          <button onClick={onManageSquad} style={{ background:'rgba(255,255,255,0.08)', border:'1px solid rgba(255,255,255,0.15)', borderRadius:8, color:'#FFF', fontSize:10, fontWeight:700, cursor:'pointer', padding:'6px 10px', flexShrink:0, display:'flex', alignItems:'center', gap:5 }}>
            <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
            Edit Team
          </button>
        </div>
      </div>

      {/* ── TAB BAR ── */}
      <div style={{ display:'flex', background:'#111111', borderBottom:'1px solid #1A1A1A', flexShrink:0 }}>
        {[
          { id:'squad', label:'Line-up', icon:<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg> },
          { id:'stats', label:'Analysis', icon:<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="20" x2="18" y2="10"/><line x1="12" y1="20" x2="12" y2="4"/><line x1="6" y1="20" x2="6" y2="14"/></svg> },
        ].map(t=>{
          const active = pickerTab === t.id;
          return (
            <button key={t.id} onClick={()=>setPickerTab(t.id)} style={{
              flex:1, padding:'10px 4px', background:'none', border:'none',
              borderBottom: active ? '2.5px solid #F5C04A' : '2.5px solid transparent',
              color: active ? '#F5C04A' : '#666',
              fontWeight: active ? 800 : 600, fontSize:11, cursor:'pointer',
              display:'flex', flexDirection:'column', alignItems:'center', gap:3,
              letterSpacing:0.3, textTransform:'uppercase',
            }}>
              {React.cloneElement(t.icon, { stroke: active ? '#F5C04A' : '#666' })}
              {t.label}
            </button>
          );
        })}
      </div>

      {/* ── SQUAD TAB ── */}
      {pickerTab === 'squad' && (
        <div style={{ display:'flex', flexDirection:'column', flex:1, overflow:'hidden' }}>
          {/* Half toggle */}
          <div style={{ display:'flex', background:'#111111', padding:'5px 10px', gap:6, flexShrink:0, borderBottom:'1px solid #1A1A1A' }}>
            {[['H1','First Half'],['H2','Second Half']].map(([label,title],hi)=>(
              <button key={hi} onClick={()=>{setActiveHalf(hi);setActivePeriod(0);setSelectedSlot(null);setSelectedBench(null);}} style={{
                flex:1,padding:'6px 0',border:'none',borderRadius:8,
                background:activeHalf===hi?'#F5C04A':'#1A1A1A',
                color:activeHalf===hi?'#000':'#666',
                fontWeight:800,fontSize:11,cursor:'pointer',
              }}>{label} — {title}</button>
            ))}
          </div>

          {/* Period tabs */}
          <div style={{ display:'flex', background:'#111111', borderBottom:'1px solid #1A1A1A', flexShrink:0 }}>
            {activePeriods.map((_,i)=>{
              const col=PAIR_COLORS[i%PAIR_COLORS.length];
              return (
                <button key={i} onClick={()=>{setActivePeriod(i);setSelectedSlot(null);setSelectedBench(null);}} style={{
                  flex:1,padding:'7px 0',background:'none',border:'none',
                  borderBottom:activePeriod===i?`2.5px solid ${col}`:'2.5px solid transparent',
                  color:activePeriod===i?col:'#555',fontWeight:700,fontSize:12,cursor:'pointer',
                }}>P{i+1}{isPeriodModified(i)?' ✎':''}</button>
              );
            })}
          </div>

          {/* Pitch + Field Players — same height, side by side */}
          <div style={{ display:'flex', flexShrink:0, alignItems:'stretch' }}>

            {/* LEFT — pitch SVG + quick subs + substitutions (52%) */}
            <div style={{ flex:'0 0 52%', minWidth:0, display:'flex', flexDirection:'column' }}>
              <div ref={leftColRef} style={{ flex:'0 0 52%', minWidth:0 }}>
              <svg viewBox="0 0 200 280" xmlns="http://www.w3.org/2000/svg" style={{ width:'100%', display:'block' }}>
                {[0,1,2,3,4,5,6].map(i=>(
                  <rect key={i} x="0" y={i*40} width="200" height="40" fill={i%2===0?'#1e421e':'#1a3a1a'}/>
                ))}
                <rect x="8" y="8" width="184" height="264" rx="3" fill="none" stroke="rgba(255,255,255,0.22)" strokeWidth="1.2"/>
                <line x1="8" y1="140" x2="192" y2="140" stroke="rgba(255,255,255,0.22)" strokeWidth="1"/>
                <circle cx="100" cy="140" r="24" fill="none" stroke="rgba(255,255,255,0.18)" strokeWidth="1"/>
                <circle cx="100" cy="140" r="2" fill="rgba(255,255,255,0.35)"/>
                <rect x="52" y="8" width="96" height="44" fill="none" stroke="rgba(255,255,255,0.18)" strokeWidth="1"/>
                <rect x="72" y="8" width="56" height="22" fill="none" stroke="rgba(255,255,255,0.12)" strokeWidth="1"/>
                <rect x="52" y="228" width="96" height="44" fill="none" stroke="rgba(255,255,255,0.18)" strokeWidth="1"/>
                <rect x="72" y="250" width="56" height="22" fill="none" stroke="rgba(255,255,255,0.12)" strokeWidth="1"/>
                <rect x="80" y="2" width="40" height="10" rx="1" fill="rgba(255,255,255,0.06)" stroke="rgba(255,255,255,0.28)" strokeWidth="1"/>
                <rect x="80" y="268" width="40" height="10" rx="1" fill="rgba(255,255,255,0.06)" stroke="rgba(255,255,255,0.28)" strokeWidth="1"/>
                {positions.map((pos,pidx)=>{
                  const name=curSlots[pos.id]||'';
                  const empty=!name;
                  const isSel=selectedSlot===pos.id;
                  const isBenchTarget=selectedBench&&!isSel;
                  const cx=parseFloat(pos.left)*2;
                  const rawPct=parseFloat(pos.top)/100;
                  let cy;
                  if(pos.id==='gk') cy=252;
                  else if(rawPct<0.15) cy=28;
                  else if(rawPct>0.34&&rawPct<0.56) cy=140;
                  else cy=rawPct*280;
                  const W=30,H=38,lx=cx-W/2,ty=cy-H/2;
                  const initials=name?name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase():'';
                  const _sqP=squad.find(p=>p.name===name);
                  const shortName=name?(_sqP?.nickname||name.split(' ').slice(-1)[0]).slice(0,8):'';
                  return (
                    <g key={pos.id} onClick={()=>{
                      if(selectedBench){assignToSlot(pos.id,selectedBench);setSelectedBench(null);setSelectedSlot(null);}
                      else if(selectedSlot&&selectedSlot!==pos.id){swapPitchSlots(selectedSlot,pos.id);}
                      else{setSelectedSlot(isSel?null:pos.id);setSelectedBench(null);}
                    }} style={{cursor:'pointer'}}>
                      <rect x={lx} y={ty} width={W} height={H} rx="4"
                        fill={isSel?'rgba(245,192,74,0.18)':isBenchTarget?'rgba(34,197,94,0.1)':subPairColors[name]?(subPairColors[name]+'18'):'rgba(18,18,18,0.92)'}
                        stroke={isSel?'#F5C04A':isBenchTarget?'#22c55e':subPairColors[name]||(name?'#3a3a3a':'#2a2a2a')}
                        strokeWidth={isSel||isBenchTarget?1.8:subPairColors[name]?2:1}/>
                      {!empty&&<text x={cx} y={ty+13} textAnchor="middle" fontSize="11" fontWeight="600" fill="#FFF" fontFamily="Outfit,sans-serif">{initials}</text>}
                      {empty&&<text x={cx} y={cy+1} textAnchor="middle" dominantBaseline="middle" fontSize="13" fill="rgba(255,255,255,0.15)" fontFamily="Outfit,sans-serif">+</text>}
                      {!empty&&<text x={cx} y={ty+H-10} textAnchor="middle" fontSize="6" fontWeight="700" fill="rgba(255,255,255,0.85)" fontFamily="Outfit,sans-serif">{shortName}</text>}
                      <text x={cx} y={ty+H-3} textAnchor="middle" fontSize="4" fill={empty?'rgba(255,255,255,0.2)':'rgba(255,255,255,0.45)'} fontFamily="Outfit,sans-serif">{posLbl[pos.id]||pos.id}</text>
                
                      <text x={lx+4} y={ty+9} fontSize="5.5" fontWeight="700" fill={isSel?'#F5C04A':empty?'#444':'rgba(255,255,255,0.45)'} fontFamily="Outfit,sans-serif">{pidx+1}</text>
                    </g>
                  );
                })}
              </svg>
            </div>

              {/* Quick Subs SVG cards */}
              <div style={{ borderTop:'1px solid #1A1A1A', background:'#0D0D0D', padding:'5px 10px 6px', flexShrink:0 }}>
                <div style={{ fontSize:7,fontWeight:800,color:'#666',letterSpacing:1.5,textTransform:'uppercase',marginBottom:2 }}>
                  {selectedSlot?'↑ TAP BENCH PLAYER TO SWAP IN':selectedBench?'↑ TAP FIELD POSITION TO SWAP':'QUICK SUBSTITUTIONS'}
                </div>
                {!selectedSlot && !selectedBench && (
                  <div style={{ fontSize:9,color:'#444',marginBottom:4,fontStyle:'italic' }}>Tap a bench player then a pitch player to substitute</div>
                )}
                <div style={{ display:'flex', gap:4, overflowX:'auto' }}>
                  {bench.length===0 && <span style={{ fontSize:10,color:'#444',fontStyle:'italic',padding:'8px 0' }}>All players on field</span>}
                  {bench.map((n,bidx)=>{
                    const isBSel=selectedBench===n;
                    const init=n.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
                    const _bqP=squad.find(p=>p.name===n);
                    const shortN=(_bqP?.nickname||n.split(' ').slice(-1)[0]).slice(0,8);
                    return (
                      <div key={n} onClick={()=>{
                        if(selectedSlot){assignToSlot(selectedSlot,n);setSelectedSlot(null);setSelectedBench(null);}
                        else{setSelectedBench(isBSel?null:n);setSelectedSlot(null);}
                      }} style={{ flexShrink:0, cursor:'pointer', width:'10vw', maxWidth:46, minWidth:28 }}>
                        <svg viewBox="0 0 30 38" width="100%" style={{ display:'block' }}>
                          <rect x="0" y="0" width="30" height="38" rx="4"
                            fill={isBSel?'rgba(245,192,74,0.18)':subPairColors[n]?(subPairColors[n]+'18'):'rgba(18,18,18,0.92)'}
                            stroke={isBSel?'#F5C04A':subPairColors[n]||'#3a3a3a'}
                            strokeWidth={isBSel?1.8:subPairColors[n]?2:1}/>
                          <text x="15" y="13" textAnchor="middle" fontSize="11" fontWeight="600" fill={isBSel?'#F5C04A':'#FFF'} fontFamily="Outfit,sans-serif">{init}</text>
                          <text x="15" y="28" textAnchor="middle" fontSize="6" fontWeight="700" fill="rgba(255,255,255,0.85)" fontFamily="Outfit,sans-serif">{shortN}</text>
                          <text x="15" y="35" textAnchor="middle" fontSize="4" fill={isBSel?'rgba(245,192,74,0.6)':'rgba(255,255,255,0.35)'} fontFamily="Outfit,sans-serif">BENCH</text>
                
                          <text x="4" y="9" fontSize="5.5" fontWeight="700" fill={isBSel?'#F5C04A':'rgba(255,255,255,0.45)'} fontFamily="Outfit,sans-serif">{bidx+1}</text>
                        </svg>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* Substitutions */}
              {/* ── SUBSTITUTIONS (current period vs previous) ── */}
            {(()=>{
              if(activePeriod === 0) {
                return (
                  <div style={{ borderTop:'1px solid #1A1A1A', padding:'6px 12px 8px', background:'#0D0D0D' }}>
                    <div style={{ fontSize:7,fontWeight:800,color:'#555',letterSpacing:2,textTransform:'uppercase',marginBottom:3 }}>SUBSTITUTIONS</div>
                    <div style={{ fontSize:10,color:'#333',fontStyle:'italic' }}>No substitutions for period 1</div>
                  </div>
                );
              }
              const prev = activePeriods[activePeriod-1];
              const curr = activePeriods[activePeriod];
              const prevLabel = `P${activePeriod}`;
              const currLabel = `P${activePeriod+1}`;
              // Build entries: detect mutual position swaps (show once) vs real subs
              const rawChanges = posIds
                .filter(id=>prev[id]!==curr[id])
                .map(id=>({ id, pos:posLbl[id]||id, on:curr[id]||'', off:prev[id]||'' }));
              const doneIds=new Set();
              const entries=[];
              rawChanges.forEach(c=>{
                if(doneIds.has(c.id)) return;
                const mutual=rawChanges.find(d=>d.id!==c.id&&!doneIds.has(d.id)&&d.on===c.off&&d.off===c.on);
                if(mutual){
                  entries.push({ type:'posSwap', a:c, b:mutual, color:subPairColors[c.on]||subPairColors[c.off] });
                  doneIds.add(c.id); doneIds.add(mutual.id);
                } else {
                  entries.push({ type:'sub', c, color:subPairColors[c.on]||subPairColors[c.off] });
                  doneIds.add(c.id);
                }
              });
              return (
                <div style={{ borderTop:'1px solid #1A1A1A', padding:'6px 12px 8px', background:'#0D0D0D' }}>
                  <div style={{ display:'flex', alignItems:'baseline', gap:6, marginBottom:6 }}>
                    <span style={{ fontSize:7,fontWeight:800,color:'#A1A1A1',letterSpacing:2,textTransform:'uppercase' }}>SUBSTITUTIONS</span>
                    <span style={{ fontSize:9,fontWeight:700,color:'#F5C04A' }}>{prevLabel} → {currLabel}</span>
                  </div>
                  {entries.length === 0 ? (
                    <div style={{ fontSize:10,color:'#333',fontStyle:'italic' }}>No changes from {prevLabel}</div>
                  ) : (
                    <div style={{ display:'flex', flexDirection:'column', gap:4 }}>
                      {entries.map((entry,i)=>{
                        const borderCol = entry.color || '#1A1A1A';
                        if(entry.type==='posSwap'){
                          const {a,b}=entry;
                          const aInit=a.on?a.on.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase():'?';
                          const bInit=b.on?b.on.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase():'?';
                          return (
                            <div key={i} style={{ display:'flex',alignItems:'center',gap:6,background:'#111111',borderRadius:10,padding:'6px 10px',border:`1px solid ${borderCol}44` }}>
                              <div style={{ display:'flex',alignItems:'center',gap:5,flex:1,minWidth:0 }}>
                                <div style={{ width:28,height:28,borderRadius:'50%',background:borderCol+'22',border:`2px solid ${borderCol}`,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                                  <span style={{ fontSize:9,fontWeight:700,color:'#FFF' }}>{aInit}</span>
                                </div>
                                <div style={{ minWidth:0 }}>
                                  <div style={{ fontSize:11,fontWeight:700,color:'#FFF',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{a.on}</div>
                                  <div style={{ fontSize:8,color:'#A1A1A1',lineHeight:1 }}>{a.pos}</div>
                                </div>
                              </div>
                              <svg width="16" height="11" viewBox="0 0 18 12" fill="none" style={{ flexShrink:0, opacity:0.5 }}>
                                <path d="M1 3h16M13 0l4 3-4 3" stroke={borderCol} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                                <path d="M17 9H1M5 6l-4 3 4 3" stroke={borderCol} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                              </svg>
                              <div style={{ display:'flex',alignItems:'center',gap:5,flex:1,minWidth:0,justifyContent:'flex-end' }}>
                                <div style={{ minWidth:0,textAlign:'right' }}>
                                  <div style={{ fontSize:11,fontWeight:700,color:'#FFF',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{b.on}</div>
                                  <div style={{ fontSize:8,color:'#A1A1A1',lineHeight:1 }}>{b.pos}</div>
                                </div>
                                <div style={{ width:28,height:28,borderRadius:'50%',background:borderCol+'22',border:`2px solid ${borderCol}`,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                                  <span style={{ fontSize:9,fontWeight:700,color:'#FFF' }}>{bInit}</span>
                                </div>
                              </div>
                            </div>
                          );
                        }
                        const {c}=entry;
                        const onInit=c.on?c.on.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase():'?';
                        const offInit=c.off?c.off.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase():'?';
                        return (
                          <div key={i} style={{ display:'flex',alignItems:'center',gap:6,background:'#111111',borderRadius:10,padding:'6px 10px',border:`1px solid ${borderCol}44` }}>
                            <div style={{ display:'flex',alignItems:'center',gap:6,flex:1,minWidth:0 }}>
                              <div style={{ width:28,height:28,borderRadius:'50%',background:'#052e16',border:'2px solid #22c55e',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                                <span style={{ fontSize:9,fontWeight:700,color:'#FFF' }}>{onInit}</span>
                              </div>
                              <div style={{ minWidth:0 }}>
                                <div style={{ fontSize:11,fontWeight:700,color:'#22c55e',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{c.on||'Empty'}</div>
                                <div style={{ fontSize:8,color:'#4ade80',lineHeight:1 }}>↑ {c.pos}</div>
                              </div>
                            </div>
                            <svg width="14" height="11" viewBox="0 0 18 14" fill="none" style={{ flexShrink:0,opacity:0.3 }}>
                              <path d="M1 4h16M13 1l4 3-4 3" stroke="#A1A1A1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                              <path d="M17 10H1M5 7l-4 3 4 3" stroke="#A1A1A1" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
                            </svg>
                            <div style={{ display:'flex',alignItems:'center',gap:6,flex:1,minWidth:0,justifyContent:'flex-end' }}>
                              <div style={{ minWidth:0,textAlign:'right' }}>
                                <div style={{ fontSize:11,fontWeight:700,color:'#ef4444',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{c.off||'Empty'}</div>
                                <div style={{ fontSize:8,color:'#f87171',lineHeight:1 }}>{c.pos} ↓</div>
                              </div>
                              <div style={{ width:28,height:28,borderRadius:'50%',background:'#2d0a0a',border:'2px solid #ef4444',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                                <span style={{ fontSize:9,fontWeight:700,color:'#FFF' }}>{offInit}</span>
                              </div>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  )}
                </div>
              );
            })()}

            </div>

            {/* RIGHT — Pitch players + Bench merged, scrollable */}
            <div style={{ flex:'0 0 48%', minWidth:0, display:'flex', flexDirection:'column', background:'#0D0D0D', borderLeft:'1px solid #1A1A1A', overflowY:'auto' }}>
              {/* Pitch section header */}
              <div style={{ padding:'5px 10px 4px', borderBottom:'1px solid #111', background:'#080808', flexShrink:0 }}>
                <div style={{ fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase' }}>PITCH · {assigned.length}/{positions.length}</div>
              </div>
              {/* Merged scrollable list */}
              <div style={{ flex:1, overflowY:'auto' }}>
                {/* ── Pitch rows ── */}
                {positions.map((pos,pidx)=>{
                  const name=curSlots[pos.id]||'';
                  const isSel=selectedSlot===pos.id;
                  const initials2=name?name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase():'?';
                  const p=squad.find(s=>s.name===name);
                  return (
                    <div key={pos.id} onClick={()=>{
                      if(selectedBench&&name){assignToSlot(pos.id,selectedBench);setSelectedBench(null);setSelectedSlot(null);}
                      else if(selectedBench&&!name){assignToSlot(pos.id,selectedBench);setSelectedBench(null);}
                      else if(selectedSlot&&selectedSlot!==pos.id){swapPitchSlots(selectedSlot,pos.id);}
                      else{setSelectedSlot(isSel?null:pos.id);setSelectedBench(null);}
                    }} style={{
                      display:'flex',alignItems:'center',gap:7,padding:'0 10px',height:34,
                      borderBottom:'1px solid #111',cursor:'pointer',
                      background:isSel?'rgba(245,192,74,0.08)':selectedBench&&name?'rgba(34,197,94,0.05)':name&&subPairColors[name]?(subPairColors[name]+'11'):'transparent',
                      borderLeft:name&&subPairColors[name]?`3px solid ${subPairColors[name]}`:'3px solid transparent',
                    }}>
                      <span style={{ fontSize:10,color:'#555',fontWeight:700,minWidth:16,textAlign:'right' }}>{pidx+1}</span>
                      <div style={{ width:28,height:28,borderRadius:'50%',background:name?'#1A1A1A':'#0a0a0a',border:`1px solid ${isSel?'#F5C04A':'#2A2A2A'}`,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                        <span style={{ fontSize:8,fontWeight:600,color:name?'#FFF':'#333' }}>{initials2}</span>
                      </div>
                      <div style={{ flex:1,minWidth:0 }}>
                        <div style={{ fontSize:11,fontWeight:700,color:name?'#FFF':'#444',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{name||posLbl[pos.id]||pos.id}</div>
                        <div style={{ fontSize:9,color:'#555' }}>{posLbl[pos.id]||pos.id}</div>
                      </div>
                      {(()=>{
                        if(!name) return <div style={{width:7,height:7,borderRadius:'50%',background:'#2A2A2A',flexShrink:0}}/>;
                        const _h1On=h1Periods.map((s,i)=>posIds.some(id=>s[id]===name)?i:-1).filter(i=>i>=0);
                        const _h2On=h2Periods.map((s,i)=>posIds.some(id=>s[id]===name)?i:-1).filter(i=>i>=0);
                        const _bar=(onIdx,periods)=>periods.map((_,i)=>{const on=onIdx.includes(i);const sub=on&&!onIdx.includes(i-1)&&i>0;return <div key={i} style={{width:9,height:9,borderRadius:2,background:!on?'#1A1A1A':sub?'#3b82f6':'#22c55e'}}/>;});
                        return (<div style={{display:'flex',gap:4,alignItems:'flex-end',flexShrink:0}}>
                          <div><div style={{fontSize:6,color:'#555',fontWeight:700,marginBottom:2,textAlign:'center'}}>1H</div><div style={{display:'flex',gap:1.5}}>{_bar(_h1On,h1Periods)}</div></div>
                          <div><div style={{fontSize:6,color:'#555',fontWeight:700,marginBottom:2,textAlign:'center'}}>2H</div><div style={{display:'flex',gap:1.5}}>{_bar(_h2On,h2Periods)}</div></div>
                          <button onClick={e=>{e.stopPropagation();onViewStats(name);}} style={{background:'none',border:'none',cursor:'pointer',padding:'2px 4px',color:'#555',fontSize:14,lineHeight:1,display:'flex',alignItems:'center'}}>›</button>
                        </div>);
                      })()}
                    </div>
                  );
                })}
                {/* ── Bench heading (same format as Pitch) ── */}
                <div style={{ padding:'5px 10px 4px', borderBottom:'1px solid #111', borderTop:'1px solid #1A1A1A', background:'#080808', flexShrink:0 }}>
                  <div style={{ fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase' }}>BENCH · {bench.length}</div>
                </div>
                {/* ── Bench rows ── */}
                {bench.length===0
                  ? <div style={{ padding:'8px 10px',fontSize:10,color:'#444',fontStyle:'italic' }}>All players on field</div>
                  : bench.map((n,bidx)=>{
                      const isBSel=selectedBench===n;
                      const init=n.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
                      const pb=squad.find(s=>s.name===n);
                      const posDisplay=pb?[pb.pos,pb.pos2,pb.pos3].filter(Boolean).join(' / '):'';
                      return (
                        <div key={n} onClick={()=>{
                          if(selectedSlot){assignToSlot(selectedSlot,n);setSelectedSlot(null);setSelectedBench(null);}
                          else{setSelectedBench(isBSel?null:n);setSelectedSlot(null);}
                        }} style={{
                          display:'flex',alignItems:'center',gap:7,padding:'0 10px',height:34,
                          borderBottom:'1px solid #111',cursor:'pointer',
                          background:isBSel?'rgba(245,192,74,0.08)':subPairColors[n]?(subPairColors[n]+'11'):'transparent',
                          borderLeft:subPairColors[n]?`3px solid ${subPairColors[n]}`:'3px solid transparent',
                        }}>
                          <span style={{ fontSize:10,color:'#555',fontWeight:700,minWidth:16,textAlign:'right' }}>{bidx+1}</span>
                          <div style={{ width:28,height:28,borderRadius:'50%',background:'#1A1A1A',border:`1px solid ${isBSel?'#F5C04A':'#2A2A2A'}`,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                            <span style={{ fontSize:8,fontWeight:600,color:isBSel?'#F5C04A':'#FFF' }}>{init}</span>
                          </div>
                          <div style={{ flex:1,minWidth:0 }}>
                            <div style={{ fontSize:11,fontWeight:700,color:isBSel?'#F5C04A':'#FFF',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{n}</div>
                            {posDisplay&&<div style={{ fontSize:9,color:'#555',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{posDisplay}</div>}
                          </div>
                          {(()=>{
                            const _h1On=h1Periods.map((s,i)=>posIds.some(id=>s[id]===n)?i:-1).filter(i=>i>=0);
                            const _h2On=h2Periods.map((s,i)=>posIds.some(id=>s[id]===n)?i:-1).filter(i=>i>=0);
                            const _bar=(onIdx,periods)=>periods.map((_,i)=>{const on=onIdx.includes(i);const sub=on&&!onIdx.includes(i-1)&&i>0;return <div key={i} style={{width:9,height:9,borderRadius:2,background:!on?'#1A1A1A':sub?'#3b82f6':'#22c55e'}}/>;});
                            return (<div style={{display:'flex',gap:4,alignItems:'flex-end',flexShrink:0}}>
                              <div><div style={{fontSize:6,color:'#555',fontWeight:700,marginBottom:2,textAlign:'center'}}>1H</div><div style={{display:'flex',gap:1.5}}>{_bar(_h1On,h1Periods)}</div></div>
                              <div><div style={{fontSize:6,color:'#555',fontWeight:700,marginBottom:2,textAlign:'center'}}>2H</div><div style={{display:'flex',gap:1.5}}>{_bar(_h2On,h2Periods)}</div></div>
                              <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#555" strokeWidth="2.5" style={{flexShrink:0}}><polyline points="9 18 15 12 9 6"/></svg>
                            </div>);
                          })()}
                        </div>
                      );
                    })
                }
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── SCOUT TAB ── */}
        {/* ── PLAYER STATS TAB ── */}
        {pickerTab === 'player-stats' && (() => {
          const games = (() => { try { return JSON.parse(localStorage.getItem('soccerCoach_games')||'[]'); } catch { return []; } })();
          return (
            <div style={{ flex:1, overflowY:'auto', padding:'14px' }}>
              <div style={{ fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:2,textTransform:'uppercase',marginBottom:12 }}>SELECT PLAYER</div>
              <div style={{ display:'flex', flexDirection:'column', gap:8 }}>
                {squad.map(p => {
                  const initials = p.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
                  const stats = (() => {
                    let apps=0, goals=0, mins=0;
                    games.forEach(g => {
                      if(!g.halves) return;
                      const allSlots = [...(g.halves.half1||[]), ...(g.halves.half2||[])];
                      const onCount = allSlots.filter(s=>Object.values(s).includes(p.name)).length;
                      if(onCount>0){ apps++; mins+=onCount*(g.config?.periodMins||15); }
                      (g.events||[]).forEach(e=>{ if(e.type==='goal'&&e.player===p.name) goals++; });
                    });
                    return { apps, goals, mins };
                  })();
                  return (
                    <div key={p.name} onClick={()=>onViewPlayerStats&&onViewPlayerStats(p.name)}
                      style={{ display:'flex',alignItems:'center',gap:12,padding:'12px 14px',background:'#111111',borderRadius:12,border:'1px solid #1A1A1A',cursor:'pointer',WebkitTapHighlightColor:'transparent' }}>
                      <div style={{ width:40,height:40,borderRadius:10,background:'#1A1A1A',border:'1.5px solid #2A2A2A',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                        <span style={{ fontSize:13,fontWeight:800,color:'#F5C04A' }}>{initials}</span>
                      </div>
                      <div style={{ flex:1,minWidth:0 }}>
                        <div style={{ fontSize:13,fontWeight:700,color:'#FFF',marginBottom:2 }}>{p.name}</div>
                        <div style={{ fontSize:10,color:'#A1A1A1' }}>{[p.pos,p.pos2,p.pos3].filter(Boolean).join(' · ')||'No position set'}</div>
                      </div>
                      <div style={{ display:'flex',gap:16,flexShrink:0 }}>
                        <div style={{ textAlign:'center' }}>
                          <div style={{ fontSize:14,fontWeight:800,color:'#F5C04A' }}>{stats.apps}</div>
                          <div style={{ fontSize:8,color:'#555',fontWeight:600 }}>APPS</div>
                        </div>
                        <div style={{ textAlign:'center' }}>
                          <div style={{ fontSize:14,fontWeight:800,color:'#FFF' }}>{stats.goals}</div>
                          <div style={{ fontSize:8,color:'#555',fontWeight:600 }}>GLS</div>
                        </div>
                        <div style={{ textAlign:'center' }}>
                          <div style={{ fontSize:14,fontWeight:800,color:'#FFF' }}>{stats.mins}'</div>
                          <div style={{ fontSize:8,color:'#555',fontWeight:600 }}>MINS</div>
                        </div>
                      </div>
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#555" strokeWidth="2"><polyline points="9 18 15 12 9 6"/></svg>
                    </div>
                  );
                })}
                {squad.length===0 && (
                  <div style={{ textAlign:'center',padding:'40px 20px',color:'#555' }}>
                    <div style={{ fontSize:13,marginBottom:8 }}>No players in squad</div>
                    <div style={{ fontSize:11 }}>Add players in the Squad tab</div>
                  </div>
                )}
              </div>
            </div>
          );
        })()}


      {pickerTab === 'scout' && (
        <div style={{ flex:1, overflowY:'auto', padding:'14px' }}>
          <div style={{ background:'#111111', borderRadius:12, padding:'16px', border:'1px solid #1A1A1A', marginBottom:14 }}>
            <div style={{ fontSize:9, fontWeight:800, color:'#A1A1A1', letterSpacing:1.5, textTransform:'uppercase', marginBottom:10 }}>⚔️ OPPONENT</div>
            <div style={{ display:'flex', gap:8, alignItems:'center', marginBottom:12 }}>
              <TeamBadge name={opponent||'?'} size={36} radius={8} />
              <div style={{ flex:1, minWidth:0 }}>
                {!customOpp ? (
                  <select value={oppInList?opponent:'__custom__'} onChange={e=>{
                    if(e.target.value==='__custom__'){setCustomOpp(true);setOpponent('');}
                    else setOpponent(e.target.value);
                  }} style={{...selStyle, width:'100%', padding:'8px 10px', fontSize:13}}>
                    <option value="" disabled>— Select opponent —</option>
                    {(()=>{const nf=FIXTURES.find(f=>(f.home===myTeam||f.away===myTeam)&&isUpcoming(f));const sug=nf?(nf.home===myTeam?nf.away:nf.home):'';return sug?<option value={sug}>📅 {sug} (next fixture)</option>:null;})()}
                    <option value="__custom__">✏️ Custom…</option>
                    {allTeams.map(t=><option key={t} value={t}>{t}</option>)}
                  </select>
                ) : (
                  <div style={{ display:'flex', gap:6 }}>
                    <input autoFocus style={{...selStyle,flex:1,padding:'8px 10px',fontSize:13,outline:'none'}} placeholder="Type opponent name…" value={opponent} onChange={e=>setOpponent(e.target.value)} />
                    <button onClick={()=>setCustomOpp(false)} style={{ background:'#2A2A2A', border:'none', borderRadius:8, color:'#A1A1A1', padding:'8px 12px', cursor:'pointer', fontSize:12 }}>List</button>
                  </div>
                )}
              </div>
            </div>
            {opponent&&onViewOpponent&&(
              <button onClick={()=>onViewOpponent(opponent)} style={{ width:'100%', background:'#1A1400', border:'1px solid #F5C04A44', borderRadius:8, padding:'10px', color:'#F5C04A', fontSize:12, fontWeight:700, cursor:'pointer' }}>🔍 View Scout Report for {opponent}</button>
            )}
          </div>
          {(()=>{
            const upcoming = FIXTURES.filter(f=>(f.home===myTeam||f.away===myTeam)&&isUpcoming(f)).slice(0,3);
            if(!upcoming.length) return null;
            return (
              <div style={{ background:'#111111', borderRadius:12, padding:'14px', border:'1px solid #1A1A1A' }}>
                <div style={{ fontSize:9, fontWeight:800, color:'#A1A1A1', letterSpacing:1.5, textTransform:'uppercase', marginBottom:10 }}>📅 UPCOMING FIXTURES</div>
                {upcoming.map((f,i)=>{
                  const isHome = f.home===myTeam;
                  const opp = isHome ? f.away : f.home;
                  return (
                    <div key={i} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom: i<upcoming.length-1?'1px solid #1A1A1A':'none' }}>
                      <TeamBadge name={opp} size={28} radius={6} />
                      <div style={{ flex:1 }}>
                        <div style={{ fontSize:12, fontWeight:700, color:'#FFF' }}>{isHome?'vs':'@'} {opp}</div>
                        <div style={{ fontSize:10, color:'#A1A1A1' }}>{f.date} · {f.time}</div>
                      </div>
                      <button onClick={()=>{setOpponent(opp);setPickerTab('squad');}} style={{ background:'#F5C04A22', border:'1px solid #F5C04A44', borderRadius:7, padding:'5px 10px', color:'#F5C04A', fontSize:10, fontWeight:700, cursor:'pointer' }}>Set →</button>
                    </div>
                  );
                })}
              </div>
            );
          })()}
        </div>
      )}

      {/* ── SETTINGS TAB ── */}
      {pickerTab === 'settings' && (
        <div style={{ flex:1, overflowY:'auto', padding:'14px 14px' }}>
          <div style={{ background:'#111111', borderRadius:12, padding:'14px', border:'1px solid #1A1A1A' }}>
            <div style={{ fontSize:9, fontWeight:800, color:'#A1A1A1', letterSpacing:1.5, textTransform:'uppercase', marginBottom:12 }}>⚙️ MATCH SETTINGS</div>
            <div style={{ display:'flex', flexDirection:'column', gap:12 }}>

              {/* Formation */}
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:8 }}>
                <span style={{ fontSize:13, color:'#A1A1A1', minWidth:100 }}>Formation</span>
                <select style={{...selStyle,flex:1,maxWidth:180}} value={formation} onChange={e=>updCfg('formation',e.target.value)}>
                  {Object.keys(FORMATIONS).map(f=><option key={f} value={f}>{f}</option>)}
                </select>
              </div>
              {/* Half length */}
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:8 }}>
                <span style={{ fontSize:13, color:'#A1A1A1', minWidth:100 }}>Half length</span>
                <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                  <button style={stepBtn} onClick={()=>updCfg('halfMins',Math.max(5,config.halfMins-5))}>−</button>
                  <span style={{ fontSize:14, fontWeight:700, color:'#FFF', minWidth:60, textAlign:'center' }}>{config.halfMins||24} min</span>
                  <button style={stepBtn} onClick={()=>updCfg('halfMins',Math.min(60,config.halfMins+5))}>+</button>
                </div>
              </div>
              {/* Periods / half */}
              <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:8 }}>
                <span style={{ fontSize:13, color:'#A1A1A1', minWidth:100 }}>Periods / half</span>
                <div style={{ display:'flex', alignItems:'center', gap:10 }}>
                  <button style={stepBtn} onClick={()=>updCfg('numPeriods',Math.max(1,(config.numPeriods||3)-1))}>−</button>
                  <span style={{ fontSize:14, fontWeight:700, color:'#FFF', minWidth:28, textAlign:'center' }}>{config.numPeriods||3}</span>
                  <button style={stepBtn} onClick={()=>updCfg('numPeriods',Math.min(6,(config.numPeriods||3)+1))}>+</button>
                </div>
              </div>
              <div style={{ fontSize:11, color:'#F5C04A', fontWeight:700, textAlign:'center', marginTop:2 }}>= {pmDisplay} min per period</div>
            </div>
          </div>
        </div>
      )}

      {/* ── STATS TAB (Analysis) ── */}
      {pickerTab === 'stats' && (()=>{
        const halfMins   = config.halfMins   || 24;
        const numP       = config.numPeriods || 3;
        const periodMins = getPeriodMins(config);
        const gameTotal  = halfMins * 2; // total game minutes

        // Target band: 75–85 %
        const TARGET_LO = 0.75, TARGET_HI = 0.85;

        // Per-player stats
        const playerRows = squad.map(p => {
          // Which periods in H1 / H2 is this player on the pitch?
          const h1On = h1Periods.map((slots,i) => posIds.some(id => slots[id]===p.name) ? i : -1).filter(i=>i>=0);
          const h2On = h2Periods.map((slots,i) => posIds.some(id => slots[id]===p.name) ? i : -1).filter(i=>i>=0);
          const totalMins  = (h1On.length + h2On.length) * periodMins;
          const pctGame    = gameTotal > 0 ? totalMins / gameTotal : 0;
          const isStarter  = h1On.includes(0);
          const subIn      = !isStarter && (h1On.length > 0 || h2On.length > 0);
          // Determine status
          let status = 'dnp'; // did not play
          if(totalMins > 0) {
            if(pctGame > TARGET_HI + 0.01)      status = 'over';
            else if(pctGame < TARGET_LO - 0.01) status = 'under';
            else                                  status = 'ok';
          }
          // Position from squad or formation slot
          const posLabel = [p.pos, p.pos2, p.pos3].filter(Boolean)[0] || '—';
          // Positions actually played in this lineup (formation slot IDs, uppercased)
          const playedPosIds = [...new Set([
            ...h1Periods.flatMap(slots => posIds.filter(id => slots[id]===p.name)),
            ...h2Periods.flatMap(slots => posIds.filter(id => slots[id]===p.name)),
          ])];
          const playedPosAbbr = playedPosIds.map(id => id.toUpperCase()).join('/');
          return { ...p, h1On, h2On, totalMins: Math.round(totalMins), pctGame, isStarter, subIn, status, posLabel, playedPosAbbr,
            initials: p.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase() };
        });

        const played    = playerRows.filter(p=>p.totalMins>0);
        const dnp       = playerRows.filter(p=>p.totalMins===0);
        const overplayed  = played.filter(p=>p.status==='over').length;
        const underplayed = played.filter(p=>p.status==='under').length;
        const totalPlayerMins = playerRows.reduce((s,p)=>s+p.totalMins,0);
        const avgPct = played.length > 0 ? played.reduce((s,p)=>s+p.pctGame,0)/played.length : 0;

        // Sort: starters first (by totalMins desc), then subs, then DNP
        const sortedPlayed = [...played].sort((a,b)=>b.totalMins-a.totalMins||b.isStarter-a.isStarter);

        // Gauge circle params
        const R=28, CIRC=2*Math.PI*R;
        const gaugePct = Math.min(avgPct, 1);

        // Insight flags
        const onTarget = played.filter(p=>p.status==='ok').length;
        const insights = [];
        // Always show all three status categories
        insights.push({ color:'#22c55e', icon:'✓', title:'On Target',
          body: onTarget > 0
            ? `${onTarget} player${onTarget!==1?'s are':' is'} within the ${Math.round(TARGET_LO*100)}–${Math.round(TARGET_HI*100)}% target range.`
            : `No players are within the ${Math.round(TARGET_LO*100)}–${Math.round(TARGET_HI*100)}% target range yet.` });
        insights.push({ color:'#ef4444', icon:'↓', title:'Overplayed',
          body: overplayed > 0
            ? `${overplayed} player${overplayed>1?'s have':' has'} played over ${Math.round(TARGET_HI*100)}% of the game — consider rotating them out.`
            : 'No players have exceeded the maximum playing time.' });
        insights.push({ color:'#f59e0b', icon:'!', title:'Underplayed',
          body: underplayed > 0
            ? `${underplayed} player${underplayed>1?'s have':' has'} played less than ${Math.round(TARGET_LO*100)}% of the game — try to get them more time.`
            : 'All active players have met the minimum playing time.' });
        if(dnp.length>0)
          insights.push({ color:'#6b7280', icon:'–', title:'Players Unused', body:`${dnp.length} player${dnp.length>1?'s':''} did not feature in the planned lineup.` });

        // Bar segment helper: returns array of {width%, color, label} for a half
        const halfBar = (onPeriods, half) => {
          const periods = half===0 ? h1Periods : h2Periods;
          return periods.map((_, i) => {
            const on = onPeriods.includes(i);
            let color = '#2A2A2A';
            if(on) color = i===0 && half===0 ? '#22c55e' : '#22c55e'; // starter always green
            // sub-in: first period on after a gap
            const subIn = on && !onPeriods.includes(i-1) && i>0;
            if(subIn) color = '#3b82f6';
            return { on, color, subIn, mins: Math.round(periodMins) };
          });
        };

        const statusIcon = (status) => {
          if(status==='ok')    return { icon:'✓', color:'#22c55e' };
          if(status==='over')  return { icon:'↓', color:'#ef4444', bg:'#2d0a0a' };
          if(status==='under') return { icon:'!', color:'#f59e0b', bg:'#2d1a00' };
          return { icon:'–', color:'#6b7280' };
        };

        const PlayerRow = ({p, idx}) => {
          const h1segs = halfBar(p.h1On, 0);
          const h2segs = halfBar(p.h2On, 1);
          const si = statusIcon(p.status);
          const pctTxt = Math.round(p.pctGame*100)+'%';
          const isOver  = p.status==='over';
          const isUnder = p.status==='under';
          return (
            <div style={{ display:'flex', alignItems:'center', gap:6, padding:'8px 10px',
              borderTop: idx>0?'1px solid #111':'none',
              background: idx%2===0?'transparent':'rgba(255,255,255,0.01)' }}>
              {/* # */}
              <div style={{ width:18, fontSize:9, fontWeight:700, color:'#555', textAlign:'right', flexShrink:0 }}>{idx+1}</div>
              {/* Avatar */}
              <div style={{ width:28,height:28,borderRadius:8,background:'#1A1A1A',border:'1px solid #2A2A2A',
                display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0 }}>
                <span style={{ fontSize:9,fontWeight:700,color:'#FFF' }}>{p.initials}</span>
              </div>
              {/* Name + pos */}
              <div style={{ flex:1, minWidth:0 }}>
                <div style={{ fontSize:11,fontWeight:700,color:'#FFF',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap' }}>{p.name}</div>
              </div>
              {/* Pos badge */}
              <div style={{ fontSize:8,fontWeight:700,color:'#A1A1A1',width:24,flexShrink:0,textAlign:'center',lineHeight:1.2 }}>{p.playedPosAbbr||p.posLabel}</div>
              {/* H1 bar */}
              <div style={{ width:60, display:'flex', gap:1, flexShrink:0, alignItems:'center' }}>
                {h1segs.length===0 ? <div style={{ flex:1, height:10, borderRadius:3, background:'#1A1A1A' }}/> :
                  h1segs.map((seg,si2)=>(
                    <div key={si2} style={{ flex:1, height:10, borderRadius:2,
                      background: seg.on ? (seg.subIn?'#3b82f6':'#22c55e') : '#1A1A1A' }}>
                    </div>
                  ))
                }
              </div>
              {/* H2 bar */}
              <div style={{ width:60, display:'flex', gap:1, flexShrink:0, alignItems:'center' }}>
                {h2segs.length===0 ? <div style={{ flex:1, height:10, borderRadius:3, background:'#1A1A1A' }}/> :
                  h2segs.map((seg,si2)=>(
                    <div key={si2} style={{ flex:1, height:10, borderRadius:2,
                      background: seg.on ? (seg.subIn?'#3b82f6':'#22c55e') : '#1A1A1A' }}>
                    </div>
                  ))
                }
              </div>
              {/* Total */}
              <div style={{ width:28, fontSize:10, fontWeight:700, color:'#FFF', textAlign:'right', flexShrink:0 }}>{p.totalMins}'</div>
              {/* % */}
              <div style={{ width:32, fontSize:10, fontWeight:700, flexShrink:0, textAlign:'right',
                color: isOver?'#ef4444':isUnder?'#f59e0b':'#A1A1A1' }}>{pctTxt}</div>
              {/* Status icon */}
              <div style={{ width:18, flexShrink:0, display:'flex', alignItems:'center', justifyContent:'center' }}>
                {p.status==='dnp' ? <div style={{ width:10,height:10,borderRadius:'50%',background:'#2A2A2A' }}/> :
                  <div style={{ width:18,height:18,borderRadius:'50%',
                    background:si.bg||si.color+'22',
                    border:`1.5px solid ${si.color}`,
                    display:'flex',alignItems:'center',justifyContent:'center' }}>
                    <span style={{ fontSize:8,fontWeight:800,color:si.color }}>{si.icon}</span>
                  </div>
                }
              </div>
            </div>
          );
        };

        return (
          <div style={{ flex:1, overflowY:'auto', background:'#0D0D0D' }}>

            {/* ── TEAM OVERVIEW ── */}
            <div style={{ margin:'10px 10px 0', background:'#111111', borderRadius:12, border:'1px solid #1A1A1A', padding:'12px 10px' }}>
              <div style={{ fontSize:8,fontWeight:800,color:'#A1A1A1',letterSpacing:2,textTransform:'uppercase',marginBottom:10 }}>TEAM OVERVIEW</div>
              <div style={{ display:'flex', alignItems:'center', gap:8 }}>
                {/* Gauge */}
                <div style={{ flexShrink:0, position:'relative', width:56, height:56, display:'flex', alignItems:'center', justifyContent:'center' }}>
                  <svg width="56" height="56" viewBox="0 0 70 70">
                    <circle cx="35" cy="35" r={R} fill="none" stroke="#1A1A1A" strokeWidth="6"/>
                    <circle cx="35" cy="35" r={R} fill="none" stroke="#22c55e" strokeWidth="6"
                      strokeDasharray={CIRC} strokeDashoffset={CIRC*(1-gaugePct)}
                      strokeLinecap="round" transform="rotate(-90 35 35)"/>
                  </svg>
                  <div style={{ position:'absolute', textAlign:'center' }}>
                    <div style={{ fontSize:11,fontWeight:800,color:'#FFF',lineHeight:1 }}>{Math.round(avgPct*100)}%</div>
                  </div>
                </div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:10,fontWeight:700,color:'#FFF' }}>Avg. Playing Time</div>
                  <div style={{ fontSize:8,color:'#A1A1A1' }}>Target: {Math.round(TARGET_LO*100)}–{Math.round(TARGET_HI*100)}%</div>
                </div>
                {/* KPI tiles */}
                <div style={{ display:'flex', gap:6 }}>
                  {[
                    { val:`${played.length}/${squad.length}`, lbl:'Players\nUsed', col:'#FFF' },
                    { val:overplayed,  lbl:'Overplayed',  col: overplayed>0?'#ef4444':'#FFF' },
                    { val:underplayed, lbl:'Underplayed', col: underplayed>0?'#f59e0b':'#FFF' },
                    { val:totalPlayerMins, lbl:'Total Mins', col:'#FFF' },
                  ].map((k,ki)=>(
                    <div key={ki} style={{ background:'#0D0D0D', borderRadius:8, padding:'6px 8px', textAlign:'center', border:'1px solid #1A1A1A', minWidth:38 }}>
                      <div style={{ fontSize:14,fontWeight:800,color:k.col,lineHeight:1 }}>{k.val}</div>
                      <div style={{ fontSize:7,color:'#555',lineHeight:1.2,marginTop:2,whiteSpace:'pre-line' }}>{k.lbl}</div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* ── PLAYER MINUTES ── */}
            <div style={{ margin:'8px 10px 0', background:'#111111', borderRadius:12, border:'1px solid #1A1A1A', overflow:'hidden' }}>
              {/* Table header */}
              <div style={{ padding:'8px 10px 4px', borderBottom:'1px solid #1A1A1A' }}>
                <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:6 }}>
                  <span style={{ fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:2,textTransform:'uppercase' }}>PLAYER MINUTES</span>
                  <span style={{ fontSize:7,color:'#555' }}>Target {Math.round(TARGET_LO*100)}–{Math.round(TARGET_HI*100)}%</span>
                </div>
                {/* Legend */}
                <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
                  {[['#22c55e','Starter'],['#3b82f6','Sub In'],['#1A1A1A','Did Not Play']].map(([c,l])=>(
                    <div key={l} style={{ display:'flex', alignItems:'center', gap:3 }}>
                      <div style={{ width:10,height:6,borderRadius:2,background:c,border:c==='#1A1A1A'?'1px solid #333':'none' }}/>
                      <span style={{ fontSize:7,color:'#A1A1A1' }}>{l}</span>
                    </div>
                  ))}
                </div>
              </div>
              {/* Column headers */}
              <div style={{ display:'flex', alignItems:'center', gap:6, padding:'4px 10px', background:'#0D0D0D' }}>
                <div style={{ width:18 }}/>
                <div style={{ width:28 }}/>
                <div style={{ flex:1, fontSize:7,fontWeight:700,color:'#555',textTransform:'uppercase' }}>Player</div>
                <div style={{ width:24, fontSize:7,fontWeight:700,color:'#555',textAlign:'center' }}>Pos</div>
                <div style={{ width:60, fontSize:7,fontWeight:700,color:'#555',textAlign:'center' }}>1st Half</div>
                <div style={{ width:60, fontSize:7,fontWeight:700,color:'#555',textAlign:'center' }}>2nd Half</div>
                <div style={{ width:28, fontSize:7,fontWeight:700,color:'#555',textAlign:'right' }}>Total</div>
                <div style={{ width:32, fontSize:7,fontWeight:700,color:'#555',textAlign:'right' }}>%</div>
                <div style={{ width:18 }}/>
              </div>
              {/* Player rows */}
              {sortedPlayed.length===0 ? (
                <div style={{ padding:'20px', textAlign:'center', color:'#333', fontSize:11, fontStyle:'italic' }}>
                  Assign players to periods to see analysis
                </div>
              ) : sortedPlayed.map((p,i)=><PlayerRow key={p.name} p={p} idx={i}/>)}
            </div>

            {/* ── DID NOT PLAY ── */}
            {dnp.length > 0 && (
              <div style={{ margin:'8px 10px 0', background:'#111111', borderRadius:12, border:'1px solid #1A1A1A', overflow:'hidden' }}>
                <div style={{ padding:'8px 10px 4px', borderBottom:'1px solid #1A1A1A' }}>
                  <span style={{ fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:2,textTransform:'uppercase' }}>DID NOT PLAY</span>
                </div>
                {dnp.map((p,i)=><PlayerRow key={p.name} p={p} idx={i}/>)}
              </div>
            )}

            {/* ── INSIGHTS ── */}
            {insights.length > 0 && (
              <div style={{ margin:'8px 10px 10px', background:'#111111', borderRadius:12, border:'1px solid #1A1A1A', padding:'10px' }}>
                <div style={{ fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:2,textTransform:'uppercase',marginBottom:8 }}>INSIGHTS</div>
                <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
                  {insights.map((ins,ii)=>(
                    <div key={ii} style={{ display:'flex', alignItems:'flex-start', gap:8, background:'#0D0D0D', borderRadius:8, padding:'8px 10px', border:`1px solid ${ins.color}33` }}>
                      <div style={{ width:22,height:22,borderRadius:'50%',background:ins.color+'22',border:`1.5px solid ${ins.color}`,
                        display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,marginTop:1 }}>
                        <span style={{ fontSize:10,fontWeight:800,color:ins.color }}>{ins.icon}</span>
                      </div>
                      <div>
                        <div style={{ fontSize:11,fontWeight:700,color:ins.color,marginBottom:2 }}>{ins.title}</div>
                        <div style={{ fontSize:10,color:'#A1A1A1',lineHeight:1.4 }}>{ins.body}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

          </div>
        );
      })()}

      {/* ── SAVE LINE-UP footer ── */}
      <div style={{ padding:'10px 12px', paddingBottom:'calc(68px + max(env(safe-area-inset-bottom), 0px))', background:'#111111', borderTop:'1px solid #1A1A1A', flexShrink:0 }}>
        <button disabled={!canStart()} onClick={()=>{
          const _lfk=linkedFix?fixtureKey(linkedFix):null;
          const _fih=linkedFix?linkedFix.home===myTeam:null;
          const _ld={h1Periods,h2Periods,config,opponent,linkedFixKey:_lfk,fixIsHome:_fih,savedAt:Date.now()};
          saveSavedLineup(_ld);
          saveContextData(contextKey,{lineup:_ld});
          if(onSave) onSave(); else if(onBack) onBack();
        }}
          style={{ width:'100%', padding:'15px', border:'none', borderRadius:12, fontSize:14, fontWeight:800, letterSpacing:0.3, cursor:canStart()?'pointer':'default',
            background:canStart()?'#22c55e':'#1A1A1A', color:canStart()?'#000':'#444', transition:'background 0.2s' }}>
          {canStart() ? '✓ Save Line-up' : 'Assign all positions to save'}
        </button>
      </div>
    </div>
  );
}


function Token({ name, color, selected, onTap, onDragStart }) {
  const bg=color||(selected?"#7c3aed":"#1E1E1E");
  return (
    <div draggable={!!onDragStart} onDragStart={onDragStart} onClick={onTap}
      style={{...S.token,background:bg,boxShadow:selected?"0 0 0 3px #a78bfa":color?`0 0 0 2.5px ${color}`:"none",transform:selected?"scale(1.1)":"none",cursor:"pointer"}}>
      {name}
    </div>
  );
}

// ── Goal Modal ────────────────────────────────────────────────────────────────
function GoalModal({ squad, slots, posIds, posLabel, onLog, onClose }) {
  const [scorer, setScorer] = useState("");
  const posOf=(name)=>{ const id=posIds.find(id=>slots[id]===name); return id?posLabel[id]:"Bench"; };
  return (
    <div style={S.modalBack} onClick={onClose}>
      <div style={S.modalBox} onClick={e=>e.stopPropagation()}>
        <div style={S.modalTitle}>⚽ Log Our Goal</div>
        <div style={S.modalLbl}>Scorer</div>
        <select style={S.sel} value={scorer} onChange={e=>setScorer(e.target.value)}>
          <option value="">— select player —</option>
          {squad.map(p=><option key={p.name} value={p.name}>{p.name}</option>)}
        </select>
        {scorer&&<div style={{fontSize:12,color:"#06b6d4",marginTop:2}}>Position: {posOf(scorer)}</div>}
        <div style={{display:"flex",gap:8,marginTop:8}}>
          <button style={{...S.btnGreen,flex:1,opacity:scorer?1:0.4}} disabled={!scorer} onClick={()=>{onLog(scorer,posOf(scorer));onClose();}}>Log Goal</button>
          <button style={S.btnCancel} onClick={onClose}>Cancel</button>
        </div>

      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: MATCH
// ════════════════════════════════════════════════════════════════════════════════

// ─── MATCH EVENT RULES ────────────────────────────────────────────────────────
const MATCH_EVENT_RULES = [
  { type:"GOAL",          color:"#22c55e", label:"Goal",               desc:"We scored",                     capture:"goal",     icon:"⚽", group:"us"   },
  { type:"BIG_CHANCE",    color:"#f97316", label:"Big Chance Created", desc:"Great opportunity for us",      capture:"player",   icon:"🎯", group:"us"   },
  { type:"CHANCE_MISSED", color:"#ef4444", label:"Big Chance Missed",  desc:"Should have scored",            capture:"player",   icon:"😞", group:"us"   },
  { type:"TEAM_PLAY",     color:"#F5C04A", label:"Excellent Team Play",desc:"Great play or positives",       capture:"note",     icon:"⭐", group:"us"   },
  { type:"COACHING",      color:"#2dd4bf", label:"Coaching Moment",    desc:"Something to improve",          capture:"note",     icon:"🔧", group:"us"   },
  { type:"GOAL_CONCEDED", color:"#ef4444", label:"Goal Conceded",      desc:"Opponent scored",               capture:"conceded", icon:"🥅", group:"them" },
  { type:"OPP_THREAT",    color:"#a78bfa", label:"Opposition Threat",  desc:"Dangerous player or situation", capture:"note",     icon:"⚠️", group:"them" },
  { type:"OPP_PATTERN",   color:"#38bdf8", label:"Opposition Pattern", desc:"Noticeable tactic or trend",    capture:"note",     icon:"🔭", group:"them" },
];

function EventsPage({ halfElapsed, goals, matchEvents, setMatchEvents, opponentName, ourName, squad, onGoal, onThemGoal, onUndoGoal, onUndoThemGoal, quickNotes, setQuickNotes, qnActive, qnLiveText, toggleQnDictation, triggerEventType, onClearTrigger, onReturnToMatch }) {
  const [modal, setModal]             = React.useState(null);
  const [scorer, setScorer]           = React.useState('');
  const [assist, setAssist]           = React.useState('');
  const [cause, setCause]             = React.useState('');
  const [player, setPlayer]           = React.useState('');
  const [noteText, setNoteText]       = React.useState('');
  const [listening, setListening]     = React.useState(false);
  const [showInfo, setShowInfo]       = React.useState(false);
  const [qnEditId, setQnEditId]       = React.useState(null);
  const [qnEditText, setQnEditText]   = React.useState('');
  const recogRef = React.useRef(null);

  const SpeechRec = typeof window !== 'undefined' && (window.SpeechRecognition || window.webkitSpeechRecognition);
  const matchMinute = Math.floor(halfElapsed / 60);
  const playerNames = (squad||[]).map(p => p.name).filter(Boolean);

  // External trigger from bottom bar quick actions
  React.useEffect(() => {
    if (triggerEventType) {
      const rule = MATCH_EVENT_RULES.find(r => r.type === triggerEventType);
      if (rule) openModal(rule);
      if (onClearTrigger) onClearTrigger();
    }
  }, [triggerEventType]);

  function stopRec(ref, setter) { try { ref.current && ref.current.stop(); } catch(e){} setter(false); }

  function toggleVoice() {
    if (listening) { stopRec(recogRef, setListening); return; }
    if (!SpeechRec) return;
    const r = new SpeechRec();
    r.continuous = true; r.interimResults = false; r.lang = 'en-AU';
    r.onresult = e => { const t = Array.from(e.results).map(x=>x[0].transcript).join(' '); setNoteText(p=>(p?p+' ':'')+t); };
    r.onend = () => setListening(false);
    recogRef.current = r; r.start(); setListening(true);
  }

  function openModal(rule) {
    stopRec(recogRef, setListening);
    setScorer(''); setAssist(''); setCause(''); setPlayer(''); setNoteText('');
    setModal({ rule, editId: null });
  }
  function closeModal() { stopRec(recogRef, setListening); setModal(null); }
  function makeEv(type, extra) {
    return { id:'ev_'+Date.now()+'_'+Math.random().toString(36).slice(2), type, eventType:type, minute:matchMinute, timestamp:Date.now(), player:'', secondaryPlayer:'', category:'', note:'', ...(extra||{}) };
  }

  function saveEvent() {
    const rule = modal.rule;
    let ev;
    if (rule.capture === 'goal') {
      if (onGoal) onGoal(scorer||'Unknown');
      ev = makeEv(rule.type, { player:scorer, secondaryPlayer:assist, team:'us', note:noteText });
    } else if (rule.capture === 'conceded') {
      if (onThemGoal) onThemGoal();
      ev = makeEv(rule.type, { category:cause, team:'them', note:noteText||cause });
    } else if (rule.capture === 'player') {
      ev = makeEv(rule.type, { player, team:'us', note:noteText });
    } else {
      const team = rule.group==='them' ? 'them' : rule.type==='COACHING' ? null : 'us';
      ev = makeEv(rule.type, { note:noteText, team });
    }
    if (modal.editId) {
      setMatchEvents(evs => evs.map(e => e.id===modal.editId ? {...e,...ev,id:modal.editId} : e));
    } else {
      setMatchEvents(evs => [...evs, ev]);
    }
    closeModal();
  }

  function undoLastEvent() {
    if (!matchEvents.length) return;
    const last = [...matchEvents].sort((a,b)=>b.timestamp-a.timestamp)[0];
    setMatchEvents(evs => evs.filter(e=>e.id!==last.id));
    if (last.type==='GOAL' && onUndoGoal) onUndoGoal();
    if (last.type==='GOAL_CONCEDED' && onUndoThemGoal) onUndoThemGoal();
  }

  function deleteEvent(id) { setMatchEvents(evs=>evs.filter(e=>e.id!==id)); }

  function editEvent(ev) {
    const rule = MATCH_EVENT_RULES.find(r=>r.type===ev.type)||{type:'NOTE',label:'Note',desc:'',capture:'note',color:'#A1A1A1',icon:'📝',group:'us'};
    setScorer(ev.player||''); setAssist(ev.secondaryPlayer||''); setCause(ev.category||''); setPlayer(ev.player||''); setNoteText(ev.note||'');
    setModal({ rule, editId:ev.id });
  }

  const recentEvents = [...matchEvents].sort((a,b)=>b.minute-a.minute||b.timestamp-a.timestamp);
  const CAUSES = ['Counter Attack','Set Piece','Defensive Error','Individual Skill','Other'];
  const notePlaceholders = { GOAL:'E.g. Great finish from 18 yards…', BIG_CHANCE:'E.g. Through ball cut open defence…', CHANCE_MISSED:'E.g. Good position, shot wide…', GOAL_CONCEDED:'E.g. Caught on the break…', OPP_THREAT:'E.g. #7 very fast down right wing…', OPP_PATTERN:'E.g. Build out through keeper…', TEAM_PLAY:'E.g. 10 pass sequence, great pressing…', COACHING:'E.g. Not tracking runners, too narrow…' };

  function PlayerPicker({ value, onChange, label, optional }) {
    return (
      <div style={{marginBottom:16}}>
        <div style={{fontSize:11,fontWeight:700,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase',marginBottom:10}}>{label}{optional?' (optional)':''}</div>
        <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
          {optional&&<button onClick={()=>onChange('')} style={{padding:'8px 14px',borderRadius:20,border:value===''?'1.5px solid #F5C04A':'1px solid #2A2A2A',background:value===''?'rgba(245,192,74,0.1)':'#1A1A1A',color:value===''?'#F5C04A':'#555',fontSize:12,fontWeight:600,cursor:'pointer'}}>None</button>}
          {playerNames.map(n=>(
            <button key={n} onClick={()=>onChange(n)} style={{padding:'8px 14px',borderRadius:20,border:value===n?'1.5px solid #F5C04A':'1px solid #2A2A2A',background:value===n?'rgba(245,192,74,0.1)':'#1A1A1A',color:value===n?'#F5C04A':'#FFF',fontSize:13,fontWeight:value===n?700:400,cursor:'pointer'}}>{n}</button>
          ))}
        </div>
      </div>
    );
  }

  function NoteField({ rule }) {
    return (
      <div style={{marginTop:16}}>
        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:8}}>
          <div style={{fontSize:11,fontWeight:700,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase'}}>
            {rule.capture==='note' ? 'Note' : 'Additional Notes'}
          </div>
          {SpeechRec&&<button onClick={toggleVoice} style={{background:listening?'rgba(239,68,68,0.1)':'#1A1A1A',border:`1px solid ${listening?'#ef4444':'#2A2A2A'}`,borderRadius:8,padding:'6px 12px',cursor:'pointer',display:'flex',alignItems:'center',gap:6,color:listening?'#ef4444':'#A1A1A1',fontSize:11,fontWeight:700}}>
            <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
            {listening?'Stop':'Dictate'}
          </button>}
        </div>
        <textarea value={noteText} onChange={e=>setNoteText(e.target.value)}
          placeholder={notePlaceholders[rule.type]||'Add a note…'}
          rows={rule.capture==='note'?4:3}
          style={{width:'100%',background:'#0D0D0D',border:`1px solid ${listening?'#ef4444':'#2A2A2A'}`,borderRadius:10,padding:'12px',color:'#FFF',fontSize:14,fontFamily:'inherit',lineHeight:1.6,resize:'none',outline:'none',boxSizing:'border-box'}}/>
        {listening&&<div style={{fontSize:11,color:'#ef4444',marginTop:5,fontWeight:600}}>🎙️ Recording — speak your note</div>}
      </div>
    );
  }

  // Flat 2×4 grid: our team cards first (green border), opposition second (red border)
  const GRID_ORDER = [
    ...MATCH_EVENT_RULES.filter(r=>r.group==='us'),
    ...MATCH_EVENT_RULES.filter(r=>r.group==='them'),
  ];

  function cardBorder(rule) {
    return rule.group==='us' ? '1px solid rgba(34,197,94,0.4)' : '1px solid rgba(239,68,68,0.4)';
  }
  function cardBg(rule) {
    return rule.group==='us' ? 'rgba(34,197,94,0.04)' : 'rgba(239,68,68,0.04)';
  }

  return (
    <div style={{flex:1,overflowY:'auto',paddingBottom:90,background:'#0D0D0D'}}>

      {/* ── Header ── */}
      <div style={{padding:'14px 16px 6px',display:'flex',alignItems:'flex-start',justifyContent:'space-between'}}>
        <div>
          <div style={{display:'flex',alignItems:'center',gap:7}}>
            <div style={{fontSize:18,fontWeight:800,color:'#FFF'}}>Match Events</div>
            <button onClick={()=>setShowInfo(!showInfo)} style={{background:'none',border:'none',padding:0,cursor:'pointer',color:'#555',display:'flex',alignItems:'center'}}>
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="8" strokeLinecap="round" strokeWidth="3"/><path d="M12 12v4"/></svg>
            </button>
          </div>
          <div style={{fontSize:11,color:'#555',marginTop:3}}>Tap an event to record it</div>
        </div>
        <button onClick={undoLastEvent} disabled={!matchEvents.length}
          style={{marginTop:2,padding:'7px 13px',border:'1px solid #2A2A2A',borderRadius:10,background:'none',color:matchEvents.length?'#A1A1A1':'#333',fontSize:11,fontWeight:700,cursor:matchEvents.length?'pointer':'default',display:'flex',alignItems:'center',gap:5,flexShrink:0}}>
          <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 7v6h6"/><path d="M21 17a9 9 0 00-9-9 9 9 0 00-6 2.3L3 13"/></svg>
          Undo
        </button>
      </div>

      {showInfo&&(
        <div style={{margin:'0 16px 10px',background:'#111111',border:'1px solid #1E1E1E',borderRadius:12,padding:'10px 14px'}}>
          <div style={{fontSize:12,color:'#A1A1A1',lineHeight:1.7}}><span style={{color:'#22c55e',fontWeight:700}}>Green border</span> = our team. <span style={{color:'#ef4444',fontWeight:700}}>Red border</span> = opposition. Goal and Goal Conceded update the live score.</div>
          <button onClick={()=>setShowInfo(false)} style={{marginTop:6,background:'none',border:'none',color:'#F5C04A',fontSize:12,fontWeight:700,cursor:'pointer',padding:0}}>Got it ✕</button>
        </div>
      )}

      {/* ── Flat 2×4 event grid ── */}
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:8,padding:'8px 12px 16px'}}>
        {GRID_ORDER.map(rule=>(
          <button key={rule.type} onClick={()=>openModal(rule)}
            style={{background:cardBg(rule),border:cardBorder(rule),borderRadius:14,padding:'12px 10px',cursor:'pointer',textAlign:'left',display:'flex',flexDirection:'column',gap:5,WebkitTapHighlightColor:'transparent'}}>
            <div style={{fontSize:24}}>{rule.icon}</div>
            <div style={{fontSize:11,fontWeight:800,color:'#FFF',lineHeight:1.25}}>{rule.label}</div>
            <div style={{fontSize:10,color:'#666',lineHeight:1.35}}>{rule.desc}</div>
          </button>
        ))}
      </div>

      {/* ── Quick Notes frame ── */}
      {(quickNotes||[]).length>0&&(
        <div style={{padding:'0 12px 16px'}}>
          <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:10}}>
            <div style={{fontSize:14,fontWeight:800,color:'#FFF'}}>Quick Notes</div>
            <div style={{fontSize:11,color:'#555'}}>{(quickNotes||[]).length} note{(quickNotes||[]).length!==1?'s':''}</div>
          </div>
          <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',overflow:'hidden'}}>
            {[...(quickNotes||[])].reverse().map((note,i,arr)=>(
              <div key={note.id} style={{borderBottom:i<arr.length-1?'1px solid #1E1E1E':'none'}}>
                {qnEditId===note.id?(
                  <div style={{padding:'10px 12px'}}>
                    <textarea value={qnEditText} onChange={e=>setQnEditText(e.target.value)} autoFocus
                      rows={3} style={{width:'100%',background:'#0D0D0D',border:'1px solid #F5C04A44',borderRadius:10,padding:'10px',color:'#FFF',fontSize:13,fontFamily:'inherit',lineHeight:1.5,resize:'none',outline:'none',boxSizing:'border-box'}}/>
                    <div style={{display:'flex',gap:8,marginTop:8}}>
                      <button onClick={()=>{setQuickNotes(prev=>prev.map(n=>n.id===note.id?{...n,text:qnEditText}:n));setQnEditId(null);}}
                        style={{flex:1,padding:'8px',background:'#22c55e',border:'none',borderRadius:9,color:'#FFF',fontSize:12,fontWeight:800,cursor:'pointer'}}>Save</button>
                      <button onClick={()=>setQnEditId(null)}
                        style={{padding:'8px 16px',background:'none',border:'1px solid #2A2A2A',borderRadius:9,color:'#666',fontSize:12,cursor:'pointer'}}>Cancel</button>
                    </div>
                  </div>
                ):(
                  <div style={{display:'flex',alignItems:'flex-start',gap:10,padding:'11px 14px'}}>
                    <div style={{width:34,height:34,borderRadius:10,background:'rgba(245,192,74,0.08)',border:'1px solid rgba(245,192,74,0.2)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:14,flexShrink:0}}>📝</div>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:13,color:'#E5E5E5',lineHeight:1.5,wordBreak:'break-word'}}>{note.text}</div>
                    </div>
                    <div style={{display:'flex',flexDirection:'column',alignItems:'flex-end',gap:5,flexShrink:0}}>
                      <div style={{fontSize:12,fontWeight:700,color:'#F5C04A'}}>{note.minute}'</div>
                      <div style={{display:'flex',gap:5}}>
                        <button onClick={()=>{setQnEditId(note.id);setQnEditText(note.text);}}
                          style={{background:'none',border:'1px solid #2A2A2A',borderRadius:7,padding:'4px 9px',color:'#666',fontSize:11,cursor:'pointer',fontWeight:600}}>Edit</button>
                        <button onClick={()=>setQuickNotes(prev=>prev.filter(n=>n.id!==note.id))}
                          style={{background:'none',border:'1px solid rgba(239,68,68,0.25)',borderRadius:7,padding:'4px 9px',color:'#ef4444',fontSize:11,cursor:'pointer'}}>✕</button>
                      </div>
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ── Recent Events ── */}
      {recentEvents.length>0&&(
        <div style={{padding:'0 12px 16px'}}>
          <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:10}}>
            <div style={{fontSize:14,fontWeight:800,color:'#FFF'}}>Recent Events</div>
            <div style={{fontSize:11,color:'#555'}}>{recentEvents.length} logged</div>
          </div>
          <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',overflow:'hidden'}}>
            {recentEvents.map((ev,i)=>{
              const rule = MATCH_EVENT_RULES.find(r=>r.type===ev.type)||{icon:'📝',label:ev.type,color:'#A1A1A1',group:'us'};
              const detail = ev.player?(ev.secondaryPlayer?`${ev.player}  ·  Assist: ${ev.secondaryPlayer}`:ev.player):(ev.note||ev.category||'');
              return (
                <div key={ev.id} style={{display:'flex',alignItems:'center',gap:10,padding:'11px 14px',borderBottom:i<recentEvents.length-1?'1px solid #1E1E1E':'none'}}>
                  <div style={{width:34,height:34,borderRadius:10,background:rule.group==='them'?'rgba(239,68,68,0.12)':'rgba(34,197,94,0.12)',border:`1px solid ${rule.color}44`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:16,flexShrink:0}}>{rule.icon}</div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:13,fontWeight:700,color:rule.color}}>{rule.label}</div>
                    {detail&&<div style={{fontSize:11,color:'#666',marginTop:2,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{detail}</div>}
                  </div>
                  <div style={{fontSize:12,fontWeight:700,color:'#444',flexShrink:0,marginRight:6}}>{ev.minute}'</div>
                  <div style={{display:'flex',gap:5,flexShrink:0}}>
                    <button onClick={()=>editEvent(ev)} style={{background:'none',border:'1px solid #2A2A2A',borderRadius:7,padding:'4px 9px',color:'#666',fontSize:11,cursor:'pointer',fontWeight:600}}>Edit</button>
                    <button onClick={()=>deleteEvent(ev.id)} style={{background:'none',border:'1px solid rgba(239,68,68,0.25)',borderRadius:7,padding:'4px 9px',color:'#ef4444',fontSize:11,cursor:'pointer'}}>✕</button>
                  </div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* ── Live transcript strip (shown while QN recording) ── */}
      {qnActive&&(
        <div style={{position:'fixed',bottom:136,left:12,right:12,zIndex:41,background:'rgba(13,13,13,0.96)',border:'1px solid #ef444455',borderRadius:16,padding:'10px 16px',display:'flex',alignItems:'center',gap:10}}>
          <div style={{width:8,height:8,borderRadius:'50%',background:'#ef4444',flexShrink:0,animation:'pulse 1s infinite'}}/>
          <div style={{flex:1,fontSize:13,color:qnLiveText?'#FFF':'#555',lineHeight:1.4,fontStyle:qnLiveText?'normal':'italic'}}>
            {qnLiveText||'Listening…'}
          </div>
          <div style={{fontSize:11,color:'#ef4444',fontWeight:700}}>{matchMinute}'</div>
        </div>
      )}

      {/* ── FAB row: Return to Match + Quick Note ── */}
      <div style={{position:'fixed',bottom:68,left:0,right:0,display:'flex',justifyContent:'center',alignItems:'center',gap:10,padding:'0 16px',zIndex:40,pointerEvents:'none'}}>
        <button onClick={()=>onReturnToMatch&&onReturnToMatch()}
          style={{background:'rgba(245,192,74,0.12)',border:'1px solid rgba(245,192,74,0.35)',borderRadius:30,padding:'12px 18px',fontSize:13,fontWeight:700,color:'#F5C04A',cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',gap:7,boxShadow:'0 4px 16px rgba(0,0,0,0.4)',pointerEvents:'all',flex:'1 1 0',maxWidth:200,whiteSpace:'nowrap'}}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
          Return to Match
        </button>
        <button onClick={toggleQnDictation}
          style={{background:qnActive?'#ef4444':'#22c55e',border:'none',borderRadius:30,padding:'12px 18px',fontSize:14,fontWeight:800,color:'#FFF',cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',gap:8,boxShadow:qnActive?'0 4px 20px rgba(239,68,68,0.45)':'0 4px 20px rgba(34,197,94,0.35)',pointerEvents:'all',flex:'1 1 0',maxWidth:200}}>
          {qnActive?(
            <>
              <div style={{width:10,height:10,borderRadius:'50%',background:'#FFF',flexShrink:0}}/>
              Stop &amp; Save
            </>
          ):(
            <>
              <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
              Quick Note
            </>
          )}
        </button>
      </div>

      {/* ── Event capture modal ── */}
      {modal&&(
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.8)',zIndex:200,display:'flex',flexDirection:'column',justifyContent:'flex-end'}}
          onClick={e=>{if(e.target===e.currentTarget)closeModal();}}>
          <div style={{background:'#111111',borderRadius:'20px 20px 0 0',padding:'20px 20px 40px',maxHeight:'90dvh',overflowY:'auto'}}>
            <div style={{width:36,height:4,background:'#2A2A2A',borderRadius:2,margin:'0 auto 20px'}}/>

            {/* Modal header */}
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:6}}>
              <div style={{display:'flex',alignItems:'center',gap:12}}>
                <div style={{width:44,height:44,borderRadius:12,background:`${modal.rule.color}18`,border:`1px solid ${modal.rule.color}44`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:22}}>{modal.rule.icon}</div>
                <div>
                  <div style={{fontSize:17,fontWeight:800,color:modal.rule.color}}>{modal.rule.label}</div>
                  <div style={{fontSize:11,color:'#555',marginTop:1}}>{matchMinute}' · {modal.rule.group==='us'?ourName||'Our Team':opponentName||'Opposition'}</div>
                </div>
              </div>
              <button onClick={closeModal} style={{background:'#1A1A1A',border:'none',borderRadius:'50%',width:32,height:32,display:'flex',alignItems:'center',justifyContent:'center',color:'#666',cursor:'pointer',fontSize:16,flexShrink:0}}>✕</button>
            </div>
            <div style={{height:1,background:'#1E1E1E',margin:'16px 0'}}/>

            {/* Goal: scorer + assist pickers */}
            {modal.rule.capture==='goal'&&<div>
              <PlayerPicker value={scorer} onChange={setScorer} label="Scorer" optional={false}/>
              <PlayerPicker value={assist} onChange={setAssist} label="Assist" optional={true}/>
            </div>}

            {/* Goal Conceded: cause radio buttons */}
            {modal.rule.capture==='conceded'&&(
              <div style={{marginBottom:8}}>
                <div style={{fontSize:11,fontWeight:700,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase',marginBottom:10}}>Cause</div>
                <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:6}}>
                  {CAUSES.map(c=>(
                    <button key={c} onClick={()=>setCause(c)}
                      style={{display:'flex',alignItems:'center',gap:10,background:cause===c?'rgba(239,68,68,0.1)':'#0D0D0D',border:`1px solid ${cause===c?'#ef4444':'#2A2A2A'}`,borderRadius:10,padding:'11px 12px',cursor:'pointer',textAlign:'left'}}>
                      <div style={{width:16,height:16,borderRadius:'50%',border:`2px solid ${cause===c?'#ef4444':'#444'}`,background:cause===c?'#ef4444':'none',flexShrink:0}}/>
                      <span style={{fontSize:12,color:cause===c?'#FFF':'#A1A1A1',fontWeight:cause===c?700:400,lineHeight:1.3}}>{c}</span>
                    </button>
                  ))}
                </div>
              </div>
            )}

            {/* Big Chance Created / Missed: player picker */}
            {modal.rule.capture==='player'&&<PlayerPicker value={player} onChange={setPlayer} label="Player" optional={false}/>}

            {/* Note field — always shown for all capture types */}
            <NoteField rule={modal.rule}/>

            <button onClick={saveEvent} style={{width:'100%',marginTop:20,padding:'16px',border:'none',borderRadius:14,background:modal.rule.color,color:['#F5C04A','#f97316','#2dd4bf'].includes(modal.rule.color)?'#000':'#FFF',fontSize:15,fontWeight:800,cursor:'pointer',letterSpacing:0.3}}>
              {modal.editId?'Update Event':'Save Event'} — {matchMinute}'
            </button>
          </div>
        </div>
      )}

    </div>
  );
}


function MatchScreen({ half1, half2, config, squad, opponent, linkedFixKey, fixIsHome, onSaveGame, onPostMatch, onExit }) {
  const positions = getPositions(config.formation);
  const posIds    = getPosIds(positions);
  const posLabel  = getPosLabel(positions);
  const periodMins = getPeriodMins(config);

  const [halves, setHalves] = useState(()=>[half1, half2 || Array.from({length:config.numPeriods},()=>({slots:null,seeded:false}))]);
  const [halfIdx, setHalfIdx] = useState(0);
  const [pidx, setPidx]         = useState(0);
  const [manualPeriod, setManualPeriod] = useState(false);
  const [selected, setSelected] = useState(null);
  const [dragging, setDragging] = useState(null);
  const [periodLeft, setPeriodLeft] = useState(Math.round(periodMins*60));
  const [halfElapsed, setHalfElapsed] = useState(0);
  const [running, setRunning] = useState(false);
  const [alarmed, setAlarmed] = useState(false);
  const [goals, setGoals]   = useState([]);
  const [matchEvents, setMatchEvents] = useState([]);
  const [modal, setModal]   = useState(null);
  const [eventsView, setEventsView] = useState(false);
  const [triggerEventType, setTriggerEventType] = React.useState(null);
  const [report, setReport] = useState("");
  const [reportLoading, setReportLoading] = useState(false);
  const [voiceNotes, setVoiceNotes]   = useState("");      // accumulated transcript
  const [quickNotes, setQuickNotes]   = React.useState([]); // structured quick notes from Events tab
  const [qnActive, setQnActive]        = React.useState(false);
  const [qnLiveText, setQnLiveText]    = React.useState('');
  const [voiceReview, setVoiceReview] = useState("");      // editable copy in review modal
  const [isVoiceRec, setIsVoiceRec]   = useState(false);
  const [voicePulse, setVoicePulse]   = useState(false);
  const [activeMatchTab, setActiveMatchTab] = useState('lineup');
  const [goalScorer, setGoalScorer] = useState('');
  const timerRef = useRef(null);
  const recognitionRef = useRef(null);
  const pulseRef = useRef(null);

  const periods = halves[halfIdx];
  const cur     = periods[pidx];

  let prevSlots = null;
  if(pidx>0) prevSlots=periods[pidx-1]?.slots;
  else if(halfIdx>0){const ph=halves[halfIdx-1];prevSlots=ph[ph.length-1]?.slots;}
  const swapPairs=(prevSlots&&cur.slots)?computeSwapPairs(prevSlots,cur.slots,posIds):{};

  useEffect(()=>{
    let need=false; halves.forEach(h=>h.forEach(p=>{if(!p.slots)need=true;})); if(!need)return;
    setHalves(hs=>{
      const next=hs.map(h=>h.map(p=>({...p}))); let prev=null;
      for(let hi=0;hi<next.length;hi++)for(let pi=0;pi<next[hi].length;pi++){
        if(next[hi][pi].slots)prev=next[hi][pi].slots;
        else if(prev){next[hi][pi].slots=cloneSlots(prev);prev=next[hi][pi].slots;}
      }
      return next;
    });
  },[halves]);

  useEffect(()=>{
    if(running){timerRef.current=setInterval(()=>{
      setHalfElapsed(g=>g+1);
      setPeriodLeft(t=>{if(t<=1){clearInterval(timerRef.current);setRunning(false);setAlarmed(true);playAlarm();return 0;}return t-1;});
    },1000);}else clearInterval(timerRef.current);
    return()=>clearInterval(timerRef.current);
  },[running]);
  // Auto-advance period tab when timer crosses period boundaries
  useEffect(()=>{
    if(manualPeriod) return;
    const pSecs = Math.round(periodMins * 60);
    const next = Math.min(Math.floor(halfElapsed / pSecs), periods.length - 1);
    if(next >= 0) setPidx(next);
  },[halfElapsed, manualPeriod, periodMins, periods.length]);

  function toggleRun(){ unlockAudio(); setRunning(r=>!r); setAlarmed(false); }

  // ── Voice notes (Web Speech API) ────────────────────────────────────────
  function startVoice() {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) { alert("Voice notes require speech recognition support. Try Chrome on Android or Safari on iOS 14.5+."); return; }
    if (isVoiceRecRef.current) return; // already recording
    let buf = '';
    let restartTimer = null;
    function doStart() {
      const rec = new SR();
      rec.lang = 'en-AU';
      rec.continuous = true;
      rec.interimResults = false;
      rec.onresult = e => {
        buf = Array.from(e.results).map(r=>r[0].transcript).join(' ');
      };
      rec.onerror = e => {
        if (e.error === 'no-speech') return; // ignore no-speech, will restart via onend
        stopVoice(buf);
      };
      rec.onend = () => {
        // On iOS, continuous mode ends automatically — restart if still recording
        if (isVoiceRecRef.current) {
          restartTimer = setTimeout(doStart, 100);
        }
      };
      try { rec.start(); } catch(e) { stopVoice(buf); return; }
      recognitionRef.current = rec;
    }
    isVoiceRecRef.current = true;
    setIsVoiceRec(true);
    pulseRef.current = setInterval(()=>setVoicePulse(p=>!p), 600);
    doStart();
    // Override stop to also clear restart timer
    const origStop = stopVoice;
    stopVoice._restartRef = () => { clearTimeout(restartTimer); };
  }
  const isVoiceRecRef = useRef(false);
  const qnRecRef_ms   = React.useRef(null);
  const qnLiveRef_ms  = React.useRef('');
  const qnSavedRef_ms = React.useRef(false);
  const halfElapsedRef_ms = React.useRef(0);
  function stopVoice(extraText) {
    if (stopVoice._restartRef) { stopVoice._restartRef(); stopVoice._restartRef = null; }
    isVoiceRecRef.current = false;
    setIsVoiceRec(false);
    clearInterval(pulseRef.current);
    setVoicePulse(false);
    try { recognitionRef.current?.stop(); recognitionRef.current = null; } catch {}
    if (extraText && extraText.trim()) {
      const ts = String(Math.floor(halfElapsed/60)).padStart(2,'0') + ':' + String(halfElapsed%60).padStart(2,'0');
      setVoiceNotes(prev => prev ? prev + '\n[' + ts + '] ' + extraText.trim() : '[' + ts + '] ' + extraText.trim());
    }
  }
  function toggleVoice() {
    if (isVoiceRecRef.current) { stopVoice(''); }
    else { startVoice(); }
  }
  function resetPeriodTimer(){ setRunning(false); setPeriodLeft(Math.round(periodMins*60)); setAlarmed(false); }
  function goNextPeriod(){
    setRunning(false); setPeriodLeft(Math.round(periodMins*60)); setAlarmed(false);
    setManualPeriod(false); // return to timer-driven period
    if(pidx<periods.length-1){setSelected(null);}
    else if(halfIdx<halves.length-1){setHalfIdx(halfIdx+1);setPidx(0);setSelected(null);setHalfElapsed(0);}
  }
  function switchPeriod(i){ setManualPeriod(true); setPidx(i); setSelected(null); }
  function switchHalf(h){ if(h<0||h>halves.length-1)return; setHalfIdx(h);setPidx(0);setManualPeriod(false);setSelected(null);setHalfElapsed(0); }

  const touchStart=useRef(null);
  function onTouchStart(e){touchStart.current={x:e.touches[0].clientX,y:e.touches[0].clientY};}
  function onTouchEnd(e){
    if(!touchStart.current)return;
    const dx=e.changedTouches[0].clientX-touchStart.current.x,dy=e.changedTouches[0].clientY-touchStart.current.y;
    touchStart.current=null;
    if(Math.abs(dx)>80&&Math.abs(dx)>Math.abs(dy)*2){dx<0?switchHalf(halfIdx+1):switchHalf(halfIdx-1);}
  }
  const pitchTouch=useRef(null);
  function onPitchTouchStart(e){e.stopPropagation();pitchTouch.current={x:e.touches[0].clientX,y:e.touches[0].clientY};}
  function onPitchTouchEnd(e){
    e.stopPropagation();if(!pitchTouch.current)return;
    const dx=e.changedTouches[0].clientX-pitchTouch.current.x,dy=e.changedTouches[0].clientY-pitchTouch.current.y;
    pitchTouch.current=null;const adx=Math.abs(dx),ady=Math.abs(dy);
    if(adx<25&&ady<25)return;
    if(adx>ady*1.2){if(dx<0&&pidx<periods.length-1)switchPeriod(pidx+1);if(dx>0&&pidx>0)switchPeriod(pidx-1);}
    else{if(dy<0)switchHalf(halfIdx+1);if(dy>0)switchHalf(halfIdx-1);}
  }

  function applyMove(slots,name,from,to){
    const s={}; posIds.forEach(id=>s[id]=slots[id]);
    let bench=[...slots.bench];
    // Remove player from wherever they currently are
    if(from==="bench")bench=bench.filter(n=>n!==name);
    else if(posIds.includes(from))s[from]="";
    // Also clear any OTHER slot that already has this player (prevents duplicates)
    posIds.forEach(id=>{if(id!==from&&s[id]===name)s[id]="";});
    bench=bench.filter(n=>n!==name);
    if(to==="bench"){if(!bench.includes(name))bench.push(name);}
    else{const d=s[to];s[to]=name;if(d&&d!==name){if(from==="bench"||from===to){if(!bench.includes(d))bench.push(d);}else s[from]=d;}}
    const onField=new Set(posIds.map(id=>s[id]).filter(Boolean));
    bench=[...new Set(bench.filter(n=>!onField.has(n)))];
    return{...s,bench};
  }
  function flatten(hs){const f=[];hs.forEach((h,hi)=>h.forEach((p,pi)=>f.push({hi,pi,slots:p.slots})));return f;}
  function movePlayer(name,from,to){
    if(from===to)return;
    setHalves(hs=>{
      const flat=flatten(hs);const idx=flat.findIndex(f=>f.hi===halfIdx&&f.pi===pidx);if(idx<0)return hs;
      const after=applyMove(flat[idx].slots,name,from,to);const newByKey={[`${halfIdx}.${pidx}`]:after};
      for(let j=idx+1;j<flat.length;j++){
        const cand=flat[j].slots;if(!cand)continue;
        let candFrom=null;
        if((cand.bench||[]).includes(name))candFrom="bench";else{const pos=posIds.find(id=>cand[id]===name);if(pos)candFrom=pos;}
        if(candFrom===from){newByKey[`${flat[j].hi}.${flat[j].pi}`]=applyMove(cand,name,from,to);}else break;
      }
      return hs.map((h,hi)=>h.map((p,pi)=>{const k=`${hi}.${pi}`;return newByKey[k]?{...p,slots:newByKey[k],seeded:true}:p;}));
    });
  }
  function handleTap(id,isBench,benchName){
    if(selected){
      const to=isBench?"bench":id;
      if(selected.from===to&&(!isBench||selected.name===benchName)){setSelected(null);return;}
      movePlayer(selected.name,selected.from,to);setSelected(null);
    } else {
      if(isBench){setSelected({name:benchName,from:"bench"});return;}
      const name=cur.slots[id];if(name)setSelected({name,from:id});
    }
  }
  function handleDrop(toId){if(!dragging)return;movePlayer(dragging.name,dragging.from,toId);setDragging(null);}
  function getTokenColor(name){if(!name)return null;const i=swapPairs[name];return i!==undefined?PAIR_COLORS[i]:null;}

  function logGoal(scorer,position){setGoals(g=>[...g,{scorer,position,secs:halfElapsed,timeStr:fmtTime(halfElapsed),team:"us",half:halfIdx+1}]);}
  function logThemGoal(){setGoals(g=>[...g,{scorer:"Opponent",secs:halfElapsed,timeStr:fmtTime(halfElapsed),team:"them",half:halfIdx+1}]);}
  function removeGoal(i){setGoals(g=>g.filter((_,j)=>j!==i));}
  React.useEffect(() => { halfElapsedRef_ms.current = halfElapsed; }, [halfElapsed]);

  function toggleQnDictation() {
    const SR = typeof window !== 'undefined' && (window.SpeechRecognition || window.webkitSpeechRecognition);
    if (qnActive) {
      qnSavedRef_ms.current = true;
      try { qnRecRef_ms.current && qnRecRef_ms.current.stop(); } catch(e){}
      setQnActive(false);
      const text = qnLiveRef_ms.current.trim();
      if (text) {
        const note = { id:'qn_'+Date.now(), minute: Math.floor(halfElapsedRef_ms.current/60), text };
        setQuickNotes(prev => [...(prev||[]), note]);
      }
      qnLiveRef_ms.current = ''; setQnLiveText('');
      return;
    }
    if (!SR) {
      // No speech rec — switch to events tab where text input is available
      setActiveMatchTab('events');
      return;
    }
    qnLiveRef_ms.current = ''; setQnLiveText(''); qnSavedRef_ms.current = false;
    const r = new SR();
    r.continuous = true; r.interimResults = false; r.lang = 'en-AU';
    r.onresult = e => {
      let finals = '';
      for (let i = 0; i < e.results.length; i++) {
        if (e.results[i].isFinal) finals += (finals ? ' ' : '') + e.results[i][0].transcript;
      }
      if (finals) { qnLiveRef_ms.current = finals; setQnLiveText(finals); }
    };
    r.onend = () => {
      setQnActive(false);
      if (!qnSavedRef_ms.current) {
        const text = qnLiveRef_ms.current.trim();
        if (text) {
          const note = { id:'qn_'+Date.now(), minute: Math.floor(halfElapsedRef_ms.current/60), text };
          setQuickNotes(pn => [...(pn||[]), note]);
        }
        qnLiveRef_ms.current = ''; setQnLiveText('');
      }
      qnSavedRef_ms.current = false;
    };
    qnRecRef_ms.current = r; r.start(); setQnActive(true);
  }

  function removeThemGoal(){setGoals(g=>{const idx=[...g].map((x,i)=>({x,i})).filter(({x})=>x.team==='them');if(!idx.length)return g;return g.filter((_,i)=>i!==idx[idx.length-1].i);});}

  const usGoals=goals.filter(g=>g.team==="us");
  const themGoals=goals.filter(g=>g.team==="them");

  function currentGameObj(){
    const _allNotes=[voiceNotes,...(quickNotes||[]).map(n=>`[${n.minute}'] ${n.text}`)].filter(s=>s&&s.trim()).join('\n');
    return{opponent,date:Date.now(),goals,matchEvents,quickNotes:quickNotes||[],scoreUs:usGoals.length,scoreThem:themGoals.length,halves,config,voiceNotes:_allNotes||"",...(linkedFixKey?{linkedFixtureKey:linkedFixKey,fixtureIsHome:fixIsHome}:{})};
  }
  async function generateReport(){
    setModal("report");setReportLoading(true);
    const game=currentGameObj();
    try{const text=await generateAIReport(game);setReport(text);}
    catch{setReport(buildLocalReport(game));}
    setReportLoading(false);
  }
  function saveAndExit(){
    const game=currentGameObj();game.id="g_"+Date.now();game.report=report||buildLocalReport(game);onSaveGame(game);if(onPostMatch)onPostMatch(game);else onExit();
  }

  const pMM=String(Math.floor(periodLeft/60)).padStart(2,"0");
  const pSS=String(periodLeft%60).padStart(2,"0");
  const gMM=String(Math.floor(halfElapsed/60)).padStart(2,"0");
  const gSS=String(halfElapsed%60).padStart(2,"0");
  const totalPeriodSecs=Math.round(periodMins*60);
  const pct=periodLeft/totalPeriodSecs;
  const ringColor=pct>0.4?"#F5C04A":pct>0.15?"#f59e0b":"#ef4444";
  const swapEntries=PAIR_COLORS.map((c,i)=>{
    const players=Object.entries(swapPairs).filter(([,v])=>v===i).map(([k])=>k);
    if(players.length!==2)return null;
    // Determine who came ON (in cur) vs went OFF (not in cur)
    const inCur=players.filter(n=>posIds.some(id=>cur.slots[id]===n));
    const offField=players.filter(n=>!inCur.includes(n));
    const onPlayer=inCur[0]||players[0], offPlayer=offField[0]||players[1];
    const onPos=posIds.find(id=>cur.slots[id]===onPlayer);
    const offPos=prevSlots?posIds.find(id=>prevSlots[id]===offPlayer):null;
    return {color:c,on:onPlayer,off:offPlayer,onPos:onPos?posLabel[onPos]||onPos:null,offPos:offPos?posLabel[offPos]||offPos:null};
  }).filter(Boolean);
  const offCounts={};
  halves.forEach((h,hi)=>h.forEach((p,pi)=>{if(!p.slots)return;const future=hi>halfIdx||(hi===halfIdx&&pi>pidx);if(!future)(p.slots.bench||[]).forEach(n=>{offCounts[n]=(offCounts[n]||0)+1;});}));
  const offSummary=Object.entries(offCounts).sort((a,b)=>b[1]-a[1]);
  const myTeam = config?.teamName || 'My Team';


  if(!cur.slots) return <div style={{minHeight:'100vh',background:'#0D0D0D',display:'flex',alignItems:'center',justifyContent:'center'}}><p style={{color:'#A1A1A1'}}>Loading…</p></div>;

  // SVG pitch helpers
  const svgX = (pct) => parseFloat(pct) / 100 * 200;
  const svgY = (pct) => parseFloat(pct) / 100 * 280;

  return (
    <div style={{height:'100dvh',background:'#0D0D0D',display:'flex',flexDirection:'column',paddingTop:'max(env(safe-area-inset-top),0px)',overflow:'hidden'}}>

      {/* ── MODALS ── */}
      {modal==='goal'&&<GoalModal squad={squad} slots={cur.slots} posIds={posIds} posLabel={posLabel} onLog={logGoal} onClose={()=>setModal(null)}/>}

      {modal==='report'&&(
        <div style={S.modalBack} onClick={()=>setModal(null)}>
          <div style={{...S.modalBox,maxWidth:460,maxHeight:'85vh',overflowY:'auto'}} onClick={e=>e.stopPropagation()}>
            <div style={S.modalHeader}><span style={S.modalTitle}>📋 Match Report</span><button style={S.btnX} onClick={()=>setModal(null)}>✕</button></div>
            <div style={S.reportBox}>{reportLoading?'✨ Generating…':report}</div>
            {!reportLoading&&(<div style={{display:'flex',gap:8}}>
              <button style={{...S.btnDark,flex:1}} onClick={()=>navigator.clipboard?.writeText(report)}>Copy</button>
              <button style={{...S.btnGreen,flex:1}} onClick={saveAndExit}>Save Game ✓</button>
            </div>)}
          </div>
        </div>
      )}

      {modal==='save'&&(
        <div style={{position:'fixed',inset:0,zIndex:999,display:'flex',alignItems:'flex-end',justifyContent:'center',background:'rgba(0,0,0,0.7)',backdropFilter:'blur(4px)'}} onClick={()=>setModal(null)}>
          <div style={{width:'100%',maxWidth:480,background:'#1A1A1A',borderRadius:'20px 20px 0 0',padding:'24px 20px',paddingBottom:'max(24px,env(safe-area-inset-bottom))',boxShadow:'0 -8px 40px rgba(0,0,0,0.6)'}} onClick={e=>e.stopPropagation()}>
            {/* Handle bar */}
            <div style={{width:40,height:4,background:'#333',borderRadius:2,margin:'0 auto 20px'}}/>
            <div style={{fontSize:18,fontWeight:800,color:'#FFF',textAlign:'center',marginBottom:6}}>End Match?</div>
            <div style={{fontSize:13,color:'#666',textAlign:'center',marginBottom:20}}>
              {(myTeam||'Us')} <span style={{color:'#FFF',fontWeight:700}}>{usGoals.length}</span>
              <span style={{color:'#444',margin:'0 8px'}}>–</span>
              <span style={{fontWeight:700,color:'#FFF'}}>{themGoals.length}</span> {opponent||'Opposition'}
            </div>
            <div style={{display:'flex',gap:10,flexDirection:'column'}}>
              <button style={{width:'100%',padding:'15px',background:'#22c55e',border:'none',borderRadius:12,color:'#FFF',fontSize:15,fontWeight:800,cursor:'pointer'}} onClick={saveAndExit}>Save Game ✓</button>
              <button style={{width:'100%',padding:'13px',background:'transparent',border:'1px solid #2A2A2A',borderRadius:12,color:'#A1A1A1',fontSize:13,fontWeight:700,cursor:'pointer'}} onClick={()=>setModal(null)}>Keep Playing</button>
            </div>
          </div>
        </div>
      )}

      {modal==='voiceReview'&&(
        <div style={S.modalBack} onClick={()=>{}}>
          <div style={{...S.modalBox,maxWidth:460,maxHeight:'85vh',display:'flex',flexDirection:'column'}} onClick={e=>e.stopPropagation()}>
            <div style={S.modalHeader}><span style={S.modalTitle}>🎙️ Voice Notes</span><button style={S.btnX} onClick={()=>setModal('save')}>✕</button></div>
            <textarea value={voiceReview} onChange={e=>setVoiceReview(e.target.value)} rows={10} style={{...S.sel,fontFamily:'inherit',lineHeight:1.6,resize:'vertical',flex:1,whiteSpace:'pre-wrap'}} placeholder="Your voice notes will appear here…"/>
            <div style={{display:'flex',gap:8,marginTop:12}}>
              <button style={{...S.btnGreen,flex:2}} onClick={()=>{const game=currentGameObj();game.voiceNotes=voiceReview.trim();game.report=voiceReview.trim()||report||buildLocalReport(game);game.id='g_'+Date.now();onSaveGame(game);}}>✓ Approve &amp; Save</button>
              <button style={{...S.btnDark,flex:1}} onClick={()=>{const game=currentGameObj();game.id='g_'+Date.now();game.report=report||buildLocalReport(game);onSaveGame(game);}}>Skip Notes</button>
            </div>
          </div>
        </div>
      )}

      {/* ── HEADER ── */}
      <div style={{background:'#111111',borderBottom:'1px solid #1A1A1A',flexShrink:0}}>

        {/* Row 1: back | venue + date | settings */}
        <div style={{display:'flex',alignItems:'center',padding:'6px 10px 4px',gap:6,borderBottom:'1px solid #1A1A1A'}}>
          <button onClick={onExit} style={{background:'none',border:'none',color:'#A1A1A1',fontSize:10,fontWeight:800,cursor:'pointer',padding:'2px 4px 2px 0',display:'flex',alignItems:'center',gap:2,flexShrink:0}}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><polyline points="15 18 9 12 15 6"/></svg>
            <span style={{letterSpacing:0.5}}>GAME</span>
          </button>
          <div style={{flex:1,textAlign:'center'}}>
            {(()=>{
              const fix=linkedFixKey?FIXTURES.find(f=>fixtureKey(f)===linkedFixKey):null;
              const venue=fix?.venue||config?.venue||'';
              const dateStr=fix?`${fix.date} · ${fix.time}`:'';
              return(<>
                {venue&&<div style={{fontSize:11,fontWeight:700,color:'#FFF',lineHeight:1.2}}>📍 {venue}</div>}
                {dateStr&&<div style={{fontSize:9,color:'#666',marginTop:1}}>{dateStr}</div>}
                {!venue&&!dateStr&&<div style={{fontSize:10,color:'#444'}}>Friendly</div>}
              </>);
            })()}
          </div>
          <button onClick={()=>{if(voiceNotes.trim()){setVoiceReview(voiceNotes);setModal('voiceReview');}else setModal('save');}} style={{background:'none',border:'none',color:'#A1A1A1',cursor:'pointer',padding:'2px 0 2px 4px',lineHeight:1,flexShrink:0}}>
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="3"/><path d="M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83-2.83l.06-.06A1.65 1.65 0 0 0 4.68 15a1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 2.83-2.83l.06.06A1.65 1.65 0 0 0 9 4.68a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 2.83l-.06.06A1.65 1.65 0 0 0 19.4 9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 0 4h-.09a1.65 1.65 0 0 0-1.51 1z"/></svg>
          </button>
        </div>

        {/* Row 2: left-team icon+name | score + game clock | right-team icon+name */}
        <div style={{display:'flex',alignItems:'center',padding:'8px 12px 10px',gap:8}}>

          {/* Left team */}
          <div style={{flex:1,display:'flex',alignItems:'center',gap:8,minWidth:0}}>
            <TeamBadge name={fixIsHome===false?opponent||'Away':myTeam||'Home'} size={68} radius={10}/>
            <div style={{minWidth:0}}>
              <div style={{fontSize:7,fontWeight:700,color:'#555',textTransform:'uppercase',letterSpacing:0.5,lineHeight:1}}>
                {fixIsHome===false?'AWAY':'HOME'}
              </div>
              <div style={{fontSize:13,fontWeight:600,color:'#FFF',lineHeight:1.3,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                {fixIsHome===false?(opponent||'Opposition'):(myTeam||'My Team')}
              </div>
            </div>
          </div>

          {/* Centre: score + half label + big clock */}
          <div style={{flexShrink:0,textAlign:'center',padding:'0 4px'}}>
            <div style={{display:'flex',alignItems:'center',gap:8,justifyContent:'center'}}>
              <span style={{fontSize:32,fontWeight:600,color:'#FFF',fontVariantNumeric:'tabular-nums',minWidth:30,textAlign:'right',lineHeight:1}}>
                {fixIsHome===false?themGoals.length:usGoals.length}
              </span>
              <div style={{display:'flex',flexDirection:'column',alignItems:'center',gap:1}}>
                <div style={{fontSize:8,fontWeight:800,color:'#F5C04A',letterSpacing:1.5,textTransform:'uppercase'}}>{halfIdx===0?'1ST':'2ND'} HALF</div>
                <div style={{fontSize:20,fontWeight:700,color:alarmed?'#ef4444':'#A1A1A1',fontVariantNumeric:'tabular-nums',lineHeight:1}}>{gMM}:{gSS}</div>
              </div>
              <span style={{fontSize:32,fontWeight:600,color:'#FFF',fontVariantNumeric:'tabular-nums',minWidth:30,textAlign:'left',lineHeight:1}}>
                {fixIsHome===false?usGoals.length:themGoals.length}
              </span>
            </div>
          </div>

          {/* Right team */}
          <div style={{flex:1,display:'flex',alignItems:'center',gap:8,justifyContent:'flex-end',minWidth:0}}>
            <div style={{minWidth:0,textAlign:'right'}}>
              <div style={{fontSize:7,fontWeight:700,color:'#555',textTransform:'uppercase',letterSpacing:0.5,lineHeight:1}}>
                {fixIsHome===false?'HOME':'AWAY'}
              </div>
              <div style={{fontSize:13,fontWeight:600,color:'#FFF',lineHeight:1.3,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>
                {fixIsHome===false?(myTeam||'My Team'):(opponent||'Opposition')}
              </div>
            </div>
            <TeamBadge name={fixIsHome===false?myTeam||'Home':opponent||'Away'} size={68} radius={10}/>
          </div>
        </div>
      </div>

      {/* ── TAB BAR ── */}
      <div style={{display:'flex',background:'#111111',borderBottom:'1px solid #1A1A1A',flexShrink:0,alignItems:'stretch'}}>
        {/* Lineup tab */}
        <button onClick={()=>setActiveMatchTab('lineup')} style={{flex:1,padding:'8px 4px',background:'none',border:'none',borderBottom:activeMatchTab==='lineup'?'2.5px solid #F5C04A':'2.5px solid transparent',cursor:'pointer',color:activeMatchTab==='lineup'?'#F5C04A':'#555',display:'flex',flexDirection:'column',alignItems:'center',gap:2}}>
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
          <span style={{fontSize:9,fontWeight:700}}>Overview</span>
        </button>
        {/* Events tab */}
        <button onClick={()=>setActiveMatchTab('events')} style={{flex:1,padding:'8px 4px',background:'none',border:'none',borderBottom:activeMatchTab==='events'?'2.5px solid #F5C04A':'2.5px solid transparent',cursor:'pointer',color:activeMatchTab==='events'?'#F5C04A':'#555',display:'flex',flexDirection:'column',alignItems:'center',gap:2}}>
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
          <span style={{fontSize:9,fontWeight:700}}>Events</span>
        </button>

        {/* Centre: period countdown + play/pause */}
        <button onClick={toggleRun} style={{flex:2,display:'flex',flexDirection:'row',alignItems:'center',justifyContent:'center',padding:'4px 8px',background:'#0D0D0D',border:'none',borderLeft:'1px solid #1A1A1A',borderRight:'1px solid #1A1A1A',gap:8,cursor:'pointer'}}>
          <div style={{display:'flex',flexDirection:'column',alignItems:'flex-start',gap:1}}>
            <div style={{fontSize:8,fontWeight:800,color:'#F5C04A',letterSpacing:1.5,textTransform:'uppercase'}}>P{pidx+1}</div>
            <div style={{fontSize:20,fontWeight:700,color:alarmed?'#ef4444':'#A1A1A1',fontVariantNumeric:'tabular-nums',lineHeight:1}}>{pMM}:{pSS}</div>
          </div>
          <div style={{width:28,height:28,borderRadius:'50%',background:running?'rgba(239,68,68,0.15)':'rgba(34,197,94,0.15)',border:running?'1.5px solid #ef4444':'1.5px solid #22c55e',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
            {running
              ? <svg width="10" height="10" viewBox="0 0 24 24" fill="#ef4444"><rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/></svg>
              : <svg width="10" height="10" viewBox="0 0 24 24" fill="#22c55e"><polygon points="5,3 19,12 5,21"/></svg>
            }
          </div>
        </button>

        {/* Stats tab */}
        <button onClick={()=>setActiveMatchTab('stats')} style={{flex:1,padding:'8px 4px',background:'none',border:'none',borderBottom:activeMatchTab==='stats'?'2.5px solid #F5C04A':'2.5px solid transparent',cursor:'pointer',color:activeMatchTab==='stats'?'#F5C04A':'#555',display:'flex',flexDirection:'column',alignItems:'center',gap:2}}>
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><line x1="18" y1="20" x2="18" y2="10"/><line x1="12" y1="20" x2="12" y2="4"/><line x1="6" y1="20" x2="6" y2="14"/></svg>
          <span style={{fontSize:9,fontWeight:700}}>Stats</span>
        </button>
        {/* Half toggle (replaces Voice) */}
        <button onClick={()=>switchHalf(halfIdx===0?1:0)} style={{flex:1,padding:'8px 4px',background:'none',border:'none',borderBottom:'2.5px solid transparent',cursor:'pointer',color:'#555',display:'flex',flexDirection:'column',alignItems:'center',gap:2}}>
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="17 1 21 5 17 9"/><path d="M3 11V9a4 4 0 0 1 4-4h14"/><polyline points="7 23 3 19 7 15"/><path d="M21 13v2a4 4 0 0 1-4 4H3"/></svg>
          <span style={{fontSize:9,fontWeight:700}}>{halfIdx===0?'→ H2':'← H1'}</span>
        </button>
      </div>

      {/* ── PERIOD TABS ── */}
      <div style={{display:'flex',background:'#0D0D0D',borderBottom:'1px solid #1A1A1A',flexShrink:0}}>
        {periods.map((_,i)=>(
          <button key={i} onClick={()=>switchPeriod(i)} style={{flex:1,padding:'5px 4px',background:'none',border:'none',borderBottom:i===pidx?'2px solid #F5C04A':'2px solid transparent',cursor:'pointer',color:i===pidx?'#F5C04A':'#444',fontSize:11,fontWeight:800,textAlign:'center'}}>
            P{i+1}
          </button>
        ))}
      </div>

      {alarmed&&<div style={{background:'#7c2d12',padding:'6px 14px',fontSize:11,color:'#FFF',textAlign:'center',fontWeight:700,flexShrink:0}}>🔔 Period over — tap Next P → above or log subs</div>}

      {/* ── MAIN CONTENT ── */}
      <div style={{flex:1,overflow:'hidden',display:'flex',flexDirection:'column'}}>

        {/* ──── LINEUP TAB ──── */}
        {activeMatchTab==='lineup'&&(
          <div style={{flex:1,display:'flex',overflow:'hidden'}} onTouchStart={onTouchStart} onTouchEnd={onTouchEnd}>

            {/* LEFT: Picker-style pitch */}
            <div style={{flex:'0 0 52%',display:'flex',flexDirection:'column',borderRight:'1px solid #1A1A1A',overflow:'hidden'}}>
              <div style={{padding:'5px 10px 3px',flexShrink:0}}>
                <div style={{fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase',display:'flex',alignItems:'center',justifyContent:'space-between'}}>
                  <span>ON THE PITCH</span>
                  <span style={{color:'#555',fontWeight:600,fontSize:8}}>{config.formation||'4-3-3'}</span>
                </div>
              </div>

              {/* SVG Pitch */}
              <div style={{flex:1,padding:'0 4px 4px',minHeight:0}} onTouchStart={onPitchTouchStart} onTouchEnd={onPitchTouchEnd}>
                <svg viewBox="0 0 200 280" xmlns="http://www.w3.org/2000/svg" style={{width:'100%',height:'100%',display:'block'}}
                  onDragOver={e=>e.preventDefault()}>
                  {/* Green stripes */}
                  {[0,1,2,3,4,5,6].map(i=>(
                    <rect key={i} x="0" y={i*40} width="200" height="40"
                      fill={i%2===0?'#1a5c1a':'#1d6b1d'}/>
                  ))}
                  {/* Pitch lines */}
                  <rect x="10" y="8" width="180" height="264" fill="none" stroke="rgba(255,255,255,0.25)" strokeWidth="1.5"/>
                  <line x1="10" y1="140" x2="190" y2="140" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
                  <circle cx="100" cy="140" r="22" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
                  <circle cx="100" cy="140" r="2" fill="rgba(255,255,255,0.3)"/>
                  <rect x="60" y="8" width="80" height="32" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
                  <rect x="60" y="240" width="80" height="32" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
                  <rect x="80" y="8" width="40" height="14" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>
                  <rect x="80" y="258" width="40" height="14" fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="1"/>

                  {/* Player tokens */}
                  {positions.map((pos,pIdx)=>{
                    const name=cur.slots[pos.id]||'';
                    const isSel=selected?.from===pos.id;
                    const swapColor=isSel?null:getTokenColor(name);
                    const init=name?name.split(' ').filter(Boolean).map(w=>w[0]).join('').toUpperCase().slice(0,2):'';
                    const shortN=name.split(' ').length>1?(name.split(' ')[0][0]+'. '+name.split(' ').slice(-1)[0]).slice(0,9):name.slice(0,9);
                    const cx=svgX(pos.left), cy=svgY(pos.top);
                    const fillCol=isSel?'rgba(245,192,74,0.25)':swapColor?(swapColor+'22'):'rgba(18,18,18,0.92)';
                    const strokeCol=isSel?'#F5C04A':swapColor||'rgba(255,255,255,0.3)';
                    const sw=isSel?2:swapColor?1.8:1;
                    return (
                      <g key={pos.id} style={{cursor:'pointer'}}
                        onClick={e=>{e.stopPropagation();handleTap(pos.id,false,null);}}
                        onDragOver={e=>e.preventDefault()} onDrop={e=>{e.preventDefault();handleDrop(pos.id);}}>
                        <rect x={cx-15} y={cy-19} width="30" height="38" rx="4" fill={fillCol} stroke={strokeCol} strokeWidth={sw}/>
                        {name
                          ? <>
                              <text x={cx} y={cy-7} textAnchor="middle" fontSize="11" fontWeight="800" fill={isSel?'#F5C04A':'#FFF'} fontFamily="Outfit,sans-serif">{init}</text>
                              <text x={cx} y={cy+8} textAnchor="middle" fontSize="4.8" fontWeight="600" fill="rgba(255,255,255,0.8)" fontFamily="Outfit,sans-serif">{shortN}</text>
                              <text x={cx} y={cy+15} textAnchor="middle" fontSize="4" fill={isSel?'rgba(245,192,74,0.7)':'rgba(255,255,255,0.35)'} fontFamily="Outfit,sans-serif">{posLabel[pos.id]||pos.id}</text>
                              <circle cx={cx+12} cy={cy-16} r="2.5" fill="#22c55e"/>
                              <text x={cx-12} y={cy-12} fontSize="5.5" fontWeight="700" fill={isSel?'#F5C04A':'rgba(255,255,255,0.4)'} fontFamily="Outfit,sans-serif">{pIdx+1}</text>
                            </>
                          : <text x={cx} y={cy+2} textAnchor="middle" fontSize="14" fill="rgba(255,255,255,0.15)" fontFamily="Outfit,sans-serif">+</text>
                        }
                        {isSel&&<rect x={cx-15} y={cy-19} width="30" height="38" rx="4" fill="none" stroke="rgba(245,192,74,0.5)" strokeWidth="4"/>}
                      </g>
                    );
                  })}
                </svg>
              </div>

              {/* Bench strip */}
              {cur.slots.bench&&cur.slots.bench.length>0&&(
                <div style={{padding:'4px 8px 6px',flexShrink:0,borderTop:'1px solid #1A1A1A'}}>
                  <div style={{fontSize:7,fontWeight:800,color:'#444',letterSpacing:1.5,textTransform:'uppercase',marginBottom:3}}>QUICK SUBS · tap pitch player then substitute</div>
                  <div style={{display:'flex',gap:4,overflowX:'auto'}}>
                    {cur.slots.bench.map((name,bidx)=>{
                      const isSel=selected?.name===name&&selected?.from==='bench';
                      const init=name.split(' ').filter(Boolean).map(w=>w[0]).join('').toUpperCase().slice(0,2);
                      const shortN=name.split(' ').length>1?(name.split(' ')[0][0]+'. '+name.split(' ').slice(-1)[0]).slice(0,9):name.slice(0,9);
                      return (
                        <div key={name} style={{flexShrink:0,cursor:'pointer',width:'10vw',maxWidth:46,minWidth:28}}
                          onClick={e=>{e.stopPropagation();handleTap(null,true,name);}}>
                          <svg viewBox="0 0 30 38" width="100%" style={{display:'block'}}>
                            <rect x="0" y="0" width="30" height="38" rx="4" fill={isSel?'rgba(124,58,237,0.2)':'rgba(18,18,18,0.92)'} stroke={isSel?'#7c3aed':'#3a3a3a'} strokeWidth={isSel?1.8:1}/>
                            <text x="15" y="13" textAnchor="middle" fontSize="11" fontWeight="600" fill={isSel?'#c4b5fd':'#FFF'} fontFamily="Outfit,sans-serif">{init}</text>
                            <text x="15" y="28" textAnchor="middle" fontSize="4.8" fontWeight="600" fill="rgba(255,255,255,0.75)" fontFamily="Outfit,sans-serif">{shortN}</text>
                            <text x="15" y="35" textAnchor="middle" fontSize="4" fill="rgba(255,255,255,0.3)" fontFamily="Outfit,sans-serif">SUB</text>
                            <circle cx="25" cy="5" r="2.5" fill="#22c55e"/>
                            <text x="4" y="9" fontSize="5.5" fontWeight="700" fill={isSel?'#c4b5fd':'rgba(255,255,255,0.4)'} fontFamily="Outfit,sans-serif">{bidx+1}</text>
                          </svg>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}
            </div>

            {/* RIGHT: Events (top) + Upcoming Subs (bottom) */}
            <div style={{flex:'0 0 48%',display:'flex',flexDirection:'column',overflow:'hidden'}}>

              {/* ── TOP ROW: Match Events ── */}
              <div style={{flex:1,display:'flex',flexDirection:'column',overflow:'hidden',borderBottom:'1px solid #1A1A1A'}}>

                {/* Events header */}
                <div style={{padding:'5px 10px 4px',borderBottom:'1px solid #1A1A1A',flexShrink:0,display:'flex',alignItems:'center',justifyContent:'space-between'}}>
                  <div style={{fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase'}}>MATCH EVENTS</div>
                  <button onClick={()=>setActiveMatchTab('events')} style={{background:'none',border:'none',color:'#F5C04A',fontSize:9,fontWeight:700,cursor:'pointer',padding:0}}>All →</button>
                </div>

                {/* Events list */}
                <div style={{flex:1,overflowY:'auto',padding:'4px 0'}}>
                  {goals.length===0&&matchEvents.length===0&&(
                    <div style={{fontSize:10,color:'#333',textAlign:'center',padding:'16px 0',fontStyle:'italic'}}>No events yet</div>
                  )}
                  {halfIdx===1&&(
                    <div style={{display:'flex',alignItems:'center',gap:4,padding:'3px 10px'}}>
                      <div style={{flex:1,height:1,background:'#1A1A1A'}}/>
                      <span style={{fontSize:8,color:'#555',fontWeight:700}}>HT</span>
                      <div style={{flex:1,height:1,background:'#1A1A1A'}}/>
                    </div>
                  )}
                  {[...goals.map(g=>({t:g.secs,type:'goal',data:g})),...matchEvents.map(e=>({t:(e.minute||0)*60,type:'event',data:e}))].sort((a,b)=>a.t-b.t).map((item,i)=>{
                    if(item.type==='goal'){const g=item.data;return(
                      <div key={'g'+i} style={{display:'flex',alignItems:'center',gap:6,padding:'5px 10px',borderBottom:'1px solid #0D0D0D'}}>
                        <span style={{fontSize:9,color:'#555',minWidth:20,fontWeight:700,flexShrink:0}}>{g.timeStr}'</span>
                        <div style={{width:20,height:20,borderRadius:'50%',background:g.team==='us'?'rgba(34,197,94,0.15)':'rgba(252,165,165,0.15)',border:`1px solid ${g.team==='us'?'#22c55e':'#fca5a5'}`,display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
                          <svg width="10" height="10" viewBox="0 0 24 24" fill={g.team==='us'?'#22c55e':'#fca5a5'}><circle cx="12" cy="12" r="10"/></svg>
                        </div>
                        <div style={{flex:1,minWidth:0}}>
                          <div style={{fontSize:10,fontWeight:700,color:g.team==='us'?'#FFF':'#fca5a5',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{g.team==='us'?g.scorer:'Opponent'}</div>
                          {g.team==='us'&&g.position&&<div style={{fontSize:8,color:'#555'}}>{g.position}</div>}
                        </div>
                        <button onClick={()=>removeGoal(goals.indexOf(g))} style={{background:'none',border:'none',color:'#2A2A2A',cursor:'pointer',fontSize:12,padding:0,lineHeight:1,flexShrink:0}}>✕</button>
                      </div>
                    );}
                    const e=item.data;
                    const evIcon=e.type==='Yellow Card'?'🟨':e.type==='Red Card'?'🟥':e.type==='Sub'?'→':'📝';
                    return(
                      <div key={'e'+i} style={{display:'flex',alignItems:'center',gap:6,padding:'5px 10px',borderBottom:'1px solid #0D0D0D'}}>
                        <span style={{fontSize:9,color:'#555',minWidth:20,fontWeight:700,flexShrink:0}}>{e.minute||'?'}'</span>
                        <div style={{width:20,height:20,borderRadius:'50%',background:'rgba(245,192,74,0.1)',border:'1px solid #2A2A2A',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:10}}>{evIcon}</div>
                        <div style={{flex:1,minWidth:0}}>
                          <div style={{fontSize:10,fontWeight:700,color:'#FFF',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{e.player||e.type}</div>
                          {e.type==='Sub'&&e.detail&&<div style={{fontSize:8,color:'#ef4444'}}>↓ {e.detail}</div>}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>

              {/* ── BOTTOM ROW: Upcoming Substitutions ── */}
              <div style={{flex:1,display:'flex',flexDirection:'column',overflow:'hidden'}}>
                <div style={{padding:'5px 10px 4px',borderBottom:'1px solid #1A1A1A',flexShrink:0}}>
                  <div style={{fontSize:9,fontWeight:800,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase'}}>UPCOMING SUBS</div>
                </div>
                <div style={{flex:1,overflowY:'auto',padding:'4px 0'}}>
                  {(()=>{
                    const nextP=halves[halfIdx]?.[pidx+1];
                    const curP=halves[halfIdx]?.[pidx];
                    if(!curP?.slots||!nextP?.slots){
                      return <div style={{fontSize:10,color:'#333',textAlign:'center',padding:'12px 0',fontStyle:'italic'}}>No subs planned</div>;
                    }
                    const subs=[];
                    posIds.forEach(id=>{const was=curP.slots[id],next=nextP.slots[id];if(was&&next&&was!==next)subs.push({on:next,off:was,pos:posLabel[id]||id});});
                    if(subs.length===0) return <div style={{fontSize:10,color:'#333',textAlign:'center',padding:'12px 0',fontStyle:'italic'}}>No subs planned</div>;
                    return subs.map((s,i)=>(
                      <div key={i} style={{display:'flex',alignItems:'center',gap:6,padding:'5px 10px',borderBottom:'1px solid #0D0D0D'}}>
                        <div style={{display:'flex',flexDirection:'column',gap:1,flex:1,minWidth:0}}>
                          <div style={{display:'flex',alignItems:'center',gap:4}}>
                            <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#22c55e" strokeWidth="2.5"><line x1="12" y1="19" x2="12" y2="5"/><polyline points="5 12 12 5 19 12"/></svg>
                            <span style={{fontSize:10,fontWeight:700,color:'#22c55e',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{s.on}</span>
                          </div>
                          <div style={{display:'flex',alignItems:'center',gap:4}}>
                            <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="#ef4444" strokeWidth="2.5"><line x1="12" y1="5" x2="12" y2="19"/><polyline points="19 12 12 19 5 12"/></svg>
                            <span style={{fontSize:10,fontWeight:700,color:'#ef4444',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{s.off}</span>
                          </div>
                        </div>
                        <span style={{fontSize:8,color:'#555',flexShrink:0}}>{s.pos}</span>
                      </div>
                    ));
                  })()}
                </div>
              </div>

              {/* Events link */}
              <div style={{padding:'5px 8px 6px',borderTop:'1px solid #1E1E1E',flexShrink:0}}>
                <button onClick={()=>setActiveMatchTab('events')}
                  style={{width:'100%',padding:'9px',background:'rgba(245,192,74,0.08)',border:'1px solid rgba(245,192,74,0.25)',borderRadius:9,color:'#F5C04A',fontSize:11,fontWeight:800,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',gap:6}}>
                  <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>
                  Match Events
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ──── EVENTS TAB (always mounted, hidden via CSS so triggers fire reliably) ──── */}
        <div style={{flex:1,overflow:'hidden',display:activeMatchTab==='events'?'flex':'none',flexDirection:'column'}}>
          <EventsPage halfElapsed={halfElapsed} goals={goals} matchEvents={matchEvents} setMatchEvents={setMatchEvents} opponentName={opponent||'Opposition'} ourName={config?.teamName||'My Team'} usGoalsLen={usGoals.length} themGoalsLen={themGoals.length} squad={squad} onGoal={(scorer,assist)=>logGoal(scorer,null)} onThemGoal={()=>logThemGoal()} onUndoGoal={()=>removeGoal(goals.filter(g=>g.team==='us').length-1)} onUndoThemGoal={removeThemGoal} quickNotes={quickNotes} setQuickNotes={setQuickNotes} triggerEventType={triggerEventType} onClearTrigger={()=>setTriggerEventType(null)} qnActive={qnActive} qnLiveText={qnLiveText} toggleQnDictation={toggleQnDictation} onReturnToMatch={()=>setActiveMatchTab('lineup')}/>
        </div>

        {/* ──── STATS TAB ──── */}
        {activeMatchTab==='stats'&&(
          <div style={{flex:1,overflowY:'auto',padding:'14px',display:'flex',flexDirection:'column',gap:12}}>
            <div style={{background:'#111111',borderRadius:12,padding:'14px',border:'1px solid #1A1A1A'}}>
              <div style={{fontSize:11,fontWeight:800,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase',marginBottom:10}}>MATCH SUMMARY</div>
              {[['Goals — Us',usGoals.length],['Goals — Them',themGoals.length],['Events logged',matchEvents.length],['Quick Notes',quickNotes.length||0]].map(([label,val])=>(
                <div key={label} style={{display:'flex',justifyContent:'space-between',fontSize:12,color:'#666',padding:'6px 0',borderBottom:'1px solid #1A1A1A'}}>
                  <span>{label}</span><span style={{fontWeight:800,color:'#FFF'}}>{val}</span>
                </div>
              ))}
            </div>
            {offSummary.length>0&&(
              <div style={{background:'#111111',borderRadius:12,padding:'14px',border:'1px solid #1A1A1A'}}>
                <div style={{fontSize:11,fontWeight:800,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase',marginBottom:10}}>PLAYER REST</div>
                {offSummary.map(([n,c])=>(
                  <div key={n} style={{display:'flex',alignItems:'center',gap:8,marginBottom:6}}>
                    <span style={{fontSize:11,color:'#FFF',flex:'0 0 90px',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{n}</span>
                    <div style={{flex:1,height:6,background:'#1A1A1A',borderRadius:3,overflow:'hidden'}}>
                      <div style={{width:`${Math.min(c/3*100,100)}%`,height:'100%',background:c>=2?'#f59e0b':'#22c55e',borderRadius:3}}/>
                    </div>
                    <span style={{fontSize:10,fontWeight:800,color:c>=2?'#f59e0b':'#22c55e',minWidth:18,textAlign:'right'}}>{c}×</span>
                  </div>
                ))}
              </div>
            )}
            <button style={{...S.btnGreen,width:'100%'}} onClick={generateReport}>📋 Generate Report</button>
          </div>
        )}

      </div>

      {/* ── QUICK ACTIONS BAR — shown on all non-events tabs; links directly into EventsPage modals ── */}
      {activeMatchTab!=='events'&&(
        <div style={{background:'#111111',borderTop:'1px solid #1E1E1E',padding:'8px 10px',paddingBottom:'max(8px,env(safe-area-inset-bottom))',marginBottom:60,flexShrink:0}}>
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr 1fr 1fr',gap:6}}>
            {/* End Match */}
            <button onClick={()=>{setRunning(false);if(isVoiceRecRef.current)stopVoice('');if(voiceNotes.trim()){setVoiceReview(voiceNotes);setModal('voiceReview');}else setModal('save');}}
              style={{padding:'10px 6px',background:'rgba(239,68,68,0.08)',border:'1px solid rgba(239,68,68,0.25)',borderRadius:10,cursor:'pointer',display:'flex',flexDirection:'column',alignItems:'center',gap:3}}>
              <svg width="16" height="16" viewBox="0 0 24 24" fill="#ef4444"><rect x="3" y="3" width="18" height="18" rx="3"/></svg>
              <span style={{fontSize:10,fontWeight:700,color:'#ef4444'}}>End Match</span>
            </button>
            {/* Goal */}
            <button onClick={()=>{setActiveMatchTab('events');setTriggerEventType('GOAL');}}
              style={{padding:'10px 6px',background:'rgba(34,197,94,0.1)',border:'1px solid rgba(34,197,94,0.3)',borderRadius:10,cursor:'pointer',display:'flex',flexDirection:'column',alignItems:'center',gap:3}}>
              <span style={{fontSize:18}}>⚽</span>
              <span style={{fontSize:10,fontWeight:700,color:'#22c55e'}}>Goal</span>
            </button>
            {/* Goal Conceded */}
            <button onClick={()=>{setActiveMatchTab('events');setTriggerEventType('GOAL_CONCEDED');}}
              style={{padding:'10px 6px',background:'rgba(239,68,68,0.1)',border:'1px solid rgba(239,68,68,0.3)',borderRadius:10,cursor:'pointer',display:'flex',flexDirection:'column',alignItems:'center',gap:3}}>
              <span style={{fontSize:18}}>🥅</span>
              <span style={{fontSize:10,fontWeight:700,color:'#ef4444'}}>Conceded</span>
            </button>
            {/* Quick Note */}
            <button onClick={toggleQnDictation}
              style={{padding:'10px 6px',background:qnActive?'rgba(239,68,68,0.15)':'#1A1A1A',border:`1px solid ${qnActive?'#ef4444':'#2A2A2A'}`,borderRadius:10,cursor:'pointer',display:'flex',flexDirection:'column',alignItems:'center',gap:3}}>
              {qnActive
                ? <><div style={{width:10,height:10,borderRadius:'50%',background:'#ef4444'}}/><span style={{fontSize:10,fontWeight:700,color:'#ef4444'}}>Stop</span></>
                : <><span style={{fontSize:18}}>📝</span><span style={{fontSize:10,fontWeight:700,color:'#A1A1A1'}}>Quick Note</span></>
              }
            </button>
          </div>
        </div>
      )}

      <BottomNav activeTab="match" onTab={(t)=>{if(t!=="match") onExit();}}/>
      <style>{`@keyframes pulse{from{opacity:1}to{opacity:0.3}}`}</style>
    </div>
  );
}

// ════════════════════════════════════════════════════════════════════════════════
//  ROOT
// ════════════════════════════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: IMPORT / EXPORT
// ════════════════════════════════════════════════════════════════════════════════
function ImportExportScreen({ onBack }) {
  const [confirmReset, setConfirmReset] = useState(false);
  const [status, setStatus]   = useState('');
  const [statusOk, setStatusOk] = useState(true);
  // Filename modal: { type, defaultName } | null
  const [exportPending, setExportPending] = useState(null);
  const [filename, setFilename] = useState('');

  function msg(text, ok=true){ setStatus(text); setStatusOk(ok); setTimeout(()=>setStatus(''),3500); }

  // ── CSV helpers ────────────────────────────────────────────────────────
  function esc(v){ const s=String(v??''); return (s.includes(',')||s.includes('"')||s.includes('\n'))?'"'+s.replace(/"/g,'""')+'"':s; }
  function row(arr){ return arr.map(esc).join(','); }

  function buildCsv(type) {
    if(type==='team'){
      const squad = JSON.parse(localStorage.getItem('soccerCoach_squad')||'[]');
      const lines = [row(['Name','Primary Position','Alt Position 1','Alt Position 2'])];
      squad.forEach(p=>lines.push(row([p.name, p.pos||'', p.pos2||'', p.pos3||''])));
      return lines.join('\n');
    }
    if(type==='scores'){
      const games   = JSON.parse(localStorage.getItem('soccerCoach_games')||'[]');
      const fxSc    = JSON.parse(localStorage.getItem('soccerCoach_fixtureScores')||'{}');
      const lines   = [row(['Date','Opponent','Our Score','Their Score','Result','Goal Scorers','MVP','Events'])];
      games.forEach(g=>{
        let us=g.scoreUs||0,them=g.scoreThem||0;
        if(g.linkedFixtureKey&&fxSc[g.linkedFixtureKey]){const sc=fxSc[g.linkedFixtureKey];us=g.fixtureIsHome?sc.home:sc.away;them=g.fixtureIsHome?sc.away:sc.home;}
        const res=us>them?'W':us<them?'L':'D';
        const scorers=[...new Set((g.goals||[]).filter(x=>x.team==='us').map(x=>x.scorer))].join('; ');
        const potm=Array.isArray(g.potm)?g.potm.join('; '):(g.potm||'');
        const evts=(g.matchEvents||[]).map(e=>e.minute+"' "+e.type+(e.team?' ('+e.team+')':'')).join('; ');
        lines.push(row([new Date(g.date).toLocaleDateString('en-AU'),g.opponent||'',us,them,res,scorers,potm,evts]));
      });
      return lines.join('\n');
    }
    if(type==='fixtures'){
      // Comma-separated CSV
      const SEP = ',';
      const tRow = arr => arr.map(v=>String(v).includes(',')?'"'+ v +'"':v).join(SEP);
      const fxSc = JSON.parse(localStorage.getItem('soccerCoach_fixtureScores')||'{}');
      const headers = ['Round','Date & Time (AEST)','Home Team','Away Team','Venue & Field','Match Status / Result'];
      const lines = [tRow(headers)];
      let lastRound = null;
      FIXTURES.forEach(f=>{
        const k = f.round+'|||'+f.home+'|||'+f.away;
        const sc = fxSc[k];
        let result;
        if(!sc)               result = '0:00';
        else if(sc.postponed) result = 'Postponed';
        else                  result = sc.home+':'+sc.away;
        const roundCell = f.round !== lastRound ? f.round : '';
        lastRound = f.round;
        // Format date: "2 May" + "9:30am" → "Sat, May 2, 2026, 09:30 AM"
        const year = new Date().getFullYear();
        const d = new Date((f.date||'')+ ' '+year);
        const dn = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][d.getDay()];
        const mn = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'][d.getMonth()];
        const tm = (f.time||'').replace(/^(\d+):(\d+)(am|pm)$/i,(_,h,m,p)=>String(h).padStart(2,'0')+':'+m+' '+p.toUpperCase());
        const dateTime = dn+', '+mn+' '+d.getDate()+', '+year+', '+tm;
        lines.push(tRow([roundCell, dateTime, f.home, f.away, f.venue||'', result]));
      });
      return lines.join('\n');
    }
    if(type==='all'){
      // JSON for full backup (CSV can't handle nested data)
      const ALL_KEYS=['soccerCoach_squad','soccerCoach_config','soccerCoach_games',
        'soccerCoach_settings','soccerCoach_fixtureScores','soccerCoach_teamNotes',
        'soccerCoach_teamNicknames','soccerCoach_fixtureTeam','soccerCoach_fixtures'];
      const data={_exported:new Date().toISOString()};
      ALL_KEYS.forEach(k=>{const v=localStorage.getItem(k);if(v)data[k]=JSON.parse(v);});
      return JSON.stringify(data,null,2);
    }
    return '';
  }

  // ── Export ────────────────────────────────────────────────────────────
  async function doExport() {
    const { type, fname } = exportPending || {};
    const isJson = type==='all';
    const ext    = isJson?'.json':'.csv';
    const mime   = isJson?'application/json':'text/csv';
    const finalName = (filename||fname)+ext;
    const data   = buildCsv(type);
    const blob   = new Blob([data], {type:mime});

    setExportPending(null); setFilename('');

    if(navigator.share && navigator.canShare){
      const file=new File([blob],finalName,{type:mime});
      if(navigator.canShare({files:[file]})){
        try{ await navigator.share({files:[file],title:finalName}); msg('Exported '+finalName); return; }
        catch(e){ if(e.name==='AbortError')return; }
      }
    }
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');
    a.href=url; a.download=finalName;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a);
    setTimeout(()=>URL.revokeObjectURL(url),1000);
    msg('Exported '+finalName);
  }

  // ── Import ────────────────────────────────────────────────────────────
  // Parse CSV or TSV — auto-detects separator from header row
  function parseSV(text){
    const lines = text.trim().split(/\r?\n/);
    if(lines.length<2) return [];
    const sep = lines[0].includes('\t') ? '\t' : ',';
    function splitLine(line){
      if(sep==='\t') return line.split('\t').map(s=>s.replace(/^"|"$/g,'').trim());
      const cols=[]; let cur='',inQ=false;
      for(let i=0;i<line.length;i++){
        const c=line[i];
        if(c==='"'&&!inQ){ inQ=true; }
        else if(c==='"'&&inQ&&line[i+1]==='"'){ cur+='"'; i++; }
        else if(c==='"'&&inQ){ inQ=false; }
        else if(c===sep&&!inQ){ cols.push(cur); cur=''; }
        else cur+=c;
      }
      cols.push(cur); return cols;
    }
    const headers = splitLine(lines[0]).map(h=>h.replace(/^"|"$/g,'').trim());
    return lines.slice(1).map(line=>{
      const cols=splitLine(line); const obj={};
      headers.forEach((h,i)=>obj[h]=(cols[i]||'').replace(/^"|"$/g,'').trim());
      return obj;
    });
  }

  function doImport(type){
    const input=document.createElement('input');
    input.type='file'; input.accept='.csv,.tsv,.txt,.json';
    input.onchange=e=>{
      const file=e.target.files[0]; if(!file)return;
      const reader=new FileReader();
      reader.onload=ev=>{
        try{
          const text=ev.target.result;
          const isJson=file.name.endsWith('.json');
          if(isJson){
            // Full JSON backup restore
            const data=JSON.parse(text);
            let count=0;
            Object.entries(data).forEach(([k,v])=>{if(k!=='_exported'){localStorage.setItem(k,JSON.stringify(v));count++;}});
            msg('Imported '+count+' data sets — reloading',true);
            setTimeout(()=>window.location.reload(),1500);
            return;
          }
          // CSV / TSV import
          const rows = parseSV(text);
          if(type==='team'){
            const squad=rows.map(r=>({name:r['Name'],pos:r['Primary Position']||'',pos2:r['Alt Position 1']||'',pos3:r['Alt Position 2']||''})).filter(p=>p.name);
            localStorage.setItem('soccerCoach_squad',JSON.stringify(squad));
            msg('Imported '+squad.length+' players — reloading',true);
            setTimeout(()=>window.location.reload(),1500);
          } else if(type==='scores'){
            // Rebuild game records from exported scores CSV
            const newGames = rows.map(r=>{
              const dateStr = (r['Date']||'').trim();
              const parts = dateStr.split('/'); // en-AU: d/m/yyyy
              let dateMs = Date.now();
              if(parts.length===3) dateMs = new Date(parts[2]+'-'+String(parts[1]).padStart(2,'0')+'-'+String(parts[0]).padStart(2,'0')).getTime();
              const us   = parseInt(r['Our Score'])||0;
              const them = parseInt(r['Their Score'])||0;
              const scorersStr = r['Goal Scorers']||'';
              const goals = scorersStr.split(';').map(s=>s.trim()).filter(Boolean).map(name=>({team:'us',scorer:name,secs:0}));
              const potm = (r['MVP']||'').trim();
              return {id:'g_imp_'+Date.now()+'_'+Math.random().toString(36).slice(2),
                date:dateMs, opponent:(r['Opponent']||'').trim(),
                scoreUs:us, scoreThem:them, goals, potm,
                halves:[], matchEvents:[], config:{}, voiceNotes:'', report:''};
            }).filter(g=>g.opponent);
            // Merge — skip rows already matching date+opponent
            const existing = loadGames();
            const eKeys = new Set(existing.map(g=>new Date(g.date).toLocaleDateString('en-AU')+'|'+g.opponent));
            const toAdd = newGames.filter(g=>!eKeys.has(new Date(g.date).toLocaleDateString('en-AU')+'|'+g.opponent));
            saveGames([...existing, ...toAdd]);
            msg('Imported '+toAdd.length+' game records'+(newGames.length-toAdd.length>0?' ('+( newGames.length-toAdd.length)+' skipped — already exist)':'')+' — reloading',true);
            setTimeout(()=>window.location.reload(),1500);
          } else if(type==='fixtures'){
            // Parse FA-format date "Sat, May 2, 2026, 09:30 AM" -> {date:"2 May", time:"9:30am"}
            function parseFADateTime(str) {
              if(!str) return {date:'',time:''};
              const m = str.match(/\w+,\s+(\w+)\s+(\d+),\s+\d+,\s+(\d+):(\d+)\s+(AM|PM)/i);
              if(!m) return {date:str, time:''};
              const [,mon,day,h,min,ampm] = m;
              return {date:day+' '+mon, time:h+':'+min+ampm.toLowerCase()};
            }
            const fxSc = {}; const fxArr = []; let scCount = 0; let lastRound = '';
            rows.forEach(r=>{
              const round = (r['Round']||'').trim() || lastRound;
              if(round) lastRound = round;
              const home = (r['Home Team']||r['Home']||'').trim();
              const away = (r['Away Team']||r['Away']||'').trim();
              if(!round||!home||!away) return;
              const k = round+'|||'+home+'|||'+away;
              // Save fixture schedule row
              const dt = parseFADateTime(r['Date & Time (AEST)']||'');
              fxArr.push({round, home, away, date:dt.date, time:dt.time, venue:(r['Venue & Field']||'').trim()});
              // Save score
              const result = (r['Match Status / Result']||r['Status']||'').trim();
              if(result && result!=='0:00'){
                if(result.toLowerCase()==='postponed'){ fxSc[k]={postponed:true}; scCount++; }
                else {
                  const parts = result.split(/[:\-]/);
                  if(parts.length===2){
                    const h=parseInt(parts[0]), a=parseInt(parts[1]);
                    if(!isNaN(h)&&!isNaN(a)){ fxSc[k]={home:h,away:a}; scCount++; }
                  }
                }
              }
            });
            // Overwrite both stores
            if(fxArr.length>0) saveFixtures(fxArr);
            localStorage.setItem('soccerCoach_fixtureScores',JSON.stringify(fxSc));
            msg('Imported '+fxArr.length+' fixtures, '+scCount+' results - reloading',true);
            setTimeout(()=>window.location.reload(),1500);
          }
        }catch(err){msg('Could not import: '+err.message,false);}
      };
      reader.readAsText(file);
    };
    input.click();
  }

  // ── Reset ─────────────────────────────────────────────────────────────
  function doReset(){
    ['soccerCoach_squad','soccerCoach_config','soccerCoach_games','soccerCoach_settings',
     'soccerCoach_fixtureScores','soccerCoach_teamNotes','soccerCoach_teamNicknames','soccerCoach_fixtureTeam','soccerCoach_fixtures']
      .forEach(k=>localStorage.removeItem(k));
    msg('All data cleared — reloading',true);
    setTimeout(()=>window.location.reload(),1200);
  }

  const CARD='#1A1A1A';
  const today=new Date().toISOString().split('T')[0];

  function Section({icon,title,subtitle,type,defaultName}){
    return(
      <div style={{background:CARD,borderRadius:12,padding:'14px 16px',marginBottom:10}}>
        <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:10}}>
          <span style={{fontSize:20}}>{icon}</span>
          <div><div style={{fontSize:14,fontWeight:700,color:'#FFFFFF'}}>{title}</div>
          <div style={{fontSize:11,color:'#A1A1A1'}}>{subtitle}</div></div>
        </div>
        <div style={{display:'flex',gap:8}}>
          <button onClick={()=>{setExportPending({type,fname:defaultName});setFilename(defaultName);}}
            style={{flex:1,padding:'11px',borderRadius:9,border:'none',background:'#E9AA23',color:'#fff',fontWeight:700,fontSize:13,cursor:'pointer'}}>
            ↑ Export {type==='all'?'JSON':'CSV'}
          </button>
          <button onClick={()=>doImport(type)}
            style={{flex:1,padding:'11px',borderRadius:9,border:'none',background:'#164e63',color:'#7dd3fc',fontWeight:700,fontSize:13,cursor:'pointer'}}>
            ↓ Import
          </button>
        </div>
      </div>
    );
  }

  return(
    <div style={{ minHeight:'100vh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)', display:'flex', flexDirection:'column' }}>
      {/* Header */}
      <div style={{ position:'relative', display:'flex', alignItems:'center', padding:'14px 16px 10px', background:'#111111', borderBottom:'1px solid #1A1A1A', flexShrink:0 }}>
        <button onClick={onBack} style={{ background:'none', border:'none', cursor:'pointer', color:'#A1A1A1', fontSize:22, padding:0, lineHeight:1, position:'absolute', left:16 }}>←</button>
        <div style={{ flex:1, textAlign:'center', fontSize:14, fontWeight:700, color:'#FFFFFF', letterSpacing:2, textTransform:'uppercase' }}>Import / Export</div>
      </div>
      {/* Filename modal */}
      {exportPending&&(
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.7)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:9999,padding:24}}>
          <div style={{background:'#1A1A1A',borderRadius:16,padding:24,width:'100%',maxWidth:380}}>
            <div style={{fontSize:16,fontWeight:800,color:'#FFFFFF',marginBottom:4}}>Save as</div>
            <div style={{fontSize:12,color:'#A1A1A1',marginBottom:16}}>Enter a filename for your export</div>
            <div style={{display:'flex',alignItems:'center',background:'#0D0D0D',border:'1px solid #2A2A2A',borderRadius:9,padding:'10px 12px',marginBottom:16,gap:4}}>
              <input autoFocus value={filename} onChange={e=>setFilename(e.target.value)}
                onKeyDown={e=>{if(e.key==='Enter')doExport();if(e.key==='Escape'){setExportPending(null);setFilename('');}}}
                style={{flex:1,background:'none',border:'none',color:'#FFFFFF',fontSize:14,outline:'none',fontFamily:'inherit'}}
                placeholder="filename" />
              <span style={{fontSize:12,color:'#A1A1A1',flexShrink:0}}>{exportPending.type==='all'?'.json':'.csv'}</span>
            </div>
            <div style={{display:'flex',gap:8}}>
              <button onClick={doExport} style={{flex:2,padding:'12px',borderRadius:9,border:'none',background:'#E9AA23',color:'#fff',fontWeight:700,fontSize:14,cursor:'pointer'}}>
                Export
              </button>
              <button onClick={()=>{setExportPending(null);setFilename('');}} style={{flex:1,padding:'12px',borderRadius:9,border:'1px solid #2A2A2A',background:'transparent',color:'#A1A1A1',fontWeight:700,fontSize:14,cursor:'pointer'}}>
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      <div style={{ flex:1, overflowY:'auto', padding:'16px' }}>
      {status&&<div style={{background:statusOk?'#110D00':'#3a0b0b',border:'1px solid '+(statusOk?'#F5C04A44':'#ef444444'),borderRadius:9,padding:'10px 14px',marginBottom:14,fontSize:13,color:statusOk?'#FCD34D':'#fca5a5',fontWeight:600,flexShrink:0}}>{status}</div>}
        <Section icon="👥" title="Squad" subtitle="Player names & positions (CSV)" type="team" defaultName={'squad-'+today} />
        <Section icon="📊" title="Scores" subtitle="Game results and match events" type="scores" defaultName={'scores-'+today} />
        <Section icon="📅" title="Fixtures" subtitle="Fixture results and team" type="fixtures" defaultName={'fixtures-'+today} />
        <Section icon="📦" title="Everything" subtitle="Full JSON backup — all data" type="all" defaultName={'soccer-backup-'+today} />

        <div style={{background:'#3a0b0b',border:'1px solid #ef444433',borderRadius:12,padding:'14px 16px',marginTop:4}}>
          <div style={{fontSize:14,fontWeight:700,color:'#fca5a5',marginBottom:4}}>🗑 Reset All Data</div>
          <div style={{fontSize:11,color:'#A1A1A1',marginBottom:12}}>Permanently clears everything. Export a backup first.</div>
          {!confirmReset
            ?<button onClick={()=>setConfirmReset(true)} style={{width:'100%',padding:'11px',borderRadius:9,border:'1px solid #ef4444',background:'transparent',color:'#ef4444',fontWeight:700,fontSize:13,cursor:'pointer'}}>Reset All Data</button>
            :<div style={{display:'flex',gap:8}}>
              <button onClick={doReset} style={{flex:1,padding:'11px',borderRadius:9,border:'none',background:'#ef4444',color:'#fff',fontWeight:700,fontSize:13,cursor:'pointer'}}>Yes, delete everything</button>
              <button onClick={()=>setConfirmReset(false)} style={{flex:1,padding:'11px',borderRadius:9,border:'1px solid #2A2A2A',background:'transparent',color:'#A1A1A1',fontWeight:700,fontSize:13,cursor:'pointer'}}>Cancel</button>
            </div>
          }
        </div>
        <div style={{borderTop:"1px solid #1E1E1E",paddingTop:10,marginTop:4}}>
          <button style={S.btnGhost} onClick={onBack}>← Menu</button>
        </div>
      </div>
    </div>
  );
}



// ════════════════════════════════════════════════════════════════════════════════
//  HELPERS — HOME SCREEN
// ════════════════════════════════════════════════════════════════════════════════
function getGreeting() {
  const h = new Date().getHours();
  if (h < 12) return 'Good morning';
  if (h < 17) return 'Good afternoon';
  return 'Good evening';
}

function getInitials(name) {
  if (!name) return '?';
  const parts = name.trim().split(/\s+/);
  return parts.length >= 2
    ? (parts[0][0] + parts[parts.length - 1][0]).toUpperCase()
    : name[0].toUpperCase();
}

// ════════════════════════════════════════════════════════════════════════════════
//  COMPONENT: BOTTOM NAV BAR
// ════════════════════════════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════════════════════════════
//  SCREEN: TRAINING
// ════════════════════════════════════════════════════════════════════════════════
function TrainingScreen({ onBack }) {
  const [view,            setView]    = useState('hub');
  const [library,         setLibrary] = useState(() => loadTrainingLibrary());
  const [logs,            setLogs]    = useState(() => loadTrainingLogs());
  const [activeTopic,     setActiveTopic]   = useState(null);
  const [activeSession,   setActiveSession] = useState(null);
  const [expandedPhase,   setExpandedPhase] = useState(null);
  const [logForm,         setLogForm]   = useState({ players:'', wellDone:'', improve:'', playerNotes:'', toes:{touches:3,organisation:3,enjoyment:3,safety:3} });
  const [filterCat,       setFilterCat] = useState('all');
  const [importError,     setImportError] = useState('');
  const [importSuccess,   setImportSuccess] = useState('');
  const fileInputRef = useRef(null);

  const CATS = [
    { id:'all', label:'All' },
    { id:'attacking', label:'Attacking' },
    { id:'defending', label:'Defending' },
    { id:'transition', label:'Transition' },
    { id:'tactical', label:'Tactical' },
    { id:'set-pieces', label:'Set Pieces' },
  ];

  const CAT_COLORS = {
    attacking:   { bg:'#22c55e22', border:'#22c55e44', text:'#22c55e' },
    defending:   { bg:'#ef444422', border:'#ef444444', text:'#ef4444' },
    transition:  { bg:'#a78bfa22', border:'#a78bfa44', text:'#a78bfa' },
    tactical:    { bg:'#F5C04A22', border:'#F5C04A44', text:'#F5C04A' },
    'set-pieces':{ bg:'#38bdf822', border:'#38bdf844', text:'#38bdf8' },
  };

  const PHASE_ICONS = { rondo:'⚽', positioning:'🔵', game:'🏟️' };

  const filteredTopics = (library.topics||[]).filter(t => filterCat==='all' || t.category===filterCat);

  // ── Back navigation ─────────────────────────────────────────────
  function goBack() {
    if (view==='detail' || view==='logs' || view==='importexport') { setView('hub'); return; }
    if (view==='browse') { setView('hub'); return; }
    if (view==='logger') { setView('detail'); return; }
    onBack();
  }

  // ── Export library as JSON ───────────────────────────────────────
  function doExport() {
    const data = JSON.stringify(library, null, 2);
    const blob = new Blob([data], { type:'application/json' });
    const url  = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'training-library.json'; a.click();
    URL.revokeObjectURL(url);
  }

  // ── Export logs as JSON ──────────────────────────────────────────
  function doExportLogs() {
    const data = JSON.stringify(logs, null, 2);
    const blob = new Blob([data], { type:'application/json' });
    const url  = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'training-logs.json'; a.click();
    URL.revokeObjectURL(url);
  }

  // ── Import library from JSON ────────────────────────────────────
  function doImport(e) {
    const file = e.target.files[0];
    if (!file) return;
    setImportError(''); setImportSuccess('');
    const reader = new FileReader();
    reader.onload = evt => {
      try {
        const parsed = JSON.parse(evt.target.result);
        if (!parsed.topics || !Array.isArray(parsed.topics)) throw new Error('Invalid format — must have a "topics" array');
        const updated = { ...parsed, updated: new Date().toISOString().slice(0,10) };
        setLibrary(updated);
        saveTrainingLibrary(updated);
        setImportSuccess(`✓ Imported ${parsed.topics.length} topics successfully`);
      } catch(err) {
        setImportError('❌ Import failed: ' + err.message);
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  }

  // ── Reset to defaults ────────────────────────────────────────────
  function doReset() {
    if (!window.confirm('Reset the training library to the original built-in content? This will overwrite any custom edits.')) return;
    setLibrary(DEFAULT_TRAINING_LIBRARY);
    saveTrainingLibrary(DEFAULT_TRAINING_LIBRARY);
    setImportSuccess('✓ Library reset to built-in defaults');
  }

  // ── Save a training session log ──────────────────────────────────
  function doSaveLog() {
    const newLog = {
      id: Date.now(),
      date: new Date().toISOString().slice(0,10),
      topicId:     activeTopic?.id,
      topicTitle:  activeTopic?.title,
      sessionNum:  activeSession?.number,
      players:     logForm.players,
      wellDone:    logForm.wellDone,
      improve:     logForm.improve,
      playerNotes: logForm.playerNotes,
      toes: { ...logForm.toes },
    };
    const updated = [newLog, ...logs];
    setLogs(updated);
    saveTrainingLogs(updated);
    setLogForm({ players:'', wellDone:'', improve:'', playerNotes:'', toes:{touches:3,organisation:3,enjoyment:3,safety:3} });
    setView('logs');
  }

  // ── Delete a log ─────────────────────────────────────────────────
  function doDeleteLog(id) {
    if (!window.confirm('Delete this session log?')) return;
    const updated = logs.filter(l => l.id !== id);
    setLogs(updated);
    saveTrainingLogs(updated);
  }

  // ── Common styles ────────────────────────────────────────────────
  const pg = {
    minHeight:'100dvh', background:'#0D0D0D', display:'flex', flexDirection:'column',
    paddingTop:'max(env(safe-area-inset-top),0px)',
    paddingBottom:'calc(env(safe-area-inset-bottom) + 80px)',
  };
  const hdr = {
    background:'#111111', borderBottom:'1px solid #1E1E1E',
    padding:'14px 16px', display:'flex', alignItems:'center', gap:12,
    position:'sticky', top:0, zIndex:10,
  };
  const body = { flex:1, overflowY:'auto', padding:'16px' };
  const card = {
    background:'#111111', border:'1px solid #1E1E1E', borderRadius:14,
    padding:'14px 16px', marginBottom:10,
  };
  const inp  = {
    background:'#0D0D0D', border:'1px solid #2A2A2A', borderRadius:8,
    color:'#FFFFFF', fontSize:14, padding:'10px 12px', width:'100%',
    boxSizing:'border-box', fontFamily:'inherit', outline:'none',
  };
  const ta   = { ...inp, minHeight:70, resize:'vertical' };
  const lbl  = { fontSize:12, fontWeight:700, color:'#A1A1A1', marginBottom:4, display:'block' };
  const btn  = (bg, col='#0D0D0D') => ({
    background:bg, color:col, border:'none', borderRadius:10,
    padding:'12px 16px', fontWeight:800, fontSize:14, cursor:'pointer',
    width:'100%', marginBottom:8, letterSpacing:0.3,
  });
  const btnSm = (bg, col='#0D0D0D') => ({
    background:bg, color:col, border:'none', borderRadius:8,
    padding:'8px 14px', fontWeight:700, fontSize:13, cursor:'pointer', letterSpacing:0.3,
  });
  const backBtn = {
    background:'none', border:'none', color:'#F5C04A', fontSize:22,
    cursor:'pointer', padding:0, lineHeight:1,
  };

  // ════ VIEWS ═══════════════════════════════════════════════════════

  // ── HUB ─────────────────────────────────────────────────────────
  if (view === 'hub') {
    const totalSessions = logs.length;
    const lastDate = logs.length ? logs[0].date : null;
    const daysSince = lastDate ? Math.floor((Date.now()-new Date(lastDate).getTime())/86400000) : null;

    return (
      <div style={pg}>
        <div style={hdr}>
          <button style={backBtn} onClick={onBack}>‹</button>
          <div style={{flex:1}}>
            <div style={{fontSize:18, fontWeight:800, color:'#FFFFFF'}}>Training</div>
            <div style={{fontSize:11, color:'#A1A1A1'}}>Plan sessions · Log results · Manage content</div>
          </div>
        </div>
        <div style={body}>
          {/* Stats bar */}
          <div style={{display:'flex', gap:10, marginBottom:16}}>
            <div style={{...card, flex:1, marginBottom:0, textAlign:'center'}}>
              <div style={{fontSize:22, fontWeight:800, color:'#F5C04A'}}>{totalSessions}</div>
              <div style={{fontSize:11, color:'#A1A1A1', marginTop:2}}>Sessions logged</div>
            </div>
            <div style={{...card, flex:1, marginBottom:0, textAlign:'center'}}>
              <div style={{fontSize:22, fontWeight:800, color:'#a78bfa'}}>{daysSince===null ? '—' : daysSince===0 ? 'Today' : daysSince+'d ago'}</div>
              <div style={{fontSize:11, color:'#A1A1A1', marginTop:2}}>Last session</div>
            </div>
          </div>

          {/* Main actions */}
          <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:10, marginBottom:16}}>
            {[
              { icon:'📋', title:'Browse Sessions', sub:'All 11 topics', action:()=>setView('browse'), color:'#F5C04A' },
              { icon:'📝', title:'Session Log', sub:`${totalSessions} recorded`, action:()=>setView('logs'), color:'#22c55e' },
              { icon:'⬆️', title:'Import / Export', sub:'Edit & reload content', action:()=>setView('importexport'), color:'#a78bfa' },
            ].map(tile => (
              <button key={tile.title} onClick={tile.action} style={{
                background:'#111111', border:`1px solid ${tile.color}33`,
                borderRadius:14, padding:'16px 14px', cursor:'pointer',
                textAlign:'left', display:'flex', flexDirection:'column', gap:6,
                gridColumn: tile.title==='Import / Export' ? 'span 2' : undefined,
              }}>
                <span style={{fontSize:24}}>{tile.icon}</span>
                <span style={{fontSize:14, fontWeight:700, color:'#FFFFFF'}}>{tile.title}</span>
                <span style={{fontSize:12, color:'#A1A1A1'}}>{tile.sub}</span>
              </button>
            ))}
          </div>

          {/* Recent sessions */}
          {logs.length > 0 && (
            <div>
              <div style={{fontSize:13, fontWeight:700, color:'#A1A1A1', marginBottom:8, letterSpacing:1}}>RECENT</div>
              {logs.slice(0,3).map(log => (
                <div key={log.id} style={{...card, display:'flex', alignItems:'center', gap:12}}>
                  <div style={{width:40, height:40, borderRadius:10, background:'#1A1A1A', display:'flex', alignItems:'center', justifyContent:'center', fontSize:20, flexShrink:0}}>
                    {(library.topics||[]).find(t=>t.id===log.topicId)?.icon || '⚽'}
                  </div>
                  <div style={{flex:1, minWidth:0}}>
                    <div style={{fontSize:14, fontWeight:700, color:'#FFFFFF', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis'}}>{log.topicTitle} — Session {log.sessionNum}</div>
                    <div style={{fontSize:12, color:'#A1A1A1'}}>{log.date} · {log.players || '?'} players</div>
                  </div>
                  <div style={{fontSize:18}}>{['','😐','😐','🙂','😄','🤩'][Math.round((log.toes.touches+log.toes.organisation+log.toes.enjoyment+log.toes.safety)/4)]||'⚽'}</div>
                </div>
              ))}
              {logs.length > 3 && (
                <button onClick={()=>setView('logs')} style={{...btn('#1A1A1A','#A1A1A1'), marginTop:4, border:'1px solid #2A2A2A'}}>
                  View all {logs.length} sessions →
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── BROWSE ───────────────────────────────────────────────────────
  if (view === 'browse') {
    return (
      <div style={pg}>
        <div style={hdr}>
          <button style={backBtn} onClick={goBack}>‹</button>
          <div style={{fontSize:17, fontWeight:800, color:'#FFFFFF', flex:1}}>Browse Sessions</div>
        </div>
        <div style={body}>
          {/* Category filter */}
          <div style={{display:'flex', gap:6, overflowX:'auto', marginBottom:14, paddingBottom:4}}>
            {CATS.map(c => (
              <button key={c.id} onClick={()=>setFilterCat(c.id)} style={{
                background: filterCat===c.id ? '#F5C04A' : '#1A1A1A',
                color: filterCat===c.id ? '#0D0D0D' : '#A1A1A1',
                border: filterCat===c.id ? 'none' : '1px solid #2A2A2A',
                borderRadius:20, padding:'6px 14px', fontSize:12, fontWeight:700,
                cursor:'pointer', whiteSpace:'nowrap', flexShrink:0,
              }}>{c.label}</button>
            ))}
          </div>
          {/* Topic grid */}
          <div style={{display:'grid', gridTemplateColumns:'1fr 1fr', gap:10}}>
            {filteredTopics.map(topic => {
              const cc = CAT_COLORS[topic.category] || CAT_COLORS.tactical;
              return (
                <button key={topic.id} onClick={()=>{setActiveTopic(topic);setActiveSession(null);setExpandedPhase(null);setView('detail');}} style={{
                  background:'#111111', border:`1px solid ${cc.border}`,
                  borderRadius:14, padding:'16px 14px', cursor:'pointer',
                  textAlign:'left', display:'flex', flexDirection:'column', gap:8,
                }}>
                  <span style={{fontSize:28}}>{topic.icon}</span>
                  <span style={{fontSize:14, fontWeight:700, color:'#FFFFFF', lineHeight:1.2}}>{topic.title}</span>
                  <span style={{
                    fontSize:10, fontWeight:700, color:cc.text,
                    background:cc.bg, border:`1px solid ${cc.border}`,
                    borderRadius:20, padding:'2px 8px', alignSelf:'flex-start',
                    letterSpacing:0.5, textTransform:'uppercase',
                  }}>{topic.category}</span>
                  <span style={{fontSize:11, color:'#A1A1A1'}}>{topic.sessions?.length || 0} session{(topic.sessions?.length||0)!==1?'s':''}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    );
  }

  // ── SESSION DETAIL ───────────────────────────────────────────────
  if (view === 'detail' && activeTopic) {
    const cc = CAT_COLORS[activeTopic.category] || CAT_COLORS.tactical;
    const sessions = activeTopic.sessions || [];
    const sess = activeSession || sessions[0];

    return (
      <div style={pg}>
        <div style={hdr}>
          <button style={backBtn} onClick={goBack}>‹</button>
          <div style={{flex:1, minWidth:0}}>
            <div style={{fontSize:17, fontWeight:800, color:'#FFFFFF', whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis'}}>{activeTopic.icon} {activeTopic.title}</div>
            <div style={{fontSize:11, color:'#A1A1A1'}}>{activeTopic.ageGroup}</div>
          </div>
        </div>
        <div style={body}>
          {/* Principle block */}
          <div style={{...card, borderColor:cc.border, marginBottom:14}}>
            <div style={{fontSize:11, fontWeight:700, color:cc.text, letterSpacing:1, marginBottom:6, textTransform:'uppercase'}}>Principle</div>
            <div style={{fontSize:14, fontWeight:600, color:'#FFFFFF', lineHeight:1.5, marginBottom:8}}>{activeTopic.principle}</div>
            <div style={{fontSize:12, color:'#A1A1A1', fontStyle:'italic', marginBottom:10}}>"{activeTopic.behaviour}"</div>

            {activeTopic.moments?.length > 0 && (
              <>
                <div style={{fontSize:11, fontWeight:700, color:'#A1A1A1', letterSpacing:1, marginBottom:4}}>WHEN TO USE IT</div>
                {activeTopic.moments.map((m,i) => (
                  <div key={i} style={{fontSize:12, color:'#CBD5E1', paddingLeft:10, borderLeft:`2px solid ${cc.border}`, marginBottom:4}}>{m}</div>
                ))}
              </>
            )}

            {activeTopic.keyPoints?.length > 0 && (
              <>
                <div style={{fontSize:11, fontWeight:700, color:'#A1A1A1', letterSpacing:1, marginTop:10, marginBottom:4}}>KEY COACHING POINTS</div>
                {activeTopic.keyPoints.map((p,i) => (
                  <div key={i} style={{fontSize:12, color:'#CBD5E1', display:'flex', gap:6, marginBottom:3}}>
                    <span style={{color:cc.text, flexShrink:0}}>•</span>{p}
                  </div>
                ))}
              </>
            )}
          </div>

          {/* Session selector */}
          {sessions.length > 1 && (
            <div style={{display:'flex', gap:8, marginBottom:12}}>
              {sessions.map(s => (
                <button key={s.number} onClick={()=>{setActiveSession(s);setExpandedPhase(null);}} style={{
                  flex:1, padding:'10px', borderRadius:10, cursor:'pointer', fontWeight:700, fontSize:14,
                  background: (sess?.number===s.number) ? '#F5C04A' : '#1A1A1A',
                  color:       (sess?.number===s.number) ? '#0D0D0D'  : '#A1A1A1',
                  border: (sess?.number===s.number) ? 'none' : '1px solid #2A2A2A',
                }}>Session {s.number}</button>
              ))}
            </div>
          )}

          {/* Phase blocks */}
          {(sess?.phases||[]).map((phase, pi) => {
            const isOpen = expandedPhase === pi;
            const totalMins = (sess.phases||[]).reduce((a,p)=>a+(p.duration||0),0);
            return (
              <div key={pi} style={{...card, marginBottom:8}}>
                <button onClick={()=>setExpandedPhase(isOpen ? null : pi)} style={{
                  background:'none', border:'none', width:'100%', textAlign:'left',
                  cursor:'pointer', padding:0, display:'flex', alignItems:'center', gap:10,
                }}>
                  <div style={{
                    width:36, height:36, borderRadius:10, background:'#1A1A1A',
                    display:'flex', alignItems:'center', justifyContent:'center', fontSize:18, flexShrink:0,
                  }}>{PHASE_ICONS[phase.type]||'⚽'}</div>
                  <div style={{flex:1}}>
                    <div style={{fontSize:14, fontWeight:700, color:'#FFFFFF'}}>{phase.name}</div>
                    <div style={{fontSize:11, color:'#A1A1A1'}}>{phase.duration} min · Phase {pi+1} of {sess.phases?.length}</div>
                  </div>
                  <div style={{fontSize:16, color:'#A1A1A1'}}>{isOpen ? '▲' : '▼'}</div>
                </button>

                {isOpen && (
                  <div style={{marginTop:14, borderTop:'1px solid #1E1E1E', paddingTop:12}}>
                    {phase.setup && (
                      <div style={{marginBottom:10}}>
                        <div style={{...lbl}}>SETUP</div>
                        <div style={{fontSize:13, color:'#CBD5E1', lineHeight:1.5}}>{phase.setup}</div>
                      </div>
                    )}
                    {phase.rules?.length > 0 && (
                      <div style={{marginBottom:10}}>
                        <div style={{...lbl}}>RULES</div>
                        {phase.rules.map((r,i)=>(
                          <div key={i} style={{fontSize:12, color:'#CBD5E1', display:'flex', gap:6, marginBottom:4}}>
                            <span style={{color:'#F5C04A', flexShrink:0}}>{i+1}.</span>{r}
                          </div>
                        ))}
                      </div>
                    )}
                    {phase.progressions?.length > 0 && (
                      <div style={{marginBottom:10}}>
                        <div style={{...lbl, color:'#22c55e'}}>PROGRESSIONS</div>
                        {phase.progressions.map((p,i)=>(
                          <div key={i} style={{fontSize:12, color:'#CBD5E1', display:'flex', gap:6, marginBottom:4}}>
                            <span style={{color:'#22c55e', flexShrink:0}}>→</span>{p}
                          </div>
                        ))}
                      </div>
                    )}
                    {phase.dualForce && (
                      <div style={{marginBottom:10}}>
                        <div style={{...lbl, color:'#a78bfa'}}>DUAL FORCE / SPEED AGILITY</div>
                        <div style={{fontSize:12, color:'#CBD5E1', lineHeight:1.5}}>{phase.dualForce}</div>
                      </div>
                    )}
                    {phase.coaching?.length > 0 && (
                      <div>
                        <div style={{...lbl, color:'#F5C04A'}}>COACHING POINTS</div>
                        {phase.coaching.map((c,i)=>(
                          <div key={i} style={{fontSize:12, color:'#CBD5E1', display:'flex', gap:6, marginBottom:4}}>
                            <span style={{color:'#F5C04A', flexShrink:0}}>⭐</span>{c}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}

          {/* Timing summary */}
          {sess?.phases?.length > 0 && (
            <div style={{...card, display:'flex', justifyContent:'space-between', alignItems:'center', marginTop:4}}>
              <span style={{fontSize:12, color:'#A1A1A1'}}>Total session time</span>
              <span style={{fontSize:16, fontWeight:800, color:'#F5C04A'}}>{(sess.phases||[]).reduce((a,p)=>a+(p.duration||0),0)} min</span>
            </div>
          )}

          {/* Log this session */}
          <button onClick={()=>{setLogForm({players:'',wellDone:'',improve:'',playerNotes:'',toes:{touches:3,organisation:3,enjoyment:3,safety:3}});setView('logger');}} style={{...btn('#F5C04A'), marginTop:12}}>
            ✏️ Log This Session
          </button>
        </div>
      </div>
    );
  }

  // ── SESSION LOGGER ───────────────────────────────────────────────
  if (view === 'logger') {
    const TOES_LABELS = [
      { key:'touches', label:'Touches', sub:'Did every player touch the ball often?' },
      { key:'organisation', label:'Organisation', sub:'Was the session well run?' },
      { key:'enjoyment', label:'Enjoyment', sub:'Were kids having fun?' },
      { key:'safety', label:'Safety', sub:'Was it safe throughout?' },
    ];
    const RATINGS = ['—','😐','😐','🙂','😄','🤩'];

    return (
      <div style={pg}>
        <div style={hdr}>
          <button style={backBtn} onClick={goBack}>‹</button>
          <div style={{flex:1}}>
            <div style={{fontSize:17, fontWeight:800, color:'#FFFFFF'}}>Log Session</div>
            <div style={{fontSize:11, color:'#A1A1A1'}}>{activeTopic?.title} — Session {(activeSession||activeTopic?.sessions?.[0])?.number}</div>
          </div>
        </div>
        <div style={body}>
          <div style={card}>
            <div style={{...lbl}}>DATE</div>
            <div style={{fontSize:14, color:'#FFFFFF', marginBottom:12}}>{new Date().toLocaleDateString('en-AU',{weekday:'long',day:'numeric',month:'long'})}</div>
            <div style={{...lbl}}>NUMBER OF PLAYERS</div>
            <input style={{...inp, marginBottom:12}} type="number" min="1" max="30" placeholder="How many players today?" value={logForm.players} onChange={e=>setLogForm(f=>({...f,players:e.target.value}))} />
            <div style={{...lbl}}>WHAT WENT WELL</div>
            <textarea style={{...ta, marginBottom:12}} placeholder="What worked? Any standout moments?" value={logForm.wellDone} onChange={e=>setLogForm(f=>({...f,wellDone:e.target.value}))} />
            <div style={{...lbl}}>WHAT TO IMPROVE</div>
            <textarea style={{...ta, marginBottom:12}} placeholder="What would you change next time?" value={logForm.improve} onChange={e=>setLogForm(f=>({...f,improve:e.target.value}))} />
            <div style={{...lbl}}>PLAYER NOTES</div>
            <textarea style={{...ta, marginBottom:16}} placeholder="Individual player observations (optional)" value={logForm.playerNotes} onChange={e=>setLogForm(f=>({...f,playerNotes:e.target.value}))} />

            {/* T.O.E.S */}
            <div style={{fontSize:12, fontWeight:700, color:'#F5C04A', letterSpacing:1, marginBottom:10}}>CREATE T.O.E.S SELF-REFLECTION</div>
            {TOES_LABELS.map(({key,label,sub}) => (
              <div key={key} style={{marginBottom:12}}>
                <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:4}}>
                  <div>
                    <span style={{fontSize:13, fontWeight:700, color:'#FFFFFF'}}>{label}</span>
                    <span style={{fontSize:11, color:'#A1A1A1', display:'block'}}>{sub}</span>
                  </div>
                  <span style={{fontSize:20}}>{RATINGS[logForm.toes[key]]}</span>
                </div>
                <div style={{display:'flex', gap:4}}>
                  {[1,2,3,4,5].map(v => (
                    <button key={v} onClick={()=>setLogForm(f=>({...f,toes:{...f.toes,[key]:v}}))} style={{
                      flex:1, padding:'8px 0', borderRadius:8, cursor:'pointer', fontSize:13, fontWeight:700,
                      background: logForm.toes[key]>=v ? '#F5C04A' : '#1A1A1A',
                      color:       logForm.toes[key]>=v ? '#0D0D0D' : '#A1A1A1',
                      border: logForm.toes[key]>=v ? 'none' : '1px solid #2A2A2A',
                    }}>{v}</button>
                  ))}
                </div>
              </div>
            ))}
          </div>
          <button onClick={doSaveLog} style={btn('#F5C04A')}>✓ Save Session Log</button>
          <button onClick={goBack} style={{...btn('#1A1A1A','#A1A1A1'), border:'1px solid #2A2A2A'}}>Cancel</button>
        </div>
      </div>
    );
  }

  // ── SESSION LOGS ─────────────────────────────────────────────────
  if (view === 'logs') {
    const avgToes = (toes) => {
      if (!toes) return 0;
      return Math.round((toes.touches+toes.organisation+toes.enjoyment+toes.safety)/4);
    };
    const RATINGS = ['','😐','😐','🙂','😄','🤩'];

    return (
      <div style={pg}>
        <div style={hdr}>
          <button style={backBtn} onClick={goBack}>‹</button>
          <div style={{fontSize:17, fontWeight:800, color:'#FFFFFF', flex:1}}>Session Log</div>
          {logs.length > 0 && (
            <button onClick={doExportLogs} style={{...btnSm('#1A1A1A','#A1A1A1'), border:'1px solid #2A2A2A'}}>Export</button>
          )}
        </div>
        <div style={body}>
          {logs.length === 0 ? (
            <div style={{textAlign:'center', padding:'60px 20px', color:'#A1A1A1'}}>
              <div style={{fontSize:40, marginBottom:12}}>📝</div>
              <div style={{fontSize:16, fontWeight:600, color:'#FFFFFF', marginBottom:6}}>No sessions logged yet</div>
              <div style={{fontSize:13}}>Browse sessions and use "Log This Session" after each training.</div>
            </div>
          ) : logs.map(log => {
            const avg = avgToes(log.toes);
            return (
              <div key={log.id} style={card}>
                <div style={{display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:8}}>
                  <div>
                    <div style={{fontSize:14, fontWeight:700, color:'#FFFFFF'}}>{log.topicTitle} — Session {log.sessionNum}</div>
                    <div style={{fontSize:12, color:'#A1A1A1'}}>{log.date} · {log.players||'?'} players</div>
                  </div>
                  <div style={{display:'flex', alignItems:'center', gap:6}}>
                    <span style={{fontSize:20}}>{RATINGS[avg]||'😐'}</span>
                    <button onClick={()=>doDeleteLog(log.id)} style={{background:'none', border:'none', color:'#ef4444', cursor:'pointer', fontSize:16, padding:0}}>🗑</button>
                  </div>
                </div>
                {log.wellDone && <div style={{fontSize:12, color:'#22c55e', marginBottom:4}}>✓ {log.wellDone}</div>}
                {log.improve  && <div style={{fontSize:12, color:'#F5C04A', marginBottom:4}}>↑ {log.improve}</div>}
                {log.playerNotes && <div style={{fontSize:12, color:'#CBD5E1', marginTop:4, fontStyle:'italic'}}>{log.playerNotes}</div>}
                {log.toes && (
                  <div style={{display:'flex', gap:8, marginTop:8}}>
                    {['T','O','E','S'].map((letter,i)=>{
                      const keys = ['touches','organisation','enjoyment','safety'];
                      const val = log.toes[keys[i]];
                      return <div key={letter} style={{flex:1, textAlign:'center', background:'#1A1A1A', borderRadius:8, padding:'6px 0'}}>
                        <div style={{fontSize:11, fontWeight:700, color:'#F5C04A'}}>{letter}</div>
                        <div style={{fontSize:14, fontWeight:700, color:'#FFFFFF'}}>{val}/5</div>
                      </div>;
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    );
  }

  // ── IMPORT / EXPORT ──────────────────────────────────────────────
  if (view === 'importexport') {
    return (
      <div style={pg}>
        <div style={hdr}>
          <button style={backBtn} onClick={goBack}>‹</button>
          <div style={{fontSize:17, fontWeight:800, color:'#FFFFFF', flex:1}}>Import / Export</div>
        </div>
        <div style={body}>
          {/* Info card */}
          <div style={{...card, borderColor:'#F5C04A44', marginBottom:16}}>
            <div style={{fontSize:13, fontWeight:700, color:'#F5C04A', marginBottom:6}}>How it works</div>
            <div style={{fontSize:13, color:'#CBD5E1', lineHeight:1.6}}>
              Export the session library as a <strong style={{color:'#FFFFFF'}}>JSON file</strong>, edit it in any text editor or VS Code, then import it back. You can change coaching points, rules, drills, session names — anything.{'\n\n'}The built-in content covers all 11 UQFC topics. Each topic has sessions, phases, rules, progressions and coaching points. Export first to see the structure.
            </div>
          </div>

          {/* Library version */}
          <div style={{...card, marginBottom:16}}>
            <div style={{fontSize:13, fontWeight:700, color:'#FFFFFF', marginBottom:4}}>Session Library</div>
            <div style={{fontSize:12, color:'#A1A1A1', marginBottom:12}}>v{library.version} · Updated {library.updated} · {library.topics?.length||0} topics</div>
            <button onClick={doExport} style={btn('#F5C04A')}>⬇️ Export Library (JSON)</button>
            <button onClick={()=>fileInputRef.current?.click()} style={{...btn('#22c55e'), marginBottom:8}}>⬆️ Import Library (JSON)</button>
            <button onClick={doReset} style={{...btn('#1A1A1A','#A1A1A1'), border:'1px solid #2A2A2A', marginBottom:0}}>↺ Reset to Built-in Defaults</button>
            <input ref={fileInputRef} type="file" accept=".json" style={{display:'none'}} onChange={doImport} />
            {importSuccess && <div style={{fontSize:13, color:'#22c55e', marginTop:8, fontWeight:600}}>{importSuccess}</div>}
            {importError   && <div style={{fontSize:13, color:'#ef4444', marginTop:8, fontWeight:600}}>{importError}</div>}
          </div>

          {/* Logs export */}
          <div style={{...card, marginBottom:16}}>
            <div style={{fontSize:13, fontWeight:700, color:'#FFFFFF', marginBottom:4}}>Training Logs</div>
            <div style={{fontSize:12, color:'#A1A1A1', marginBottom:12}}>{logs.length} session{logs.length!==1?'s':''} recorded</div>
            <button onClick={doExportLogs} style={{...btn('#a78bfa'), marginBottom:0}}>⬇️ Export Session Logs (JSON)</button>
          </div>

          {/* JSON structure guide */}
          <div style={card}>
            <div style={{fontSize:13, fontWeight:700, color:'#FFFFFF', marginBottom:8}}>JSON Structure</div>
            <div style={{fontSize:11, color:'#A1A1A1', fontFamily:'monospace', background:'#0D0D0D', borderRadius:8, padding:12, lineHeight:1.7}}>
              {`{
  "version": "1.0",
  "topics": [{
    "id": "pressing",
    "title": "Pressing",
    "icon": "⚡",
    "category": "defending",
    "ageGroup": "U9-U13",
    "principle": "...",
    "behaviour": "...",
    "moments": ["..."],
    "keyPoints": ["..."],
    "sessions": [{
      "number": 1,
      "phases": [{
        "name": "Rondo 4v2",
        "type": "rondo",
        "duration": 20,
        "setup": "...",
        "rules": ["..."],
        "progressions": ["..."],
        "dualForce": "...",
        "coaching": ["..."]
      }]
    }]
  }]
}`}
            </div>
          </div>
        </div>
      </div>
    );
  }

  return null;
}



function BottomNav({ activeTab, onTab }) {
  const tabs = [
    { id:'home',     icon:'⊞',  svg:<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg>, label:'Home' },
    { id:'match',    icon:'⚽', svg:<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><rect x="1" y="3" width="22" height="18" rx="1.5"/><line x1="12" y1="3" x2="12" y2="21"/><circle cx="12" cy="12" r="3"/><path d="M1 8h3.5M1 16h3.5M19.5 8H23M19.5 16H23"/></svg>, label:'Match' },
    { id:'season',   icon:'📅', svg:<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>, label:'Season' },
    { id:'team',     icon:'👥', svg:<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="9" cy="7" r="4"/><path d="M3 21v-2a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/><circle cx="18" cy="9" r="3"/><path d="M21 21v-2a3 3 0 0 0-2-2.83"/></svg>, label:'Team' },
    { id:'training', icon:'🏋️', svg:<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="6" y1="12" x2="18" y2="12" strokeLinecap="round"/><rect x="2" y="9.5" width="4" height="5" rx="1"/><rect x="18" y="9.5" width="4" height="5" rx="1"/></svg>, label:'Training' },
    { id:'more',     icon:'···', svg:<svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="5" r="1"/><circle cx="12" cy="12" r="1"/><circle cx="12" cy="19" r="1"/></svg>, label:'More' },
  ];
  return (
    <nav style={{
      position:'fixed', bottom:0, left:0, right:0, zIndex:200,
      background:'#0d1526', borderTop:'1px solid #1E1E1E',
      display:'flex', justifyContent:'space-around', alignItems:'center',
      paddingBottom:'max(env(safe-area-inset-bottom),4px)',
      paddingTop:6,
    }}>
      {tabs.map(t => {
        const active = activeTab === t.id;
        return (
          <button key={t.id} onClick={() => onTab(t.id)} style={{
            background:'none', border:'none', cursor:'pointer',
            display:'flex', flexDirection:'column', alignItems:'center', gap:3,
            padding:'4px 8px', color: active ? '#F5C04A' : '#A1A1A1',
            minWidth:56,
          }}>
            <span style={{display:'flex', alignItems:'center', justifyContent:'center', width:22, height:22}}>
              {React.cloneElement(t.svg, { stroke: active ? '#F5C04A' : '#A1A1A1' })}
            </span>
            <span style={{fontSize:10, fontWeight: active ? 700 : 500, letterSpacing:0.3}}>{t.label}</span>
          </button>
        );
      })}
    </nav>
  );
}

