function TeamBadge({ name, size=44, radius=10, style={} }) {
  const logo = getTeamLogo(name);
  const dim  = { width:size, height:size, borderRadius:radius, overflow:'hidden', flexShrink:0, ...style };
  if (logo) return (
    <div style={{ ...dim, background:'#1A1A1A', border:'1px solid #2A2A2A', display:'flex', alignItems:'center', justifyContent:'center' }}>
      <img src={logo} alt={name} style={{ width:size-4, height:size-4, objectFit:'contain' }}/>
    </div>
  );
  // Fallback: first letter
  const letter = (name||'?')[0].toUpperCase();
  return (
    <div style={{ ...dim, background:'#2A2A2A', display:'flex', alignItems:'center', justifyContent:'center', fontSize:size*0.4, fontWeight:700, color:'#A1A1A1' }}>
      {letter}
    </div>
  );
}




function MatchPlayersScreen({ contextKey, onBack }) {
  const globalSquad = React.useMemo(() => loadSquad(), []);
  const cx0 = loadContextData(contextKey);
  const mp0 = cx0.matchPlayers || {};
  const initStatuses = () => {
    const saved = mp0.statuses || {};
    const out = {};
    globalSquad.forEach(p => { out[p.name] = saved[p.name] || 'available'; });
    return out;
  };
  const [statuses,    setStatuses]    = React.useState(initStatuses);
  const [guests,      setGuests]      = React.useState(() => mp0.guests || []);
  const [search,      setSearch]      = React.useState('');
  const [showModal,   setShowModal]   = React.useState(false);
  const [guestName,   setGuestName]   = React.useState('');
  const [guestPos,    setGuestPos]    = React.useState('');
  const [guestNumber, setGuestNumber] = React.useState('');

  const POSITIONS = ['Goalkeeper','Left Back','Right Back','Centre Back','Left Mid','Right Mid','Centre Mid','Left Wing','Right Wing','Striker'];
  const STATUS_OPTS = [
    { val:'available',   label:'Available',   color:'#22c55e' },
    { val:'unavailable', label:'Unavailable', color:'#ef4444' },
    { val:'maybe',       label:'Maybe',       color:'#F5C04A' },
  ];

  function setStatus(name, val) { setStatuses(prev => ({...prev, [name]: val})); }

  function submitGuest() {
    const n = guestName.trim();
    if (!n) return;
    setGuests(prev => [...prev, { name: n, pos: guestPos, number: guestNumber }]);
    setGuestName(''); setGuestPos(''); setGuestNumber(''); setShowModal(false);
  }
  function removeGuest(name) { setGuests(prev => prev.filter(g => g.name !== name)); }

  function save() {
    saveContextData(contextKey, { matchPlayers: { statuses, guests }, playersSeen: true });
    onBack();
  }

  const counts = {
    available:   globalSquad.filter(p => statuses[p.name] === 'available').length + guests.length,
    unavailable: globalSquad.filter(p => statuses[p.name] === 'unavailable').length,
    maybe:       globalSquad.filter(p => statuses[p.name] === 'maybe').length,
  };

  const filtered = globalSquad.filter(p => !search || p.name.toLowerCase().includes(search.toLowerCase()));
  const statusColor = s => ({ available:'#22c55e', unavailable:'#ef4444', maybe:'#F5C04A' }[s] || '#555');

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100dvh',background:'#0D0D0D',overflow:'hidden'}}>

      {/* Modal */}
      {showModal && (
        <div style={{position:'fixed',inset:0,zIndex:200,display:'flex',flexDirection:'column',justifyContent:'flex-end',background:'rgba(0,0,0,0.7)'}}
          onClick={e=>{if(e.target===e.currentTarget){setShowModal(false);}}}>
          <div style={{background:'#161616',borderRadius:'20px 20px 0 0',padding:'20px',paddingBottom:'calc(20px + env(safe-area-inset-bottom))'}}>
            <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:20}}>
              <div>
                <div style={{fontSize:18,fontWeight:800,color:'#FFF',lineHeight:1.25}}>Add Additional</div>
                <div style={{fontSize:18,fontWeight:800,color:'#FFF',lineHeight:1.25}}>Game Day Player</div>
              </div>
              <button onClick={()=>setShowModal(false)} style={{background:'#2A2A2A',border:'none',borderRadius:20,width:32,height:32,display:'flex',alignItems:'center',justifyContent:'center',cursor:'pointer',color:'#FFF',flexShrink:0}}>
                <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
              </button>
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:12}}>
              <div>
                <div style={{fontSize:13,fontWeight:500,color:'#FFF',marginBottom:6}}>Name *</div>
                <input value={guestName} onChange={e=>setGuestName(e.target.value)} onKeyDown={e=>e.key==='Enter'&&submitGuest()}
                  placeholder="e.g. Lily Smith"
                  style={{width:'100%',background:'#1A1A1A',border:'1px solid #2A2A2A',borderRadius:10,padding:'11px 14px',color:'#FFF',fontSize:14,outline:'none',boxSizing:'border-box'}}/>
              </div>
              <div style={{display:'flex',gap:10}}>
                <div style={{flex:1}}>
                  <div style={{fontSize:13,fontWeight:500,color:'#FFF',marginBottom:6}}>Position</div>
                  <select value={guestPos} onChange={e=>setGuestPos(e.target.value)}
                    style={{width:'100%',background:'#1A1A1A',border:'1px solid #2A2A2A',borderRadius:10,padding:'11px 12px',color:guestPos?'#FFF':'#555',fontSize:13,outline:'none'}}>
                    <option value="">Select…</option>
                    {POSITIONS.map(p=><option key={p} value={p}>{p}</option>)}
                  </select>
                </div>
                <div style={{width:80}}>
                  <div style={{fontSize:13,fontWeight:500,color:'#FFF',marginBottom:6}}>Shirt #</div>
                  <input value={guestNumber} onChange={e=>setGuestNumber(e.target.value)} placeholder="15"
                    style={{width:'100%',background:'#1A1A1A',border:'1px solid #2A2A2A',borderRadius:10,padding:'11px 10px',color:'#FFF',fontSize:14,outline:'none',boxSizing:'border-box',textAlign:'center'}}/>
                </div>
              </div>
              <div style={{display:'flex',alignItems:'center',gap:8,background:'#0D1A2A',borderRadius:10,padding:'10px 12px'}}>
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#60a5fa" strokeWidth="2" style={{flexShrink:0}}><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
                <span style={{fontSize:12,color:'#60a5fa',lineHeight:1.4}}>This player will only be added for this game.</span>
              </div>
              <button onClick={submitGuest} disabled={!guestName.trim()}
                style={{width:'100%',padding:'14px',border:'none',borderRadius:12,fontSize:15,fontWeight:800,cursor:guestName.trim()?'pointer':'default',background:guestName.trim()?'#22c55e':'#1A1A1A',color:guestName.trim()?'#000':'#444',marginTop:4}}>
                Add Player
              </button>
              <button onClick={()=>setShowModal(false)} style={{width:'100%',padding:'10px',border:'none',background:'none',fontSize:14,fontWeight:500,color:'#555',cursor:'pointer'}}>
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Header */}
      <div style={{padding:'54px 16px 14px',background:'#111111',borderBottom:'1px solid #1A1A1A',flexShrink:0}}>
        <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:14}}>
          <button onClick={save} style={{background:'none',border:'none',cursor:'pointer',padding:4,color:'#A1A1A1',display:'flex',flexShrink:0}}>
            <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><polyline points="15 18 9 12 15 6"/></svg>
          </button>
          <div style={{fontSize:18,fontWeight:800,color:'#FFF',flex:1}}>Players</div>
          <button onClick={save} style={{background:'#22c55e',border:'none',borderRadius:10,padding:'8px 16px',color:'#000',fontWeight:700,fontSize:13,cursor:'pointer'}}>Save</button>
        </div>
        <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:8}}>
          {[{label:'Available',val:counts.available,color:'#22c55e'},{label:'Unavailable',val:counts.unavailable,color:'#ef4444'},{label:'Maybe',val:counts.maybe,color:'#F5C04A'}].map(s=>(
            <div key={s.label} style={{textAlign:'center'}}>
              <div style={{fontSize:22,fontWeight:500,color:'#FFF',lineHeight:1}}>{s.val}</div>
              <div style={{fontSize:10,color:s.color,fontWeight:600,marginTop:3}}>{s.label}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Search bar */}
      <div style={{display:'flex',alignItems:'center',gap:8,padding:'10px 16px',borderBottom:'1px solid #1A1A1A',background:'#111111',flexShrink:0}}>
        <div style={{fontSize:11,fontWeight:700,color:'#A1A1A1',flexShrink:0}}>SQUAD ({globalSquad.length})</div>
        <div style={{flex:1,display:'flex',alignItems:'center',gap:8,background:'#0D0D0D',border:'1px solid #2A2A2A',borderRadius:8,padding:'6px 10px'}}>
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="#555" strokeWidth="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
          <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search players…"
            style={{flex:1,background:'none',border:'none',outline:'none',color:'#FFF',fontSize:12}}/>
        </div>
      </div>

      {/* Scrollable list */}
      <div style={{flex:1,overflowY:'auto'}}>
        {filtered.map((p, i) => {
          const st = statuses[p.name] || 'available';
          const initials = p.name.split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2);
          return (
            <div key={p.name} style={{display:'flex',alignItems:'center',gap:10,padding:'10px 16px',borderBottom:'1px solid #1A1A1A',background:st==='unavailable'?'rgba(239,68,68,0.03)':'transparent'}}>
              <div style={{width:36,height:36,borderRadius:18,background:'#1A1A2E',border:'1.5px solid #2A2A3E',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,fontSize:12,fontWeight:700,color:'#A1A1A1'}}>{initials}</div>
              <div style={{background:'#1A1A1A',borderRadius:6,padding:'2px 6px',fontSize:11,fontWeight:500,color:'#666',flexShrink:0,minWidth:22,textAlign:'center'}}>{i+1}</div>
              <div style={{flex:1,minWidth:0,display:'flex',alignItems:'center',gap:7}}>
                <span style={{fontSize:14,fontWeight:600,color:st==='unavailable'?'#555':'#FFF',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{p.name}</span>
                {p.pos&&<span style={{background:'#1A1A1A',borderRadius:5,padding:'2px 6px',fontSize:10,fontWeight:500,color:'#666',flexShrink:0}}>{p.pos}</span>}
              </div>
              <select value={st} onChange={e=>setStatus(p.name,e.target.value)}
                style={{background:'#1A1A1A',border:`1px solid ${statusColor(st)}44`,borderRadius:8,padding:'6px 10px',color:statusColor(st),fontSize:12,fontWeight:600,outline:'none',cursor:'pointer',flexShrink:0}}>
                {STATUS_OPTS.map(o=><option key={o.val} value={o.val}>{o.label}</option>)}
              </select>
            </div>
          );
        })}
        {guests.length > 0 && guests.map(g=>(
          <div key={g.name} style={{display:'flex',alignItems:'center',gap:10,padding:'10px 16px',borderBottom:'1px solid #1A1A1A'}}>
            <div style={{width:36,height:36,borderRadius:18,background:'#1A1400',border:'1.5px solid #2A2000',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0}}>
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="#F5C04A" strokeWidth="2"><circle cx="12" cy="8" r="4"/><path d="M20 21a8 8 0 1 0-16 0"/></svg>
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{display:'flex',alignItems:'center',gap:6}}>
                <span style={{fontSize:14,fontWeight:600,color:'#FFF'}}>{g.name}</span>
                {g.pos&&<span style={{background:'#1A1A1A',borderRadius:5,padding:'2px 6px',fontSize:10,fontWeight:500,color:'#666'}}>{g.pos}</span>}
                {g.number&&<span style={{fontSize:10,color:'#555'}}>#{g.number}</span>}
              </div>
              <div style={{fontSize:10,color:'#F5C04A',fontWeight:600,marginTop:1}}>GAME DAY ONLY</div>
            </div>
            <div style={{display:'flex',alignItems:'center',gap:8,flexShrink:0}}>
              <div style={{background:'#1A1A1A',border:'1px solid #22c55e44',borderRadius:8,padding:'6px 10px',color:'#22c55e',fontSize:12,fontWeight:600}}>Available</div>
              <button onClick={()=>removeGuest(g.name)} style={{background:'none',border:'none',cursor:'pointer',padding:6,color:'#555',display:'flex'}}>
                <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><line x1="18" y1="6" x2="6" y2="18"/><line x1="6" y1="6" x2="18" y2="18"/></svg>
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Fixed footer */}
      <div style={{flexShrink:0,background:'#111111',borderTop:'1px solid #1A1A1A',padding:'12px 16px',paddingBottom:'calc(env(safe-area-inset-bottom) + 80px)'}}>
        <button onClick={()=>setShowModal(true)}
          style={{width:'100%',border:'1.5px dashed #2A3A2A',borderRadius:12,padding:'12px',background:'#0A120A',cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',gap:8,marginBottom:10}}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#22c55e" strokeWidth="2.5"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          <span style={{fontSize:13,fontWeight:600,color:'#22c55e'}}>Add Additional Game Day Player</span>
        </button>
        <button onClick={save} style={{width:'100%',padding:'14px',border:'none',borderRadius:12,fontSize:15,fontWeight:800,cursor:'pointer',background:'#22c55e',color:'#000'}}>
          ✓ Save Team
        </button>
      </div>
    </div>
  );
}

function QuickPlayScreen({ opponent, linkedFixKey, fixIsHome, settings, onBack, onSaved, onSaveGame }) {
  const myTeam = localStorage.getItem('soccerCoach_fixtureTeam') || settings?.teamName || 'My Team';
  const squad  = React.useMemo(()=>{ try{return JSON.parse(localStorage.getItem('soccerCoach_squad')||'[]');}catch{return[];} },[]);
  const [scoreUs,   setScoreUs]   = React.useState(0);
  const [scoreThem, setScoreThem] = React.useState(0);
  const [scorers,   setScorers]   = React.useState({}); // {name: count}
  const [potm,      setPotm]      = React.useState('');  // player of the match name
  const [notes,     setNotes]     = React.useState('');
  const [listening, setListening] = React.useState(false);
  const recogRef = React.useRef(null);
  const SpeechRec = typeof window !== 'undefined' && (window.SpeechRecognition || window.webkitSpeechRecognition);

  function toggleVoice() {
    if (listening) { recogRef.current && recogRef.current.stop(); setListening(false); return; }
    if (!SpeechRec) return;
    const r = new SpeechRec();
    r.continuous = true; r.interimResults = false; r.lang = 'en-AU';
    r.onresult = e => { const t = Array.from(e.results).map(x=>x[0].transcript).join(' '); setNotes(prev=>(prev?prev+' ':'')+t); };
    r.onend = () => setListening(false);
    recogRef.current = r; r.start(); setListening(true);
  }

  function adjUs(d)   { setScoreUs(s=>Math.max(0,s+d)); }
  function adjThem(d) { setScoreThem(s=>Math.max(0,s+d)); }

  // keep scorers in sync if scoreUs drops below total
  React.useEffect(()=>{
    const total = Object.values(scorers).reduce((a,b)=>a+b,0);
    if(total > scoreUs){
      setScorers(prev=>{
        const next={...prev}; let excess=total-scoreUs;
        for(const n of Object.keys(next).reverse()){
          if(excess<=0)break;
          const dec=Math.min(next[n],excess);
          next[n]-=dec; excess-=dec;
          if(next[n]<=0)delete next[n];
        }
        return next;
      });
    }
  },[scoreUs]);

  function doSave() {
    if (listening) { recogRef.current && recogRef.current.stop(); setListening(false); }
    const goals = [];
    Object.entries(scorers).forEach(([name,count])=>{
      for(let i=0;i<count;i++) goals.push({team:'us',scorer:name,minute:null});
    });
    const game = {
      id: 'g_'+Date.now(),
      date: Date.now(),
      opponent: opponent||'Unknown',
      scoreUs, scoreThem,
      goals,
      potm: potm ? [potm] : [],
      matchEvents: [],
      halves: [],
      config: { teamName: myTeam, periods:2, periodMins:40 },
      voiceNotes: notes.trim(),
      report: '',
      quickPlay: true,
      ...(linkedFixKey ? { linkedFixtureKey: linkedFixKey, fixtureIsHome: fixIsHome } : {})
    };
    if (onSaveGame) {
      onSaveGame(game);
    } else {
      const games = JSON.parse(localStorage.getItem('soccerCoach_games')||'[]');
      games.push(game);
      localStorage.setItem('soccerCoach_games', JSON.stringify(games));
    }
    if(linkedFixKey) {
      const fxSc = JSON.parse(localStorage.getItem('soccerCoach_fixtureScores')||'{}');
      fxSc[linkedFixKey] = fixIsHome ? { home: scoreUs, away: scoreThem } : { home: scoreThem, away: scoreUs };
      localStorage.setItem('soccerCoach_fixtureScores', JSON.stringify(fxSc));
    }
    onSaved(game);
  }

  const scorerTotal = Object.values(scorers).reduce((a,b)=>a+b,0);
  const unaccounted = scoreUs - scorerTotal;
  const result = scoreUs > scoreThem ? 'W' : scoreUs < scoreThem ? 'L' : scoreUs===0&&scoreThem===0 ? '' : 'D';
  const resultColor = result==='W'?'#22c55e':result==='L'?'#ef4444':'#A1A1A1';

  const SectionTitle = ({label})=>(
    <div style={{fontSize:9,fontWeight:700,color:'#A1A1A1',letterSpacing:1.5,textTransform:'uppercase',marginBottom:12}}>{label}</div>
  );

  const ScoreBtn = ({label,onClick})=>(
    <button onClick={onClick} style={{width:40,height:40,borderRadius:10,border:'1px solid #2A2A2A',background:'#1A1A1A',color:'#A1A1A1',fontSize:20,fontWeight:500,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',flexShrink:0,lineHeight:1}}>
      {label}
    </button>
  );

  return (
    <div style={{display:'flex',flexDirection:'column',height:'100dvh',background:'#0D0D0D'}}>
      {/* Header */}
      <div style={{display:'flex',alignItems:'center',gap:12,padding:'max(env(safe-area-inset-top),14px) 16px 14px',background:'#111111',borderBottom:'1px solid #1E1E1E',flexShrink:0}}>
        <button onClick={onBack} style={{background:'none',border:'none',cursor:'pointer',color:'#F5C04A',fontSize:22,padding:0,lineHeight:1}}>‹</button>
        <div style={{flex:1}}>
          <div style={{fontSize:11,fontWeight:800,color:'#F5C04A',letterSpacing:2,textTransform:'uppercase'}}>Quick Play</div>
          {opponent&&<div style={{fontSize:17,fontWeight:800,color:'#FFF',marginTop:1}}>vs {opponent}</div>}
        </div>
        {result&&<div style={{width:40,height:40,borderRadius:10,background:resultColor+'22',border:`1px solid ${resultColor}44`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:16,fontWeight:700,color:resultColor}}>{result}</div>}
      </div>

      <div style={{flex:1,overflowY:'auto',padding:'16px',paddingBottom:'calc(env(safe-area-inset-bottom) + 90px)',display:'flex',flexDirection:'column',gap:12}}>

        {/* Score */}
        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'18px 20px'}}>
          <SectionTitle label="Score"/>
          <div style={{display:'flex',alignItems:'center',gap:8}}>
            {/* Us */}
            <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:8}}>
              <div style={{fontSize:10,fontWeight:600,color:'#777',textTransform:'uppercase',letterSpacing:1,textAlign:'center',maxWidth:120,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{myTeam}</div>
              <div style={{display:'flex',alignItems:'center',gap:10}}>
                <ScoreBtn label="−" onClick={()=>adjUs(-1)}/>
                <div style={{fontSize:52,fontWeight:600,color:'#FFFFFF',minWidth:48,textAlign:'center',lineHeight:1}}>{scoreUs}</div>
                <ScoreBtn label="+" onClick={()=>adjUs(1)}/>
              </div>
            </div>
            <div style={{fontSize:22,fontWeight:300,color:'#333',marginTop:14}}>:</div>
            {/* Them */}
            <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:8}}>
              <div style={{fontSize:10,fontWeight:600,color:'#777',textTransform:'uppercase',letterSpacing:1,textAlign:'center',maxWidth:120,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{opponent||'Opposition'}</div>
              <div style={{display:'flex',alignItems:'center',gap:10}}>
                <ScoreBtn label="−" onClick={()=>adjThem(-1)}/>
                <div style={{fontSize:52,fontWeight:600,color:'#FFFFFF',minWidth:48,textAlign:'center',lineHeight:1}}>{scoreThem}</div>
                <ScoreBtn label="+" onClick={()=>adjThem(1)}/>
              </div>
            </div>
          </div>
        </div>

        {/* Goal scorers — only shown when we scored */}
        {squad.length > 0 && scoreUs > 0 && (
          <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'16px'}}>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:12}}>
              <SectionTitle label="Goal Scorers"/>
              {unaccounted > 0 && <div style={{fontSize:10,color:'#F5C04A',fontWeight:600,marginTop:-12}}>{unaccounted} unassigned</div>}
            </div>
            <div style={{display:'flex',flexDirection:'column',gap:4}}>
              {squad.map(p=>{
                const count = scorers[p.name]||0;
                const canAdd = scorerTotal < scoreUs;
                const initials = p.name.split(' ').map(w=>w[0]||'').join('').slice(0,2).toUpperCase();
                return (
                  <div key={p.name} style={{display:'flex',alignItems:'center',gap:10,padding:'7px 10px',borderRadius:9,background:count>0?'rgba(255,255,255,0.04)':'transparent',border:'1px solid',borderColor:count>0?'#2A2A2A':'transparent',transition:'all 0.15s'}}>
                    <div style={{width:28,height:28,borderRadius:'50%',background:count>0?'#2A2A2A':'#1A1A1A',display:'flex',alignItems:'center',justifyContent:'center',fontSize:9,fontWeight:700,color:count>0?'#FFF':'#555',flexShrink:0}}>{initials}</div>
                    <div style={{flex:1,fontSize:13,fontWeight:500,color:count>0?'#FFF':'#777'}}>{p.name}</div>
                    {count>0&&(
                      <div style={{display:'flex',alignItems:'center',gap:6}}>
                        <button onClick={()=>setScorers(prev=>{const n={...prev};n[p.name]=(count-1);if(!n[p.name])delete n[p.name];return n;})}
                          style={{width:26,height:26,borderRadius:6,border:'1px solid #2A2A2A',background:'#1A1A1A',color:'#A1A1A1',fontSize:14,fontWeight:500,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',lineHeight:1}}>−</button>
                        <div style={{fontSize:14,fontWeight:600,color:'#FFF',minWidth:14,textAlign:'center'}}>{count}</div>
                      </div>
                    )}
                    <button onClick={()=>{ if(canAdd){setScorers(prev=>({...prev,[p.name]:(prev[p.name]||0)+1}));} }}
                      disabled={!canAdd}
                      style={{width:26,height:26,borderRadius:6,border:'1px solid',borderColor:canAdd?'#2A2A2A':'transparent',background:canAdd?'#1A1A1A':'transparent',color:canAdd?'#A1A1A1':'#333',fontSize:14,fontWeight:500,cursor:canAdd?'pointer':'default',display:'flex',alignItems:'center',justifyContent:'center',lineHeight:1}}>+</button>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Player of the Match */}
        {squad.length > 0 && (
          <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'16px'}}>
            <SectionTitle label="Player of the Match"/>
            <div style={{display:'flex',flexWrap:'wrap',gap:6}}>
              {squad.map(p=>{
                const sel = potm===p.name;
                const initials = p.name.split(' ').map(w=>w[0]||'').join('').slice(0,2).toUpperCase();
                return (
                  <button key={p.name} onClick={()=>setPotm(sel?'':p.name)}
                    style={{display:'flex',alignItems:'center',gap:6,padding:'5px 10px 5px 5px',borderRadius:20,border:'1px solid',borderColor:sel?'#F5C04A':'#1A1A1A',background:sel?'rgba(245,192,74,0.08)':'#0D0D0D',cursor:'pointer',transition:'all 0.15s'}}>
                    <div style={{width:24,height:24,borderRadius:'50%',background:sel?'#F5C04A22':'#1A1A1A',display:'flex',alignItems:'center',justifyContent:'center',fontSize:8,fontWeight:700,color:sel?'#F5C04A':'#555',flexShrink:0}}>{initials}</div>
                    <div style={{fontSize:12,fontWeight:sel?600:500,color:sel?'#F5C04A':'#777',whiteSpace:'nowrap'}}>{p.name.split(' ')[0]}</div>
                    {sel&&<div style={{fontSize:10}}>⭐</div>}
                  </button>
                );
              })}
            </div>
          </div>
        )}

        {/* Match notes */}
        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'16px'}}>
          <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:12}}>
            <SectionTitle label="Coach Notes"/>
            {SpeechRec && (
              <button onClick={toggleVoice}
                style={{background:listening?'#ef444418':'#1A1A1A',border:`1px solid ${listening?'#ef4444':'#2A2A2A'}`,borderRadius:8,padding:'6px 12px',cursor:'pointer',display:'flex',alignItems:'center',gap:6,color:listening?'#ef4444':'#A1A1A1',fontSize:11,fontWeight:700,marginTop:-12}}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg>
                {listening ? 'Stop' : 'Dictate'}
              </button>
            )}
          </div>
          <textarea value={notes} onChange={e=>setNotes(e.target.value)}
            placeholder="Key moments, tactical notes, things to work on… or use Dictate to speak your notes"
            rows={5}
            style={{width:'100%',background:'#0D0D0D',border:`1px solid ${listening?'#ef4444':'#2A2A2A'}`,borderRadius:9,padding:'10px 12px',color:'#FFF',fontSize:13,fontFamily:'inherit',lineHeight:1.6,resize:'vertical',outline:'none',boxSizing:'border-box'}}/>
          {listening && <div style={{fontSize:11,color:'#ef4444',marginTop:6,fontWeight:600}}>🎙️ Recording… speak your notes</div>}
        </div>
      </div>

      {/* Footer */}
      <div style={{position:'fixed',bottom:0,left:0,right:0,padding:'12px 16px',paddingBottom:'calc(env(safe-area-inset-bottom) + 76px)',background:'linear-gradient(transparent,#0D0D0D 40%)',zIndex:50}}>
        <button onClick={doSave}
          style={{width:'100%',padding:'16px',border:'none',borderRadius:14,fontSize:15,fontWeight:800,letterSpacing:0.5,cursor:'pointer',background:'#F5C04A',color:'#000'}}>
          Save &amp; Review →
        </button>
      </div>
    </div>
  );
}


function MatchDayScreen({ settings, onStartMatch, onLineup, onScout, onSettings, onPlayers, onQuickPlay, onBack }) {
  const myTeam  = localStorage.getItem('soccerCoach_fixtureTeam') || settings?.teamName || 'My Team';
  const allTeams = [...new Set(FIXTURES.flatMap(f=>[f.home,f.away]).filter(Boolean))].filter(t=>t!==myTeam).sort();
  const nextFix = FIXTURES.find(f => isUpcoming(f) && (f.home===myTeam||f.away===myTeam));
  const nextOpp = nextFix ? (nextFix.home===myTeam ? nextFix.away : nextFix.home) : '';
  const squad = React.useMemo(()=>{ try{return JSON.parse(localStorage.getItem('soccerCoach_squad')||'[]');}catch{return[];} },[]);
  const [mdOpponent, setMdOpponent] = React.useState(nextOpp||'');
  const [customMode, setCustomMode] = React.useState(false);
  const linkedFix = FIXTURES.find(f=>isUpcoming(f)&&((f.home===myTeam&&f.away===mdOpponent)||(f.away===myTeam&&f.home===mdOpponent)));
  const isHome = linkedFix ? linkedFix.home===myTeam : true;
  const ctxKey = makeContextKey(linkedFix, mdOpponent);
  const [contextData, setContextData] = React.useState(()=>loadContextData(ctxKey));
  React.useEffect(()=>{ setContextData(loadContextData(ctxKey)); }, [ctxKey]);
  const savedLineup  = contextData.lineup || null;
  const lineupReady  = savedLineup && savedLineup.h1Periods && savedLineup.h1Periods.length > 0;
  const playersSeen  = contextData.playersSeen || false;
  const scoutSeen    = contextData.scoutSeen || false;
  const settingsSeen = contextData.settingsSeen || false;
  const DAYS=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const MONTHS=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  function fmtDate(s){if(!s)return'';const d=parseFixtureDate(s);if(!d)return s;return`${DAYS[d.getDay()]} ${d.getDate()} ${MONTHS[d.getMonth()]}`;}
  const selStyle={background:'#0D0D0D',border:'1px solid #2A2A2A',borderRadius:8,padding:'7px 10px',color:'#FFF',fontSize:12,fontWeight:600,outline:'none',cursor:'pointer',flex:1};
  function CheckStatus({seen}){
    if(seen)return(<div style={{display:'flex',alignItems:'center',gap:8}}><span style={{fontSize:13,fontWeight:700,color:'#22c55e'}}>Ready</span><svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#22c55e" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><polyline points="9 12 11 14 15 10"/></svg></div>);
    return <span style={{fontSize:13,fontWeight:700,color:'#F5C04A'}}>Review →</span>;
  }
  return (
    <div style={{display:'flex',flexDirection:'column',minHeight:'100vh',background:'#0D0D0D'}}>
      <div style={{padding:'54px 16px 14px',background:'#111111',borderBottom:'1px solid #1A1A1A'}}>
        <div style={{fontSize:11,fontWeight:800,color:'#F5C04A',letterSpacing:2,textTransform:'uppercase',marginBottom:10}}>MATCH DAY</div>
        <div style={{display:'flex',gap:6,alignItems:'center'}}>
          {customMode?(<><input autoFocus value={mdOpponent} onChange={e=>setMdOpponent(e.target.value)} placeholder="Type opponent name…" style={{...selStyle,outline:'none'}}/><button onClick={()=>setCustomMode(false)} style={{background:'#2A2A2A',border:'none',borderRadius:8,color:'#A1A1A1',padding:'7px 10px',cursor:'pointer',fontSize:11,flexShrink:0}}>List</button></>):(
          <select value={allTeams.includes(mdOpponent)?mdOpponent:(mdOpponent?'__custom__':'')} onChange={e=>{if(e.target.value==='__custom__'){setCustomMode(true);setMdOpponent('');}else setMdOpponent(e.target.value);}} style={selStyle}>
            <option value="" disabled>— Select opposition —</option>
            {nextOpp&&<option value={nextOpp}>📅 {nextOpp} (next fixture)</option>}
            <option value="__custom__">✏️ Custom…</option>
            {allTeams.filter(t=>t!==nextOpp).map(t=><option key={t} value={t}>{t}</option>)}
          </select>)}
        </div>
      </div>
      <div style={{flex:1,overflowY:'auto',padding:'16px',paddingBottom:'calc(80px + env(safe-area-inset-bottom))',display:'flex',flexDirection:'column',gap:14}}>
        <div style={{background:'#111111',borderRadius:16,padding:'20px 16px 0',border:'1px solid #1A1A1A'}}>
          <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',gap:8}}>
            <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:8}}><TeamBadge name={isHome?myTeam:(mdOpponent||'Away')} size={64} radius={12}/><div style={{fontSize:13,fontWeight:700,color:'#FFF',textAlign:'center',lineHeight:1.2}}>{isHome?myTeam:(mdOpponent||'—')}</div><div style={{fontSize:9,fontWeight:700,color:'#555',letterSpacing:1,textTransform:'uppercase'}}>HOME</div></div>
            <div style={{fontSize:18,fontWeight:800,color:'#A1A1A1',flexShrink:0,padding:'22px 8px 0'}}>VS</div>
            <div style={{flex:1,display:'flex',flexDirection:'column',alignItems:'center',gap:8}}><TeamBadge name={isHome?(mdOpponent||'Away'):myTeam} size={64} radius={12}/><div style={{fontSize:13,fontWeight:700,color:'#FFF',textAlign:'center',lineHeight:1.2}}>{isHome?(mdOpponent||'—'):myTeam}</div><div style={{fontSize:9,fontWeight:700,color:'#555',letterSpacing:1,textTransform:'uppercase'}}>AWAY</div></div>
          </div>
          <div style={{display:'flex',alignItems:'center',justifyContent:'center',gap:16,padding:'12px 0',marginTop:14,borderTop:'1px solid #1A1A1A',flexWrap:'wrap'}}>
            {linkedFix?.date&&<div style={{display:'flex',alignItems:'center',gap:5,color:'#A1A1A1',fontSize:12}}><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg><span>{fmtDate(linkedFix.date)}</span></div>}
            {linkedFix?.time&&<div style={{display:'flex',alignItems:'center',gap:5,color:'#A1A1A1',fontSize:12}}><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg><span>{linkedFix.time}</span></div>}
            {linkedFix?.venue&&<div style={{display:'flex',alignItems:'center',gap:5,color:'#A1A1A1',fontSize:12}}><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg><span>{linkedFix.venue}</span></div>}
            {!linkedFix&&mdOpponent&&<span style={{fontSize:11,color:'#555',fontStyle:'italic'}}>Friendly / no fixture</span>}
            {!mdOpponent&&<span style={{fontSize:11,color:'#555',fontStyle:'italic'}}>Select opposition above</span>}
          </div>
        </div>
        <button onClick={()=>onQuickPlay&&onQuickPlay(mdOpponent,ctxKey,isHome)}
          style={{width:'100%',padding:'16px',border:'none',borderRadius:14,fontSize:15,fontWeight:800,letterSpacing:0.5,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',gap:10,background:'#1A1A1A',color:'#A1A1A1',transition:'background 0.2s'}}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="2"><polygon points="5,3 19,12 5,21"/><line x1="19" y1="3" x2="19" y2="21"/></svg>
          QUICK PLAY
        </button>
        <button disabled={!lineupReady} onClick={()=>onStartMatch(savedLineup,mdOpponent)}
          style={{width:'100%',padding:'16px',border:'none',borderRadius:14,fontSize:15,fontWeight:800,letterSpacing:0.5,cursor:lineupReady?'pointer':'default',display:'flex',alignItems:'center',justifyContent:'center',gap:10,background:lineupReady?'#22c55e':'#1A1A1A',color:lineupReady?'#000':'#444',transition:'background 0.2s'}}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill={lineupReady?'#000':'#444'}><polygon points="5,3 19,12 5,21"/></svg>
          {lineupReady?'START MATCH':'Save your line-up first'}
        </button>
        <div style={{background:'#111111',borderRadius:16,border:'1px solid #1A1A1A',overflow:'hidden'}}>
          <div style={{padding:'12px 16px 10px',borderBottom:'1px solid #1A1A1A'}}><div style={{fontSize:9,fontWeight:800,color:'#F5C04A',letterSpacing:1.5,textTransform:'uppercase'}}>PRE MATCH CHECKLIST</div></div>
          <button onClick={()=>onPlayers(ctxKey)} style={{width:'100%',display:'flex',alignItems:'center',padding:'14px 16px',borderBottom:'1px solid #1A1A1A',background:'none',border:'none',borderTop:'none',cursor:'pointer'}}>
            <span style={{flex:1,fontSize:13,color:'#FFF',fontWeight:500,textAlign:'left'}}>Players</span>
            <CheckStatus seen={playersSeen}/>
          </button>
          <button onClick={()=>playersSeen&&onLineup(ctxKey)} style={{width:'100%',display:'flex',alignItems:'center',padding:'14px 16px',borderBottom:'1px solid #1A1A1A',background:'none',border:'none',borderTop:'none',cursor:playersSeen?'pointer':'default',opacity:playersSeen?1:0.45}}>
            <span style={{flex:1,fontSize:13,color:'#FFF',fontWeight:500,textAlign:'left'}}>Line-up</span>
            <div style={{display:'flex',alignItems:'center',gap:8}}><span style={{fontSize:13,fontWeight:700,color:lineupReady?'#22c55e':'#F5C04A'}}>{lineupReady?'Ready':'Set up →'}</span>{lineupReady&&<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#22c55e" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><polyline points="9 12 11 14 15 10"/></svg>}</div>
          </button>
          <button onClick={()=>{if(!mdOpponent)return;saveContextData(ctxKey,{scoutSeen:true});setContextData(cd=>({...cd,scoutSeen:true}));onScout(mdOpponent);}} style={{width:'100%',display:'flex',alignItems:'center',padding:'14px 16px',borderBottom:'1px solid #1A1A1A',background:'none',border:'none',borderTop:'none',cursor:mdOpponent?'pointer':'default',opacity:mdOpponent?1:0.45}}>
            <span style={{flex:1,fontSize:13,color:'#FFF',fontWeight:500,textAlign:'left'}}>Scout</span><CheckStatus seen={scoutSeen}/>
          </button>
          <button onClick={()=>{saveContextData(ctxKey,{settingsSeen:true});setContextData(cd=>({...cd,settingsSeen:true}));onSettings(ctxKey);}} style={{width:'100%',display:'flex',alignItems:'center',padding:'14px 16px',background:'none',border:'none',cursor:'pointer'}}>
            <span style={{flex:1,fontSize:13,color:'#FFF',fontWeight:500,textAlign:'left'}}>Match Settings</span><CheckStatus seen={settingsSeen}/>
          </button>
        </div>
        {(()=>{
          const upcoming=FIXTURES.filter(f=>(f.home===myTeam||f.away===myTeam)&&isUpcoming(f)).slice(0,3);
          if(upcoming.length===0)return null;
          return(<div style={{background:'#111111',borderRadius:16,border:'1px solid #1A1A1A',overflow:'hidden'}}>
            <div style={{padding:'12px 16px 10px',borderBottom:'1px solid #1A1A1A'}}><div style={{fontSize:9,fontWeight:800,color:'#F5C04A',letterSpacing:1.5,textTransform:'uppercase'}}>UPCOMING</div></div>
            {upcoming.map((f,i)=>{
              const opp=f.home===myTeam?f.away:f.home;
              const home=f.home===myTeam;
              const isActive=opp===mdOpponent;
              const ck=makeContextKey(f,opp);
              const cx=loadContextData(ck);
              const ready=cx.lineup?.h1Periods?.length>0;
              return(<button key={i} onClick={()=>setMdOpponent(opp)}
                style={{width:'100%',display:'flex',alignItems:'center',gap:10,padding:'12px 16px',borderBottom:i<upcoming.length-1?'1px solid #1A1A1A':'none',background:isActive?'rgba(245,192,74,0.06)':'none',border:'none',borderTop:'none',cursor:'pointer',textAlign:'left'}}>
                <TeamBadge name={opp} size={32} radius={6}/>
                <div style={{flex:1,minWidth:0}}><div style={{fontSize:13,fontWeight:600,color:isActive?'#F5C04A':'#FFF',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{opp}</div><div style={{fontSize:11,color:'#555',marginTop:1}}>{home?'Home':'Away'}{f.venue?' · '+f.venue:''}</div></div>
                <div style={{textAlign:'right',flexShrink:0}}><div style={{fontSize:12,color:'#A1A1A1',fontWeight:500}}>{fmtDate(f.date)}</div>{f.time&&<div style={{fontSize:11,color:'#555',marginTop:1}}>{f.time}</div>}</div>
                {ready?<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#22c55e" strokeWidth="2.5"><circle cx="12" cy="12" r="10"/><polyline points="9 12 11 14 15 10"/></svg>:isActive?<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#F5C04A" strokeWidth="2.5"><polyline points="9 18 15 12 9 6"/></svg>:null}
              </button>);
            })}
          </div>);
        })()}
      </div>
      <BottomNav activeTab="match" onTab={onBack}/>
    </div>
  );
}

function generatePostMatchOutputs({ game, opponent, teamName, oppR, ourR, notes, priorities, mostImproved, playerNotes, isQuick }) {
  const won = game.scoreUs > game.scoreThem;
  const drew = game.scoreUs === game.scoreThem;
  const result = won ? 'won' : drew ? 'drew' : 'lost';
  const score = `${game.scoreUs}–${game.scoreThem}`;
  const emoji = won ? '🏆' : drew ? '🤝' : '💪';

  const avgRating = (obj) => {
    const vals = Object.values(obj).filter(v => v > 0);
    return vals.length ? (vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1) : null;
  };
  const stars = (n) => '★'.repeat(Math.round(n||0)) + '☆'.repeat(5-Math.round(n||0));
  const oppAvg = avgRating(oppR);
  const ourAvg = avgRating(ourR);

  // Derive strengths/weaknesses from ratings
  const oppStrengths = Object.entries(oppR).filter(([,v])=>v>=4).map(([k])=>k);
  const oppWeaknesses = Object.entries(oppR).filter(([,v])=>v<=2).map(([k])=>k);
  const ourStrengths = Object.entries(ourR).filter(([,v])=>v>=4).map(([k])=>k);
  const ourWeaknesses = Object.entries(ourR).filter(([,v])=>v<=2).map(([k])=>k);

  const label = (k) => ({
    overallStrength:'Overall Strength', attacking:'Attacking', defending:'Defending',
    passing:'Passing', pressing:'Pressing', physicality:'Physicality', goalkeeper:'Goalkeeper',
    overallPerformance:'Overall Performance', teamShape:'Team Shape', communication:'Communication',
    workRate:'Work Rate', decisionMaking:'Decision Making', composure:'Composure', finishing:'Finishing'
  }[k] || k);

  // 1. Parent Summary
  const parentSummary = [
    `${emoji} ${teamName} ${result} ${score} against ${opponent} today!`,
    notes.ourPleased ? `\n✅ ${notes.ourPleased}` : (ourStrengths.length ? `\n✅ Great ${ourStrengths.slice(0,2).map(label).join(' & ').toLowerCase()} today.` : ''),
    priorities.length ? `\n📈 This week we'll focus on: ${priorities.slice(0,2).join(' & ')}.` : (notes.ourImprove ? `\n📈 Next focus: ${notes.ourImprove.split('.')[0]}.` : ''),
    mostImproved ? `\n⭐ Special shoutout to ${mostImproved} for their improvement today!` : '',
    `\nWell done everyone! 👏`,
  ].filter(Boolean).join('');

  // 2. Scout Report
  const scoutLines = [`${opponent} – Scout Report`, `Overall: ${oppAvg ? stars(oppAvg) + ' (' + oppAvg + '/5)' : 'Not rated'}`, ''];
  Object.entries(oppR).forEach(([k,v]) => { if(v) scoutLines.push(`${label(k)}: ${stars(v)}`); });
  if(oppStrengths.length) { scoutLines.push('', 'Strengths:'); oppStrengths.forEach(k => scoutLines.push(`• Strong ${label(k).toLowerCase()}`)); }
  if(oppWeaknesses.length) { scoutLines.push('', 'Vulnerabilities:'); oppWeaknesses.forEach(k => scoutLines.push(`• Weak ${label(k).toLowerCase()}`)); }
  if(notes.oppDidWell) scoutLines.push('', 'What they did well:', notes.oppDidWell);
  if(notes.oppProblems) scoutLines.push('', 'Caused us problems with:', notes.oppProblems);
  if(notes.oppAdvice) scoutLines.push('', 'Coach advice:', notes.oppAdvice);
  const scoutReport = scoutLines.join('\n');

  // 3. Team Review
  const teamLines = [`${teamName} – Match Review vs ${opponent} (${score})`, ''];
  if(ourAvg) teamLines.push(`Overall Rating: ${stars(ourAvg)} (${ourAvg}/5)`, '');
  if(ourStrengths.length || notes.ourPleased) {
    teamLines.push('Positives:');
    if(notes.ourPleased) teamLines.push(`• ${notes.ourPleased}`);
    ourStrengths.forEach(k => teamLines.push(`• Strong ${label(k).toLowerCase()}`));
  }
  if(ourWeaknesses.length || notes.ourImprove || priorities.length) {
    teamLines.push('', 'Development Areas:');
    if(notes.ourImprove) teamLines.push(`• ${notes.ourImprove}`);
    ourWeaknesses.forEach(k => teamLines.push(`• Improve ${label(k).toLowerCase()}`));
  }
  const teamReview = teamLines.join('\n');

  // 4. Training Recommendation
  const trainingLines = ['Recommended Training Focus:'];
  if(priorities.length) { priorities.forEach((p,i) => trainingLines.push(`${i===0?'Primary':'Additional'}: ${p}`)); }
  else if(ourWeaknesses.length) { ourWeaknesses.slice(0,3).forEach(k => trainingLines.push(`• ${label(k)}`)); }
  const trainingRec = trainingLines.join('\n');

  // 5. Player Updates
  const playerLines = [];
  if(mostImproved) playerLines.push(`⭐ Most Improved: ${mostImproved}`);
  Object.entries(playerNotes).filter(([,v])=>v.trim()).forEach(([name,note]) => {
    playerLines.push('', `${name}:`, note);
  });
  const playerUpdates = playerLines.length ? playerLines.join('\n') : 'No individual notes recorded.';

  return { parentSummary, scoutReport, teamReview, trainingRec, playerUpdates };
}

function PostMatchReviewScreen({ game, squad, opponent, config, onDone }) {
  const teamName = config?.teamName || localStorage.getItem('soccerCoach_fixtureTeam') || 'Us';
  const players  = (squad || []).map(p => p.name);

  const [step,            setStep]           = React.useState(0); // 0=summary, 1=ratings, 2=notes, 3=training
  const [oppR,            setOppR]           = React.useState({});
  const [ourR,            setOurR]           = React.useState({});
  const [notes,           setNotes]          = React.useState({ oppProblems:'', oppDidWell:'', oppAdvice:'', ourPleased:'', ourImprove:'' });
  const [priorities,      setPriorities]     = React.useState([]);
  const [mostImproved,    setMostImproved]   = React.useState('');
  const [playerNotes,     setPlayerNotes]    = React.useState({});
  const [generating,      setGenerating]     = React.useState(false);
  const [outputs,         setOutputs]        = React.useState(null);
  const [copiedKey,       setCopiedKey]      = React.useState(null);
  const [listeningField,  setListeningField] = React.useState(null);
  const [aiReview,        setAiReview]       = React.useState('');
  const recogRef = React.useRef(null);

  const won  = game.scoreUs > game.scoreThem;
  const drew = game.scoreUs === game.scoreThem;
  const resultColor = won ? '#22c55e' : drew ? '#F5C04A' : '#ef4444';
  const resultLabel = won ? 'WIN' : drew ? 'DRAW' : 'LOSS';

  const voiceNotes   = game.voiceNotes || '';
  const matchEvents  = game.matchEvents || [];
  const goals        = game.goals || [];

  // Format match events for display/AI
  function fmtEvents(evts) {
    return evts.map(e => {
      const rule = (typeof MATCH_EVENT_RULES !== 'undefined' ? MATCH_EVENT_RULES : []).find(r => r.type === e.type) || { icon:'📝', label: e.type };
      const team = e.team === 'us' ? teamName : (opponent || 'Them');
      const parts = [];
      if (e.player) parts.push(e.player + (e.secondaryPlayer ? ` (assist: ${e.secondaryPlayer})` : ''));
      if (e.category) parts.push(`cause: ${e.category}`);
      const noteVal = e.note || e.notes || '';
      if (noteVal) parts.push(noteVal);
      return `${rule.icon} ${e.minute}' ${rule.label}${e.team ? ` (${team})` : ''}${parts.length ? ' — ' + parts.join(', ') : ''}`;
    }).join('\n');
  }

  // ── Voice dictation ──────────────────────────────────────────────────────────
  const SpeechRec = typeof window !== 'undefined' && (window.SpeechRecognition || window.webkitSpeechRecognition);
  function toggleVoice(field) {
    if (listeningField === field) { recogRef.current && recogRef.current.stop(); setListeningField(null); return; }
    if (!SpeechRec) return;
    const r = new SpeechRec();
    r.continuous = true; r.interimResults = false; r.lang = 'en-AU';
    r.onresult = e => { const t = Array.from(e.results).map(x=>x[0].transcript).join(' '); setNotes(prev=>({...prev,[field]:(prev[field]?prev[field]+' ':'')+t})); };
    r.onend = () => setListeningField(null);
    recogRef.current = r; r.start(); setListeningField(field);
  }

  // ── Star rating ──────────────────────────────────────────────────────────────
  function StarRow({ label, field, ratings, setRatings }) {
    const val = ratings[field] || 0;
    return (
      <div style={{display:'flex',alignItems:'center',padding:'10px 0',borderBottom:'1px solid #1E1E1E'}}>
        <div style={{flex:1,fontSize:13,color:'#A1A1A1'}}>{label}</div>
        <div style={{display:'flex',gap:2}}>
          {[1,2,3,4,5].map(n=>(
            <button key={n} onClick={()=>setRatings(prev=>({...prev,[field]:n}))}
              style={{background:'none',border:'none',cursor:'pointer',padding:'2px',fontSize:26,lineHeight:1,color:n<=val?'#F5C04A':'#2A2A2A',transition:'color 0.1s'}}>★</button>
          ))}
        </div>
      </div>
    );
  }

  // ── Note field with mic ──────────────────────────────────────────────────────
  function NoteField({ label, field, placeholder, rows=3 }) {
    const isLive = listeningField === field;
    return (
      <div style={{marginBottom:14}}>
        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:6}}>
          <div style={{fontSize:12,fontWeight:700,color:'#A1A1A1',textTransform:'uppercase',letterSpacing:0.8}}>{label}</div>
          {SpeechRec && (
            <button onClick={()=>toggleVoice(field)}
              style={{background:isLive?'#ef444418':'none',border:isLive?'1px solid #ef4444':'none',borderRadius:6,padding:'3px 8px',cursor:'pointer',display:'flex',alignItems:'center',gap:4,color:isLive?'#ef4444':'#555'}}>
              <svg width="11" height="11" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/></svg>
              <span style={{fontSize:10,fontWeight:700}}>{isLive?'Stop':'Dictate'}</span>
            </button>
          )}
        </div>
        <textarea value={notes[field]} onChange={e=>setNotes(prev=>({...prev,[field]:e.target.value}))}
          placeholder={placeholder} rows={rows}
          style={{width:'100%',background:'#0D0D0D',border:`1px solid ${isLive?'#ef4444':'#2A2A2A'}`,borderRadius:10,padding:'10px 12px',color:'#FFF',fontSize:13,outline:'none',resize:'vertical',fontFamily:'inherit',boxSizing:'border-box',lineHeight:1.5}}/>
      </div>
    );
  }

  // ── Training priorities ──────────────────────────────────────────────────────
  const ALL_PRIORITIES = ['Building Out','Playing Through Midfield','Final Third','Finishing','Width','Switching Play','First Touch','Passing','Communication','Team Shape','Pressing','Recovery Runs','Counter Attacking','1v1 Attacking','1v1 Defending','Throw Ins','Corners','Goal Kicks','Goalkeeping'];
  function togglePriority(p) { setPriorities(prev=>prev.includes(p)?prev.filter(x=>x!==p):prev.length<3?[...prev,p]:prev); }

  // ── Delete voice transcript from saved game ──────────────────────────────────
  const [localVoiceNotes, setLocalVoiceNotes] = React.useState(voiceNotes);
  function deleteTranscript() {
    setLocalVoiceNotes('');
    try {
      const games = loadGames();
      const updated = games.map(g => g.id === game.id ? { ...g, voiceNotes: '' } : g);
      saveGames(updated);
    } catch {}
  }

  // ── Build AI prompt ────────────────────────────────────────────────────────────
  function buildAIPrompt() {
    const us = goals.filter(g=>g.team==='us').length;
    const them = goals.filter(g=>g.team==='them').length;
    const goalSummary = goals.map(g=>`${g.team==='us'?`${g.scorer||'Unknown'}${g.position?` (${g.position})`:''} (us)`:'Opponent'} — H${g.half} ${g.timeStr}`).join('\n') || 'No goals logged';
    const evtSummary = matchEvents.length ? fmtEvents(matchEvents) : 'No match events recorded';
    const coachNotes = [
      notes.ourPleased ? `What pleased us: ${notes.ourPleased}` : '',
      notes.ourImprove ? `Areas to improve: ${notes.ourImprove}` : '',
      notes.oppProblems ? `Opposition caused problems with: ${notes.oppProblems}` : '',
      notes.oppAdvice ? `Advice for playing them: ${notes.oppAdvice}` : '',
      priorities.length ? `Training priorities: ${priorities.join(', ')}` : '',
      mostImproved ? `Most improved: ${mostImproved}` : '',
    ].filter(Boolean).join('\n');
    const pNotes = Object.entries(playerNotes).filter(([,v])=>v.trim()).map(([n,v])=>`${n}: ${v}`).join('\n');
    return `Generate a detailed match review for a U11 girls soccer match. Be direct and factual. Do not embellish with fluff.

Opponent: ${opponent || 'Opposition'}
Formation: ${game.config?.formation || '1-3-2-3'}
Final score: Us ${us} – Them ${them}
Result: ${won?'Win':drew?'Draw':'Loss'}

Goals:
${goalSummary}

Match events:
${evtSummary}
${localVoiceNotes.trim() ? `\nVoice note transcription from coach:\n${localVoiceNotes.trim()}` : ''}
${coachNotes ? `\nCoach notes:\n${coachNotes}` : ''}
${pNotes ? `\nPlayer observations:\n${pNotes}` : ''}

Write 3-4 focused paragraphs covering: result and key moments, what worked well (with player names where known), 1-2 clear development areas, and brief next steps. Be specific and grounded.`;
  }

  // ── Generate match notes (AI + local outputs) ─────────────────────────────────
  async function handleGenerate() {
    setGenerating(true);
    // Run local outputs
    const result = generatePostMatchOutputs({ game, opponent, teamName, oppR, ourR, notes, priorities, mostImproved, playerNotes, isQuick: true });
    // Run AI review
    let ai = '';
    try {
      const resp = await fetch('https://api.anthropic.com/v1/messages', {
        method:'POST',
        headers:{'Content-Type':'application/json','anthropic-version':'2023-06-01'},
        body: JSON.stringify({ model:'claude-sonnet-4-6', max_tokens:900, messages:[{role:'user',content:buildAIPrompt()}] })
      });
      const data = await resp.json();
      ai = data?.content?.[0]?.text || '';
    } catch {}
    setAiReview(ai);
    try {
      const key = 'soccerCoach_postMatch_' + (game.id || Date.now());
      const stored = JSON.parse(localStorage.getItem('soccerCoach_allPostMatch') || '[]');
      stored.unshift({ id:key, gameId:game.id, opponent, date:Date.now(), oppR, ourR, notes, priorities, mostImproved, playerNotes, aiReview:ai, outputs:result });
      localStorage.setItem('soccerCoach_allPostMatch', JSON.stringify(stored.slice(0,50)));
    } catch {}
    setOutputs(result);
    setGenerating(false);
  }

  function copyOutput(key, text) {
    try { navigator.clipboard.writeText(text); } catch {}
    setCopiedKey(key); setTimeout(()=>setCopiedKey(null), 2000);
  }

  const oppCats = [['overallStrength','Overall Strength'],['attacking','Attacking'],['defending','Defending'],['pressing','Pressing']];
  const ourCats = [['overallPerformance','Overall Performance'],['attacking','Attacking'],['defending','Defending'],['teamShape','Team Shape']];

  // ── Shared page header ────────────────────────────────────────────────────────
  function PageHeader({ title, step: s, total, onBack }) {
    return (
      <div style={{background:'#0D0D0D',borderBottom:'1px solid #1A1A1A',paddingTop:'max(env(safe-area-inset-top),14px)',paddingBottom:14,paddingLeft:16,paddingRight:16,flexShrink:0,display:'flex',alignItems:'center',position:'relative'}}>
        <button onClick={onBack} style={{background:'none',border:'none',color:'#F5C04A',fontSize:22,cursor:'pointer',padding:0,lineHeight:1,flexShrink:0,zIndex:1}}>←</button>
        <img src={KHULA_LOGO} alt="Khula" style={{height:40,objectFit:'contain',marginLeft:8,zIndex:1}} />
        <div style={{position:'absolute',left:0,right:0,textAlign:'center',pointerEvents:'none'}}>
          <span style={{fontSize:17,fontWeight:500,color:'#CCC'}}>{title}</span>
        </div>
        <div style={{flex:1}} />
        {s && total && (
          <div style={{display:'flex',alignItems:'center',gap:4,zIndex:1}}>
            <span style={{fontSize:11,color:'#555'}}>{s}/{total}</span>
            <div style={{display:'flex',gap:3}}>
              {Array.from({length:total}).map((_,i)=>(
                <div key={i} style={{height:3,borderRadius:2,width:i<s?18:10,background:i<s?'#F5C04A':'#2A2A2A',transition:'all 0.3s'}}/>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  }

  // ────────────────────────────────────────────────────────────────────────────
  // SCREEN 0: Match Summary (entry point)
  // ────────────────────────────────────────────────────────────────────────────
  if (step === 0 && !outputs) return (
    <div style={{minHeight:'100dvh',background:'#0D0D0D',display:'flex',flexDirection:'column',paddingBottom:90}}>
      {/* Header */}
      <div style={{background:'#0D0D0D',borderBottom:'1px solid #1A1A1A',paddingTop:'max(env(safe-area-inset-top),14px)',paddingBottom:14,paddingLeft:16,paddingRight:16,display:'flex',alignItems:'center',position:'relative',flexShrink:0}}>
        <img src={KHULA_LOGO} alt="Khula" style={{height:40,objectFit:'contain',zIndex:1}} />
        <div style={{position:'absolute',left:0,right:0,textAlign:'center',pointerEvents:'none'}}>
          <span style={{fontSize:17,fontWeight:500,color:'#CCC'}}>Post Match Review</span>
        </div>
        <div style={{flex:1}} />
        <button onClick={onDone} style={{background:'none',border:'none',color:'#555',fontSize:13,cursor:'pointer',padding:0,zIndex:1}}>Skip</button>
      </div>
      <div style={{background:'#111111',borderBottom:'1px solid #1E1E1E',padding:'14px 16px'}}>
        <div style={{display:'flex',alignItems:'center',gap:12}}>
          <TeamBadge name={teamName} size={44} radius={10}/>
          <div style={{flex:1}}>
            <div style={{fontSize:28,fontWeight:900,color:'#FFFFFF',lineHeight:1}}>{game.scoreUs} – {game.scoreThem}</div>
            <div style={{fontSize:13,color:'#A1A1A1',marginTop:3}}>vs {opponent}</div>
          </div>
          <div style={{background:resultColor+'22',border:`1px solid ${resultColor}44`,borderRadius:10,padding:'6px 14px',fontSize:13,fontWeight:800,color:resultColor}}>{resultLabel}</div>
        </div>
      </div>

      <div style={{flex:1,overflowY:'auto',padding:'16px 16px 8px'}}>

        {/* Voice notes summary */}
        {localVoiceNotes.trim() && (
          <div style={{background:'#111111',border:'1px solid #a78bfa33',borderRadius:14,padding:'14px 16px',marginBottom:12}}>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:8}}>
              <div style={{fontSize:11,fontWeight:800,color:'#a78bfa',letterSpacing:1.2,textTransform:'uppercase'}}>🎙️ Voice Note Transcription</div>
              <button onClick={deleteTranscript}
                style={{background:'#1A0A0A',border:'1px solid #ef444433',borderRadius:6,padding:'3px 8px',color:'#ef4444',fontSize:10,fontWeight:700,cursor:'pointer'}}>
                Delete
              </button>
            </div>
            <div style={{fontSize:13,color:'#d1d5db',lineHeight:1.6,whiteSpace:'pre-wrap',maxHeight:120,overflow:'hidden',WebkitMaskImage:'linear-gradient(to bottom, black 70%, transparent 100%)',maskImage:'linear-gradient(to bottom, black 70%, transparent 100%)'}}>{localVoiceNotes.trim()}</div>
          </div>
        )}

        {/* Match events summary */}
        {matchEvents.length > 0 && (
          <div style={{background:'#111111',border:'1px solid #1E1E1E',borderRadius:14,padding:'14px 16px',marginBottom:12}}>
            <div style={{fontSize:11,fontWeight:800,color:'#38bdf8',letterSpacing:1.2,textTransform:'uppercase',marginBottom:8}}>📋 Match Events ({matchEvents.length})</div>
            <div style={{display:'flex',flexDirection:'column',gap:4}}>
              {matchEvents.slice(0,6).map((ev,i) => {
                const rule = (typeof MATCH_EVENT_RULES !== 'undefined' ? MATCH_EVENT_RULES : []).find(r=>r.type===ev.type) || {icon:'📝',label:ev.type,color:'#A1A1A1'};
                return (
                  <div key={i} style={{display:'flex',alignItems:'center',gap:8,padding:'4px 0',borderBottom:i<Math.min(matchEvents.length,6)-1?'1px solid #1E1E1E':'none'}}>
                    <span style={{fontSize:12,color:'#555',minWidth:24,fontWeight:700}}>{ev.minute}'</span>
                    <span style={{fontSize:13}}>{rule.icon}</span>
                    <span style={{fontSize:12,color:rule.color||'#A1A1A1',fontWeight:600}}>{rule.label}</span>
                    <span style={{fontSize:11,color:'#555'}}>{ev.team==='us'?teamName:opponent||'Them'}</span>
                    {ev.notes && <span style={{fontSize:11,color:'#555',flex:1,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>— {ev.notes}</span>}
                  </div>
                );
              })}
              {matchEvents.length > 6 && <div style={{fontSize:11,color:'#555',paddingTop:4}}>+{matchEvents.length-6} more events</div>}
            </div>
          </div>
        )}

        {/* Goals summary */}
        {goals.length > 0 && (
          <div style={{background:'#111111',border:'1px solid #1E1E1E',borderRadius:14,padding:'14px 16px',marginBottom:12}}>
            <div style={{fontSize:11,fontWeight:800,color:'#F5C04A',letterSpacing:1.2,textTransform:'uppercase',marginBottom:8}}>⚽ Goals</div>
            {goals.filter(g=>g.team==='us').map((g,i)=>(
              <div key={i} style={{fontSize:13,color:'#FFFFFF',paddingBottom:4}}>⚽ {g.scorer} <span style={{color:'#555',fontSize:11}}>{g.timeStr}</span></div>
            ))}
            {goals.filter(g=>g.team==='them').map((g,i)=>(
              <div key={i} style={{fontSize:13,color:'#fca5a5',paddingBottom:4}}>⚽ {opponent} <span style={{color:'#555',fontSize:11}}>{g.timeStr}</span></div>
            ))}
          </div>
        )}

        {/* No data notice */}
        {!voiceNotes.trim() && matchEvents.length === 0 && goals.length === 0 && (
          <div style={{background:'#111111',border:'1px solid #1E1E1E',borderRadius:14,padding:'20px 16px',marginBottom:12,textAlign:'center'}}>
            <div style={{fontSize:32,marginBottom:8}}>📋</div>
            <div style={{fontSize:14,fontWeight:700,color:'#FFF',marginBottom:4}}>Match saved</div>
            <div style={{fontSize:12,color:'#555'}}>Add further notes below to capture your coaching observations.</div>
          </div>
        )}

        {/* CTAs */}
        <button onClick={()=>setStep(1)}
          style={{width:'100%',padding:'16px',border:'none',borderRadius:14,fontSize:15,fontWeight:800,cursor:'pointer',background:'#F5C04A',color:'#000',marginBottom:10}}>
          Further Notes →
        </button>
        <button onClick={handleGenerate}
          style={{width:'100%',padding:'14px',border:'1px solid #22c55e44',borderRadius:14,fontSize:14,fontWeight:700,cursor:'pointer',background:'#22c55e18',color:'#22c55e',marginBottom:10}}>
          Generate Match Notes
        </button>

      </div>
      <BottomNav activeTab="match" onTab={()=>{}}/>
    </div>
  );

  // ────────────────────────────────────────────────────────────────────────────
  // STEP 1: Ratings
  // ────────────────────────────────────────────────────────────────────────────
  if (step === 1 && !outputs) return (
    <div style={{display:'flex',flexDirection:'column',height:'100dvh',background:'#0D0D0D',overflow:'hidden'}}>
      <PageHeader title="Match Ratings" step={1} total={3} onBack={()=>setStep(0)}/>
      <div style={{flex:1,overflowY:'auto',padding:'16px',paddingBottom:110}}>

        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',overflow:'hidden',marginBottom:12}}>
          <div style={{padding:'12px 16px',borderBottom:'1px solid #1E1E1E',display:'flex',alignItems:'center',gap:10}}>
            <TeamBadge name={opponent} size={28} radius={6}/>
            <div style={{fontSize:12,fontWeight:800,color:'#38bdf8',letterSpacing:1,textTransform:'uppercase'}}>{opponent}</div>
          </div>
          <div style={{padding:'0 16px'}}>
            {oppCats.map(([field,label])=>(<StarRow key={field} label={label} field={field} ratings={oppR} setRatings={setOppR}/>))}
          </div>
        </div>

        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',overflow:'hidden',marginBottom:12}}>
          <div style={{padding:'12px 16px',borderBottom:'1px solid #1E1E1E',display:'flex',alignItems:'center',gap:10}}>
            <TeamBadge name={teamName} size={28} radius={6}/>
            <div style={{fontSize:12,fontWeight:800,color:'#22c55e',letterSpacing:1,textTransform:'uppercase'}}>{teamName}</div>
          </div>
          <div style={{padding:'0 16px'}}>
            {ourCats.map(([field,label])=>(<StarRow key={field} label={label} field={field} ratings={ourR} setRatings={setOurR}/>))}
          </div>
        </div>
      </div>
      <div style={{position:'fixed',bottom:80,left:0,right:0,padding:'12px 16px',background:'#0D0D0D',borderTop:'1px solid #1E1E1E'}}>
        <button onClick={()=>setStep(2)} style={{width:'100%',padding:'15px',border:'none',borderRadius:14,fontSize:15,fontWeight:800,cursor:'pointer',background:'#F5C04A',color:'#000'}}>
          Next →
        </button>
      </div>
      <BottomNav activeTab="match" onTab={()=>{}}/>
    </div>
  );

  // ────────────────────────────────────────────────────────────────────────────
  // STEP 2: Coaching notes + Player notes
  // ────────────────────────────────────────────────────────────────────────────
  if (step === 2 && !outputs) return (
    <div style={{display:'flex',flexDirection:'column',height:'100dvh',background:'#0D0D0D',overflow:'hidden'}}>
      <PageHeader title="Coaching Notes" step={2} total={3} onBack={()=>setStep(1)}/>
      <div style={{flex:1,overflowY:'auto',padding:'16px',paddingBottom:110}}>

        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'14px 16px',marginBottom:12}}>
          <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:14}}>
            <TeamBadge name={opponent} size={22} radius={5}/>
            <div style={{fontSize:11,fontWeight:800,color:'#38bdf8',letterSpacing:1,textTransform:'uppercase'}}>{opponent}</div>
          </div>
          <NoteField label="What caused us the most problems?" field="oppProblems" placeholder="Their pressing, direct play, set pieces…"/>
          <NoteField label="Advice for playing them next time" field="oppAdvice" placeholder="Play wide, quick transitions, watch #9…"/>
        </div>

        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'14px 16px',marginBottom:12}}>
          <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:14}}>
            <TeamBadge name={teamName} size={22} radius={5}/>
            <div style={{fontSize:11,fontWeight:800,color:'#22c55e',letterSpacing:1,textTransform:'uppercase'}}>{teamName}</div>
          </div>
          <NoteField label="What pleased you today?" field="ourPleased" placeholder="Great pressing, team shape held well…"/>
          <NoteField label="What should we improve?" field="ourImprove" placeholder="Final third decisions, composure in front of goal…"/>
        </div>

        {/* Player notes — always shown */}
        {players.length > 0 && (
          <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'14px 16px',marginBottom:12}}>
            <div style={{fontSize:11,fontWeight:800,color:'#F5C04A',letterSpacing:1.2,textTransform:'uppercase',marginBottom:4}}>Player Notes</div>
            <div style={{fontSize:11,color:'#555',marginBottom:12}}>Individual observations — optional</div>
            {players.slice(0,14).map(name=>(
              <div key={name} style={{marginBottom:10}}>
                <div style={{fontSize:12,fontWeight:700,color:'#A1A1A1',marginBottom:4}}>{name}</div>
                <input value={playerNotes[name]||''} onChange={e=>setPlayerNotes(prev=>({...prev,[name]:e.target.value}))}
                  placeholder="Short observation…"
                  style={{width:'100%',background:'#0D0D0D',border:'1px solid #2A2A2A',borderRadius:8,padding:'9px 12px',color:'#FFF',fontSize:13,outline:'none',boxSizing:'border-box'}}/>
              </div>
            ))}
          </div>
        )}
      </div>
      <div style={{position:'fixed',bottom:80,left:0,right:0,padding:'12px 16px',background:'#0D0D0D',borderTop:'1px solid #1E1E1E'}}>
        <button onClick={()=>setStep(3)} style={{width:'100%',padding:'15px',border:'none',borderRadius:14,fontSize:15,fontWeight:800,cursor:'pointer',background:'#F5C04A',color:'#000'}}>
          Next →
        </button>
      </div>
      <BottomNav activeTab="match" onTab={()=>{}}/>
    </div>
  );

  // ────────────────────────────────────────────────────────────────────────────
  // STEP 3: Training priorities + AI Review
  // ────────────────────────────────────────────────────────────────────────────
  if (step === 3 && !outputs) return (
    <div style={{display:'flex',flexDirection:'column',height:'100dvh',background:'#0D0D0D',overflow:'hidden'}}>
      <PageHeader title="Training Focus" step={3} total={3} onBack={()=>setStep(2)}/>
      <div style={{flex:1,overflowY:'auto',padding:'16px',paddingBottom:110}}>

        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'14px 16px',marginBottom:12}}>
          <div style={{fontSize:11,fontWeight:800,color:'#F5C04A',letterSpacing:1.2,textTransform:'uppercase',marginBottom:4}}>Training Priorities <span style={{color:'#555',fontWeight:500,fontSize:11}}>({priorities.length}/3)</span></div>
          <div style={{fontSize:11,color:'#555',marginBottom:12}}>Select up to 3 focus areas for next session</div>
          <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
            {ALL_PRIORITIES.map(p => {
              const sel = priorities.includes(p);
              const dis = !sel && priorities.length >= 3;
              return (
                <button key={p} onClick={()=>!dis&&togglePriority(p)}
                  style={{padding:'8px 14px',borderRadius:20,border:`1.5px solid ${sel?'#F5C04A':'#2A2A2A'}`,background:sel?'#F5C04A18':'#1A1A1A',color:sel?'#F5C04A':dis?'#333':'#A1A1A1',fontSize:12,fontWeight:sel?700:500,cursor:dis?'default':'pointer'}}>
                  {p}
                </button>
              );
            })}
          </div>
        </div>

        <div style={{background:'#111111',borderRadius:14,border:'1px solid #1E1E1E',padding:'14px 16px',marginBottom:12}}>
          <div style={{fontSize:11,fontWeight:800,color:'#F5C04A',letterSpacing:1.2,textTransform:'uppercase',marginBottom:4}}>Most Improved Player</div>
          <div style={{fontSize:11,color:'#555',marginBottom:10}}>Track development — not Player of the Match</div>
          <select value={mostImproved} onChange={e=>setMostImproved(e.target.value)}
            style={{width:'100%',background:'#0D0D0D',border:'1px solid #2A2A2A',borderRadius:10,padding:'11px 14px',color:mostImproved?'#FFF':'#555',fontSize:14,outline:'none'}}>
            <option value="">Select player…</option>
            {players.map(p=><option key={p} value={p}>{p}</option>)}
          </select>
        </div>

      </div>
      <div style={{position:'fixed',bottom:80,left:0,right:0,padding:'12px 16px',background:'#0D0D0D',borderTop:'1px solid #1E1E1E'}}>
        <button onClick={handleGenerate}
          style={{width:'100%',padding:'16px',border:'none',borderRadius:14,fontSize:15,fontWeight:800,cursor:'pointer',background:'#22c55e',color:'#000'}}>
          ✨ Generate Match Notes
        </button>
      </div>
      <BottomNav activeTab="match" onTab={()=>{}}/>
    </div>
  );

  // ────────────────────────────────────────────────────────────────────────────
  // Generating loader
  // ────────────────────────────────────────────────────────────────────────────
  if (generating) return (
    <div style={{minHeight:'100dvh',background:'#0D0D0D',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',gap:20,padding:32}}>
      <div style={{fontSize:40}}>✨</div>
      <div style={{fontSize:18,fontWeight:800,color:'#FFF',textAlign:'center'}}>Generating Match Notes…</div>
      <div style={{fontSize:13,color:'#555',textAlign:'center',maxWidth:280}}>Building AI review, parent summary, scout report, team review, and training plan</div>
      <div style={{display:'flex',gap:6,marginTop:4}}>
        {[0,1,2].map(i=>(
          <div key={i} style={{width:8,height:8,borderRadius:4,background:'#22c55e',opacity:0.4,animation:'pulse 1.2s ease-in-out infinite',animationDelay:`${i*0.3}s`}}/>
        ))}
      </div>
      <style>{`@keyframes pulse{0%,100%{opacity:0.2}50%{opacity:1}}`}</style>
    </div>
  );

  // ────────────────────────────────────────────────────────────────────────────
  // Outputs screen
  // ────────────────────────────────────────────────────────────────────────────
  if (outputs) {
    const OUT_CARDS = [
      { key:'parentSummary', title:'📱 Parent Summary',  subtitle:'WhatsApp-ready', color:'#22c55e',  text:outputs.parentSummary },
      { key:'scoutReport',   title:'🔍 Scout Report',    subtitle:opponent,         color:'#F5C04A',  text:outputs.scoutReport   },
      { key:'teamReview',    title:'📊 Team Review',     subtitle:teamName,         color:'#38bdf8',  text:outputs.teamReview    },
      { key:'trainingRec',   title:'🏋️ Training Focus',  subtitle:'Next session',   color:'#a78bfa',  text:outputs.trainingRec   },
      { key:'playerUpdates', title:'⭐ Player Notes',    subtitle:'Development',    color:'#fb923c',  text:outputs.playerUpdates },
    ];
    if (aiReview) OUT_CARDS.splice(2, 0, { key:'aiReview', title:'✨ AI Match Review', subtitle:'Detailed analysis', color:'#a78bfa', text:aiReview });

    return (
      <div style={{display:'flex',flexDirection:'column',minHeight:'100dvh',background:'#0D0D0D'}}>
        <div style={{background:'#0D0D0D',borderBottom:'1px solid #1A1A1A',paddingTop:'max(env(safe-area-inset-top),14px)',paddingBottom:14,paddingLeft:16,paddingRight:16,display:'flex',alignItems:'center',position:'relative'}}>
          <img src={KHULA_LOGO} alt="Khula" style={{height:40,objectFit:'contain',zIndex:1}} />
          <div style={{position:'absolute',left:0,right:0,textAlign:'center',pointerEvents:'none'}}>
            <span style={{fontSize:17,fontWeight:500,color:'#CCC'}}>Review Complete</span>
          </div>
          <div style={{flex:1}} />
          <div style={{display:'flex',alignItems:'center',gap:5,zIndex:1}}>
            <span style={{fontSize:11,color:'#22c55e',fontWeight:600}}>✓ Done</span>
          </div>
        </div>
        <div style={{flex:1,padding:'16px',paddingBottom:120,display:'flex',flexDirection:'column',gap:10}}>
          {OUT_CARDS.map(card=>(
            <div key={card.key} style={{background:'#111111',borderRadius:14,border:`1px solid ${card.color}33`,overflow:'hidden'}}>
              <div style={{padding:'12px 16px',borderBottom:`1px solid ${card.color}22`,display:'flex',alignItems:'center',justifyContent:'space-between'}}>
                <div>
                  <div style={{fontSize:14,fontWeight:600,color:card.color}}>{card.title}</div>
                  <div style={{fontSize:11,color:'#555',marginTop:1}}>{card.subtitle}</div>
                </div>
                <button onClick={()=>copyOutput(card.key,card.text)}
                  style={{background:copiedKey===card.key?card.color+'22':'#1A1A1A',border:`1px solid ${copiedKey===card.key?card.color:'#2A2A2A'}`,borderRadius:8,padding:'6px 12px',cursor:'pointer',color:copiedKey===card.key?card.color:'#A1A1A1',fontSize:11,fontWeight:700}}>
                  {copiedKey===card.key?'✓ Copied':'Copy'}
                </button>
              </div>
              <div style={{padding:'12px 16px'}}>
                <pre style={{margin:0,fontFamily:'inherit',fontSize:12,color:'#A1A1A1',whiteSpace:'pre-wrap',lineHeight:1.6}}>{card.text}</pre>
              </div>
            </div>
          ))}
        </div>
        <div style={{position:'fixed',bottom:80,left:0,right:0,padding:'12px 16px',background:'#0D0D0D',borderTop:'1px solid #1E1E1E'}}>
          <button onClick={onDone} style={{width:'100%',padding:'15px',border:'none',borderRadius:14,fontSize:15,fontWeight:700,cursor:'pointer',background:'#22c55e',color:'#000'}}>
            Done ✓
          </button>
        </div>
        <BottomNav activeTab="match" onTab={()=>{}}/>
      </div>
    );
  }

  return null;
}

function HomeScreen({ games, settings, onMatchDay, onGoSeason, onGoTeam, onGoMore, onGoAccount, setTab }) {
  const coachName = settings?.coachName || 'Coach';
  const teamName  = settings?.teamName || localStorage.getItem('soccerCoach_fixtureTeam') || 'My Team';
  const myTeam    = localStorage.getItem('soccerCoach_fixtureTeam') || '';

  const playerCount = (() => {
    try { return JSON.parse(localStorage.getItem('soccerCoach_squad')||'[]').length; }
    catch(e) { return 0; }
  })();

  const nextFix = FIXTURES.find(f => isUpcoming(f) && (f.home===myTeam||f.away===myTeam));
  const { played, wins, draws, losses, gf, ga, gd } = computeSeasonStats();
  const winRate = played > 0 ? Math.round(wins / played * 100) : 0;
  const recentRes = getAllResults().slice(-3).reverse();

  const DAYS   = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
  const MONTHS = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  function fmtDate(dateStr) {
    if (!dateStr) return '';
    const d = parseFixtureDate(dateStr);
    if (!d) return dateStr;
    return `${DAYS[d.getDay()]} ${d.getDate()} ${MONTHS[d.getMonth()]}`;
  }

  const R = 46, CIRC = 2 * Math.PI * R;
  const arcLen = CIRC * winRate / 100;
  const arcGap = CIRC - arcLen;

  // Slide-in drawer state
  const [drawerOpen, setDrawerOpen] = React.useState(false);

  const NAV_ITEMS = [
    { id:'home',   label:'Home',   icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"/><polyline points="9 22 9 12 15 12 15 22"/></svg> },
    { id:'match',  label:'Match',  icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="3" width="20" height="18" rx="2"/><line x1="12" y1="3" x2="12" y2="21"/><line x1="2" y1="12" x2="22" y2="12"/></svg> },
    { id:'season', label:'Season', icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg> },
    { id:'team',   label:'Team',   icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="9" cy="7" r="4"/><path d="M3 21v-2a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/><circle cx="18" cy="9" r="3"/><path d="M21 21v-2a3 3 0 0 0-2-2.83"/></svg> },
    { id:'more',   label:'More',   icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="1"/><circle cx="19" cy="12" r="1"/><circle cx="5" cy="12" r="1"/></svg> },
    { id:'account',label:'Account',icon:<svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="8" r="4"/><path d="M20 21a8 8 0 1 0-16 0"/></svg> },
  ];

  function handleNavItem(id) {
    setDrawerOpen(false);
    if (id === 'account') { onGoAccount(); return; }
    if (id === 'more')    { onGoMore();    return; }
    if (setTab)           setTab(id);
  }

  return (
    <div style={{ minHeight:'100vh', background:'#0D0D0D', paddingBottom:90, paddingTop:'max(env(safe-area-inset-top),0px)' }}>

      {/* ── Slide-in drawer overlay ── */}
      {drawerOpen && (
        <div style={{ position:'fixed', inset:0, zIndex:1000 }} onClick={()=>setDrawerOpen(false)}>
          <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.65)' }}/>
          <div onClick={e=>e.stopPropagation()} style={{ position:'absolute', left:0, top:0, bottom:0, width:260, background:'#111111', borderRight:'1px solid #2A2A2A', display:'flex', flexDirection:'column', paddingTop:'max(env(safe-area-inset-top),24px)' }}>
            <div style={{ padding:'0 20px 20px', borderBottom:'1px solid #1A1A1A' }}>
              <img src={KHULA_LOGO} alt="Khula" style={{ height:38, objectFit:'contain' }}/>
            </div>
            {NAV_ITEMS.map(item => (
              <button key={item.id} onClick={()=>handleNavItem(item.id)} style={{ display:'flex', alignItems:'center', gap:14, padding:'16px 22px', background:'none', border:'none', cursor:'pointer', color:'#FFFFFF', borderBottom:'1px solid #1A1A1A20', textAlign:'left' }}>
                <span style={{ color:'#F5C04A' }}>{item.icon}</span>
                <span style={{ fontSize:15, fontWeight:500, color:'#FFFFFF' }}>{item.label}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* ── Top bar ── */}
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', padding:'4px 18px', background:'#000000', borderBottom:'1px solid #1A1A1A' }}>
        <button onClick={()=>setDrawerOpen(true)} style={{ background:'none', border:'none', cursor:'pointer', padding:6 }}>
          <svg width="22" height="16" viewBox="0 0 22 16" fill="none">
            <line x1="0" y1="1"  x2="22" y2="1"  stroke="#F5C04A" strokeWidth="2" strokeLinecap="round"/>
            <line x1="0" y1="8"  x2="22" y2="8"  stroke="#F5C04A" strokeWidth="2" strokeLinecap="round"/>
            <line x1="0" y1="15" x2="22" y2="15" stroke="#F5C04A" strokeWidth="2" strokeLinecap="round"/>
          </svg>
        </button>
        <img src={KHULA_LOGO} alt="Khula" style={{ height:88, objectFit:'contain' }}/>
        <button onClick={onGoAccount} style={{ background:'none', border:'none', cursor:'pointer', padding:6, color:'#A1A1A1' }}>
          <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <circle cx="12" cy="8" r="4"/><path d="M20 21a8 8 0 1 0-16 0"/>
          </svg>
        </button>
      </div>

      {/* ── Hero gradient + greeting ── */}
      <div style={{ display:'flex', alignItems:'stretch', justifyContent:'space-between', background:'radial-gradient(ellipse at 65% -10%, #3D2800 0%, #1A1000 40%, #0D0D0D 72%)', borderBottom:'1px solid #1A1A1A', overflow:'hidden' }}>
        <div style={{ flex:1, padding:'10px 12px 10px 16px', display:'flex', flexDirection:'column', justifyContent:'center' }}>
          <div style={{ fontSize:12, color:'#A1A1A1', fontWeight:400, marginBottom:1 }}>{getGreeting()}, Coach</div>
          <div style={{ fontSize:32, fontWeight:700, color:'#FFFFFF', lineHeight:1.0, marginBottom:1 }}>{coachName}</div>
          <div style={{ fontSize:12, color:'#A1A1A1', fontStyle:'italic', fontWeight:300 }}>Let's elevate today.</div>
        </div>
        <img src={STADIUM_IMG} alt="Stadium" style={{ display:'block', alignSelf:'stretch', width:'auto', objectFit:'cover', opacity:0.9, flexShrink:0 }}/>
      </div>

      {/* ── Your Team ── */}
      <div style={{ padding:'14px 16px 0' }}>
        <div onClick={onGoTeam} style={{ background:'#1A1A1A', borderRadius:14, padding:'14px 16px', border:'1px solid #2A2A2A', cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
          <div style={{ display:'flex', alignItems:'center', gap:12 }}>
            <TeamBadge name={teamName} size={48} radius={10} />
            <div>
              <div style={{ fontSize:10, color:'#A1A1A1', fontWeight:600, letterSpacing:0.5, marginBottom:2 }}>Your Team</div>
              <div style={{ fontSize:17, fontWeight:600, color:'#FFFFFF' }}>{teamName}</div>
              <div style={{ fontSize:11, color:'#A1A1A1', marginTop:1 }}>{playerCount > 0 ? `${playerCount} Players` : 'Tap to manage squad'}</div>
            </div>
          </div>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#F5C04A" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18l6-6-6-6"/></svg>
        </div>
      </div>

      {/* ── Next Match ── */}
      {nextFix && (
        <div style={{ padding:'12px 16px 0' }}>
          <div style={{ background:'#1A1A1A', borderRadius:14, padding:'16px', border:'1px solid #2A2A2A' }}>
            <div style={{ fontSize:11, color:'#A1A1A1', fontWeight:600, letterSpacing:0.5, marginBottom:14 }}>Next Match</div>
            <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:14 }}>
              <div style={{ flex:1 }}>
                <TeamBadge name={nextFix.home} size={46} radius={10} style={{marginBottom:6}} />
                <div style={{ fontSize:13, fontWeight:600, color:'#FFFFFF', lineHeight:1.2 }}>{nextFix.home}</div>
              </div>
              <div style={{ flexShrink:0, alignSelf:'center', paddingBottom:20 }}>
                <div style={{ padding:'5px 12px', background:'#0D0D0D', borderRadius:8, border:'1px solid #2A2A2A', fontSize:11, color:'#A1A1A1', fontWeight:600 }}>vs</div>
              </div>
              <div style={{ flex:1, display:'flex', flexDirection:'column', alignItems:'flex-end' }}>
                <TeamBadge name={nextFix.away} size={46} radius={10} style={{marginBottom:6}} />
                <div style={{ fontSize:13, fontWeight:600, color:'#FFFFFF', textAlign:'right', lineHeight:1.2 }}>{nextFix.away}</div>
              </div>
            </div>
            <div style={{ display:'flex', alignItems:'center', gap:14, marginBottom:14, flexWrap:'wrap' }}>
              <div style={{ display:'flex', alignItems:'center', gap:5 }}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="1.8" strokeLinecap="round"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
                <span style={{ fontSize:11, color:'#A1A1A1', fontWeight:400 }}>{fmtDate(nextFix.date)}</span>
              </div>
              {nextFix.venue && <div style={{ display:'flex', alignItems:'center', gap:5 }}>
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="#A1A1A1" strokeWidth="1.8"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>
                <span style={{ fontSize:11, color:'#A1A1A1', fontWeight:400 }}>{nextFix.venue}</span>
              </div>}
            </div>
            <button onClick={onMatchDay} style={{ width:'100%', background:'#F5C04A', color:'#0D0D0D', border:'none', borderRadius:10, padding:'12px 0', fontWeight:600, fontSize:14, cursor:'pointer' }}>View Match</button>
          </div>
        </div>
      )}

      {/* ── Performance Overview ── */}
      <div style={{ padding:'12px 16px 0' }}>
        <div style={{ background:'#1A1A1A', borderRadius:14, padding:'16px', border:'1px solid #2A2A2A' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
            <span style={{ fontSize:14, fontWeight:600, color:'#FFFFFF' }}>Performance Overview</span>
            <button onClick={()=>{ _pendingSeasonSub='log'; onGoSeason(); }} style={{ background:'none', border:'none', cursor:'pointer', fontSize:12, fontWeight:600, color:'#F5C04A', padding:0 }}>See All</button>
          </div>
          <div style={{ display:'flex', gap:12, alignItems:'center' }}>
            <div style={{ flexShrink:0, position:'relative', width:110, height:110 }}>
              <svg width="110" height="110" viewBox="0 0 110 110">
                <circle cx="55" cy="55" r={R} fill="none" stroke="#2A2A2A" strokeWidth="7"/>
                {played > 0 && <circle cx="55" cy="55" r={R} fill="none" stroke="#F5C04A" strokeWidth="7"
                  strokeDasharray={`${arcLen} ${arcGap}`} strokeDashoffset={CIRC*0.25}
                  strokeLinecap="round" transform="rotate(-90 55 55)"/>}
              </svg>
              <div style={{ position:'absolute', inset:0, display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center' }}>
                <div style={{ fontSize:22, fontWeight:700, color:'#FFFFFF', lineHeight:1 }}>{winRate}<span style={{ fontSize:12, fontWeight:400 }}>%</span></div>
                <div style={{ fontSize:9, color:'#A1A1A1', fontWeight:500, textAlign:'center', marginTop:2 }}>Win Rate</div>
              </div>
            </div>
            <div style={{ flex:1, display:'grid', gridTemplateColumns:'1fr 1fr', gap:8 }}>
              {[['Played',played,'#FFFFFF'],['Won',wins,'#F5C04A'],['Lost',losses,'#ef4444'],['Drawn',draws,'#f59e0b']].map(([label,val,color])=>(
                <div key={label} style={{ background:'#0D0D0D', borderRadius:10, padding:'10px 6px', textAlign:'center' }}>
                  <div style={{ fontSize:20, fontWeight:700, color }}>{val}</div>
                  <div style={{ fontSize:10, color:'#A1A1A1', marginTop:2, fontWeight:400 }}>{label}</div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* ── Recent Activity ── */}
      <div style={{ padding:'12px 16px 16px' }}>
        <div style={{ background:'#1A1A1A', borderRadius:14, padding:'16px', border:'1px solid #2A2A2A' }}>
          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>
            <span style={{ fontSize:14, fontWeight:600, color:'#FFFFFF' }}>Recent Activity</span>
            <button onClick={onGoSeason} style={{ background:'none', border:'none', cursor:'pointer', fontSize:12, fontWeight:600, color:'#F5C04A', padding:0 }}>See All</button>
          </div>
          {recentRes.length === 0 ? (
            <div style={{ textAlign:'center', color:'#A1A1A1', fontSize:13, padding:'16px 0' }}>No matches logged yet</div>
          ) : recentRes.map((r,i) => {
            const res = r.us > r.them ? 'W' : r.us < r.them ? 'L' : 'D';
            const col = res==='W' ? '#22c55e' : res==='L' ? '#ef4444' : '#f59e0b';
            const notLast = i < recentRes.length - 1;
            return (
              <div key={r.id||i} style={{ display:'flex', alignItems:'center', gap:12, paddingBottom:notLast?12:0, borderBottom:notLast?'1px solid #2A2A2A':'none', marginBottom:notLast?12:0 }}>
                <div style={{ width:40, height:40, borderRadius:'50%', background:col+'22', display:'flex', alignItems:'center', justifyContent:'center', flexShrink:0 }}>
                  <span style={{ fontSize:13, fontWeight:700, color:col }}>{res}</span>
                </div>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:13, fontWeight:500, color:'#FFFFFF' }}>vs {r.opponent}</div>
                  <div style={{ fontSize:11, color:'#A1A1A1', marginTop:1, fontWeight:400 }}>{r.us}–{r.them} · {fmtDate(r.dateStr)}</div>
                </div>
                <div style={{ fontSize:11, fontWeight:600, color:col, flexShrink:0 }}>{res==='W'?'Win':res==='L'?'Loss':'Draw'}</div>
              </div>
            );
          })}
        </div>
      </div>

    </div>
  );
}


